# Tracks cumulative item-processed totals over time for windowed counting.
# Each entry: (timestamp, cumulative_total). Polled every ~5s, 24h = ~17280 entries.
_enrichment_activity_log = {}  # key -> deque of (timestamp, total)

def _get_windowed_calls(key, current_total):
    """Record current cumulative total and return (calls_1h, calls_24h).
    Deque stores (timestamp, cumulative_total) in chronological order.
    To get calls in a window: current_total minus the oldest total within that window."""
    now = time.time()
    history = _enrichment_activity_log.setdefault(key, collections.deque(maxlen=17300))
    history.append((now, current_total))

    cutoff_1h = now - 3600
    cutoff_24h = now - 86400

    # Forward scan: first entry with ts >= cutoff is the oldest in that window
    oldest_1h_total = current_total
    oldest_24h_total = current_total
    found_24h = False
    for ts, total in history:
        if not found_24h and ts >= cutoff_24h:
            oldest_24h_total = total
            found_24h = True
        if ts >= cutoff_1h:
            oldest_1h_total = total
            break

    return max(0, current_total - oldest_1h_total), max(0, current_total - oldest_24h_total)


_idle_since = {}  # worker_key -> timestamp when current_item first became None
_IDLE_GRACE_SECONDS = 5  # Don't report idle until current_item has been None this long

def _get_enrichment_status():
    """Get lightweight status for all enrichment services (no DB queries).
    Reads worker properties directly to avoid expensive get_stats() calls."""
    services = {}

    # Worker-based enrichment services: (key, display_name, worker_var)
    workers_info = [
        ('musicbrainz', 'MusicBrainz', lambda: mb_worker),
        ('spotify_enrichment', 'Spotify', lambda: spotify_enrichment_worker),
        ('itunes_enrichment', 'iTunes', lambda: itunes_enrichment_worker),
        ('deezer_enrichment', 'Deezer', lambda: deezer_worker),
        ('tidal_enrichment', 'Tidal', lambda: tidal_enrichment_worker),
        ('qobuz_enrichment', 'Qobuz', lambda: qobuz_enrichment_worker),
        ('lastfm', 'Last.fm', lambda: lastfm_worker),
        ('genius', 'Genius', lambda: genius_worker),
        ('audiodb', 'AudioDB', lambda: audiodb_worker),
        ('discogs', 'Discogs', lambda: discogs_worker),
    ]

    # Config-based "configured" checks for services that need API keys/credentials
    configured_checks = {
        'spotify_enrichment': lambda: bool(config_manager.get('spotify.client_id') and config_manager.get('spotify.client_secret')),
        'tidal_enrichment': lambda: bool(tidal_client and getattr(tidal_client, 'access_token', None)),
        'qobuz_enrichment': lambda: bool(qobuz_enrichment_worker and qobuz_enrichment_worker.client and qobuz_enrichment_worker.client.user_auth_token),
        'lastfm': lambda: bool(config_manager.get('lastfm.api_key', '')),
        'genius': lambda: bool(config_manager.get('genius.access_token', '')),
    }

    for key, name, get_worker in workers_info:
        worker = get_worker()
        if worker is not None:
            is_alive = worker.thread is not None and worker.thread.is_alive()
            try:
                configured = configured_checks.get(key, lambda: True)()
            except Exception:
                configured = False

            # Compute windowed API call counts from cumulative stats
            stats = worker.stats
            total_processed = stats.get('matched', 0) + stats.get('not_found', 0) + stats.get('errors', 0)
            calls_1h, calls_24h = _get_windowed_calls(key, total_processed)

            # Debounced idle detection — only report idle after 5s of no current_item
            has_item = getattr(worker, 'current_item', None) is not None
            if has_item:
                _idle_since.pop(key, None)
                is_idle = False
            else:
                if key not in _idle_since:
                    _idle_since[key] = time.time()
                is_idle = (time.time() - _idle_since[key]) >= _IDLE_GRACE_SECONDS

            svc_data = {
                'name': name,
                'configured': configured,
                'running': worker.running and is_alive and not worker.paused,
                'paused': worker.paused,
                'idle': is_alive and not worker.paused and is_idle,
                'calls_1h': calls_1h,
                'calls_24h': calls_24h,
            }

            # Spotify-specific: include daily budget info
            if key == 'spotify_enrichment':
                try:
                    svc_data['daily_budget'] = worker._get_daily_budget_info()
                except Exception:
                    pass

            services[key] = svc_data
        else:
            services[key] = {
                'name': name,
                'configured': False,
                'running': False,
                'paused': False,
                'idle': False,
                'calls_1h': 0,
                'calls_24h': 0,
            }

    # Non-worker services (configured status only)
    services['acoustid'] = {
        'name': 'AcoustID',
        'configured': bool(config_manager.get('acoustid.api_key', '')),
    }
    services['listenbrainz'] = {
        'name': 'ListenBrainz',
        'configured': bool(config_manager.get('listenbrainz.token', '')),
    }

    return services


# Status check caching to reduce unnecessary API calls
_status_cache = {
    'spotify': {'connected': False, 'response_time': 0, 'source': 'itunes'},
    'media_server': {'connected': False, 'response_time': 0, 'type': None},
    'soulseek': {'connected': False, 'response_time': 0}
}
_status_cache_timestamps = {
    'spotify': 0,
    'media_server': 0,
    'soulseek': 0
}
STATUS_CACHE_TTL = 120  # Cache for 2 minutes (reduces API calls while staying fresh)

@app.route('/status')
def get_status():
    if not config_manager:
        return jsonify({"error": "Server configuration manager is not initialized."}), 500
    try:
        import time

        current_time = time.time()
        active_server = config_manager.get_active_media_server()

        # Test Spotify - with caching to avoid excessive API calls
        if current_time - _status_cache_timestamps['spotify'] > STATUS_CACHE_TTL:
            # Guard against spotify_client being None (partial init)
            is_rate_limited = spotify_client.is_rate_limited() if spotify_client else False
            rate_limit_info = spotify_client.get_rate_limit_info() if (spotify_client and is_rate_limited) else None
            cooldown_remaining = spotify_client.get_post_ban_cooldown_remaining() if spotify_client else 0

            if is_rate_limited or cooldown_remaining > 0:
                # During rate limit or post-ban cooldown, skip the auth probe entirely.
                # Probing Spotify here would reset the rate limit timer.
                music_source = _get_metadata_fallback_source()
                if music_source == 'spotify':
                    music_source = 'deezer'  # Spotify rate limited — can't use it
                spotify_response_time = 0
            else:
                spotify_start = time.time()
                spotify_connected = spotify_client.is_spotify_authenticated() if spotify_client else False
                spotify_response_time = (time.time() - spotify_start) * 1000
                # Use whatever the user configured as primary metadata source
                music_source = _get_metadata_fallback_source()
                # If user selected spotify but it's not authed, fall back
                if music_source == 'spotify' and not spotify_connected:
                    music_source = 'deezer'

            _status_cache['spotify'] = {
                'connected': True,  # Always true — iTunes fallback is always available
                'response_time': round(spotify_response_time, 1),
                'source': music_source,
                'rate_limited': is_rate_limited,
                'rate_limit': rate_limit_info,
                'post_ban_cooldown': cooldown_remaining if cooldown_remaining > 0 else None
            }
            _status_cache_timestamps['spotify'] = current_time
        # else: use cached value

        # Test media server - use EXISTING instances (they have internal caching)
        # Media server clients already cache connection checks internally
        if current_time - _status_cache_timestamps['media_server'] > STATUS_CACHE_TTL:
            media_server_start = time.time()
            media_server_status = False
            if active_server == "plex" and plex_client:
                # Use existing instance - has 30s internal connection cache
                media_server_status = plex_client.is_connected()
            elif active_server == "jellyfin" and jellyfin_client:
                # Use existing instance - has internal connection caching
                media_server_status = jellyfin_client.is_connected()
            elif active_server == "navidrome" and navidrome_client:
                # Use existing instance
                media_server_status = navidrome_client.is_connected()
            media_server_response_time = (time.time() - media_server_start) * 1000
            _status_cache['media_server'] = {
                'connected': media_server_status,
                'response_time': round(media_server_response_time, 1),
                'type': active_server
            }
            _status_cache_timestamps['media_server'] = current_time
        # else: use cached value

        # Test Soulseek - only if it's the active source or in the hybrid order
        if current_time - _status_cache_timestamps['soulseek'] > STATUS_CACHE_TTL:
            download_mode = config_manager.get('download_source.mode', 'hybrid')
            hybrid_order = config_manager.get('download_source.hybrid_order', ['hifi', 'youtube', 'soulseek'])
            soulseek_relevant = (download_mode == 'soulseek' or
                                (download_mode == 'hybrid' and 'soulseek' in hybrid_order))

            # Serverless sources (YouTube, HiFi, Qobuz) are always available
            serverless_sources = ('youtube', 'hifi', 'qobuz')
            is_serverless = (download_mode in serverless_sources or
                             (download_mode == 'hybrid' and
                              hybrid_order and any(s in serverless_sources for s in hybrid_order)))

            # Serverless check first — avoids slow slskd timeout when YouTube/HiFi are in hybrid order
            if is_serverless:
                soulseek_status = True
                soulseek_response_time = 0
            elif soulseek_relevant and soulseek_client:
                soulseek_start = time.time()
                try:
                    soulseek_status = run_async(soulseek_client.check_connection())
                except Exception:
                    soulseek_status = False
                soulseek_response_time = (time.time() - soulseek_start) * 1000
            else:
                soulseek_status = False
                soulseek_response_time = 0

            _status_cache['soulseek'] = {
                'connected': soulseek_status,
                'response_time': round(soulseek_response_time, 1)
            }
            _status_cache_timestamps['soulseek'] = current_time

        # Include download source mode so frontend can update labels
        download_mode = config_manager.get('download_source.mode', 'hybrid')
        _status_cache['soulseek']['source'] = download_mode

        # Count active downloads for nav badge
        active_dl_count = 0
        with tasks_lock:
            for t in download_tasks.values():
                if t.get('status') in ('downloading', 'searching', 'post_processing', 'queued', 'pending'):
                    active_dl_count += 1

        status_data = {
            'spotify': _status_cache['spotify'],
            'media_server': _status_cache['media_server'],
            'soulseek': _status_cache['soulseek'],
            'active_media_server': active_server,
            'enrichment': _get_enrichment_status(),
            'active_downloads': active_dl_count,
        }
        return jsonify(status_data)
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/fix-navidrome-urls', methods=['POST'])
def fix_navidrome_urls():
    """Fix Navidrome artist image URLs to use correct Subsonic format"""
    try:
        db = get_database()
        with db._get_connection() as conn:
            cursor = conn.cursor()

            # Get all Navidrome artists with old URL format
            cursor.execute('SELECT id, name, thumb_url FROM artists WHERE server_source = "navidrome" AND thumb_url LIKE "/api/artist/%"')
            artists = cursor.fetchall()

            if not artists:
                return jsonify({"status": "success", "message": "No URLs needed fixing", "updated": 0})

            # Update URLs to new Subsonic format
            import re
            updated = 0
            examples = []

            for artist_id, name, old_url in artists:
                # Extract artist ID from old URL: /api/artist/ARTIST_ID/image
                match = re.search(r'/api/artist/([^/]+)/image', old_url)
                if match:
                    artist_spotify_id = match.group(1)
                    new_url = f'/rest/getCoverArt?id={artist_spotify_id}'

                    cursor.execute('UPDATE artists SET thumb_url = ? WHERE id = ? AND server_source = "navidrome"', (new_url, artist_id))
                    updated += 1

                    if len(examples) < 3:  # Show first 3 as examples
                        examples.append(f'{name}: {old_url} -> {new_url}')

            conn.commit()

            return jsonify({
                "status": "success",
                "message": f"Updated {updated} Navidrome artist URLs to Subsonic format",
                "updated": updated,
                "examples": examples
            })

    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/api/save-playlist-m3u', methods=['POST'])
def save_playlist_m3u():
    """Save M3U playlist file to the relevant download folder"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({"status": "error", "message": "No data provided"}), 400

        playlist_name = data.get('playlist_name', 'Playlist')
        m3u_content = data.get('m3u_content', '')
        context_type = data.get('context_type', 'playlist')
        artist_name = data.get('artist_name', '')
        album_name = data.get('album_name', '')
        year = data.get('year', '')
        force = data.get('force', False)

        # Check if M3U export is enabled (unless force=True from manual Export button)
        if not force and not config_manager.get('m3u_export.enabled', False):
            return jsonify({"status": "success", "message": "M3U export disabled in settings", "skipped": True})

        if not m3u_content:
            return jsonify({"status": "error", "message": "No M3U content provided"}), 400

        # Compute target folder using the template system
        transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
        m3u_folder = _compute_m3u_folder(transfer_dir, context_type, playlist_name, artist_name, album_name, year)
        os.makedirs(m3u_folder, exist_ok=True)

        # Build M3U filename from playlist or album name
        if context_type == 'album' and artist_name and album_name:
            safe_filename = _sanitize_filename(f"{artist_name} - {album_name}")
        else:
            safe_filename = _sanitize_filename(playlist_name)
        m3u_filename = f"{safe_filename}.m3u"
        m3u_path = os.path.join(m3u_folder, m3u_filename)

        # Write M3U file (overwrite if exists)
        with open(m3u_path, 'w', encoding='utf-8') as f:
            f.write(m3u_content)

        logger.info(f"Saved M3U file: {m3u_path}")
        return jsonify({
            "status": "success",
            "message": f"M3U file saved: {m3u_filename}",
            "path": m3u_path
        })

    except Exception as e:
        logger.error(f"Error saving M3U file: {e}")
        return jsonify({"status": "error", "message": str(e)}), 500

def _build_system_stats():
    """Build system statistics dict — shared by HTTP handler and WebSocket emitter."""
    import psutil
    import time
    from datetime import timedelta

    # Calculate uptime
    start_time = getattr(app, 'start_time', time.time())
    uptime_seconds = time.time() - start_time
    uptime = str(timedelta(seconds=int(uptime_seconds)))

    # Get memory usage
    memory = psutil.virtual_memory()
    memory_usage = f"{memory.percent}%"

    # Count active downloads from download_batches (batches that are currently downloading)
    active_downloads = len([batch_id for batch_id, batch_data in download_batches.items()
                           if batch_data.get('phase') == 'downloading'])

    # Count finished downloads (completed this session) - use session counter like dashboard.py
    with session_stats_lock:
        finished_downloads = session_completed_downloads

    # Calculate total download speed from active soulseek transfers
    total_download_speed = 0.0
    try:
        transfers_data = run_async(soulseek_client._make_request('GET', 'transfers/downloads'))
        if transfers_data:
            for user_data in transfers_data:
                if 'directories' in user_data:
                    for directory in user_data['directories']:
                        if 'files' in directory:
                            for file_info in directory['files']:
                                state = file_info.get('state', '').lower()
                                # Only count actively downloading files
                                if 'inprogress' in state or 'downloading' in state or 'transferring' in state:
                                    speed = file_info.get('averageSpeed', 0)
                                    if isinstance(speed, (int, float)) and speed > 0:
                                        total_download_speed += float(speed)
    except Exception as e:
        print(f"Warning: Could not fetch download speeds: {e}")

    # Convert bytes/sec to KB/s and format
    if total_download_speed > 0:
        speed_kb_s = total_download_speed / 1024
        if speed_kb_s >= 1024:
            speed_mb_s = speed_kb_s / 1024
            download_speed_str = f"{speed_mb_s:.1f} MB/s"
        else:
            download_speed_str = f"{speed_kb_s:.1f} KB/s"
    else:
        download_speed_str = "0 KB/s"

    # Count active syncs (playlists currently syncing)
    active_syncs = 0
    # Count Spotify playlist syncs
    for playlist_id, sync_state in sync_states.items():
        if sync_state.get('status') == 'syncing':
            active_syncs += 1
    # Count YouTube playlist syncs
    for url_hash, state in youtube_playlist_states.items():
        if state.get('phase') == 'syncing':
            active_syncs += 1
    # Count Tidal playlist syncs
    for playlist_id, state in tidal_discovery_states.items():
        if state.get('phase') == 'syncing':
            active_syncs += 1

    return {
        'active_downloads': active_downloads,
        'finished_downloads': finished_downloads,
        'download_speed': download_speed_str,
        'active_syncs': active_syncs,
        'uptime': uptime,
        'memory_usage': memory_usage
    }

@app.route('/api/system/stats')
def get_system_stats():
    """Get system statistics for dashboard"""
    try:
        return jsonify(_build_system_stats())
    except Exception as e:
        return jsonify({'error': str(e)}), 500


def _safe_check(fn, default=False):
    """Safely evaluate a check function, returning default on any error."""
    try:
        return fn()
    except Exception:
        return default


@app.route('/api/debug-info')
def get_debug_info():
    """Collect system diagnostics for troubleshooting support requests."""
    import platform
    import sys
    import psutil
    import time
    from datetime import timedelta

    log_lines = request.args.get('lines', 20, type=int)
    log_lines = max(10, min(log_lines, 500))
    log_source = request.args.get('log', 'app')

    info = {}

    # App info
    info['version'] = SOULSYNC_VERSION
    info['os'] = f"{platform.system()} {platform.release()}"
    info['python'] = sys.version.split()[0]
    info['docker'] = os.path.exists('/.dockerenv')

    # Uptime
    start_time = getattr(app, 'start_time', time.time())
