@app.route('/api/mirrored-playlists/list', methods=['GET'])
def get_mirrored_playlists_list():
    """Return simple list of mirrored playlists for automation config dropdowns."""
    try:
        database = get_database()
        profile_id = get_current_profile_id()
        playlists = database.get_mirrored_playlists(profile_id=profile_id)
        spotify_authed = bool(spotify_client and spotify_client.is_spotify_authenticated())
        return jsonify({
            "playlists": [{"id": p['id'], "name": p['name'], "source": p.get('source', '')} for p in playlists],
            "spotify_authenticated": spotify_authed
        })
    except Exception as e:
        return jsonify({"playlists": [], "spotify_authenticated": False}), 200

@app.route('/api/setup/status', methods=['GET'])
def setup_status_endpoint():
    """Check if first-run setup has been completed."""
    # The setup wizard sets this flag when completed. download_source.mode is only
    # set by user action (wizard or settings page), never by config.json defaults.
    setup_done = config_manager.get('setup.completed', False)
    download_mode = config_manager.get('download_source.mode', '')
    # Either the explicit flag or a user-configured download source means setup is done
    has_user_config = bool(setup_done) or bool(download_mode)
    return jsonify({
        "setup_complete": has_user_config,
    })

@app.route('/api/setup/complete', methods=['POST'])
def setup_complete_endpoint():
    """Mark first-run setup as completed."""
    config_manager.set('setup.completed', True)
    return jsonify({"success": True})

@app.route('/api/test-connection', methods=['POST'])
def test_connection_endpoint():
    data = request.get_json()
    service = data.get('service')
    if not service:
        return jsonify({"success": False, "error": "No service specified."}), 400

    print(f"Received test connection request for: {service}")
    
    # Get the current settings from the main config manager to test with
    test_config = config_manager.get(service, {})
    
    # For media servers, the service name might be 'server'
    if service == 'server':
        active_server = config_manager.get_active_media_server()
        test_config = config_manager.get(active_server, {})
        service = active_server # use the actual server name for the test

    success, message = run_service_test(service, test_config)

    # Update status cache immediately when test succeeds to reflect current state
    import time
    if success:
        current_time = time.time()
        if service == 'spotify':
            _status_cache['spotify']['connected'] = True
            _status_cache['spotify']['source'] = _get_metadata_fallback_source()
            _status_cache_timestamps['spotify'] = current_time
            print("Updated Spotify status cache after successful test")
        elif service in ['plex', 'jellyfin', 'navidrome']:
            _status_cache['media_server']['connected'] = True
            _status_cache['media_server']['type'] = service
            _status_cache_timestamps['media_server'] = current_time
            print(f"Updated {service} status cache after successful test")
        elif service == 'soulseek':
            _status_cache['soulseek']['connected'] = True
            _status_cache_timestamps['soulseek'] = current_time
            print("Updated Soulseek status cache after successful test")
        elif service == 'listenbrainz':
            print("ListenBrainz test successful")

    # Add activity for connection test
    if success:
        add_activity_item("", "Connection Test", message, "Now")
    else:
        add_activity_item("", "Connection Test", f"{service.title()} connection failed", "Now")

    return jsonify({"success": success, "error": "" if success else message, "message": message if success else ""})

