@app.route('/api/search', methods=['POST'])
def search_music():
    """Real search using soulseek_client"""
    data = request.get_json()
    query = data.get('query')
    if not query:
        return jsonify({"error": "No search query provided."}), 400

    logger.info(f"Web UI Search initiated for: '{query}'")

    # Add activity for search start
    add_activity_item("", "Search Started", f"'{query}'", "Now")
    
    try:
        tracks, albums = run_async(soulseek_client.search(query))

        # Convert to dictionaries for JSON response
        processed_albums = []
        for album in albums:
            album_dict = album.__dict__.copy()
            album_dict["tracks"] = [track.__dict__ for track in album.tracks]
            album_dict["result_type"] = "album"
            processed_albums.append(album_dict)

        processed_tracks = []
        for track in tracks:
            track_dict = track.__dict__.copy()
            track_dict["result_type"] = "track"
            processed_tracks.append(track_dict)
        
        # Sort by quality score
        all_results = sorted(processed_albums + processed_tracks, key=lambda x: x.get('quality_score', 0), reverse=True)

        # Add activity for search completion
        total_results = len(all_results)
        add_activity_item("", "Search Complete", f"'{query}' - {total_results} results", "Now")

        return jsonify({"results": all_results})
        
    except Exception as e:
        print(f"Search error: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/enhanced-search', methods=['POST'])
def enhanced_search():
    """
    Unified search across metadata sources and local database for enhanced search mode.
    Returns categorized results: DB artists, source artists, albums, and tracks.

    Fires parallel queries against all available sources (Spotify, iTunes, Deezer)
    and returns results keyed by source, plus backward-compatible top-level keys
    mapped from the primary source.
    """
    data = request.get_json()
    query = data.get('query', '').strip()

    empty_source = {"artists": [], "albums": [], "tracks": [], "available": False}

    if not query:
        return jsonify({
            "db_artists": [],
            "spotify_artists": [],
            "spotify_albums": [],
            "spotify_tracks": [],
            "sources": {},
            "primary_source": "spotify",
            "metadata_source": "spotify"
        })

    logger.info(f"Enhanced search initiated for: '{query}'")

    try:
        # Search local database for artists (always)
        database = get_database()
        active_server = config_manager.get_active_media_server()
        db_artists_objs = database.search_artists(query, limit=5, server_source=active_server)

        db_artists = []
        for artist in db_artists_objs:
            image_url = None
            if hasattr(artist, 'thumb_url') and artist.thumb_url:
                image_url = fix_artist_image_url(artist.thumb_url)
            db_artists.append({
                "id": artist.id,
                "name": artist.name,
                "image_url": image_url
            })

        # ── Determine primary source and search it synchronously ──
        primary_source = "spotify"
        primary_results = empty_source

        if _is_hydrabase_active():
            primary_source = "hydrabase"
            try:
                primary_results = _enhanced_search_source(query, hydrabase_client)
                # Fire off background comparison
                _run_background_comparison(query, hydrabase_counts={
                    'tracks': len(primary_results['tracks']),
                    'artists': len(primary_results['artists']),
                    'albums': len(primary_results['albums'])
                })
            except Exception as e:
                logger.error(f"Hydrabase search failed: {e}")
                primary_source = "spotify"
                primary_results = empty_source

        if primary_source != "hydrabase":
            # Mirror to Hydrabase worker (fire-and-forget)
            if hydrabase_worker and dev_mode_enabled:
                hydrabase_worker.enqueue(query, 'tracks')
                hydrabase_worker.enqueue(query, 'albums')
                hydrabase_worker.enqueue(query, 'artists')

            # Search using the user's configured primary metadata source
            fb_source = _get_metadata_fallback_source()
            try:
                primary_results = _enhanced_search_source(query, _get_metadata_fallback_client())
                primary_source = fb_source
            except Exception as e:
                logger.debug(f"Primary source ({fb_source}) search failed: {e}")

            # If primary source failed and it wasn't Spotify, try Spotify as fallback
            if primary_results is empty_source and fb_source != 'spotify':
                if spotify_client and spotify_client.is_spotify_authenticated():
                    try:
                        primary_results = _enhanced_search_source(query, spotify_client)
                        primary_source = "spotify"
                    except Exception as e:
                        logger.debug(f"Spotify fallback search failed: {e}")

        # Determine which alternate sources are available (for frontend to fetch async)
        spotify_available = bool(spotify_client and spotify_client.is_spotify_authenticated())
        hydrabase_available = bool(hydrabase_client and hydrabase_client.is_connected())
        discogs_available = bool(config_manager.get('discogs.token', ''))
        alternate_sources = []
        if primary_source != 'spotify' and spotify_available:
            alternate_sources.append('spotify')
        if primary_source != 'itunes':
            alternate_sources.append('itunes')
        if primary_source != 'deezer':
            alternate_sources.append('deezer')
        if primary_source != 'discogs' and discogs_available:
            alternate_sources.append('discogs')
        if primary_source != 'hydrabase' and hydrabase_available:
            alternate_sources.append('hydrabase')
        # YouTube music videos always available (uses yt-dlp, no auth needed)
        alternate_sources.append('youtube_videos')

        logger.info(f"Enhanced search results ({primary_source}): {len(db_artists)} DB artists, "
                     f"{len(primary_results['artists'])} artists, {len(primary_results['albums'])} albums, "
                     f"{len(primary_results['tracks'])} tracks | "
                     f"Alt sources available: {alternate_sources}")

        return jsonify({
            # Backward compat — same shape as before
            "db_artists": db_artists,
            "spotify_artists": primary_results["artists"],
            "spotify_albums": primary_results["albums"],
            "spotify_tracks": primary_results["tracks"],
            "metadata_source": primary_source,
            # New multi-source data
            "primary_source": primary_source,
            "alternate_sources": alternate_sources,
        })

    except Exception as e:
        logger.error(f"Enhanced search error: {e}")
        return jsonify({"error": str(e)}), 500


def _enhanced_search_source(query, client):
    """Search a single metadata source and return normalized results dict."""
    artists = []
    albums = []
    tracks = []

    try:
        artist_objs = client.search_artists(query, limit=10)
        for artist in artist_objs:
            artists.append({
                "id": artist.id,
                "name": artist.name,
                "image_url": artist.image_url,
                "external_urls": artist.external_urls or {},
            })
    except Exception as e:
        logger.debug(f"Artist search failed for {type(client).__name__}: {e}")

    try:
        album_objs = client.search_albums(query, limit=10)
        for album in album_objs:
            artist_name = ', '.join(album.artists) if album.artists else 'Unknown Artist'
            albums.append({
                "id": album.id,
                "name": album.name,
                "artist": artist_name,
                "image_url": album.image_url,
                "release_date": album.release_date,
                "total_tracks": album.total_tracks,
                "album_type": album.album_type,
                "external_urls": album.external_urls or {},
            })
    except Exception as e:
        logger.warning(f"Album search failed for {type(client).__name__}: {e}", exc_info=True)

    try:
        track_objs = client.search_tracks(query, limit=10)
        for track in track_objs:
            artist_name = ', '.join(track.artists) if track.artists else 'Unknown Artist'
            tracks.append({
                "id": track.id,
                "name": track.name,
                "artist": artist_name,
                "album": track.album,
                "duration_ms": track.duration_ms,
                "image_url": track.image_url,
                "release_date": track.release_date,
                "external_urls": track.external_urls or {},
            })
    except Exception as e:
        logger.warning(f"Track search failed for {type(client).__name__}: {e}", exc_info=True)

    return {"artists": artists, "albums": albums, "tracks": tracks, "available": True}


@app.route('/api/enhanced-search/source/<source_name>', methods=['POST'])
def enhanced_search_source(source_name):
    """Fetch search results from a specific alternate metadata source.

    Streams NDJSON — one line per search type (artists, albums, tracks) as each completes.
    This prevents slow sources (iTunes with 3s rate limit) from blocking the UI.
    Falls back to single JSON response if streaming not supported.
    """
    if source_name not in ('spotify', 'itunes', 'deezer', 'discogs', 'hydrabase', 'youtube_videos'):
        return jsonify({"error": f"Unknown source: {source_name}"}), 400

    data = request.get_json()
    query = (data.get('query', '') if data else '').strip()
    if not query:
        return jsonify({"artists": [], "albums": [], "tracks": [], "available": False})

    # YouTube music videos — separate flow from metadata sources
    if source_name == 'youtube_videos':
        if not soulseek_client or not hasattr(soulseek_client, 'youtube') or not soulseek_client.youtube:
            return jsonify({"videos": [], "available": False})
        try:
            def generate_videos():
                try:
                    # Search YouTube via yt-dlp
                    video_query = f"{query} official music video"
                    results = run_async(soulseek_client.youtube.search_videos(video_query, max_results=20))
                    videos = []
                    for v in (results or []):
                        videos.append({
                            'video_id': v.video_id,
                            'title': v.title,
                            'channel': v.channel,
                            'duration': v.duration,
                            'thumbnail': v.thumbnail,
                            'url': v.url,
                            'view_count': v.view_count,
                            'upload_date': v.upload_date,
                        })
                    yield json.dumps({"type": "videos", "data": videos}) + "\n"
                except Exception as e:
                    logger.error(f"YouTube music video search failed: {e}")
                    yield json.dumps({"type": "videos", "data": []}) + "\n"
                yield json.dumps({"type": "done"}) + "\n"
            return app.response_class(generate_videos(), mimetype='application/x-ndjson')
        except Exception as e:
            return jsonify({"error": str(e)}), 500

    try:
        client = None
        if source_name == 'spotify':
            if spotify_client and spotify_client.is_spotify_authenticated():
                client = spotify_client
            else:
                return jsonify({"artists": [], "albums": [], "tracks": [], "available": False})
        elif source_name == 'itunes':
            client = _get_itunes_client()
        elif source_name == 'deezer':
            client = _get_deezer_client()
        elif source_name == 'discogs':
            token = config_manager.get('discogs.token', '')
            if token:
                client = _get_discogs_client(token)
            else:
                return jsonify({"artists": [], "albums": [], "tracks": [], "available": False})
        elif source_name == 'hydrabase':
            if hydrabase_client and hydrabase_client.is_connected():
                client = hydrabase_client
            else:
                return jsonify({"artists": [], "albums": [], "tracks": [], "available": False})

        def generate():
            # Stream each search type as it completes
            try:
                artist_objs = client.search_artists(query, limit=10)
                artists = []
                for artist in artist_objs:
                    artists.append({
                        "id": artist.id, "name": artist.name,
                        "image_url": artist.image_url,
                        "external_urls": artist.external_urls or {},
                    })
                yield json.dumps({"type": "artists", "data": artists}) + "\n"
            except Exception as e:
                logger.debug(f"Artist search failed for {source_name}: {e}")
                yield json.dumps({"type": "artists", "data": []}) + "\n"

            try:
                album_objs = client.search_albums(query, limit=10)
                albums = []
                for album in album_objs:
                    artist_name = ', '.join(album.artists) if album.artists else 'Unknown Artist'
                    albums.append({
                        "id": album.id, "name": album.name, "artist": artist_name,
                        "image_url": album.image_url, "release_date": album.release_date,
                        "total_tracks": album.total_tracks, "album_type": album.album_type,
                        "external_urls": album.external_urls or {},
                    })
                yield json.dumps({"type": "albums", "data": albums}) + "\n"
            except Exception as e:
                logger.warning(f"Album search failed for {source_name}: {e}")
                yield json.dumps({"type": "albums", "data": []}) + "\n"

            try:
                track_objs = client.search_tracks(query, limit=10)
                tracks = []
                for track in track_objs:
                    artist_name = ', '.join(track.artists) if track.artists else 'Unknown Artist'
                    tracks.append({
                        "id": track.id, "name": track.name, "artist": artist_name,
                        "album": track.album, "duration_ms": track.duration_ms,
                        "image_url": track.image_url, "release_date": track.release_date,
                        "external_urls": track.external_urls or {},
                    })
                yield json.dumps({"type": "tracks", "data": tracks}) + "\n"
            except Exception as e:
                logger.warning(f"Track search failed for {source_name}: {e}")
                yield json.dumps({"type": "tracks", "data": []}) + "\n"

            yield json.dumps({"type": "done"}) + "\n"

        return app.response_class(generate(), mimetype='application/x-ndjson')
    except Exception as e:
        logger.error(f"Enhanced search source ({source_name}) error: {e}")
        return jsonify({"artists": [], "albums": [], "tracks": [], "available": False})


@app.route('/api/enhanced-search/library-check', methods=['POST'])
def enhanced_search_library_check():
    """Batch check which albums/tracks from search results exist in the library.
    Called async after search results render — doesn't block the search."""
    try:
        data = request.get_json() or {}
        albums = data.get('albums', [])
        tracks = data.get('tracks', [])

        database = get_database()
        conn = database._get_connection()
        try:
            cursor = conn.cursor()

            # Build lookup sets from library — two fast queries
            cursor.execute("SELECT LOWER(al.title) || '|||' || LOWER(ar.name) FROM albums al JOIN artists ar ON ar.id = al.artist_id")
            owned_albums = {r[0] for r in cursor.fetchall()}

            cursor.execute("""
                SELECT LOWER(t.title) || '|||' || LOWER(a.name), t.id, t.file_path, t.title, a.name, al.title, al.thumb_url
                FROM tracks t JOIN artists a ON a.id = t.artist_id JOIN albums al ON al.id = t.album_id
            """)
            owned_tracks = {}
            for r in cursor.fetchall():
                if r[0] not in owned_tracks:  # Keep first match only
                    owned_tracks[r[0]] = {'track_id': r[1], 'file_path': r[2], 'title': r[3], 'artist_name': r[4], 'album_title': r[5], 'album_thumb_url': r[6]}

            # Build wishlist lookup set — track name|||artist
            wishlist_keys = set()
            try:
                profile_id = get_current_profile_id()
                cursor.execute("SELECT spotify_data FROM wishlist_tracks WHERE profile_id = ?", (profile_id,))
                for wr in cursor.fetchall():
                    try:
                        wd = json.loads(wr[0]) if isinstance(wr[0], str) else {}
                        wname = (wd.get('name') or '').lower()
                        wartists = wd.get('artists', [])
                        if wartists:
                            wa = wartists[0].get('name', '') if isinstance(wartists[0], dict) else str(wartists[0])
                        else:
                            wa = ''
                        if wname:
                            wishlist_keys.add(wname + '|||' + wa.lower().strip())
                    except Exception:
                        pass
            except Exception:
                # profile_id column may not exist on older DBs — try without it
                try:
                    cursor.execute("SELECT spotify_data FROM wishlist_tracks")
                    for wr in cursor.fetchall():
                        try:
                            wd = json.loads(wr[0]) if isinstance(wr[0], str) else {}
                            wname = (wd.get('name') or '').lower()
                            wartists = wd.get('artists', [])
                            if wartists:
                                wa = wartists[0].get('name', '') if isinstance(wartists[0], dict) else str(wartists[0])
                            else:
                                wa = ''
                            if wname:
                                wishlist_keys.add(wname + '|||' + wa.lower().strip())
                        except Exception:
                            pass
                except Exception:
                    pass

            # O(1) lookups per item
            album_results = []
            for a in albums:
                key = (a.get('name', '').lower() + '|||' + a.get('artist', '').split(',')[0].strip().lower())
                album_results.append(key in owned_albums)

            # Resolve Plex thumb URLs (relative paths need base URL + token)
            _plex_base = ''
            _plex_token = ''
            if plex_client and plex_client.server:
                _plex_base = getattr(plex_client.server, '_baseurl', '') or ''
                _plex_token = getattr(plex_client.server, '_token', '') or ''
            if not _plex_base:
                _pc = config_manager.get_plex_config()
                _plex_base = (_pc.get('base_url', '') or '').rstrip('/')
                _plex_token = _plex_token or _pc.get('token', '')

            track_results = []
            for t in tracks:
                key = (t.get('name', '').lower() + '|||' + t.get('artist', '').split(',')[0].strip().lower())
                in_wishlist = key in wishlist_keys
                match = owned_tracks.get(key)
                if match:
                    # Resolve thumb URL
                    thumb = match.get('album_thumb_url') or ''
                    if thumb and not thumb.startswith('http') and _plex_base and thumb.startswith('/'):
                        thumb = f"{_plex_base}{thumb}?X-Plex-Token={_plex_token}" if _plex_token else f"{_plex_base}{thumb}"
                    match['album_thumb_url'] = thumb
                    track_results.append({'in_library': True, 'in_wishlist': in_wishlist, **match})
                else:
                    track_results.append({'in_library': False, 'in_wishlist': in_wishlist})
        finally:
            conn.close()

        return jsonify({'albums': album_results, 'tracks': track_results})
    except Exception as e:
        logger.debug(f"Library check error: {e}")
        return jsonify({'albums': [], 'tracks': []})

@app.route('/api/enhanced-search/stream-track', methods=['POST'])
def stream_enhanced_search_track():
    """
    Quick slskd search for a single track to stream from enhanced search.
    Uses multi-query retry strategy to work around Soulseek keyword filtering.
    Returns the best matching result from Soulseek.
    """
    data = request.get_json()
    track_name = data.get('track_name', '').strip()
    artist_name = data.get('artist_name', '').strip()
    album_name = data.get('album_name', '').strip()
    duration_ms = data.get('duration_ms', 0)

    if not track_name or not artist_name:
        return jsonify({"error": "Track name and artist name are required"}), 400

    logger.info(f"Enhanced search stream request: '{track_name}' by '{artist_name}'")

    try:
        # Create a temporary SpotifyTrack-like object for the matching engine
        temp_track = type('TempTrack', (), {
            'name': track_name,
            'artists': [artist_name],
            'album': album_name if album_name else None,
            'duration_ms': duration_ms
        })()

        # Determine effective stream source
        # stream_source: "youtube" (default, instant) or "active" (use download source)
        stream_source = config_manager.get('download_source.stream_source', 'youtube')
        download_mode = config_manager.get('download_source.mode', 'hybrid')

        # Resolve the effective mode for streaming
        if stream_source == 'youtube':
            effective_mode = 'youtube'
        else:
            # "active" mode — use download source, but fall back to YouTube if Soulseek
            _hybrid_order = config_manager.get('download_source.hybrid_order', ['hifi', 'youtube', 'soulseek'])
            _hybrid_first = _hybrid_order[0] if _hybrid_order else config_manager.get('download_source.hybrid_primary', 'hifi')
            if download_mode == 'soulseek' or (download_mode == 'hybrid' and _hybrid_first == 'soulseek'):
                effective_mode = 'youtube'  # Soulseek is too slow for streaming preview
                logger.info("Stream source is 'active' but primary is Soulseek — falling back to YouTube")
            elif download_mode == 'hybrid':
                effective_mode = _hybrid_first
            else:
                effective_mode = download_mode

        logger.info(f"Stream source: {stream_source} → effective: {effective_mode}")

        # Generate search queries based on effective stream mode
        search_queries = []
        import re

        if effective_mode in ('youtube', 'tidal', 'qobuz', 'hifi', 'deezer_dl', 'lidarr'):
            # Streaming sources: Include artist for better context
            if artist_name and track_name:
                search_queries.append(f"{artist_name} {track_name}".strip())

            # Fallback: Artist + Cleaned track (remove parentheses/brackets)
            cleaned_name = re.sub(r'\s*\([^)]*\)', '', track_name).strip()
            cleaned_name = re.sub(r'\s*\[[^\]]*\]', '', cleaned_name).strip()
            if cleaned_name and cleaned_name.lower() != track_name.lower():
                search_queries.append(f"{artist_name} {cleaned_name}".strip())

            logger.info(f"{effective_mode.title()} stream: Searching with artist + track name: {search_queries}")
        else:
            # Soulseek mode: Track name only to avoid keyword filtering
            if track_name.strip():
                search_queries.append(track_name.strip())

            cleaned_name = re.sub(r'\s*\([^)]*\)', '', track_name).strip()
            cleaned_name = re.sub(r'\s*\[[^\]]*\]', '', cleaned_name).strip()

            if cleaned_name and cleaned_name.lower() != track_name.lower():
                search_queries.append(cleaned_name.strip())

            logger.info(f"Soulseek mode: Searching by track name only (will match with artist): {search_queries}")

        # Remove duplicates while preserving order
        unique_queries = []
        seen = set()
        for query in search_queries:
            if query and query.lower() not in seen:
                unique_queries.append(query)
                seen.add(query.lower())

        search_queries = unique_queries

        # Select the search client based on effective stream mode
        _stream_clients = {
            'youtube': soulseek_client.youtube,
            'tidal': soulseek_client.tidal,
            'qobuz': soulseek_client.qobuz,
            'hifi': soulseek_client.hifi,
            'deezer_dl': soulseek_client.deezer_dl,
            'lidarr': soulseek_client.lidarr,
        }
        stream_client = _stream_clients.get(effective_mode)
        use_direct_client = stream_client is not None

        # Try queries sequentially until we find a good match
        for query_index, query in enumerate(search_queries):
            logger.info(f"Query {query_index + 1}/{len(search_queries)}: '{query}'")

            try:
                # Search using the stream source client (not the download source)
                if use_direct_client:
                    tracks_result, _ = run_async(stream_client.search(query, timeout=15))
                else:
                    tracks_result, _ = run_async(soulseek_client.search(query, timeout=15))

                if tracks_result:
                    logger.info(f"Found {len(tracks_result)} results for query: '{query}'")

                    # Use matching engine to find best match
                    _max_q = config_manager.get('soulseek.max_peer_queue', 0) or 0
                    best_matches = matching_engine.find_best_slskd_matches_enhanced(temp_track, tracks_result, max_peer_queue=_max_q)

                    if best_matches:
                        # Get the first (best) result
                        best_result = best_matches[0]

                        # Convert to dictionary for JSON response (same format as basic search)
                        result_dict = {
                            "username": best_result.username,
                            "filename": best_result.filename,
                            "size": best_result.size,
                            "bitrate": best_result.bitrate,
                            "duration": best_result.duration,
                            "quality": best_result.quality,
                            "free_upload_slots": best_result.free_upload_slots,
                            "upload_speed": best_result.upload_speed,
                            "queue_length": best_result.queue_length,
                            "result_type": "track"
                        }

                        logger.info(f"Returning best match from query '{query}': {best_result.filename} ({best_result.quality})")

                        return jsonify({
                            "success": True,
                            "result": result_dict
                        })
                    else:
                        logger.info(f"No suitable matches for query '{query}', trying next query...")
                else:
                    logger.info(f"No results for query '{query}', trying next query...")

            except Exception as search_error:
                logger.warning(f"Error searching with query '{query}': {search_error}")
                continue

        # If we get here, none of the queries found a suitable match
        logger.warning(f"No suitable matches found after trying {len(search_queries)} queries")
        return jsonify({
            "success": False,
            "error": "No suitable track found after trying multiple search strategies"
        }), 404

    except Exception as e:
        logger.error(f"Error streaming enhanced search track: {e}", exc_info=True)
        return jsonify({"error": str(e)}), 500

# =============================================================================
# MUSIC VIDEO DOWNLOADS
# =============================================================================

_music_video_downloads = {}  # {video_id: {status, progress, path, error}}

@app.route('/api/music-video/download', methods=['POST'])
def download_music_video():
    """Download a YouTube video as a music video file to the configured music videos folder."""
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data"}), 400

    video_id = data.get('video_id', '')
    video_url = data.get('url', '')
    raw_title = data.get('title', '')
    raw_channel = data.get('channel', '')

    if not video_id or not video_url:
        return jsonify({"error": "Missing video_id or url"}), 400

    # Check if already downloading
    if video_id in _music_video_downloads and _music_video_downloads[video_id].get('status') == 'downloading':
        return jsonify({"error": "Already downloading"}), 409

    # Get and validate music videos path
    music_videos_path = config_manager.get('library.music_videos_path', '') or ''
    if not music_videos_path.strip():
        return jsonify({"error": "Music Videos directory not configured. Set it in Settings > Downloads."}), 400
    music_videos_path = docker_resolve_path(music_videos_path)
    try:
        os.makedirs(music_videos_path, exist_ok=True)
        # Quick write test
        test_file = os.path.join(music_videos_path, '.soulsync_write_test')
        with open(test_file, 'w') as f:
            f.write('test')
        os.remove(test_file)
    except (OSError, PermissionError) as e:
        return jsonify({"error": f"Music Videos directory is not writable: {e}"}), 400

    # Initialize download state
    _music_video_downloads[video_id] = {'status': 'searching', 'progress': 0, 'path': None, 'error': None}

    def _do_download():
        try:
            # Step 1: Try to match against primary metadata source for clean artist/title
            _music_video_downloads[video_id]['status'] = 'matching'
            artist_name = raw_channel
            track_title = raw_title

            # Strip common YouTube suffixes for cleaner search
            import re as _re
            clean_search = _re.sub(r'\s*[\(\[](official\s*(music\s*)?video|official\s*lyric\s*video|official\s*audio|official\s*hd|hd|4k|remastered|lyric\s*video|visualizer|audio)[\)\]]', '', raw_title, flags=_re.IGNORECASE).strip()
            clean_search = _re.sub(r'\s*-\s*$', '', clean_search).strip()

            try:
                fallback_client = _get_metadata_fallback_client()
                results = fallback_client.search_tracks(clean_search, limit=5)
                if results:
                    from difflib import SequenceMatcher
                    best = None
                    best_score = 0
                    for r in results:
                        name_sim = SequenceMatcher(None, clean_search.lower(), r.name.lower()).ratio()
                        if r.artists:
                            artist_sim = SequenceMatcher(None, raw_channel.lower(), r.artists[0].lower()).ratio()
                            name_sim = (name_sim * 0.6) + (artist_sim * 0.4)
                        if name_sim > best_score:
                            best_score = name_sim
                            best = r
                    if best and best_score >= 0.5:
                        artist_name = best.artists[0] if best.artists else raw_channel
                        track_title = best.name
                        print(f"[Music Video] Matched to: {artist_name} - {track_title} (confidence: {best_score:.2f})")
                    else:
                        # Parse artist from video title: "Artist - Title" pattern
                        if ' - ' in raw_title:
                            parts = raw_title.split(' - ', 1)
                            artist_name = parts[0].strip()
                            track_title = _re.sub(r'\s*[\(\[].*?[\)\]]', '', parts[1]).strip()
                        print(f"[Music Video] No metadata match, using parsed: {artist_name} - {track_title}")
            except Exception as e:
                print(f"[Music Video] Metadata lookup failed: {e}")
                if ' - ' in raw_title:
                    parts = raw_title.split(' - ', 1)
                    artist_name = parts[0].strip()
                    track_title = _re.sub(r'\s*[\(\[].*?[\)\]]', '', parts[1]).strip()

            # Sanitize for filesystem
            def _sanitize(s):
                return _re.sub(r'[<>:"/\\|?*]', '_', s).strip().rstrip('.')

            artist_folder = _sanitize(artist_name)
            video_filename = f"{_sanitize(track_title)}-video"

            # Build output path: MusicVideos/Artist/Title-video
            artist_dir = os.path.join(music_videos_path, artist_folder)
            os.makedirs(artist_dir, exist_ok=True)
            output_path = os.path.join(artist_dir, video_filename)

            # Step 2: Download
            _music_video_downloads[video_id]['status'] = 'downloading'
            _music_video_downloads[video_id]['artist'] = artist_name
            _music_video_downloads[video_id]['title'] = track_title

            def _progress(pct):
                _music_video_downloads[video_id]['progress'] = round(pct, 1)

            final_path = soulseek_client.youtube.download_music_video(video_url, output_path, progress_callback=_progress)

            if final_path and os.path.exists(final_path):
                _music_video_downloads[video_id]['status'] = 'completed'
                _music_video_downloads[video_id]['progress'] = 100
                _music_video_downloads[video_id]['path'] = final_path
                print(f"[Music Video] Downloaded: {artist_name} - {track_title} → {final_path}")
                add_activity_item("", "Music Video Downloaded", f"{artist_name} - {track_title}", "Now")
            else:
                _music_video_downloads[video_id]['status'] = 'error'
                _music_video_downloads[video_id]['error'] = 'Download failed — file not found'
                print(f"[Music Video] Download failed for: {artist_name} - {track_title}")

        except Exception as e:
            _music_video_downloads[video_id]['status'] = 'error'
            _music_video_downloads[video_id]['error'] = str(e)
            print(f"[Music Video] Error: {e}")

    # Run in background thread
    import threading
    threading.Thread(target=_do_download, daemon=True, name=f'music-video-{video_id}').start()

    return jsonify({"success": True, "video_id": video_id})


@app.route('/api/music-video/status/<video_id>', methods=['GET'])
def get_music_video_status(video_id):
    """Get download status for a music video."""
    status = _music_video_downloads.get(video_id)
    if not status:
        return jsonify({"status": "unknown"})
    return jsonify(status)


@app.route('/api/download', methods=['POST'])
def start_download():
    """Simple download route"""
    dl_err = check_download_permission()
    if dl_err:
        return dl_err
    data = request.get_json()
    if not data:
        return jsonify({"error": "No download data provided."}), 400
    
    try:
        result_type = data.get('result_type', 'track')
        
        if result_type == 'album':
            tracks = data.get('tracks', [])
            if not tracks:
                return jsonify({"error": "No tracks found in album."}), 400

            started_downloads = 0
            for track_data in tracks:
                try:
                    username = track_data.get('username')
                    filename = track_data.get('filename')
                    file_size = track_data.get('size', 0)

                    download_id = run_async(soulseek_client.download(
                        username,
                        filename,
                        file_size
                    ))
                    if download_id:
                        # Register download for post-processing (simple transfer to /Transfer)
                        context_key = _make_context_key(username, filename)
                        with matched_context_lock:
                            matched_downloads_context[context_key] = {
                                'search_result': {
                                    'username': username,
                                    'filename': filename,
                                    'size': file_size,
                                    'title': track_data.get('title', 'Unknown'),
                                    'artist': track_data.get('artist', 'Unknown'),
                                    'quality': track_data.get('quality', 'Unknown'),
                                    'is_simple_download': True  # Flag for simple processing
                                },
                                'spotify_artist': None,  # No Spotify metadata
                                'spotify_album': None,
                                'track_info': None
                            }
                        started_downloads += 1
                except Exception as e:
                    logger.error(f"Failed to start track download: {e}")
                    continue

            # Add activity for album download start
            album_name = data.get('album_name', 'Unknown Album')
            logger.info(f"Starting simple album download: '{album_name}' with {started_downloads}/{len(tracks)} tracks")
            add_activity_item("", "Album Download Started", f"'{album_name}' - {started_downloads} tracks", "Now")

            return jsonify({
                "success": True,
                "message": f"Started {started_downloads} downloads from album"
            })
        
        else:
            # Single track download
            username = data.get('username')
            filename = data.get('filename')
            file_size = data.get('size', 0)

            logger.info(f"Download request - Username: {username}, Filename: {filename[:50]}...")

            if not username or not filename:
                return jsonify({"error": "Missing username or filename."}), 400

            download_id = run_async(soulseek_client.download(username, filename, file_size))
            logger.info(f"Download ID returned: {download_id}")

            if download_id:
                # Register download for post-processing (simple transfer to /Transfer)
                context_key = _make_context_key(username, filename)
                is_streaming_source = username in ('youtube', 'tidal', 'qobuz', 'hifi', 'deezer_dl', 'lidarr')
                with matched_context_lock:
                    matched_downloads_context[context_key] = {
                        'search_result': {
                            'username': username,
                            'filename': filename,
                            'size': file_size,
                            'title': data.get('title', 'Unknown'),
                            'artist': data.get('artist', 'Unknown'),
                            'quality': data.get('quality', 'Unknown'),
                            'is_simple_download': True  # Flag for simple processing
                        },
                        'spotify_artist': None,  # No Spotify metadata
                        'spotify_album': None,
                        'track_info': None
                    }
                    source_label = username.title() if is_streaming_source else 'Soulseek'
                    logger.info(f"[{source_label}] Registered simple download for post-processing: {context_key}")

                # Extract track name from filename for activity
                track_name = filename.split('/')[-1] if '/' in filename else filename.split('\\')[-1] if '\\' in filename else filename
                logger.info(f"Starting simple track download: '{track_name}'")
                add_activity_item("", "Track Download Started", f"'{track_name}'", "Now")
                return jsonify({"success": True, "message": "Download started"})
            else:
                logger.error(f"Failed to start download for: {filename}")
                return jsonify({"error": "Failed to start download"}), 500
                
    except Exception as e:
        logger.error(f"Download error: {e}")
        return jsonify({"error": str(e)}), 500











def _find_completed_file_robust(download_dir, api_filename, transfer_dir=None):
    """
    Robustly finds a completed file on disk, accounting for name variations and
    unexpected subdirectories. This version uses the superior normalization logic
    from the GUI's matching_engine.py to ensure consistency.

    First searches in download_dir, then optionally searches in transfer_dir if provided.
    Returns tuple (file_path, location) where location is 'downloads' or 'transfer'.
    """
    import re
    import os
    from difflib import SequenceMatcher
    from unidecode import unidecode

    # YOUTUBE/TIDAL SUPPORT: Handle encoded filename format "id||title"
    # Extract just the title part for file matching
    if '||' in api_filename:
        _, title = api_filename.split('||', 1)
        api_filename = title  # Use just the title for file searching

    def normalize_for_finding(text: str) -> str:
        """A powerful normalization function adapted from matching_engine.py."""
        if not text: return ""
        text = unidecode(text).lower()
        # Replace common separators with spaces to preserve word boundaries
        text = re.sub(r'[._/]', ' ', text)
        # Keep alphanumeric, spaces, and hyphens. Remove brackets/parentheses content.
        text = re.sub(r'[\[\(].*?[\]\)]', '', text)
        text = re.sub(r'[^a-z0-9\s-]', '', text)
        # Consolidate multiple spaces
        return ' '.join(text.split()).strip()

    def _path_matches_api_dirs(file_path):
        """Check if ALL api directory components appear in the file's path."""
        path_parts = set(p.lower() for p in file_path.replace('\\', '/').split('/'))
        return all(d in path_parts for d in api_dir_parts)

    def search_in_directory(search_dir, location_name):
        """Search for the file in a specific directory."""
        best_fuzzy_path = None
        highest_fuzzy_similarity = 0.0
        exact_matches = []

        # Walk through the entire directory
        for root, dirs, files in os.walk(search_dir):
            # Skip quarantine folder — contains known-wrong files from AcoustID verification
            dirs[:] = [d for d in dirs if d != 'ss_quarantine']
            for file in files:
                # Direct basename match
                if os.path.basename(file) == target_basename:
                    file_path = os.path.join(root, file)
                    # Fast path: if path aligns with expected directory structure, return now
                    if api_dir_parts and _path_matches_api_dirs(file_path):
                        print(f"Found path-confirmed match in {location_name}: {file_path}")
                        return file_path, 1.0
                    if not api_dir_parts:
                        # No directory info to disambiguate — return first match (original behavior)
                        print(f"Found exact match in {location_name}: {file_path}")
                        return file_path, 1.0
                    exact_matches.append(file_path)
                    continue

                # Check for slskd dedup suffix (e.g. "Song_639067852665564677.flac")
                # slskd appends _<timestamp> when a file with the same name already exists
                file_stem, file_ext_part = os.path.splitext(file)
                stripped_stem = re.sub(r'_\d{10,}$', '', file_stem)
                if stripped_stem != file_stem and stripped_stem + file_ext_part == target_basename:
                    file_path = os.path.join(root, file)
                    if api_dir_parts and _path_matches_api_dirs(file_path):
                        print(f"Found path-confirmed dedup match in {location_name}: {file_path}")
                        return file_path, 1.0
                    if not api_dir_parts:
                        print(f"Found dedup-suffix match in {location_name}: {file_path}")
                        return file_path, 1.0
                    exact_matches.append(file_path)
                    continue

                # Fuzzy matching for variations
                normalized_file = normalize_for_finding(file)
                similarity = SequenceMatcher(None, normalized_target, normalized_file).ratio()

                if similarity > highest_fuzzy_similarity:
                    highest_fuzzy_similarity = similarity
                    best_fuzzy_path = os.path.join(root, file)

        # Return best exact match (disambiguated by path), or fall back to fuzzy
        if exact_matches:
            if len(exact_matches) == 1:
                print(f"Found exact match in {location_name}: {exact_matches[0]}")
                return exact_matches[0], 1.0
            # Multiple files share the basename — pick the one whose path best
            # matches the expected directory structure from the Soulseek remote path
            best = exact_matches[0]
            best_score = -1
            for m in exact_matches:
                m_parts = set(p.lower() for p in m.replace('\\', '/').split('/'))
                score = sum(1 for d in api_dir_parts if d in m_parts)
                if score > best_score:
                    best_score = score
                    best = m
            print(f"Found {len(exact_matches)} files named '{target_basename}' in {location_name}, picked best path match: {best}")
            return best, 1.0

        return best_fuzzy_path, highest_fuzzy_similarity

    # Extract filename using the helper function
    target_basename = extract_filename(api_filename)
    normalized_target = normalize_for_finding(target_basename)

    # Extract directory components from the API path for disambiguation.
    # When multiple downloads produce the same basename (e.g., "01 - Silent Night.flac"
    # from different albums/users), these let us pick the correct file on disk.
    api_path_normalized = api_filename.replace('\\', '/') if api_filename else ''
    api_dir_parts = [p.lower() for p in api_path_normalized.split('/')[:-1] if p]

    # First search in downloads directory
    best_downloads_path, downloads_similarity = search_in_directory(download_dir, 'downloads')

    # Use a high confidence threshold for fuzzy matches to prevent false positives
    if downloads_similarity > 0.85:
        location = 'downloads'
        if downloads_similarity < 1.0:
            print(f"Found fuzzy match in downloads ({downloads_similarity:.2f}): {best_downloads_path}")
        return (best_downloads_path, location)

    # If not found in downloads and transfer_dir is provided, search there
    transfer_similarity = 0.0  # Initialize transfer_similarity
    if transfer_dir and os.path.exists(transfer_dir):
        best_transfer_path, transfer_similarity = search_in_directory(transfer_dir, 'transfer')

        if transfer_similarity > 0.85:
            location = 'transfer'
            if transfer_similarity < 1.0:
                print(f"Found fuzzy match in transfer ({transfer_similarity:.2f}): {best_transfer_path}")
            return (best_transfer_path, location)

    # Don't spam logs - file not found is common for completed/processed downloads
    return (None, None)




@app.route('/api/downloads/status')
def get_download_status():
    """
    A robust status checker that correctly finds completed files by searching
    the entire download directory with fuzzy matching, mirroring the logic from downloads.py.
    """
    if not soulseek_client:
        return jsonify({"transfers": []})

    try:
        global _processed_download_ids
        transfers_data = run_async(soulseek_client._make_request('GET', 'transfers/downloads'))

        # Don't return early if no Soulseek transfers - YouTube/Tidal downloads need to be checked too!
        all_transfers = []
        completed_matched_downloads = []
        # Track files already claimed this poll cycle to prevent two contexts from
        # grabbing the same physical file when downloads share a basename (e.g.,
        # "07 - Aurora.flac" from two different albums/artists).
        _files_claimed_this_cycle = set()

        if not transfers_data:
            # No Soulseek transfers, but continue to check YouTube/Tidal downloads below
            pass
        else:
            # This logic now correctly processes the nested structure from the slskd API
            for user_data in transfers_data:
                username = user_data.get('username', 'Unknown')
                if 'directories' in user_data:
                    for directory in user_data['directories']:
                        if 'files' in directory:
                            for file_info in directory['files']:
                                file_info['username'] = username
                                all_transfers.append(file_info)
                                state = file_info.get('state', '').lower()

                                # Check for completion state
                                if ('succeeded' in state or 'completed' in state) and 'errored' not in state and 'rejected' not in state:
                                    # Verify bytes actually transferred before trusting state
                                    _fi_size = file_info.get('size', 0)
                                    _fi_transferred = file_info.get('bytesTransferred', 0)
                                    if _fi_size > 0 and _fi_transferred < _fi_size:
                                        continue  # Not truly complete yet
                                    filename_from_api = file_info.get('filename')
                                    if not filename_from_api: continue

                                    # Check if this completed download has a matched context
                                    context_key = _make_context_key(username, filename_from_api)

                                    # Check if this is an orphaned download that completed after retry
                                    if context_key in _orphaned_download_keys:
                                        # Safety check: if a new context exists for this key, the retry
                                        # re-claimed the same source — treat it as active, not orphaned
                                        with matched_context_lock:
                                            has_active_context = context_key in matched_downloads_context
                                        if has_active_context:
                                            print(f"Orphaned key {context_key} has active context — retry re-used same source, treating as active")
                                            _orphaned_download_keys.discard(context_key)
                                            # Fall through to normal processing below
                                        else:
                                            download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
                                            found_result = _find_completed_file_robust(download_dir, filename_from_api)
                                            found_path = found_result[0] if found_result and found_result[0] else None
                                            orphan_cleaned = False
                                            if found_path:
                                                try:
                                                    os.remove(found_path)
                                                    print(f"Deleted orphaned download: {os.path.basename(found_path)}")
                                                    orphan_cleaned = True
                                                except Exception as e:
                                                    print(f"Failed to delete orphaned file (will retry next poll): {e}")
                                            else:
                                                # File not on disk (already gone or never written) — nothing to clean
                                                orphan_cleaned = True
                                            if orphan_cleaned:
                                                # Remove transfer from slskd
                                                transfer_id = file_info.get('id')
                                                if transfer_id:
                                                    try:
                                                        run_async(soulseek_client.cancel_download(str(transfer_id), username, remove=True))
                                                    except Exception:
                                                        pass
                                                _orphaned_download_keys.discard(context_key)
                                            continue  # Skip normal post-processing either way

                                    # Skip downloads we've already processed (prevents log spam)
                                    if context_key in _processed_download_ids:
                                        continue

                                    with matched_context_lock:
                                        context = matched_downloads_context.get(context_key)
                                        available_keys = list(matched_downloads_context.keys())[:5] if not context else None

                                    if context:
                                        print(f"[Context Lookup] Found context for key: {context_key}")
                                    elif context_key not in _stale_transfer_keys:
                                        # Only log once per stale key to avoid spamming every poll cycle
                                        print(f"[Context Lookup] No context found for key: {context_key}")
                                        print(f"   Available keys: {available_keys}...")
                                        _stale_transfer_keys.add(context_key)

                                    if context:
                                        download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
                                        # Use the new robust file finder (only search downloads for post-processing candidates)
                                        found_result = _find_completed_file_robust(download_dir, filename_from_api)
                                        found_path = found_result[0] if found_result and found_result[0] else None

                                        if found_path:
                                            # Prevent two contexts from claiming the same physical file
                                            _norm_path = os.path.normpath(found_path)
                                            if _norm_path in _files_claimed_this_cycle:
                                                print(f"File already claimed by another context this cycle: {os.path.basename(found_path)} — deferring to next poll")
                                            else:
                                                _files_claimed_this_cycle.add(_norm_path)
                                                print(f"Found completed matched file on disk: {found_path}")
                                                completed_matched_downloads.append((context_key, context, found_path))
                                                # Don't add to _processed_download_ids yet - wait until thread starts successfully

                                                # Clean up retry tracking if file was found after retries
                                                with _download_retry_lock:
                                                    if context_key in _download_retry_attempts:
                                                        retry_count = _download_retry_attempts[context_key]['count']
                                                        elapsed = time.time() - _download_retry_attempts[context_key]['first_attempt']
                                                        print(f"File found after {retry_count} retry attempt(s) ({elapsed:.1f}s): {os.path.basename(filename_from_api)}")
                                                        del _download_retry_attempts[context_key]
                                        else:
                                            # File not found yet - implement retry logic instead of immediate give-up
                                            # This fixes race condition where slskd reports completion before file is written to disk
                                            with _download_retry_lock:
                                                if context_key not in _download_retry_attempts:
                                                    # First retry attempt
                                                    _download_retry_attempts[context_key] = {
                                                        'count': 1,
                                                        'first_attempt': time.time()
                                                    }
                                                    print(f"File not found yet: '{os.path.basename(filename_from_api)}' - Will retry (attempt 1/{_download_retry_max})")
                                                else:
                                                    # Increment retry count
                                                    _download_retry_attempts[context_key]['count'] += 1
                                                    retry_count = _download_retry_attempts[context_key]['count']
                                                    elapsed = time.time() - _download_retry_attempts[context_key]['first_attempt']

                                                    if retry_count >= _download_retry_max:
                                                        # Max retries reached, give up
                                                        print(f"CRITICAL: Could not find '{os.path.basename(filename_from_api)}' after {retry_count} attempts over {elapsed:.1f}s. Giving up.")
                                                        _processed_download_ids.add(context_key)
                                                        # Clean up retry tracking
                                                        del _download_retry_attempts[context_key]
                                                    else:
                                                        print(f"File not found yet: '{os.path.basename(filename_from_api)}' - Will retry (attempt {retry_count}/{_download_retry_max}, elapsed: {elapsed:.1f}s)")

        # If we found completed matched downloads, start processing them in background threads
        if completed_matched_downloads:
            def process_completed_downloads():
                for context_key, context, found_path in completed_matched_downloads:
                    try:
                        print(f"Starting post-processing thread for: {context_key}")
                        # Use verification wrapper if context has task tracking IDs,
                        # otherwise call directly (race guard flag still gets set on context)
                        _pp_task_id = context.get('task_id')
                        _pp_batch_id = context.get('batch_id')
                        if _pp_task_id and _pp_batch_id:
                            _pp_target = _post_process_matched_download_with_verification
                            _pp_args = (context_key, context, found_path, _pp_task_id, _pp_batch_id)
                        else:
                            _pp_target = _post_process_matched_download
                            _pp_args = (context_key, context, found_path)
                        thread = threading.Thread(target=_pp_target, args=_pp_args)
                        thread.daemon = True
                        thread.start()

                        # Only mark as processed AFTER thread starts successfully
                        _processed_download_ids.add(context_key)
                        print(f"Marked as processed: {context_key}")

                        # DON'T remove context immediately - verification worker needs it
                        # Context will be cleaned up by verification worker after both processors complete
                        print(f"Keeping context for verification worker: {context_key}")

                    except Exception as e:
                        print(f"Error starting post-processing thread for {context_key}: {e}")
                        # Don't add to processed set if thread failed to start
                        print(f"Will retry {context_key} on next check")

            # Start a single thread to manage the launching of all processing threads
            processing_thread = threading.Thread(target=process_completed_downloads)
            processing_thread.daemon = True
            processing_thread.start()

        # Also include YouTube/Tidal downloads in the response
        try:
            all_streaming_downloads = run_async(soulseek_client.get_all_downloads())

            for download in all_streaming_downloads:
                if download.username in ('youtube', 'tidal', 'qobuz', 'hifi', 'deezer_dl', 'lidarr'):
                    source_label = download.username.title()
                    # Convert DownloadStatus to transfer format that frontend expects
                    streaming_transfer = {
                        'id': download.id,
                        'filename': download.filename,
                        'username': download.username,
                        'state': download.state,
                        'percentComplete': download.progress,
                        'size': download.size,
                        'bytesTransferred': download.transferred,
                        'averageSpeed': download.speed,
                        'direction': 'Download',  # Required by frontend
                    }
                    all_transfers.append(streaming_transfer)

                    # Check if download is completed and needs post-processing
                    # Verify bytes match before trusting state string
                    _st_bytes_ok = download.size <= 0 or download.transferred >= download.size
                    if _st_bytes_ok and download.state and ('succeeded' in download.state.lower() or 'completed' in download.state.lower()):
                        context_key = _make_context_key(download.username, download.filename)

                        with matched_context_lock:
                            context = matched_downloads_context.get(context_key)

                        if context and context_key not in _processed_download_ids:
                            download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
                            found_result = _find_completed_file_robust(download_dir, download.filename)
                            found_path = found_result[0] if found_result and found_result[0] else None

                            if found_path:
                                # Prevent two contexts from claiming the same physical file
                                _st_norm = os.path.normpath(found_path)
                                if _st_norm in _files_claimed_this_cycle:
                                    print(f"[{source_label}] File already claimed this cycle: {os.path.basename(found_path)} — deferring")
                                    continue
                                _files_claimed_this_cycle.add(_st_norm)
                                print(f"[{source_label}] Found completed matched file on disk: {found_path}")
                                # Start post-processing thread
                                def process_streaming_download(_ctx_key=context_key, _ctx=context, _path=found_path, _label=source_label):
                                    try:
                                        print(f"[{_label}] Starting post-processing thread for: {_ctx_key}")
                                        # Use verification wrapper if context has task tracking IDs
                                        _st_task_id = _ctx.get('task_id')
                                        _st_batch_id = _ctx.get('batch_id')
                                        if _st_task_id and _st_batch_id:
                                            _st_target = _post_process_matched_download_with_verification
                                            _st_args = (_ctx_key, _ctx, _path, _st_task_id, _st_batch_id)
                                        else:
                                            _st_target = _post_process_matched_download
                                            _st_args = (_ctx_key, _ctx, _path)
                                        thread = threading.Thread(target=_st_target, args=_st_args)
                                        thread.daemon = True
                                        thread.start()
                                        _processed_download_ids.add(_ctx_key)
                                        print(f"[{_label}] Marked as processed: {_ctx_key}")
                                    except Exception as e:
                                        print(f"[{_label}] Error starting post-processing thread for {_ctx_key}: {e}")

                                processing_thread = threading.Thread(target=process_streaming_download)
                                processing_thread.daemon = True
                                processing_thread.start()
                            else:
                                # File not found - likely already processed and moved to library
                                # Mark as processed to prevent infinite checking
                                _processed_download_ids.add(context_key)
        except Exception as streaming_error:
            import traceback
            print(f"Could not fetch YouTube/Tidal downloads for status: {streaming_error}")
            traceback.print_exc()

        return jsonify({"transfers": all_transfers})

    except Exception as e:
        print(f"Error fetching download status: {e}")
        return jsonify({"error": str(e)}), 500





@app.route('/api/downloads/cancel', methods=['POST'])
def cancel_download():
    """
    Cancel a specific download transfer, matching GUI functionality.
    """
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "No data provided."}), 400
    
    download_id = data.get('download_id')
    username = data.get('username')

    if not all([download_id, username]):
        return jsonify({"success": False, "error": "Missing download_id or username."}), 400

    try:
        # Call the same client method the GUI uses
        success = run_async(soulseek_client.cancel_download(download_id, username, remove=True))
        if success:
            return jsonify({"success": True, "message": "Download cancelled."})
        else:
            return jsonify({"success": False, "error": "Failed to cancel download via slskd."}), 500
    except Exception as e:
        print(f"Error cancelling download: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/downloads/cancel-all', methods=['POST'])
def cancel_all_downloads():
    """
    Cancel all active downloads from slskd, then clear completed ones.
    """
    try:
        # First cancel all active downloads
        cancel_success = run_async(soulseek_client.cancel_all_downloads())
        if not cancel_success:
            return jsonify({"success": False, "error": "Failed to cancel active downloads."}), 500

        # Then clear the now-cancelled/completed downloads
        clear_success = run_async(soulseek_client.clear_all_completed_downloads())

        # Sweep empty directories
        _sweep_empty_download_directories()

        return jsonify({"success": True, "message": "All downloads cancelled and cleared."})
    except Exception as e:
        print(f"Error cancelling all downloads: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/downloads/clear-finished', methods=['POST'])
def clear_finished_downloads():
    """
    Clear all terminal (completed, cancelled, failed) downloads from slskd.
    """
    try:
        # This single client call handles clearing everything that is no longer active
        success = run_async(soulseek_client.clear_all_completed_downloads())
        if success:
            # Also sweep empty directories left behind by completed downloads
            _sweep_empty_download_directories()
            return jsonify({"success": True, "message": "Finished downloads cleared."})
        else:
            return jsonify({"success": False, "error": "Backend failed to clear downloads."}), 500
    except Exception as e:
        print(f"Error clearing finished downloads: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/downloads/task/<task_id>/candidates', methods=['GET'])
def get_task_candidates(task_id):
    """Returns the cached search candidates for a download task so the UI can show what was found."""
    try:
        with tasks_lock:
            task = download_tasks.get(task_id)
            if not task:
                return jsonify({"error": "Task not found"}), 404

            candidates = task.get('cached_candidates', [])
            track_info = task.get('track_info', {})
            error_message = task.get('error_message', '')

            serialized = []
            for c in candidates:
                if hasattr(c, '__dict__'):
                    serialized.append({
                        'username': getattr(c, 'username', ''),
                        'filename': getattr(c, 'filename', ''),
                        'size': getattr(c, 'size', 0),
                        'bitrate': getattr(c, 'bitrate', None),
                        'duration': getattr(c, 'duration', None),
                        'quality': getattr(c, 'quality', ''),
                        'free_upload_slots': getattr(c, 'free_upload_slots', 0),
                        'upload_speed': getattr(c, 'upload_speed', 0),
                        'queue_length': getattr(c, 'queue_length', 0),
                        'artist': getattr(c, 'artist', None),
                        'title': getattr(c, 'title', None),
                        'album': getattr(c, 'album', None),
                    })
                elif isinstance(c, dict):
                    serialized.append(c)

        return jsonify({
            "task_id": task_id,
            "track_info": {
                "name": track_info.get('name', 'Unknown') if isinstance(track_info, dict) else 'Unknown',
                "artist": _get_track_artist_name(track_info) if isinstance(track_info, dict) else 'Unknown',
            },
            "error_message": error_message,
            "candidates": serialized,
            "candidate_count": len(serialized),
        })
    except Exception as e:
        print(f"[Candidates] Error fetching candidates for task {task_id}: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/downloads/task/<task_id>/download-candidate', methods=['POST'])
def download_selected_candidate(task_id):
    """Restart a not_found/failed task by downloading a user-selected candidate."""
    dl_err = check_download_permission()
    if dl_err:
        return dl_err
    try:
        data = request.get_json()
        if not data or not data.get('username') or not data.get('filename'):
            return jsonify({"error": "Missing username or filename"}), 400

        username = data['username']
        filename = data['filename']
        size = data.get('size', 0)

        with tasks_lock:
            task = download_tasks.get(task_id)
            if not task:
                return jsonify({"error": "Task not found"}), 404
            if task['status'] not in ('not_found', 'failed'):
                return jsonify({"error": f"Task is {task['status']}, not eligible for retry"}), 400

            batch_id = task.get('batch_id')
            track_info = task.get('track_info', {})

            # Reset task state
            task['status'] = 'downloading'
            task['error_message'] = None
            task['status_change_time'] = time.time()
            task.pop('download_id', None)
            task.pop('username', None)
            task.pop('filename', None)
            # Clear the selected candidate from used_sources so it won't be skipped
            used_sources = task.get('used_sources', set())
            source_key = f"{username}_{filename}"
            used_sources.discard(source_key)

            # Reset batch tracking for this task
            if batch_id and batch_id in download_batches:
                batch = download_batches[batch_id]
                # Remove from completed set so _on_download_completed can fire again
                completed_set = batch.get('_completed_task_ids', set())
                completed_set.discard(task_id)
                # Remove from permanently_failed_tracks
                track_index = task.get('track_index')
                batch['permanently_failed_tracks'] = [
                    t for t in batch.get('permanently_failed_tracks', [])
                    if t.get('table_index') != track_index and t.get('download_index') != track_index
                ]
                # Restore worker slot
                batch['active_count'] = batch.get('active_count', 0) + 1

        # Build a TrackResult-like candidate object
        from core.soulseek_client import TrackResult
        candidate = TrackResult(
            username=username,
            filename=filename,
            size=size,
            bitrate=data.get('bitrate'),
            duration=data.get('duration'),
            quality=data.get('quality', 'unknown'),
            free_upload_slots=data.get('free_upload_slots', 0),
            upload_speed=data.get('upload_speed', 0),
            queue_length=data.get('queue_length', 0),
            artist=data.get('artist'),
            title=data.get('title'),
            album=data.get('album'),
        )
        candidate.confidence = 1.0  # Required by _attempt_download_with_candidates sort

        # Reconstruct Track object from task's track_info
        from core.itunes_client import Track
        artists = track_info.get('artists', [])
        artist_names = []
        for a in (artists if isinstance(artists, list) else []):
            if isinstance(a, dict):
                artist_names.append(a.get('name', 'Unknown'))
            elif isinstance(a, str):
                artist_names.append(a)
        if not artist_names:
            artist_names = [track_info.get('artist', 'Unknown')]

        track = Track(
            id=track_info.get('id', ''),
            name=track_info.get('name', 'Unknown'),
            artists=artist_names,
            album=track_info.get('album', {}).get('name', '') if isinstance(track_info.get('album'), dict) else track_info.get('album', ''),
            duration_ms=track_info.get('duration_ms', 0),
            popularity=0,
        )

        # Submit to thread pool — don't block the request
        def _run_manual_download():
            success = _attempt_download_with_candidates(task_id, [candidate], track, batch_id)
            if not success:
                with tasks_lock:
                    if task_id in download_tasks:
                        download_tasks[task_id]['status'] = 'failed'
                        download_tasks[task_id]['error_message'] = 'Manual download failed to start — user may be offline'
                if batch_id:
                    _on_download_completed(batch_id, task_id, success=False)

        missing_download_executor.submit(_run_manual_download)

        track_name = track_info.get('name', 'Unknown')
        print(f"[Manual Download] User selected candidate for '{track_name}' from {username}")
        return jsonify({"success": True, "message": f"Download initiated for '{track_name}'"})

    except Exception as e:
        print(f"[Manual Download] Error: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"error": str(e)}), 500

@app.route('/api/quarantine/clear', methods=['POST'])
def clear_quarantine():
    """Delete all files and folders inside the ss_quarantine directory."""
    import shutil
    try:
        download_path = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
        quarantine_path = os.path.join(download_path, 'ss_quarantine')

        if not os.path.isdir(quarantine_path):
            return jsonify({"success": True, "message": "Quarantine folder is already empty."})

        removed_files = 0
        for entry in os.listdir(quarantine_path):
            entry_path = os.path.join(quarantine_path, entry)
            try:
                if os.path.isfile(entry_path):
                    os.remove(entry_path)
                    removed_files += 1
                elif os.path.isdir(entry_path):
                    shutil.rmtree(entry_path)
                    removed_files += 1
            except Exception as e:
                print(f"[Quarantine] Failed to remove {entry}: {e}")

        print(f"[Quarantine] Cleared {removed_files} item(s) from quarantine folder")
        return jsonify({"success": True, "message": f"Quarantine cleared ({removed_files} item{'s' if removed_files != 1 else ''} removed)."})
    except Exception as e:
        print(f"[Quarantine] Error clearing quarantine: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

