def _build_issue_snapshot(database, entity_type, entity_id):
    """Capture current state of the entity for the issue report."""
    snapshot = {}
    try:
        conn = database._get_connection()
        cursor = conn.cursor()

        if entity_type == 'track':
            cursor.execute("""
                SELECT t.id, t.title, t.track_number, t.duration,
                       t.file_path, t.bitrate, t.bpm,
                       t.spotify_track_id, t.musicbrainz_recording_id, t.deezer_id as track_deezer_id,
                       a.name as artist_name, a.id as artist_id,
                       a.spotify_artist_id, a.musicbrainz_id as artist_musicbrainz_id,
                       a.deezer_id as artist_deezer_id, a.tidal_id as artist_tidal_id,
                       a.qobuz_id as artist_qobuz_id, a.thumb_url as artist_thumb,
                       al.title as album_title, al.year, al.thumb_url as album_thumb,
                       al.id as album_id, al.spotify_album_id, al.musicbrainz_release_id,
                       al.deezer_id as album_deezer_id, al.tidal_id as album_tidal_id,
                       al.qobuz_id as album_qobuz_id, al.label, al.record_type,
                       al.track_count as album_track_count
                FROM tracks t
                JOIN artists a ON t.artist_id = a.id
                JOIN albums al ON t.album_id = al.id
                WHERE t.id = ?
            """, (entity_id,))
            row = cursor.fetchone()
            if row:
                d = dict(row)
                # Add format info if file exists
                resolved = _resolve_library_file_path(d.get('file_path'))
                if resolved:
                    ext = os.path.splitext(resolved)[1].lower().lstrip('.')
                    d['format'] = ext.upper()
                    d['quality'] = _get_audio_quality_string(resolved)
                # Fix Plex/Jellyfin relative thumb URLs
                if d.get('artist_thumb'):
                    d['artist_thumb'] = fix_artist_image_url(d['artist_thumb']) or d['artist_thumb']
                if d.get('album_thumb'):
                    d['album_thumb'] = fix_artist_image_url(d['album_thumb']) or d['album_thumb']
                snapshot = d

        elif entity_type == 'album':
            cursor.execute("""
                SELECT al.id, al.title, al.year, al.track_count, al.thumb_url,
                       al.genres, al.label, al.record_type, al.duration,
                       al.spotify_album_id, al.musicbrainz_release_id,
                       al.deezer_id as album_deezer_id, al.tidal_id as album_tidal_id,
                       al.qobuz_id as album_qobuz_id, al.upc,
                       a.name as artist_name, a.id as artist_id,
                       a.spotify_artist_id, a.musicbrainz_id as artist_musicbrainz_id,
                       a.deezer_id as artist_deezer_id, a.tidal_id as artist_tidal_id,
                       a.qobuz_id as artist_qobuz_id, a.thumb_url as artist_thumb
                FROM albums al
                JOIN artists a ON al.artist_id = a.id
                WHERE al.id = ?
            """, (entity_id,))
            row = cursor.fetchone()
            if row:
                d = dict(row)
                # Fix Plex/Jellyfin relative thumb URLs
                if d.get('thumb_url'):
                    d['thumb_url'] = fix_artist_image_url(d['thumb_url']) or d['thumb_url']
                if d.get('artist_thumb'):
                    d['artist_thumb'] = fix_artist_image_url(d['artist_thumb']) or d['artist_thumb']
                # Parse genres
                if d.get('genres'):
                    try:
                        d['genres'] = json.loads(d['genres'])
                    except (json.JSONDecodeError, TypeError):
                        pass
                # Get track listing with enriched data
                cursor.execute("""
                    SELECT id, title, track_number, duration, file_path, bitrate,
                           spotify_track_id, bpm
                    FROM tracks WHERE album_id = ? ORDER BY track_number
                """, (entity_id,))
                tracks_list = []
                for r in cursor.fetchall():
                    td = dict(r)
                    # Add format from file extension
                    if td.get('file_path'):
                        resolved = _resolve_library_file_path(td['file_path'])
                        if resolved:
                            ext = os.path.splitext(resolved)[1].lower().lstrip('.')
                            td['format'] = ext.upper()
                    tracks_list.append(td)
                d['tracks'] = tracks_list
                snapshot = d

        elif entity_type == 'artist':
            cursor.execute("""
                SELECT id, name, thumb_url, genres, summary,
                       spotify_artist_id, musicbrainz_id as artist_musicbrainz_id,
                       deezer_id as artist_deezer_id, tidal_id as artist_tidal_id,
                       qobuz_id as artist_qobuz_id
                FROM artists WHERE id = ?
            """, (entity_id,))
            row = cursor.fetchone()
            if row:
                d = dict(row)
                # Fix Plex/Jellyfin relative thumb URL
                if d.get('thumb_url'):
                    d['thumb_url'] = fix_artist_image_url(d['thumb_url']) or d['thumb_url']
                if d.get('genres'):
                    try:
                        d['genres'] = json.loads(d['genres'])
                    except (json.JSONDecodeError, TypeError):
                        pass
                snapshot = d

    except Exception as e:
        logger.error(f"Error building issue snapshot: {e}")
        snapshot['_snapshot_error'] = str(e)

    return snapshot


def _sync_tracks_to_server(track_rows, server_type):
    """Sync metadata for tracks to the active media server after writing file tags.

    Args:
        track_rows: list of track dicts (must include 'id', 'title', 'artist_name', 'album_title', 'year', 'server_source')
        server_type: 'plex', 'jellyfin', or 'navidrome'

    Returns:
        dict with 'synced', 'failed', 'skipped' counts and 'errors' list
    """
    result = {'synced': 0, 'failed': 0, 'skipped': 0, 'errors': []}

    if server_type == 'navidrome':
        # Navidrome auto-detects file tag changes, no action needed
        result['synced'] = len(track_rows)
        return result

    if server_type == 'plex':
        for track_data in track_rows:
            # Only sync tracks that came from this server
            if track_data.get('server_source') and track_data['server_source'] != 'plex':
                result['skipped'] += 1
                continue
            try:
                metadata = {}
                if track_data.get('title'):
                    metadata['title'] = track_data['title']
                if track_data.get('artist_name'):
                    metadata['artist'] = track_data['artist_name']
                if track_data.get('album_title'):
                    metadata['album'] = track_data['album_title']
                if track_data.get('year'):
                    metadata['year'] = track_data['year']
                if metadata:
                    success = plex_client.update_track_metadata(str(track_data['id']), metadata)
                    if success:
                        result['synced'] += 1
                    else:
                        result['failed'] += 1
                        result['errors'].append({'track_id': track_data['id'], 'error': 'Plex update returned false'})
                else:
                    result['skipped'] += 1
            except Exception as e:
                result['failed'] += 1
                result['errors'].append({'track_id': track_data['id'], 'error': str(e)})

    elif server_type == 'jellyfin':
        # Jellyfin: just trigger a library scan once after all file writes
        try:
            success = jellyfin_client.trigger_library_scan()
            if success:
                result['synced'] = len(track_rows)
            else:
                result['failed'] = len(track_rows)
                result['errors'].append({'error': 'Jellyfin library scan failed'})
        except Exception as e:
            result['failed'] = len(track_rows)
            result['errors'].append({'error': f'Jellyfin scan error: {e}'})

    return result


def _resolve_library_file_path(file_path):
    """Resolve a library file path to an actual file on disk."""
    if not file_path:
        return None
    if os.path.exists(file_path):
        return file_path

    # Try resolving server-side paths to local directories
    # Check transfer path, download path, and media server library paths
    transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
    download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))

    # Also check the media server's music library path (handles Docker↔host path mismatch)
    library_dirs = set()
    try:
        if plex_client and plex_client.server and plex_client.music_library:
            for loc in plex_client.music_library.locations:
                library_dirs.add(loc)
    except Exception:
        pass

    # Check user-configured music library paths (Settings > Library)
    try:
        music_paths = config_manager.get('library.music_paths', [])
        if isinstance(music_paths, list):
            for p in music_paths:
                if p and isinstance(p, str):
                    resolved_p = docker_resolve_path(p.strip())
                    if resolved_p:
                        library_dirs.add(resolved_p)
    except Exception:
        pass

    path_parts = file_path.replace('\\', '/').split('/')

    # Try progressively shorter path suffixes against each candidate directory
    # (skip index 0 to avoid drive letter issues)
    for base_dir in [transfer_dir, download_dir] + list(library_dirs):
        if not base_dir or not os.path.isdir(base_dir):
            continue
        for i in range(1, len(path_parts)):
            candidate = os.path.join(base_dir, *path_parts[i:])
            if os.path.exists(candidate):
                return candidate

    return None


def _get_file_not_found_error(file_path):
    """Return a helpful error message when a library file can't be found."""
    active_server = config_manager.get_active_media_server()
    if active_server == 'navidrome':
        # Check if path looks like a Navidrome fake path (no real filesystem root)
        # Fake paths look like: "Artist/Album/01 - Track.flac" or just "Track.flac"
        if file_path and ('/' not in file_path or not file_path.startswith('/')):
            return ('File not found — Navidrome may be sending virtual paths. '
                    'Go to Navidrome → Profile → Players → select SoulSync → enable "Report Real Path", '
                    'then run a full database refresh in SoulSync.')
        return ('File not found on disk — check that your Navidrome music folder '
                'is mounted in the SoulSync container and that "Report Real Path" is enabled '
                'in Navidrome\'s player settings.')
    return 'File not found on disk'


@app.route('/api/library/play', methods=['POST'])
def library_play_track():
    """Start playing a track directly from the user's library (no download needed)."""
    try:
        data = request.get_json()
        if not data or not data.get('file_path'):
            return jsonify({"success": False, "error": "file_path is required"}), 400

        file_path = data['file_path']

        # Resolve server-side paths (e.g. /mnt/musicBackup/...) to local transfer path
        resolved = _resolve_library_file_path(file_path)
        if resolved:
            file_path = resolved
        else:
            return jsonify({"success": False, "error": _get_file_not_found_error(file_path)}), 404

        print(f"Library play request: {os.path.basename(file_path)}")

        # Set stream state to ready with the library file path directly
        with stream_lock:
            stream_state.update({
                "status": "ready",
                "progress": 100,
                "track_info": {
                    "title": data.get('title', os.path.basename(file_path)),
                    "artist": data.get('artist', 'Unknown Artist'),
                    "album": data.get('album', 'Unknown Album'),
                },
                "file_path": file_path,
                "error_message": None,
                "is_library": True
            })

        return jsonify({"success": True, "message": "Library track ready for playback"})

    except Exception as e:
        print(f"Error playing library track: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

_enrichment_locks = {svc: threading.Lock() for svc in ('audiodb', 'deezer', 'musicbrainz', 'spotify', 'itunes', 'lastfm', 'genius', 'tidal', 'qobuz', 'discogs')}

@app.route('/api/library/enrich', methods=['POST'])
def library_enrich_entity():
    """Trigger enrichment of a specific entity from a single service.
    Body: { entity_type: 'artist'|'album'|'track', entity_id: str, service: str,
            name: str, artist_name: str? }
    service: 'audiodb', 'deezer', 'musicbrainz', 'spotify', 'itunes', 'lastfm', 'genius', 'tidal', 'qobuz'
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"success": False, "error": "No data provided"}), 400

        entity_type = data.get('entity_type')  # artist, album, track
        entity_id = data.get('entity_id')
        service = data.get('service')
        name = data.get('name', '')
        artist_name = data.get('artist_name', '')

        if not entity_type or not entity_id or not service:
            return jsonify({"success": False, "error": "entity_type, entity_id, and service are required"}), 400

        if entity_type not in ('artist', 'album', 'track'):
            return jsonify({"success": False, "error": "entity_type must be artist, album, or track"}), 400

        valid_services = ('audiodb', 'deezer', 'musicbrainz', 'spotify', 'itunes', 'lastfm', 'genius', 'tidal', 'qobuz', 'discogs')
        if service not in valid_services:
            return jsonify({"success": False, "error": f"service must be one of: {', '.join(valid_services)}"}), 400

        # Per-service lock to avoid thread-safety issues with shared worker clients
        lock = _enrichment_locks.get(service)
        if not lock:
            return jsonify({"success": False, "error": f"Unknown service: {service}"}), 400

        acquired = lock.acquire(blocking=False)
        if not acquired:
            return jsonify({"success": False, "error": f"{service} enrichment already in progress. Please wait."}), 429

        try:
            results = {}
            try:
                result = _run_single_enrichment(service, entity_type, entity_id, name, artist_name)
                results[service] = result
            except Exception as e:
                results[service] = {"success": False, "error": str(e)}
        finally:
            lock.release()

        # Re-fetch updated data to return fresh state
        database = get_database()
        updated = database.get_artist_full_detail(
            data.get('artist_id', entity_id) if entity_type == 'artist' else
            _get_artist_id_for_entity(database, entity_type, entity_id)
        )

        # Fix image URLs in updated data
        if updated.get('success'):
            if updated.get('artist', {}).get('thumb_url'):
                updated['artist']['thumb_url'] = fix_artist_image_url(updated['artist']['thumb_url'])
            for album in updated.get('albums', []):
                if album.get('thumb_url'):
                    album['thumb_url'] = fix_artist_image_url(album['thumb_url'])

        return jsonify({
            "success": True,
            "results": results,
            "updated_data": updated if updated.get('success') else None
        })

    except Exception as e:
        print(f"Error enriching entity: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


def _get_artist_id_for_entity(database, entity_type, entity_id):
    """Look up the artist_id for an album or track."""
    try:
        with database._get_connection() as conn:
            cursor = conn.cursor()
            if entity_type == 'album':
                cursor.execute("SELECT artist_id FROM albums WHERE id = ?", (entity_id,))
            elif entity_type == 'track':
                cursor.execute("SELECT artist_id FROM tracks WHERE id = ?", (entity_id,))
            else:
                return entity_id
            row = cursor.fetchone()
            return row['artist_id'] if row else entity_id
    except Exception:
        return entity_id


def _run_single_enrichment(service, entity_type, entity_id, name, artist_name):
    """Run a single enrichment service on a single entity."""
    if service == 'audiodb':
        if not audiodb_worker:
            return {"success": False, "error": "AudioDB worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name}
        if entity_type in ('album', 'track'):
            item['artist'] = artist_name
        audiodb_worker._process_item(item)
        return {"success": True, "message": f"AudioDB lookup complete for {entity_type}"}

    elif service == 'deezer':
        if not deezer_worker:
            return {"success": False, "error": "Deezer worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name, 'artist': artist_name}
        if entity_type == 'artist':
            deezer_worker._process_artist(entity_id, name)
        elif entity_type == 'album':
            deezer_worker._process_album(entity_id, name, artist_name, item)
        elif entity_type == 'track':
            deezer_worker._process_track(entity_id, name, artist_name, item)
        return {"success": True, "message": f"Deezer lookup complete for {entity_type}"}

    elif service == 'musicbrainz':
        if not mb_worker:
            return {"success": False, "error": "MusicBrainz worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name}
        if entity_type in ('album', 'track'):
            item['artist'] = artist_name
        mb_worker._process_item(item)
        return {"success": True, "message": f"MusicBrainz lookup complete for {entity_type}"}

    elif service == 'spotify':
        if not spotify_enrichment_worker:
            return {"success": False, "error": "Spotify worker not initialized"}
        if entity_type == 'artist':
            spotify_enrichment_worker._process_artist({'type': 'artist', 'id': entity_id, 'name': name})
        elif entity_type == 'album':
            spotify_enrichment_worker._process_album_individual({'type': 'album_individual', 'id': entity_id, 'name': name, 'artist': artist_name})
        elif entity_type == 'track':
            spotify_enrichment_worker._process_track_individual({'type': 'track_individual', 'id': entity_id, 'name': name, 'artist': artist_name})
        return {"success": True, "message": f"Spotify lookup complete for {entity_type}"}

    elif service == 'itunes':
        if not itunes_enrichment_worker:
            return {"success": False, "error": "iTunes worker not initialized"}
        if entity_type == 'artist':
            itunes_enrichment_worker._process_artist({'type': 'artist', 'id': entity_id, 'name': name})
        elif entity_type == 'album':
            itunes_enrichment_worker._process_album_individual({'type': 'album_individual', 'id': entity_id, 'name': name, 'artist': artist_name})
        elif entity_type == 'track':
            itunes_enrichment_worker._process_track_individual({'type': 'track_individual', 'id': entity_id, 'name': name, 'artist': artist_name})
        return {"success": True, "message": f"iTunes lookup complete for {entity_type}"}

    elif service == 'lastfm':
        if not lastfm_worker:
            return {"success": False, "error": "Last.fm worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name}
        if entity_type in ('album', 'track'):
            item['artist'] = artist_name
        lastfm_worker._process_item(item)
        return {"success": True, "message": f"Last.fm lookup complete for {entity_type}"}

    elif service == 'genius':
        if not genius_worker:
            return {"success": False, "error": "Genius worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name}
        if entity_type == 'track':
            item['artist'] = artist_name
        elif entity_type == 'album':
            return {"success": False, "error": "Genius does not support album enrichment"}
        genius_worker._process_item(item)
        return {"success": True, "message": f"Genius lookup complete for {entity_type}"}

    elif service == 'tidal':
        if not tidal_enrichment_worker:
            return {"success": False, "error": "Tidal worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name, 'artist': artist_name}
        if entity_type == 'artist':
            tidal_enrichment_worker._process_artist(entity_id, name)
        elif entity_type == 'album':
            tidal_enrichment_worker._process_album(entity_id, name, artist_name, item)
        elif entity_type == 'track':
            tidal_enrichment_worker._process_track(entity_id, name, artist_name, item)
        return {"success": True, "message": f"Tidal lookup complete for {entity_type}"}

    elif service == 'qobuz':
        if not qobuz_enrichment_worker:
            return {"success": False, "error": "Qobuz worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name, 'artist': artist_name}
        if entity_type == 'artist':
            qobuz_enrichment_worker._process_artist(entity_id, name)
        elif entity_type == 'album':
            qobuz_enrichment_worker._process_album(entity_id, name, artist_name, item)
        elif entity_type == 'track':
            qobuz_enrichment_worker._process_track(entity_id, name, artist_name, item)
        return {"success": True, "message": f"Qobuz lookup complete for {entity_type}"}

    elif service == 'discogs':
        if not discogs_worker:
            return {"success": False, "error": "Discogs worker not initialized"}
        item = {'type': entity_type, 'id': entity_id, 'name': name}
        if entity_type in ('album', 'track'):
            item['artist'] = artist_name
        if entity_type == 'track':
            return {"success": False, "error": "Discogs does not support track-level enrichment"}
        discogs_worker._process_item(item)
        return {"success": True, "message": f"Discogs lookup complete for {entity_type}"}

    else:
        return {"success": False, "error": f"Unknown service: {service}"}


@app.route('/api/library/search-service', methods=['POST'])
def library_search_service():
    """Search a specific service for matching entities (for manual matching).
    Body: { service: str, entity_type: str, query: str }
    Returns normalized list of results.
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({"success": False, "error": "Invalid or missing JSON body"}), 400
        service = data.get('service', '')
        entity_type = data.get('entity_type', '')
        query = data.get('query', '').strip()

        if not service or not entity_type or not query:
            return jsonify({"success": False, "error": "service, entity_type, and query are required"}), 400

        results = _search_service(service, entity_type, query)
        return jsonify({"success": True, "results": results})

    except Exception as e:
        print(f"Error searching service: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


def _detect_provider(items, client):
    """Detect actual provider from result IDs. Spotify IDs are alphanumeric;
    iTunes/Deezer IDs are purely numeric. If the results have numeric IDs,
    they came from the fallback source, not Spotify."""
    if items and str(items[0].id).isdigit():
        return client._fallback_source
    return 'spotify'


def _search_service(service, entity_type, query):
    """Search a service and return normalized results."""
    import requests as req_lib

    if service == 'spotify':
        if not spotify_enrichment_worker or not spotify_enrichment_worker.client:
            raise ValueError("Spotify worker not initialized")
        client = spotify_enrichment_worker.client
        if entity_type == 'artist':
            items = client.search_artists(query, limit=8)
            # Detect actual provider from result IDs — Spotify IDs are alphanumeric,
            # iTunes/Deezer IDs are purely numeric. Prevents storing wrong IDs.
            provider = _detect_provider(items, client)
            return [{'id': a.id, 'name': a.name, 'image': a.image_url, 'extra': ', '.join(a.genres[:3]) if a.genres else '', 'provider': provider} for a in items]
        elif entity_type == 'album':
            items = client.search_albums(query, limit=8)
            provider = _detect_provider(items, client)
            return [{'id': a.id, 'name': a.name, 'image': a.image_url, 'extra': f"{', '.join(a.artists)} · {a.release_date or ''}", 'provider': provider} for a in items]
        elif entity_type == 'track':
            items = client.search_tracks(query, limit=8)
            provider = _detect_provider(items, client)
            return [{'id': t.id, 'name': t.name, 'image': t.image_url, 'extra': f"{', '.join(t.artists)} · {t.album or ''}", 'provider': provider} for t in items]

    elif service == 'itunes':
        if not itunes_enrichment_worker or not itunes_enrichment_worker.client:
            raise ValueError("iTunes worker not initialized")
        client = itunes_enrichment_worker.client
        if entity_type == 'artist':
            items = client.search_artists(query, limit=8)
            return [{'id': a.id, 'name': a.name, 'image': a.image_url, 'extra': ', '.join(a.genres[:3]) if a.genres else ''} for a in items]
        elif entity_type == 'album':
            items = client.search_albums(query, limit=8)
            return [{'id': a.id, 'name': a.name, 'image': a.image_url, 'extra': f"{', '.join(a.artists)} · {a.release_date or ''}"} for a in items]
        elif entity_type == 'track':
            items = client.search_tracks(query, limit=8)
            return [{'id': t.id, 'name': t.name, 'image': t.image_url, 'extra': f"{', '.join(t.artists)} · {t.album or ''}"} for t in items]

    elif service == 'musicbrainz':
        if not mb_worker or not mb_worker.mb_service:
            raise ValueError("MusicBrainz worker not initialized")
        mb_client = mb_worker.mb_service.mb_client
        if entity_type == 'artist':
            items = mb_client.search_artist(query, limit=8)
            return [{'id': a['id'], 'name': a.get('name', ''), 'image': None,
                      'extra': f"Score: {a.get('score', '')} · {a.get('disambiguation', '') or a.get('country', '')}"} for a in items]
        elif entity_type == 'album':
            items = mb_client.search_release(query, limit=8)
            results = []
            for r in items:
                artists = ', '.join(ac.get('name', '') for ac in r.get('artist-credit', []) if isinstance(ac, dict))
                # Cover Art Archive provides album art by release MBID
                cover_url = f"https://coverartarchive.org/release/{r['id']}/front-250" if r.get('id') else None
                results.append({'id': r['id'], 'name': r.get('title', ''), 'image': cover_url,
                                'extra': f"{artists} · {r.get('date', '')} · Score: {r.get('score', '')}"})
            return results
        elif entity_type == 'track':
            items = mb_client.search_recording(query, limit=8)
            results = []
            for r in items:
                artists = ', '.join(ac.get('name', '') for ac in r.get('artist-credit', []) if isinstance(ac, dict))
                results.append({'id': r['id'], 'name': r.get('title', ''), 'image': None,
                                'extra': f"{artists} · Score: {r.get('score', '')}"})
            return results

    elif service == 'deezer':
        # Deezer client only returns single results, so hit the API directly for multiple
        type_map = {'artist': 'artist', 'album': 'album', 'track': 'track'}
        deezer_type = type_map.get(entity_type, 'track')
        try:
            resp = req_lib.get(f'https://api.deezer.com/search/{deezer_type}', params={'q': query, 'limit': 8}, timeout=10)
            data = resp.json().get('data', [])
        except Exception:
            data = []
        results = []
        for item in data:
            if entity_type == 'artist':
                results.append({'id': str(item.get('id', '')), 'name': item.get('name', ''),
                                'image': item.get('picture_medium'), 'extra': f"{item.get('nb_fan', 0)} fans"})
            elif entity_type == 'album':
                artist_name = item.get('artist', {}).get('name', '') if isinstance(item.get('artist'), dict) else ''
                results.append({'id': str(item.get('id', '')), 'name': item.get('title', ''),
                                'image': item.get('cover_medium'), 'extra': artist_name})
            elif entity_type == 'track':
                artist_name = item.get('artist', {}).get('name', '') if isinstance(item.get('artist'), dict) else ''
                album_name = item.get('album', {}).get('title', '') if isinstance(item.get('album'), dict) else ''
                results.append({'id': str(item.get('id', '')), 'name': item.get('title', ''),
                                'image': item.get('album', {}).get('cover_medium') if isinstance(item.get('album'), dict) else None,
                                'extra': f"{artist_name} · {album_name}"})
        return results

    elif service == 'lastfm':
        if not lastfm_worker or not lastfm_worker.client:
            raise ValueError("Last.fm worker not initialized")
        client = lastfm_worker.client
        if entity_type == 'artist':
            result = client.search_artist(query)
            if result:
                image = client.get_best_image(result.get('image', []))
                return [{'id': result.get('url', ''), 'name': result.get('name', ''),
                         'image': image, 'extra': f"{result.get('listeners', '0')} listeners"}]
        elif entity_type == 'album':
            result = client.search_album(query, '')
            if result:
                image = client.get_best_image(result.get('image', []))
                return [{'id': result.get('url', ''), 'name': result.get('name', ''),
                         'image': image, 'extra': result.get('artist', '')}]
        elif entity_type == 'track':
            # search_track takes separate artist/track params
            parts = query.split(' - ', 1) if ' - ' in query else ['', query]
            result = client.search_track(parts[0], parts[1])
            if result:
                artist_name = result.get('artist', '')
                return [{'id': result.get('url', ''), 'name': result.get('name', ''),
                         'image': None, 'extra': f"{artist_name} · {result.get('listeners', '0')} listeners"}]
        return []

    elif service == 'genius':
        if not genius_worker or not genius_worker.client:
            raise ValueError("Genius worker not initialized")
        client = genius_worker.client
        if entity_type == 'artist':
            artists = client.search_artists(query, limit=8)
            return [{'id': str(a.get('id', '')), 'name': a.get('name', ''),
                     'image': a.get('image_url'), 'extra': a.get('url', '')} for a in artists]
        elif entity_type == 'track':
            # Search with broader results for manual matching
            hits = client.search(f"{query}", per_page=10)
            results = []
            seen_ids = set()
            for hit in hits:
                r = hit.get('result', {})
                rid = r.get('id')
                if rid and rid not in seen_ids:
                    seen_ids.add(rid)
                    results.append({'id': str(rid), 'name': r.get('title', ''),
                                    'image': r.get('song_art_image_url'), 'extra': r.get('artist_names', '')})
            return results
        return []

    elif service == 'tidal':
        if not tidal_enrichment_worker or not tidal_enrichment_worker.client:
            raise ValueError("Tidal worker not initialized")
        client = tidal_enrichment_worker.client
        if entity_type == 'artist':
            result = client.search_artist(query)
            if result:
                thumb = result.get('picture', '')
                if isinstance(thumb, list) and thumb:
                    thumb = thumb[0].get('url', '') if isinstance(thumb[0], dict) else str(thumb[0])
                return [{'id': str(result.get('id', '')), 'name': result.get('name', ''),
                         'image': thumb if isinstance(thumb, str) else None, 'extra': ''}]
        elif entity_type == 'album':
            result = client.search_album('', query)
            if result:
                return [{'id': str(result.get('id', '')), 'name': result.get('title', ''),
                         'image': None, 'extra': result.get('artist', {}).get('name', '') if isinstance(result.get('artist'), dict) else ''}]
        elif entity_type == 'track':
            result = client.search_track('', query)
            if result:
                artist_name = result.get('artist', {}).get('name', '') if isinstance(result.get('artist'), dict) else ''
                return [{'id': str(result.get('id', '')), 'name': result.get('title', ''),
                         'image': None, 'extra': artist_name}]
        return []

    elif service == 'qobuz':
        if not qobuz_enrichment_worker or not qobuz_enrichment_worker.client:
            raise ValueError("Qobuz worker not initialized")
        client = qobuz_enrichment_worker.client
        if entity_type == 'artist':
            result = client.search_artist(query)
            if result:
                image = result.get('image', {})
                thumb = image.get('large', image.get('medium', '')) if isinstance(image, dict) else ''
                return [{'id': str(result.get('id', '')), 'name': result.get('name', ''),
                         'image': thumb, 'extra': ''}]
        elif entity_type == 'album':
            result = client.search_album('', query)
            if result:
                artist_name = result.get('artist', {}).get('name', '') if isinstance(result.get('artist'), dict) else ''
                image = result.get('image', {})
                thumb = image.get('large', image.get('medium', '')) if isinstance(image, dict) else ''
                return [{'id': str(result.get('id', '')), 'name': result.get('title', ''),
                         'image': thumb, 'extra': artist_name}]
        elif entity_type == 'track':
            result = client.search_track('', query)
            if result:
                artist_name = result.get('performer', {}).get('name', '') if isinstance(result.get('performer'), dict) else ''
                if not artist_name:
                    artist_name = result.get('artist', {}).get('name', '') if isinstance(result.get('artist'), dict) else ''
                return [{'id': str(result.get('id', '')), 'name': result.get('title', ''),
                         'image': None, 'extra': artist_name}]
        return []

    elif service == 'discogs':
        if not discogs_worker or not discogs_worker.client:
            raise ValueError("Discogs worker not initialized")
        client = discogs_worker.client
        if entity_type == 'artist':
            items = client.search_artists(query, limit=8)
            return [{'id': str(a.id), 'name': a.name, 'image': a.image_url,
                     'extra': ', '.join(a.genres[:3]) if a.genres else ''} for a in items]
        elif entity_type == 'album':
            items = client.search_albums(query, limit=8)
            return [{'id': str(a.id), 'name': a.name, 'image': a.image_url,
                     'extra': f"{', '.join(a.artists)} · {a.release_date or ''}"} for a in items]
        elif entity_type == 'track':
            items = client.search_tracks(query, limit=8)
            return [{'id': str(t.id), 'name': t.name, 'image': t.image_url,
                     'extra': f"{', '.join(t.artists)} · {t.album or ''}"} for t in items]
        return []

    elif service == 'audiodb':
        if not audiodb_worker or not audiodb_worker.client:
            raise ValueError("AudioDB worker not initialized")
        client = audiodb_worker.client
        result = None
        if entity_type == 'artist':
            result = client.search_artist(query)
        elif entity_type == 'album':
            # AudioDB album search needs artist + album, try query as-is
            parts = query.split(' - ', 1) if ' - ' in query else [query, '']
            result = client.search_album(parts[0], parts[1] if len(parts) > 1 else query)
        elif entity_type == 'track':
            parts = query.split(' - ', 1) if ' - ' in query else [query, '']
            result = client.search_track(parts[0], parts[1] if len(parts) > 1 else query)
        if result:
            if entity_type == 'artist':
                return [{'id': str(result.get('idArtist', '')), 'name': result.get('strArtist', ''),
                         'image': result.get('strArtistThumb'), 'extra': result.get('strGenre', '')}]
            elif entity_type == 'album':
                return [{'id': str(result.get('idAlbum', '')), 'name': result.get('strAlbum', ''),
                         'image': result.get('strAlbumThumb'), 'extra': f"{result.get('strArtist', '')} · {result.get('intYearReleased', '')}"}]
            elif entity_type == 'track':
                return [{'id': str(result.get('idTrack', '')), 'name': result.get('strTrack', ''),
                         'image': None, 'extra': f"{result.get('strArtist', '')} · {result.get('strAlbum', '')}"}]
        return []

    return []


# Column name mappings for manual matching
_SERVICE_ID_COLUMNS = {
    'spotify': {'artist': 'spotify_artist_id', 'album': 'spotify_album_id', 'track': 'spotify_track_id'},
    'musicbrainz': {'artist': 'musicbrainz_id', 'album': 'musicbrainz_release_id', 'track': 'musicbrainz_recording_id'},
    'deezer': {'artist': 'deezer_id', 'album': 'deezer_id', 'track': 'deezer_id'},
    'audiodb': {'artist': 'audiodb_id', 'album': 'audiodb_id', 'track': 'audiodb_id'},
    'discogs': {'artist': 'discogs_id', 'album': 'discogs_id'},
    'itunes': {'artist': 'itunes_artist_id', 'album': 'itunes_album_id', 'track': 'itunes_track_id'},
    'lastfm': {'artist': 'lastfm_url', 'album': 'lastfm_url', 'track': 'lastfm_url'},
    'genius': {'artist': 'genius_id', 'track': 'genius_id'},
    'tidal': {'artist': 'tidal_id', 'album': 'tidal_id', 'track': 'tidal_id'},
    'qobuz': {'artist': 'qobuz_id', 'album': 'qobuz_id', 'track': 'qobuz_id'},
}

@app.route('/api/library/manual-match', methods=['PUT'])
def library_manual_match():
    """Manually set a service ID for an entity.
    Body: { entity_type: str, entity_id: str, service: str, service_id: str, artist_id: str }
    """
    try:
        data = request.get_json()
        entity_type = data.get('entity_type')
        entity_id = data.get('entity_id')
        service = data.get('service')
        service_id = data.get('service_id')

        if not all([entity_type, entity_id, service, service_id]):
            return jsonify({"success": False, "error": "entity_type, entity_id, service, and service_id are required"}), 400

        id_col = _SERVICE_ID_COLUMNS.get(service, {}).get(entity_type)
        if not id_col:
            return jsonify({"success": False, "error": f"Invalid service/entity_type combination"}), 400

        status_col = f"{service}_match_status"
        attempted_col = f"{service}_last_attempted"
        table = {'artist': 'artists', 'album': 'albums', 'track': 'tracks'}[entity_type]

        database = get_database()
        with database._get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(f"""
                UPDATE {table}
                SET {id_col} = ?, {status_col} = 'matched', {attempted_col} = CURRENT_TIMESTAMP
                WHERE id = ?
            """, (service_id, entity_id))
            conn.commit()
            if cursor.rowcount == 0:
                return jsonify({"success": False, "error": "Entity not found"}), 404

        # Re-fetch fresh data
        artist_id = data.get('artist_id', entity_id)
        if entity_type != 'artist':
            artist_id = _get_artist_id_for_entity(database, entity_type, entity_id)

        updated = database.get_artist_full_detail(artist_id)
        if updated.get('success'):
            if updated.get('artist', {}).get('thumb_url'):
                updated['artist']['thumb_url'] = fix_artist_image_url(updated['artist']['thumb_url'])
            for album in updated.get('albums', []):
                if album.get('thumb_url'):
                    album['thumb_url'] = fix_artist_image_url(album['thumb_url'])

        return jsonify({
            "success": True,
            "message": f"Manually matched {entity_type} to {service} ID: {service_id}",
            "updated_data": updated if updated.get('success') else None
        })

    except Exception as e:
        print(f"Error manual matching: {e}")

@app.route('/api/library/clear-match', methods=['PUT'])
def library_clear_match():
    """Clear a service ID match for an entity, reverting it to not_found.
    Body: { entity_type: str, entity_id: str, service: str }
    """
    try:
        data = request.get_json()
        entity_type = data.get('entity_type')
        entity_id = data.get('entity_id')
        service = data.get('service')

        if not all([entity_type, entity_id, service]):
            return jsonify({"success": False, "error": "entity_type, entity_id, and service are required"}), 400

        id_col = _SERVICE_ID_COLUMNS.get(service, {}).get(entity_type)
        if not id_col:
            return jsonify({"success": False, "error": f"Invalid service/entity_type combination"}), 400

        status_col = f"{service}_match_status"
        attempted_col = f"{service}_last_attempted"
        table = {'artist': 'artists', 'album': 'albums', 'track': 'tracks'}.get(entity_type)
        if not table:
            return jsonify({"success": False, "error": "Invalid entity_type"}), 400

        database = get_database()
        with database._get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(f"""
                UPDATE {table}
                SET {id_col} = NULL, {status_col} = 'not_found', {attempted_col} = NULL
                WHERE id = ?
            """, (entity_id,))
            conn.commit()
            if cursor.rowcount == 0:
                return jsonify({"success": False, "error": "Entity not found"}), 404

        # Re-fetch fresh data
        artist_id = data.get('artist_id', entity_id)
        if entity_type != 'artist':
            artist_id = _get_artist_id_for_entity(database, entity_type, entity_id)

        updated = database.get_artist_full_detail(artist_id)
        if updated.get('success'):
            if updated.get('artist', {}).get('thumb_url'):
                updated['artist']['thumb_url'] = fix_artist_image_url(updated['artist']['thumb_url'])
            for album in updated.get('albums', []):
                if album.get('thumb_url'):
                    album['thumb_url'] = fix_artist_image_url(album['thumb_url'])

        return jsonify({
            "success": True,
            "message": f"Cleared {service} match for {entity_type}",
            "updated_data": updated if updated.get('success') else None
        })

    except Exception as e:
        print(f"Error clearing match: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/track/<track_id>', methods=['DELETE'])
def library_delete_track(track_id):
    """Delete a track from the database, optionally deleting the file and blacklisting the source."""
    try:
        delete_file = request.args.get('delete_file', 'false').lower() == 'true'
        add_blacklist = request.args.get('blacklist', 'false').lower() == 'true'

        database = get_database()
        file_deleted = False
        blacklisted = False

        with database._get_connection() as conn:
            cursor = conn.cursor()

            # Get track info before deleting (for file removal + blacklist)
            track_info = None
            if delete_file or add_blacklist:
                cursor.execute("""
                    SELECT t.file_path, t.title, ar.name AS artist_name
                    FROM tracks t
                    JOIN artists ar ON t.artist_id = ar.id
                    WHERE t.id = ?
                """, (track_id,))
                track_info = cursor.fetchone()

            # Delete file from disk if requested
            if delete_file and track_info and track_info['file_path']:
                resolved = _resolve_library_file_path(track_info['file_path'])
                if resolved and os.path.exists(resolved):
                    try:
                        os.remove(resolved)
                        file_deleted = True
                        logger.info(f"Deleted file from disk: {resolved}")
                    except Exception as e:
                        logger.warning(f"Failed to delete file: {e}")

            # Add to blacklist if requested
            if add_blacklist and track_info and track_info['file_path']:
                # Extract username and filename from the file path for blacklisting
                # Soulseek paths are stored as: username/path/to/file.ext or just the local path
                fp = track_info['file_path'].replace('\\', '/')
                database.add_to_blacklist(
                    track_title=track_info['title'],
                    track_artist=track_info['artist_name'],
                    blocked_filename=os.path.basename(fp),
                    blocked_username='',  # Local files don't have a username
                    reason='user_rejected'
                )
                blacklisted = True

            # Delete DB record
            cursor.execute("DELETE FROM tracks WHERE id = ?", (track_id,))
            conn.commit()
            if cursor.rowcount == 0:
                return jsonify({"success": False, "error": "Track not found"}), 404

            return jsonify({"success": True, "deleted_count": cursor.rowcount, "file_deleted": file_deleted, "blacklisted": blacklisted})
    except Exception as e:
        print(f"Error deleting track {track_id}: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500


