def _sanitize_filename(filename: str) -> str:
    """Sanitize filename for file system compatibility."""
    import re
    sanitized = re.sub(r'[<>:"/\\|?*]', '_', filename)
    sanitized = re.sub(r'\s+', ' ', sanitized).strip()
    # Windows forbids trailing dots/spaces on files and folders.
    # Artists like "Fred again.." would create mangled 8.3 short names.
    sanitized = sanitized.rstrip('. ') or '_'
    # Windows reserved device names (CON, PRN, AUX, NUL, COM1-9, LPT1-9)
    # can't be used as file or folder names even with extensions.
    if re.match(r'^(CON|PRN|AUX|NUL|COM[1-9]|LPT[1-9])(\.|$)', sanitized, re.IGNORECASE):
        sanitized = '_' + sanitized
    return sanitized[:200]

def _sanitize_context_values(context: dict) -> dict:
    """
    Sanitize all string values in context dict for path safety.

    Prevents characters like '/' in artist names (e.g., 'AC/DC')
    from being interpreted as path separators during template substitution.

    Args:
        context: Dictionary with metadata values

    Returns:
        New dictionary with sanitized string values
    """
    sanitized = {}
    for key, value in context.items():
        if isinstance(value, str) and value:
            sanitized[key] = _sanitize_filename(value)
        else:
            sanitized[key] = value
    return sanitized

def _clean_track_title(track_title: str, artist_name: str) -> str:
    """Clean up track title by removing artist prefix and other noise."""
    import re
    original = track_title.strip()
    cleaned = original
    cleaned = re.sub(r'^\d{1,2}[\.\s\-]+', '', cleaned)
    artist_pattern = re.escape(artist_name) + r'\s*-\s*'
    cleaned = re.sub(f'^{artist_pattern}', '', cleaned, flags=re.IGNORECASE)
    cleaned = re.sub(r'^[A-Za-z0-9\.]+\s*-\s*\d{1,2}\s*-\s*', '', cleaned)
    quality_patterns = [r'\s*[\[\(][0-9]+\s*kbps[\]\)]\s*', r'\s*[\[\(]flac[\]\)]\s*', r'\s*[\[\(]mp3[\]\)]\s*']
    for pattern in quality_patterns:
        cleaned = re.sub(pattern, '', cleaned, flags=re.IGNORECASE)
    cleaned = re.sub(r'^[-\s\.]+', '', cleaned)
    cleaned = re.sub(r'[-\s\.]+$', '', cleaned)
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    return cleaned if cleaned else original

def _extract_track_number_from_filename(filename: str, title: str = None) -> int:
    """Extract track number from filename, returns 1 if not found.
    Requires a separator after digits to avoid matching artist names like '50 Cent'."""
    import re
    import os
    basename = os.path.splitext(os.path.basename(filename))[0].strip()
    # Match: "01 - Song", "01. Song", "01-Song", "1.Song", "(01) Song", "[01] Song"
    match = re.match(r'^\(?(\d{1,3})\)?\s*[\-\.)\]]\s*', basename)
    if match:
        num = int(match.group(1))
        if 1 <= num <= 999:
            return num
    # Match: "1-03 Song" (disc-track format)
    match = re.match(r'^\d[\-\.](\d{1,2})\s*[\-\.]\s*', basename)
    if match:
        num = int(match.group(1))
        if 1 <= num <= 99:
            return num
    return 1

def _search_track_in_album_context(original_search: dict, artist: dict) -> dict:
    """
    Searches for a track within its album context to avoid matching promotional singles.
    This is a direct port from downloads.py for web server use.
    """
    try:
        album_name = original_search.get('album')
        track_title = original_search.get('title')
        if not all([album_name, track_title, artist]):
            return None

        clean_album = _clean_track_title(album_name, artist['name']) # Use track cleaner for album too
        clean_track = _clean_track_title(track_title, artist['name'])

        album_query = f"album:\"{clean_album}\" artist:\"{artist['name']}\""
        albums = spotify_client.search_albums(album_query, limit=1)

        if not albums:
            return None

        spotify_album = albums[0]
        album_tracks_data = spotify_client.get_album_tracks(spotify_album.id)
        if not album_tracks_data or 'items' not in album_tracks_data:
            return None

        for track_data in album_tracks_data['items']:
            similarity = matching_engine.similarity_score(
                matching_engine.normalize_string(clean_track),
                matching_engine.normalize_string(track_data['name'])
            )
            if similarity > 0.7:
                print(f"Found track in album context: '{track_data['name']}'")
                return {
                    'is_album': True,
                    'album_name': spotify_album.name,
                    'track_number': track_data['track_number'],
                    'clean_track_name': track_data['name'],
                    'album_image_url': spotify_album.image_url
                }
        return None
    except Exception as e:
        print(f"Error in _search_track_in_album_context: {e}")
        return None




def _detect_album_info_web(context: dict, artist: dict) -> dict:
    """
    Enhanced album detection with GUI parity - multi-priority logic.
    (Updated to match GUI downloads.py logic exactly)
    """
    try:
        # Log available data for debugging (GUI PARITY)
        original_search = context.get("original_search_result", {})
        print(f"\n[Album Detection] Starting for track: '{original_search.get('title', 'Unknown')}'")
        print(f"[Data Available]:")
        print(f"   - Clean Spotify title: '{original_search.get('spotify_clean_title', 'None')}'")
        print(f"   - Clean Spotify album: '{original_search.get('spotify_clean_album', 'None')}'")
        print(f"   - Filename album: '{original_search.get('album', 'None')}'")
        print(f"   - Artist: '{artist.get('name', 'Unknown')}'")
        print(f"   - Context has clean data: {context.get('has_clean_spotify_data', False)}")
        print(f"   - Is album download: {context.get('is_album_download', False)}")
        spotify_album_context = context.get("spotify_album")
        is_album_download = context.get("is_album_download", False)
        artist_name = artist['name']
        
        print(f"Album detection for '{original_search.get('title', 'Unknown')}' by '{artist_name}':")
        print(f"    Has album attr: {bool(original_search.get('album'))}")
        if original_search.get('album'):
            print(f"    Album value: '{original_search.get('album')}'")

        # --- THIS IS THE CRITICAL FIX ---
        # If this is part of a matched album download, we TRUST the context data completely.
        # This is the exact logic from downloads.py.
        if is_album_download and spotify_album_context:
            print("Matched Album context found. Prioritizing pre-matched Spotify data.")
            
            # We exclusively use the track number and title that were matched
            # *before* the download started. We do not try to re-parse the filename.
            track_number = original_search.get('track_number', 1)
            clean_track_name = original_search.get('title', 'Unknown Track')

            print(f"   -> Using pre-matched Track #{track_number} and Title '{clean_track_name}'")

            return {
                'is_album': True,
                'album_name': spotify_album_context['name'],
                'track_number': track_number,
                'clean_track_name': clean_track_name,
                'album_image_url': spotify_album_context.get('image_url')
            }

        # PRIORITY 1: Try album-aware search using clean Spotify album name (GUI PARITY)
        # Prioritize clean Spotify album name over filename-parsed album
        clean_album_name = original_search.get('spotify_clean_album')
        fallback_album_name = original_search.get('album')
        
        album_name_to_use = None
        album_source = None
        
        if clean_album_name and clean_album_name.strip() and clean_album_name != "Unknown Album":
            album_name_to_use = clean_album_name
            album_source = "CLEAN_SPOTIFY"
        elif fallback_album_name and fallback_album_name.strip() and fallback_album_name != "Unknown Album":
            album_name_to_use = fallback_album_name
            album_source = "FILENAME_PARSED"
        
        if album_name_to_use:
            track_title = original_search.get('spotify_clean_title') or original_search.get('title', 'Unknown')
            print(f"ALBUM-AWARE SEARCH ({album_source}): Looking for '{track_title}' in album '{album_name_to_use}'")
            
            # Temporarily set the album for the search
            original_album = original_search.get('album')
            original_search['album'] = album_name_to_use
            
            try:
                album_result = _search_track_in_album_context_web(context, artist)
                if album_result:
                    print(f"PRIORITY 1 SUCCESS: Found track using {album_source} album name - FORCING album classification")
                    return album_result
                else:
                    print(f"PRIORITY 1 FAILED: Track not found using {album_source} album name")
            finally:
                # Restore original album value
                if original_album is not None:
                    original_search['album'] = original_album
                else:
                    original_search.pop('album', None)

        # PRIORITY 2: Fallback to individual track search for clean metadata
        print(f"Searching Spotify for individual track info (PRIORITY 2)...")
        
        # Clean the track title before searching - remove artist prefix  
        # Prioritize clean Spotify title over filename-parsed title
        track_title_to_use = original_search.get('spotify_clean_title') or original_search.get('title', '')
        clean_title = _clean_track_title_web(track_title_to_use, artist_name)
        print(f"Cleaned title: '{track_title_to_use}' -> '{clean_title}'")
        
        # Search for the track by artist and cleaned title
        query = f"artist:{artist_name} track:{clean_title}"
        tracks = spotify_client.search_tracks(query, limit=5)
        
        # Find the best matching track (prefer album versions over singles)
        best_match = None
        best_confidence = 0

        if tracks:
            from core.matching_engine import MusicMatchingEngine
            matching_engine = MusicMatchingEngine()
            for track in tracks:
                # Calculate confidence based on artist and title similarity
                artist_confidence = matching_engine.similarity_score(
                    matching_engine.normalize_string(artist_name),
                    matching_engine.normalize_string(track.artists[0] if track.artists else '')
                )
                title_confidence = matching_engine.similarity_score(
                    matching_engine.normalize_string(clean_title),
                    matching_engine.normalize_string(track.name)
                )

                combined_confidence = (artist_confidence * 0.6 + title_confidence * 0.4)

                # Small bonus for album tracks so they win ties over singles/EPs
                album_type = getattr(track, 'album_type', None) or ''
                if album_type == 'album':
                    combined_confidence += 0.02
                elif album_type == 'ep':
                    combined_confidence += 0.01

                if combined_confidence > best_confidence and combined_confidence > 0.75:  # Higher threshold to avoid bad matches
                    best_match = track
                    best_confidence = combined_confidence

        # If we found a good Spotify match, use it for clean metadata
        if best_match and best_confidence > 0.75:
            print(f"Found matching Spotify track: '{best_match.name}' - Album: '{best_match.album}' (confidence: {best_confidence:.2f})")
            
            # Get detailed track information using Spotify's track API
            detailed_track = None
            if hasattr(best_match, 'id') and best_match.id:
                print(f"Getting detailed track info from Spotify API for track ID: {best_match.id}")
                detailed_track = spotify_client.get_track_details(best_match.id)
            
            # Use detailed track data if available
            if detailed_track:
                print(f"Got detailed track data from Spotify API")
                album_name = _clean_album_title_web(detailed_track['album']['name'], artist_name)
                clean_track_name = detailed_track['name']  # Use Spotify's clean track name
                album_type = detailed_track['album'].get('album_type', 'album')
                total_tracks = detailed_track['album'].get('total_tracks', 1)
                spotify_track_number = detailed_track.get('track_number', 1)
                
                print(f"Spotify album info: '{album_name}' (type: {album_type}, total_tracks: {total_tracks}, track#: {spotify_track_number})")
                print(f"Clean track name from Spotify: '{clean_track_name}'")
                
                # Enhanced album detection using detailed API data (GUI PARITY)
                is_album = (
                    # Album type is 'album' (not 'single')
                    album_type == 'album' and
                    # Album has multiple tracks
                    total_tracks > 1 and
                    # Album name different from track name
                    matching_engine.normalize_string(album_name) != matching_engine.normalize_string(clean_track_name) and
                    # Album name is not just the artist name
                    matching_engine.normalize_string(album_name) != matching_engine.normalize_string(artist_name)
                )
                
                album_image_url = None
                if detailed_track['album'].get('images'):
                    album_image_url = detailed_track['album']['images'][0].get('url')
                
                print(f"Album classification: {is_album} (type={album_type}, tracks={total_tracks})")
                
                return {
                    'is_album': is_album,
                    'album_name': album_name,
                    'track_number': spotify_track_number,
                    'clean_track_name': clean_track_name,
                    'album_image_url': album_image_url,
                    'confidence': best_confidence,
                    'source': 'spotify_api_detailed'
                }

        # Fallback: Use original data with basic cleaning
        print("No good Spotify match found, using original data")
        fallback_title = _clean_track_title_web(original_search.get('title', 'Unknown Track'), artist_name)

        # Preserve track_number from context if available (playlist sync tracks have it)
        _ctx_track_number = (original_search.get('track_number')
                             or context.get('track_info', {}).get('track_number')
                             or 1)

        return {
            'is_album': False,
            'clean_track_name': fallback_title,
            'album_name': fallback_title,
            'track_number': _ctx_track_number,
            'confidence': 0.0,
            'source': 'fallback_original'
        }

    except Exception as e:
        print(f"Error in _detect_album_info_web: {e}")
        clean_title = _clean_track_title_web(context.get("original_search_result", {}).get('title', 'Unknown'), artist.get('name', ''))
        _err_tn = (context.get("original_search_result", {}).get('track_number')
                   or context.get('track_info', {}).get('track_number')
                   or 1)
        return {'is_album': False, 'clean_track_name': clean_title, 'album_name': clean_title, 'track_number': _err_tn}




def _cleanup_empty_directories(download_path, moved_file_path):
    """Cleans up empty directories after a file move, ignoring hidden files."""
    import os
    try:
        current_dir = os.path.dirname(moved_file_path)
        while current_dir != download_path and current_dir.startswith(download_path):
            is_empty = not any(not f.startswith('.') for f in os.listdir(current_dir))
            if is_empty:
                print(f"Removing empty directory: {current_dir}")
                os.rmdir(current_dir)
                current_dir = os.path.dirname(current_dir)
            else:
                break
    except Exception as e:
        print(f"Warning: An error occurred during directory cleanup: {e}")


def _sweep_empty_download_directories():
    """
    Walk the download directory bottom-up and remove ALL empty directories.
    Called periodically when no downloads or post-processing are active.
    Handles the edge case where per-file cleanup misses folders that become
    empty only after all sibling downloads in a batch have been processed.
    """
    import os
    try:
        download_path = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
        if not os.path.isdir(download_path):
            return 0

        removed = 0
        # os.walk bottom-up: deepest directories first so parents become empty after children removed
        for dirpath, _dirnames, _filenames in os.walk(download_path, topdown=False):
            # Never remove the root download directory itself
            if os.path.normpath(dirpath) == os.path.normpath(download_path):
                continue
            # Re-read actual contents — os.walk's lists are stale after child removal
            try:
                entries = os.listdir(dirpath)
            except OSError:
                continue
            visible = [e for e in entries if not e.startswith('.')]
            if not visible:
                try:
                    # Remove any leftover hidden files (e.g. .DS_Store) before rmdir
                    for hidden in entries:
                        try:
                            os.remove(os.path.join(dirpath, hidden))
                        except Exception:
                            pass
                    os.rmdir(dirpath)
                    removed += 1
                except OSError:
                    pass  # Directory not actually empty or locked — skip silently

        if removed > 0:
            print(f"[Folder Cleanup] Removed {removed} empty director{'y' if removed == 1 else 'ies'} from downloads folder")
        return removed
    except Exception as e:
        print(f"[Folder Cleanup] Error sweeping empty directories: {e}")
        return 0


# ===================================================================
# ALBUM GROUPING SYSTEM (Ported from GUI downloads.py)
# ===================================================================

def _get_base_album_name(album_name: str) -> str:
    """
    Extract the base album name without edition indicators.
    E.g., 'good kid, m.A.A.d city (Deluxe Edition)' -> 'good kid, m.A.A.d city'
         'Battle Hymns (MMXI Special Edition)' -> 'Battle Hymns'
    """
    import re

    # Remove common edition suffixes
    base_name = album_name

    # Remove edition indicators in parentheses or brackets
    # Allow any prefix before the keyword (e.g. "MMXI Special Edition", "20th Anniversary Edition")
    base_name = re.sub(r'\s*[\[\(][^)\]]*\b(deluxe|special|expanded|extended|bonus|remaster(?:ed)?|anniversary|collectors?|limited|silver|gold|platinum)\b[^)\]]*[\]\)]\s*$', '', base_name, flags=re.IGNORECASE)

    # Generic: any parenthesized/bracketed text ending with "edition"
    base_name = re.sub(r'\s*[\[\(][^)\]]*\bedition\b[^)\]]*[\]\)]\s*$', '', base_name, flags=re.IGNORECASE)

    # Remove standalone edition words at the end
    base_name = re.sub(r'\s+(deluxe|special|expanded|extended|bonus|remastered|anniversary|collectors?|limited|silver|gold|platinum)\s*(edition)?\s*$', '', base_name, flags=re.IGNORECASE)

    return base_name.strip()

def _detect_deluxe_edition(album_name: str) -> bool:
    """
    Detect if an album name indicates a deluxe/special edition.
    Returns True if it's a deluxe variant, False for standard.
    """
    if not album_name:
        return False
    
    album_lower = album_name.lower()
    
    # Check for deluxe indicators
    deluxe_indicators = [
        'deluxe',
        'deluxe edition',
        'special edition',
        'expanded edition',
        'extended edition',
        'bonus',
        'remastered',
        'anniversary',
        'collectors edition',
        'limited edition',
        'silver edition',
        'gold edition',
        'platinum edition',
    ]
    
    for indicator in deluxe_indicators:
        if indicator in album_lower:
            print(f"Detected deluxe edition: '{album_name}' contains '{indicator}'")
            return True
    
    return False

def _normalize_base_album_name(base_album: str, artist_name: str) -> str:
    """
    Normalize the base album name to handle case variations and known corrections.
    """
    import re
    
    # Apply known album corrections for consistent naming
    normalized_lower = base_album.lower().strip()
    
    # Handle common album title variations
    known_corrections = {
        # Add specific album name corrections here as needed
        # Example: "good kid maad city": "good kid, m.A.A.d city"
    }
    
    # Check for exact matches in our corrections
    for variant, correction in known_corrections.items():
        if normalized_lower == variant.lower():
            print(f"Album correction applied: '{base_album}' -> '{correction}'")
            return correction
    
    # Handle punctuation variations 
    normalized = base_album
    
    # Normalize common punctuation patterns
    normalized = re.sub(r'\s*&\s*', ' & ', normalized)  # Standardize & spacing
    normalized = re.sub(r'\s+', ' ', normalized)  # Clean multiple spaces
    normalized = normalized.strip()
    
    print(f"Album variant normalization: '{base_album}' -> '{normalized}'")
    return normalized

def _resolve_album_group(spotify_artist: dict, album_info: dict, original_album: str = None) -> str:
    """
    Smart album grouping: Start with standard, upgrade to deluxe if ANY track is deluxe.
    This ensures all tracks from the same album get the same folder name.
    (Adapted from GUI downloads.py)
    """
    try:
        with album_cache_lock:
            artist_name = spotify_artist["name"]
            detected_album = album_info.get('album_name', '')
            
            # Extract base album name (without edition indicators)
            if detected_album:
                base_album = _get_base_album_name(detected_album)
            elif original_album:
                # Clean the original Soulseek album name 
                cleaned_original = _clean_album_title_web(original_album, artist_name)
                base_album = _get_base_album_name(cleaned_original)
            else:
                base_album = _get_base_album_name(detected_album)
            
            # Normalize the base name (handle case variations, etc.)
            base_album = _normalize_base_album_name(base_album, artist_name)
            
            # Create a key for this album group (artist + base album)
            album_key = f"{artist_name}::{base_album}"
            
            # Check if we already have a cached result for this album
            if album_key in album_name_cache:
                cached_name = album_name_cache[album_key]
                print(f"Using cached album name for '{album_key}': '{cached_name}'")
                return cached_name
            
            print(f"Album grouping - Key: '{album_key}', Detected: '{detected_album}'")
            
            # Check if this track indicates a deluxe edition
            is_deluxe_track = False
            if detected_album:
                is_deluxe_track = _detect_deluxe_edition(detected_album)
            elif original_album:
                is_deluxe_track = _detect_deluxe_edition(original_album)
            
            # Get current edition level for this album group (default to standard)
            current_edition = album_editions.get(album_key, "standard")
            
            # SMART ALGORITHM: Upgrade to deluxe if this track is deluxe
            if is_deluxe_track and current_edition == "standard":
                print(f"UPGRADE: Album '{base_album}' upgraded from standard to deluxe!")
                album_editions[album_key] = "deluxe"
                current_edition = "deluxe"
            
            # Build final album name based on edition level
            if current_edition == "deluxe":
                final_album_name = f"{base_album} (Deluxe Edition)"
            else:
                final_album_name = base_album
            
            # Store the resolution in both caches
            album_groups[album_key] = final_album_name
            album_name_cache[album_key] = final_album_name
            album_artists[album_key] = artist_name
            
            print(f"Album resolution: '{detected_album}' -> '{final_album_name}' (edition: {current_edition})")
            
            return final_album_name
        
    except Exception as e:
        print(f"Error resolving album group: {e}")
        return album_info.get('album_name', 'Unknown Album')

def _clean_album_title_web(album_title: str, artist_name: str) -> str:
    """Clean up album title by removing common prefixes, suffixes, and artist redundancy"""
    import re
    
    # Start with the original title
    original = album_title.strip()
    cleaned = original
    print(f"Album Title Cleaning: '{original}' (artist: '{artist_name}')")
    
    # Remove "Album - " prefix
    cleaned = re.sub(r'^Album\s*-\s*', '', cleaned, flags=re.IGNORECASE)
    
    # Remove artist name prefix if it appears at the beginning
    # This handles cases like "Kendrick Lamar - good kid, m.A.A.d city"
    artist_pattern = re.escape(artist_name) + r'\s*-\s*'
    cleaned = re.sub(f'^{artist_pattern}', '', cleaned, flags=re.IGNORECASE)
    
    # Remove common Soulseek suffixes in square brackets and parentheses
    # Examples: [Deluxe Edition] [2012] [320 Kbps] [Album+iTunes+Bonus Tracks] [F10]
    #           (Deluxe Edition) (2012) (320 Kbps) etc.
    # Remove year patterns like [2012], (2020), etc.
    cleaned = re.sub(r'\s*[\[\(]\d{4}[\]\)]\s*', ' ', cleaned)
    
    # Remove quality/format indicators
    quality_patterns = [
        r'\s*[\[\(].*?320.*?kbps.*?[\]\)]\s*',
        r'\s*[\[\(].*?256.*?kbps.*?[\]\)]\s*',
        r'\s*[\[\(].*?flac.*?[\]\)]\s*',
        r'\s*[\[\(].*?mp3.*?[\]\)]\s*',
        r'\s*[\[\(].*?itunes.*?[\]\)]\s*',
        r'\s*[\[\(].*?web.*?[\]\)]\s*',
        r'\s*[\[\(].*?cd.*?[\]\)]\s*'
    ]
    
    for pattern in quality_patterns:
        cleaned = re.sub(pattern, ' ', cleaned, flags=re.IGNORECASE)
    
    # Remove common edition indicators (but preserve them for deluxe detection above)
    # This happens AFTER deluxe detection to avoid interfering with that logic
    
    # Clean up spacing
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    
    # Remove leading/trailing punctuation
    cleaned = re.sub(r'^[-\s]+|[-\s]+$', '', cleaned)
    
    print(f"Album Title Result: '{original}' -> '{cleaned}'")
    return cleaned if cleaned else original

def _search_track_in_album_context_web(context: dict, spotify_artist: dict) -> dict:
    """
    Search for a track within its album context to avoid promotional single confusion.
    (Ported from GUI downloads.py)
    """
    try:
        from core.matching_engine import MusicMatchingEngine
        matching_engine = MusicMatchingEngine()
        
        # Get album and track info from context
        original_search = context.get("original_search_result", {})
        album_name = original_search.get("album")
        track_title = original_search.get("title")
        artist_name = spotify_artist["name"]
        
        if not album_name or not track_title:
            print(f"Album-aware search failed: Missing album ({album_name}) or track ({track_title})")
            return None
        
        print(f"Album-aware search: '{track_title}' in album '{album_name}' by '{artist_name}'")
        
        # Clean the album name for better search results
        clean_album = _clean_album_title_web(album_name, artist_name)
        clean_track = _clean_track_title_web(track_title, artist_name)
        
        # Search for the specific album first
        album_query = f"album:{clean_album} artist:{artist_name}"
        print(f"Searching albums: {album_query}")
        albums = spotify_client.search_albums(album_query, limit=5)
        
        if not albums:
            print(f"No albums found for query: {album_query}")
            return None
        
        # Check each album to see if our track is in it
        for album in albums:
            print(f"Checking album: '{album.name}' ({album.total_tracks} tracks)")
            
            # Get tracks from this album
            album_tracks_data = spotify_client.get_album_tracks(album.id)
            if not album_tracks_data or 'items' not in album_tracks_data:
                print(f"Could not get tracks for album: {album.name}")
                continue
            
            # Check if our track is in this album
            for track_data in album_tracks_data['items']:
                track_name = track_data['name']
                track_number = track_data['track_number']
                
                # Calculate similarity between our track and this album track
                similarity = matching_engine.similarity_score(
                    matching_engine.normalize_string(clean_track),
                    matching_engine.normalize_string(track_name)
                )
                
                # Use higher threshold for remix matching to ensure precision (GUI PARITY)
                is_remix = any(word in clean_track.lower() for word in ['remix', 'mix', 'edit', 'version'])
                threshold = 0.9 if is_remix else 0.65  # Lower threshold to favor album matches over singles
                
                if similarity > threshold:
                    print(f"FOUND: '{track_name}' (track #{track_number}) matches '{clean_track}' (similarity: {similarity:.2f})")

                    # Classify as album vs single using same logic as _detect_album_info_web
                    ctx_album_type = getattr(album, 'album_type', 'album') or 'album'
                    ctx_total_tracks = getattr(album, 'total_tracks', 1) or 1
                    ctx_is_album = (
                        ctx_album_type == 'album' and
                        ctx_total_tracks > 1 and
                        matching_engine.normalize_string(album.name) != matching_engine.normalize_string(clean_track) and
                        matching_engine.normalize_string(album.name) != matching_engine.normalize_string(artist_name)
                    )
                    print(f"Album context classification: is_album={ctx_is_album} (type={ctx_album_type}, tracks={ctx_total_tracks})")

                    return {
                        'is_album': ctx_is_album,
                        'album_name': album.name,
                        'track_number': track_number,
                        'clean_track_name': clean_track,  # Use the ORIGINAL download title, not the database match
                        'album_image_url': album.image_url,
                        'confidence': similarity,
                        'source': 'album_context_search'
                    }
            
            print(f"Track '{clean_track}' not found in album '{album.name}'")
        
        print(f"Track '{clean_track}' not found in any matching albums")
        return None
        
    except Exception as e:
        print(f"Error in album-aware search: {e}")
        return None

def _clean_track_title_web(track_title: str, artist_name: str) -> str:
    """Clean up track title by removing artist prefix and common patterns"""
    import re
    
    # Start with the original title
    original = track_title.strip()
    cleaned = original
    print(f"Track Title Cleaning: '{original}' (artist: '{artist_name}')")
    
    # Remove artist name prefix if it appears at the beginning
    # This handles cases like "Kendrick Lamar - HUMBLE."
    artist_pattern = re.escape(artist_name) + r'\s*-\s*'
    cleaned = re.sub(f'^{artist_pattern}', '', cleaned, flags=re.IGNORECASE)
    
    # Remove common prefixes
    cleaned = re.sub(r'^Track\s*\d*\s*-\s*', '', cleaned, flags=re.IGNORECASE)
    cleaned = re.sub(r'^\d+\.\s*', '', cleaned)  # Remove track numbers like "01. "
    
    # Remove quality/format indicators
    quality_patterns = [
        r'\s*[\[\(].*?320.*?kbps.*?[\]\)]\s*',
        r'\s*[\[\(].*?256.*?kbps.*?[\]\)]\s*',
        r'\s*[\[\(].*?flac.*?[\]\)]\s*',
        r'\s*[\[\(].*?mp3.*?[\]\)]\s*',
        r'\s*[\[\(].*?explicit.*?[\]\)]\s*'
    ]
    
    for pattern in quality_patterns:
        cleaned = re.sub(pattern, ' ', cleaned, flags=re.IGNORECASE)
    
    # Clean up spacing
    cleaned = re.sub(r'\s+', ' ', cleaned).strip()
    
    # Remove leading/trailing punctuation
    cleaned = re.sub(r'^[-\s]+|[-\s]+$', '', cleaned)
    
    print(f"Track Title Result: '{original}' -> '{cleaned}'")
    return cleaned if cleaned else original


# ===================================================================
# YOUTUBE TRACK CLEANING FUNCTIONS (Ported from GUI sync.py)
# ===================================================================

def clean_youtube_track_title(title, artist_name=None):
    """
    Aggressively clean YouTube track titles by removing video noise and extracting clean track names
    
    Examples:
    'No Way Jose (Official Music Video)' → 'No Way Jose'
    'bbno$ - mary poppins (official music video)' → 'mary poppins'
    'Beyond (From "Moana 2") (Official Video) ft. Rachel House' → 'Beyond'
    'Temporary (feat. Skylar Grey) [Official Music Video]' → 'Temporary'
    'ALL MY LOVE (Directors\' Cut)' → 'ALL MY LOVE'
    'Espresso Macchiato | Estonia 🇪🇪 | Official Music Video | #Eurovision2025' → 'Espresso Macchiato'
    """
    import re
    
    if not title:
        return title
    
    original_title = title
    
    # FIRST: Try to extract track name from "Artist - Track" or "Track - Artist" format
    artist_removed = False
    if artist_name and '-' in title:
        # Check if artist is at the start: "Artist - Track" or "Artist & Others - Track"
        # Handle collaborations: "Artist1 & Artist2 - Track" or "Artist, Artist2 - Track"
        artist_pattern = r'^' + re.escape(artist_name.strip()) + r'(?:\s*[&,x]\s*[^-]+)?\s*[-–—]\s*'
        cleaned_title = re.sub(artist_pattern, '', title, flags=re.IGNORECASE).strip()

        if cleaned_title != title:
            print(f"Removed artist from start: '{title}' -> '{cleaned_title}' (artist: '{artist_name}')")
            title = cleaned_title
            artist_removed = True
        else:
            # Artist not at start, check if format is "Track - Artist" by looking for artist at end
            # Only remove trailing artist if it comes after a dash
            artist_end_pattern = r'\s*[-–—]\s*' + re.escape(artist_name.strip()) + r'(?:\s*[&,x]\s*[^-]+)?\s*$'
            cleaned_title = re.sub(artist_end_pattern, '', title, flags=re.IGNORECASE).strip()

            if cleaned_title != title:
                print(f"Removed artist from end: '{title}' -> '{cleaned_title}' (artist: '{artist_name}')")
                title = cleaned_title
                artist_removed = True

    # Remove content in brackets/braces BEFORE removing dashes
    title = re.sub(r'【[^】]*】', '', title)  # Japanese brackets
    title = re.sub(r'\s*\([^)]*\)', '', title)   # Parentheses - removes everything after first (
    title = re.sub(r'\s*\(.*$', '', title)      # Remove everything after lone ( (unmatched parentheses)
    title = re.sub(r'\[[^\]]*\]', '', title)  # Square brackets
    title = re.sub(r'\{[^}]*\}', '', title)   # Curly braces
    title = re.sub(r'<[^>]*>', '', title)     # Angle brackets

    # ONLY remove trailing dashes with garbage if artist was already removed
    # This prevents "Artist1, Artist2 - Song" from becoming "Artist1, Artist2"
    if artist_removed:
        # Safe to remove any remaining trailing dash content (likely album/extra info)
        title = re.sub(r'\s*-\s*.*$', '', title)
    
    # Remove everything after pipes (|) - often used for additional context
    title = re.split(r'\s*\|\s*', title)[0].strip()
    
    # Remove common video/platform noise
    noise_patterns = [
        r'\bapple\s+music\b',
        r'\bfull\s+video\b', 
        r'\bmusic\s+video\b',
        r'\bofficial\s+video\b',
        r'\bofficial\s+music\s+video\b',
        r'\bofficial\b',
        r'\bcensored\s+version\b',
        r'\buncensored\s+version\b',
        r'\bexplicit\s+version\b',
        r'\blive\s+version\b',
        r'\bversion\b',
        r'\btopic\b',
        r'\baudio\b',
        r'\blyrics?\b',
        r'\blyric\s+video\b',
        r'\bwith\s+lyrics?\b',
        r'\bvisuali[sz]er\b',
        r'\bmv\b',
        r'\bdirectors?\s+cut\b',
        r'\bremaster(ed)?\b',
        r'\bremix\b'
    ]
    
    for pattern in noise_patterns:
        title = re.sub(pattern, '', title, flags=re.IGNORECASE)
    
    # Only remove artist name if it's standalone (not part of "Artist1 & Artist2")
    # Skip this if the title contains collaboration indicators near the artist name
    if artist_name:
        # Check if artist appears with collaboration indicators (& or ,)
        collab_pattern = rf'\b{re.escape(artist_name)}\s*[&,]\s*\w+|[\w\s]+[&,]\s*{re.escape(artist_name)}\b'
        has_collab = re.search(collab_pattern, title, flags=re.IGNORECASE)

        if not has_collab:
            # Safe to remove artist - it's standalone
            title = re.sub(rf'\b{re.escape(artist_name)}\b', '', title, flags=re.IGNORECASE)
            title = re.sub(rf'\b{re.escape(artist_name)}\s*[-–—:]\s*', '', title, flags=re.IGNORECASE)
            title = re.sub(rf'^{re.escape(artist_name)}\s*[-–—:]\s*', '', title, flags=re.IGNORECASE)
        else:
            print(f"Skipping artist removal - collaboration detected: '{title}'")
    
    # Remove "prod. Producer" patterns
    title = re.sub(r'\s+prod\.?\s+\S+', '', title, flags=re.IGNORECASE)

    # Remove all quotes and other punctuation
    title = re.sub(r'["\'''""„‚‛‹›«»]', '', title)

    # Remove featured artist patterns (after removing parentheses)
    feat_patterns = [
        r'\s+feat\.?\s+.+$',     # " feat Artist" at end
        r'\s+ft\.?\s+.+$',       # " ft Artist" at end  
        r'\s+featuring\s+.+$',   # " featuring Artist" at end
        r'\s+with\s+.+$',        # " with Artist" at end
    ]
    
    for pattern in feat_patterns:
        title = re.sub(pattern, '', title, flags=re.IGNORECASE).strip()
    
    # Clean up whitespace and punctuation
    title = re.sub(r'\s+', ' ', title).strip()
    title = re.sub(r'^[-–—:,.\s]+|[-–—:,.\s]+$', '', title).strip()
    
    # If we cleaned too much, return original
    if not title.strip() or len(title.strip()) < 2:
        title = original_title
    
    if title != original_title:
        print(f"YouTube title cleaned: '{original_title}' → '{title}'")
    
    return title

def clean_youtube_artist(artist_string):
    """
    Clean YouTube artist strings to get primary artist name
    
    Examples:
    'Yung Gravy, bbno$ (BABY GRAVY)' → 'Yung Gravy'
    'Y2K, bbno$' → 'Y2K'
    'LITTLE BIG' → 'LITTLE BIG'
    'Artist "Nickname" Name' → 'Artist Nickname Name'
    'ArtistVEVO' → 'Artist'
    """
    import re
    
    if not artist_string:
        return artist_string
    
    original_artist = artist_string
    
    # Remove all quotes - they're usually not part of artist names
    artist_string = artist_string.replace('"', '').replace("'", '').replace(''', '').replace(''', '').replace('"', '').replace('"', '')
    
    # Remove anything in parentheses (often group/label names)
    artist_string = re.sub(r'\s*\([^)]*\)', '', artist_string).strip()
    
    # Remove anything in brackets (often additional info)
    artist_string = re.sub(r'\s*\[[^\]]*\]', '', artist_string).strip()
    
    # Remove common YouTube channel suffixes
    channel_suffixes = [
        r'\s*-\s*Topic\s*$',       # YouTube auto-generated "Topic" channels (e.g. "Koven - Topic")
        r'\s*VEVO\s*$',
        r'\s*Music\s*$',
        r'\s*Official\s*$',
        r'\s*Records\s*$',
        r'\s*Entertainment\s*$',
        r'\s*TV\s*$',
        r'\s*Channel\s*$'
    ]
    
    for suffix in channel_suffixes:
        artist_string = re.sub(suffix, '', artist_string, flags=re.IGNORECASE).strip()
    
    # Split on common separators and take the first artist
    separators = [',', '&', ' and ', ' x ', ' X ', ' feat.', ' ft.', ' featuring', ' with', ' vs ', ' vs.']
    
    for sep in separators:
        if sep in artist_string:
            parts = artist_string.split(sep)
            artist_string = parts[0].strip()
            break
    
    # Clean up extra whitespace and punctuation
    artist_string = re.sub(r'\s+', ' ', artist_string).strip()
    artist_string = re.sub(r'^\-\s*|\s*\-$', '', artist_string).strip()  # Remove leading/trailing dashes
    artist_string = re.sub(r'^,\s*|\s*,$', '', artist_string).strip()    # Remove leading/trailing commas
    
    # If we cleaned too much, return original
    if not artist_string.strip():
        artist_string = original_artist
    
    if artist_string != original_artist:
        print(f"YouTube artist cleaned: '{original_artist}' → '{artist_string}'")
    
    return artist_string

def parse_youtube_playlist(url):
    """
    Parse a YouTube Music playlist URL and extract track information using yt-dlp
    Uses flat playlist extraction to avoid rate limits and get all tracks
    Returns a list of track dictionaries compatible with our Track structure
    """
    try:
        # Configure yt-dlp options for flat playlist extraction (avoids rate limits)
        ydl_opts = {
            'quiet': True,
            'no_warnings': True,
            'extract_flat': 'in_playlist',  # Only extract basic info, no individual video metadata
            'skip_download': True,  # Don't download, just extract IDs and basic info
            'lazy_playlist': False,  # Force full playlist resolution (prevents ~100 entry cap)
        }
        
        tracks = []
        
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            # Extract playlist info
            playlist_info = ydl.extract_info(url, download=False)
            
            if not playlist_info:
                print("Could not extract playlist information")
                return None
            
            playlist_name = playlist_info.get('title', 'Unknown Playlist')
            playlist_id = playlist_info.get('id', 'unknown_id')
            entries = list(playlist_info.get('entries', []) or [])
            
            print(f"Found YouTube playlist: '{playlist_name}' with {len(entries)} entries")
            
            for entry in entries:
                if not entry:
                    continue
                
                # Extract basic information from flat extraction
                raw_title = entry.get('title', 'Unknown Track')
                raw_uploader = entry.get('uploader', 'Unknown Artist')
                duration = entry.get('duration', 0)
                video_id = entry.get('id', '')
                
                # Clean the track title and artist using our cleaning functions
                cleaned_artist = clean_youtube_artist(raw_uploader)
                cleaned_title = clean_youtube_track_title(raw_title, cleaned_artist)
                
                # Create track object matching GUI structure
                track_data = {
                    'id': video_id,
                    'name': cleaned_title,
                    'artists': [cleaned_artist],
                    'duration_ms': duration * 1000 if duration else 0,
                    'raw_title': raw_title,  # Keep original for reference
                    'raw_artist': raw_uploader,  # Keep original for reference
                    'url': f"https://www.youtube.com/watch?v={video_id}"
                }
                
                tracks.append(track_data)
            
            # Create playlist object matching GUI structure
            playlist_data = {
                'id': playlist_id,
                'name': playlist_name,
                'tracks': tracks,
                'track_count': len(tracks),
                'url': url,
                'source': 'youtube'
            }
            
            print(f"Successfully parsed YouTube playlist: {len(tracks)} tracks extracted")
            return playlist_data
            
    except Exception as e:
        print(f"Error parsing YouTube playlist: {e}")
        return None


# ===================================================================
# FILE ORGANIZATION TEMPLATE ENGINE
# ===================================================================

def _compute_m3u_folder(transfer_dir, context_type, playlist_name, artist_name='', album_name='', year=''):
    """
    Compute the target folder for an M3U file using the template system.

    For playlists: uses playlist_path template, extracts folder portion.
    For albums: uses album_path template, extracts folder portion.

    Returns: absolute folder path
    """
    if context_type == 'album' and artist_name and album_name:
        template_context = {
            'artist': artist_name,
            'albumartist': artist_name,
            'album': album_name,
            'title': 'placeholder',
            'track_number': 1,
            'disc_number': 1,
            'year': year,
            'quality': ''
        }
        folder_path, _ = _get_file_path_from_template(template_context, 'album_path')
        if folder_path:
            return os.path.join(transfer_dir, folder_path)
        # Fallback
        artist_sanitized = _sanitize_filename(artist_name)
        album_sanitized = _sanitize_filename(album_name)
        return os.path.join(transfer_dir, artist_sanitized, f"{artist_sanitized} - {album_sanitized}")
    else:
        template_context = {
            'artist': 'placeholder',
            'albumartist': 'placeholder',
            'album': 'placeholder',
            'title': 'placeholder',
            'playlist_name': playlist_name,
            'track_number': 1,
            'disc_number': 1,
            'year': '',
            'quality': ''
        }
        folder_path, _ = _get_file_path_from_template(template_context, 'playlist_path')
        if folder_path:
            return os.path.join(transfer_dir, folder_path)
        # Fallback
        playlist_sanitized = _sanitize_filename(playlist_name)
        return os.path.join(transfer_dir, playlist_sanitized)


def _build_final_path_for_track(context, spotify_artist, album_info, file_ext):
    """
    SHARED PATH BUILDER - Used by both post-processing AND verification.
    This ensures they always produce the same path.

    Returns: (final_path, folder_created_successfully)
    """
    transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
    track_info = context.get("track_info", {})
    original_search = context.get("original_search_result", {})
    playlist_folder_mode = track_info.get("_playlist_folder_mode", False)

    # ENHANCE BYPASS: Place file in same location as original (different extension OK)
    _source_info = track_info.get('source_info') or {}
    if isinstance(_source_info, str):
        try:
            _source_info = json.loads(_source_info)
        except (json.JSONDecodeError, TypeError):
            _source_info = {}
    if _source_info.get('enhance') and _source_info.get('original_file_path'):
        original_path = _source_info['original_file_path']
        original_dir = os.path.dirname(original_path)
        original_stem = os.path.splitext(os.path.basename(original_path))[0]
        final_path = os.path.join(original_dir, original_stem + file_ext)
        os.makedirs(original_dir, exist_ok=True)
        print(f"[Enhance] Using original file location: {final_path}")
        return final_path, True

    # Extract year and album_type from spotify_album for template use (safe for all modes)
    year = ''  # Empty string instead of 'Unknown' to avoid "Unknown albumName"
    spotify_album = context.get("spotify_album", {})
    if spotify_album and spotify_album.get('release_date'):
        release_date = spotify_album['release_date']
        if release_date and len(release_date) >= 4:
            year = release_date[:4]

    # Album type for $albumtype template variable (Album, EP, Single, Compilation)
    raw_album_type = ''
    if spotify_album:
        raw_album_type = spotify_album.get('album_type', '') or ''
    total_tracks = (spotify_album.get('total_tracks', 0) or 0) if spotify_album else 0

    if raw_album_type.lower() == 'compilation':
        album_type_display = 'Compilation'
    elif raw_album_type.lower() == 'album':
        album_type_display = 'Album'
    elif raw_album_type.lower() in ('single', 'ep'):
        # Spotify labels both singles and EPs as 'single' — use track count to distinguish
        if total_tracks <= 3:
            album_type_display = 'Single'
        elif total_tracks <= 6:
            album_type_display = 'EP'
        else:
            album_type_display = 'Album'
    elif not raw_album_type:
        # No album_type from API (e.g. iTunes source) — infer from track count
        if total_tracks <= 0:
            album_type_display = 'Album'  # Unknown, safe default
        elif total_tracks <= 3:
            album_type_display = 'Single'
        elif total_tracks <= 6:
            album_type_display = 'EP'
        else:
            album_type_display = 'Album'
    else:
        album_type_display = raw_album_type.capitalize() or 'Album'

    # Determine which template type to use
    if playlist_folder_mode:
        # PLAYLIST MODE
        playlist_name = track_info.get("_playlist_name", "Unknown Playlist")
        track_name = original_search.get('spotify_clean_title') or original_search.get('title', 'Unknown Track')

        _artists = original_search.get('artists') or track_info.get('artists') or []

        template_context = {
            'artist': spotify_artist["name"] if isinstance(spotify_artist, dict) else spotify_artist.name,
            'albumartist': spotify_artist["name"] if isinstance(spotify_artist, dict) else spotify_artist.name,
            'album': track_name,
            'title': track_name,
            'playlist_name': playlist_name,
            'track_number': 1,
            'disc_number': 1,
            'year': year,
            'quality': context.get('_audio_quality', ''),
            'albumtype': album_type_display,
            '_artists_list': _artists,
            '_itunes_artist_id': str(spotify_artist.get('id', '')) if isinstance(spotify_artist, dict) and str(spotify_artist.get('id', '')).isdigit() and (original_search.get('_source') == 'itunes' or track_info.get('_source') == 'itunes') else None,
        }

        folder_path, filename_base = _get_file_path_from_template(template_context, 'playlist_path')
        if folder_path and filename_base:
            final_path = os.path.join(transfer_dir, folder_path, filename_base + file_ext)
            os.makedirs(os.path.join(transfer_dir, folder_path), exist_ok=True)
            return final_path, True
        else:
            # Fallback
            playlist_name_sanitized = _sanitize_filename(playlist_name)
            playlist_dir = os.path.join(transfer_dir, playlist_name_sanitized)
            os.makedirs(playlist_dir, exist_ok=True)
            artist_name_sanitized = _sanitize_filename(template_context['artist'])
            track_name_sanitized = _sanitize_filename(track_name)
            new_filename = f"{artist_name_sanitized} - {track_name_sanitized}{file_ext}"
            return os.path.join(playlist_dir, new_filename), True

    elif album_info and album_info.get('is_album'):
        # ALBUM MODE
        clean_track_name = album_info.get('clean_track_name', 'Unknown Track')
        if original_search.get('spotify_clean_title'):
            clean_track_name = original_search['spotify_clean_title']
        elif album_info.get('clean_track_name'):
            clean_track_name = album_info['clean_track_name']
        else:
            clean_track_name = original_search.get('title', 'Unknown Track')

        track_number = album_info.get('track_number', 1)
        if track_number is None or not isinstance(track_number, int) or track_number < 1:
            track_number = 1

        # Multi-disc album subfolder support
        disc_number = album_info.get('disc_number', 1)

        # Get structured artists list for collab artist handling
        _artists = original_search.get('artists') or track_info.get('artists') or []
        # Extract iTunes artist ID for primary artist resolution (only for iTunes source)
        _spotify_album = context.get('spotify_album', {})
        _itunes_aid = None
        _track_source = original_search.get('_source') or track_info.get('_source', '')
        _is_itunes = _track_source == 'itunes' or (isinstance(spotify_artist, dict) and str(spotify_artist.get('id', '')).isdigit() and _track_source != 'deezer')
        if _is_itunes and isinstance(spotify_artist, dict):
            _aid = spotify_artist.get('id', '')
            if str(_aid).isdigit():
                _itunes_aid = str(_aid)
        if not _itunes_aid and _spotify_album:
            _ext = _spotify_album.get('external_urls', {})
            if isinstance(_ext, dict) and _ext.get('itunes_artist_id'):
                _itunes_aid = _ext['itunes_artist_id']

        # Resolve album-level artist name for $albumartist.
        # Per-track spotify_artist may vary on collab albums or after artist name changes.
        # Prefer stable album-level sources so all tracks land in the same folder.
        _artist_name = spotify_artist["name"] if isinstance(spotify_artist, dict) else spotify_artist.name
        _album_artist_name = _artist_name  # default: same as track artist

        # Build album-level artists list for collab mode resolution.
        # Using album-level artists (instead of per-track _artists) ensures collab mode
        # produces the SAME result for every track, preventing folder/tag splits.
        _album_artists_for_collab = None  # None = fall back to per-track _artists
        _explicit_artist_ctx = track_info.get('_explicit_artist_context') if isinstance(track_info, dict) else None
        if isinstance(_explicit_artist_ctx, dict) and _explicit_artist_ctx.get('name'):
            _album_artist_name = _explicit_artist_ctx['name']
            _album_artists_for_collab = [_explicit_artist_ctx]
        elif isinstance(_explicit_artist_ctx, str) and _explicit_artist_ctx:
            _album_artist_name = _explicit_artist_ctx
            _album_artists_for_collab = [{'name': _explicit_artist_ctx}]
        else:
            _sa_artists = _spotify_album.get('artists', []) if _spotify_album else []
            if _sa_artists:
                _first_sa = _sa_artists[0]
                if isinstance(_first_sa, dict) and _first_sa.get('name'):
                    _album_artist_name = _first_sa['name']
                elif isinstance(_first_sa, str) and _first_sa:
                    _album_artist_name = _first_sa
                _album_artists_for_collab = _sa_artists

        template_context = {
            'artist': _artist_name,
            'albumartist': _album_artist_name,
            'album': album_info['album_name'],
            'title': clean_track_name,
            'track_number': track_number,
            'disc_number': disc_number,
            'year': year,
            'quality': context.get('_audio_quality', ''),
            'albumtype': album_type_display,
            '_artists_list': _album_artists_for_collab if _album_artists_for_collab else _artists,
            '_itunes_artist_id': _itunes_aid,
        }
        spotify_album = context.get('spotify_album', {})
        total_discs = spotify_album.get('total_discs', 1) if spotify_album else 1

        # Check if user controls disc structure via $disc in their template
        album_template = config_manager.get('file_organization.templates.album_path', '')
        user_controls_disc = '$disc' in album_template

        disc_label = config_manager.get('file_organization.disc_label', 'Disc')

        folder_path, filename_base = _get_file_path_from_template(template_context, 'album_path')
        if folder_path and filename_base:
            if total_discs > 1 and not user_controls_disc:
                disc_folder = f"{disc_label} {disc_number}"
                final_path = os.path.join(transfer_dir, folder_path, disc_folder, filename_base + file_ext)
                os.makedirs(os.path.join(transfer_dir, folder_path, disc_folder), exist_ok=True)
            else:
                final_path = os.path.join(transfer_dir, folder_path, filename_base + file_ext)
                os.makedirs(os.path.join(transfer_dir, folder_path), exist_ok=True)
            return final_path, True
        else:
            # Fallback — use albumartist for folder consistency (same as template)
            artist_name_sanitized = _sanitize_filename(template_context['albumartist'])
            album_name_sanitized = _sanitize_filename(album_info['album_name'])
            artist_dir = os.path.join(transfer_dir, artist_name_sanitized)
            album_folder_name = f"{artist_name_sanitized} - {album_name_sanitized}"
            album_dir = os.path.join(artist_dir, album_folder_name)
            if total_discs > 1:
                album_dir = os.path.join(album_dir, f"{disc_label} {disc_number}")
            os.makedirs(album_dir, exist_ok=True)
            final_track_name_sanitized = _sanitize_filename(clean_track_name)
            new_filename = f"{track_number:02d} - {final_track_name_sanitized}{file_ext}"
            return os.path.join(album_dir, new_filename), True

    else:
        # SINGLE MODE
        clean_track_name = album_info.get('clean_track_name', 'Unknown Track') if album_info else 'Unknown Track'
        if original_search.get('spotify_clean_title'):
            clean_track_name = original_search['spotify_clean_title']
        elif album_info and album_info.get('clean_track_name'):
            clean_track_name = album_info['clean_track_name']
        else:
            clean_track_name = original_search.get('title', 'Unknown Track')

        # Get structured artists list for collab artist handling (same as album/playlist modes)
        _artists = original_search.get('artists') or track_info.get('artists') or []
        # Extract iTunes artist ID for primary artist resolution (only for iTunes source)
        _spotify_album = context.get('spotify_album', {})
        _itunes_aid = None
        _track_source = original_search.get('_source') or track_info.get('_source', '')
        _is_itunes = _track_source == 'itunes' or (isinstance(spotify_artist, dict) and str(spotify_artist.get('id', '')).isdigit() and _track_source != 'deezer')
        if _is_itunes and isinstance(spotify_artist, dict):
            _aid = spotify_artist.get('id', '')
            if str(_aid).isdigit():
                _itunes_aid = str(_aid)
        if not _itunes_aid and _spotify_album:
            _ext = _spotify_album.get('external_urls', {})
            if isinstance(_ext, dict) and _ext.get('itunes_artist_id'):
                _itunes_aid = _ext['itunes_artist_id']

        template_context = {
            'artist': spotify_artist["name"] if isinstance(spotify_artist, dict) else spotify_artist.name,
            'albumartist': spotify_artist["name"] if isinstance(spotify_artist, dict) else spotify_artist.name,
            'album': album_info.get('album_name', clean_track_name) if album_info else clean_track_name,
            'title': clean_track_name,
            'track_number': 1,
            'disc_number': 1,
            'year': year,
            'quality': context.get('_audio_quality', ''),
            'albumtype': album_type_display,
            '_artists_list': _artists,
            '_itunes_artist_id': _itunes_aid,
        }

        folder_path, filename_base = _get_file_path_from_template(template_context, 'single_path')
        if folder_path and filename_base:
            final_path = os.path.join(transfer_dir, folder_path, filename_base + file_ext)
            os.makedirs(os.path.join(transfer_dir, folder_path), exist_ok=True)
            return final_path, True
        else:
            # Fallback
            artist_name_sanitized = _sanitize_filename(template_context['artist'])
            final_track_name_sanitized = _sanitize_filename(clean_track_name)
            artist_dir = os.path.join(transfer_dir, artist_name_sanitized)
            single_folder_name = f"{artist_name_sanitized} - {final_track_name_sanitized}"
            single_dir = os.path.join(artist_dir, single_folder_name)
            os.makedirs(single_dir, exist_ok=True)
            new_filename = f"{final_track_name_sanitized}{file_ext}"
            return os.path.join(single_dir, new_filename), True

def _get_file_path_from_template_raw(template: str, context: dict) -> tuple:
    """
    Build file path using a user-provided template string directly.
    Unlike _get_file_path_from_template, this bypasses config lookup and the
    file_organization.enabled check — used by the reorganize feature where the
    user supplies the template explicitly.

    Args:
        template: Template string like "$artist/$album/$track - $title"
        context: Dict with all track/album metadata

    Returns:
        (folder_path, filename_base) tuple — no file extension included
    """
    import re
    full_path = _apply_path_template(template, context)

    quality_value = context.get('quality', '')
    disc_value = f"{context.get('disc_number', 1):02d}"
    disc_value_raw = str(context.get('disc_number', 1))

    path_parts = full_path.split('/')

    if len(path_parts) > 1:
        folder_parts = path_parts[:-1]
        filename_base = path_parts[-1]

        # $discnum before $disc — longer match first
        cleaned_folders = []
        for part in folder_parts:
            part = part.replace('$quality', '')
            part = part.replace('$discnum', '')
            part = part.replace('$disc', '')
            part = re.sub(r'\s*\[\s*\]', '', part)
            part = re.sub(r'\s*\(\s*\)', '', part)
            part = re.sub(r'\s*\{\s*\}', '', part)
            part = re.sub(r'\s*-\s*$', '', part)
            part = re.sub(r'^\s*-\s*', '', part)
            part = re.sub(r'\s+', ' ', part).strip()
            if part:
                cleaned_folders.append(part)

        filename_base = filename_base.replace('$quality', quality_value)
        filename_base = filename_base.replace('$discnum', disc_value_raw)
        filename_base = filename_base.replace('$disc', disc_value)
        filename_base = re.sub(r'\s*\[\s*\]', '', filename_base)
        filename_base = re.sub(r'\s*\(\s*\)', '', filename_base)
        filename_base = re.sub(r'\s*\{\s*\}', '', filename_base)
        filename_base = re.sub(r'\s*-\s*$', '', filename_base)
        filename_base = re.sub(r'\s+', ' ', filename_base).strip()

        sanitized_folders = [_sanitize_filename(part) for part in cleaned_folders]
        folder_path = os.path.join(*sanitized_folders) if sanitized_folders else ''
        return folder_path, _sanitize_filename(filename_base)
    else:
        full_path = full_path.replace('$quality', quality_value)
        full_path = full_path.replace('$discnum', disc_value_raw)
        full_path = full_path.replace('$disc', disc_value)
        full_path = re.sub(r'\s*\[\s*\]', '', full_path)
        full_path = re.sub(r'\s*\(\s*\)', '', full_path)
        full_path = re.sub(r'\s*\{\s*\}', '', full_path)
        full_path = re.sub(r'\s*-\s*$', '', full_path)
        full_path = re.sub(r'\s+', ' ', full_path).strip()
        return '', _sanitize_filename(full_path)


def _get_audio_quality_string(file_path):
    """
    Read audio file and return a quality descriptor string.

    Returns strings like 'FLAC 16bit', 'MP3-320', 'M4A-256', 'OGG-192'.
    Returns empty string on any error.
    """
    try:
        ext = os.path.splitext(file_path)[1].lower()

        if ext == '.flac':
            audio = FLAC(file_path)
            bits = audio.info.bits_per_sample
            return f"FLAC {bits}bit"

        elif ext == '.mp3':
            from mutagen.mp3 import MP3, BitrateMode
            audio = MP3(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            if audio.info.bitrate_mode == BitrateMode.VBR:
                return "MP3-VBR"
            return f"MP3-{bitrate_kbps}"

        elif ext in ('.m4a', '.aac', '.mp4'):
            audio = MP4(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            return f"M4A-{bitrate_kbps}"

        elif ext == '.ogg':
            audio = OggVorbis(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            return f"OGG-{bitrate_kbps}"

        elif ext == '.opus':
            from mutagen.oggopus import OggOpus
            audio = OggOpus(file_path)
            bitrate_kbps = audio.info.bitrate // 1000
            return f"OPUS-{bitrate_kbps}"

        return ''
    except Exception as e:
        logger.debug(f"Could not determine audio quality for {file_path}: {e}")
        return ''

def _downsample_hires_flac(final_path, context):
    """Downsample a 24-bit hi-res FLAC to 16-bit/44.1kHz CD quality.

    Only runs when downsample_hires is enabled and the file is a 24-bit FLAC.
    Replaces the original file in-place (write to temp, verify, swap).

    Returns the (possibly renamed) final_path, or None if no conversion needed.
    """
    if not config_manager.get('lossy_copy.downsample_hires', False):
        return None

    ext = os.path.splitext(final_path)[1].lower()
    if ext != '.flac':
        return None

    # Check current bit depth — only downsample if hi-res (>16 bit)
    try:
        from mutagen.flac import FLAC
        audio = FLAC(final_path)
        original_bits = audio.info.bits_per_sample
        original_rate = audio.info.sample_rate
    except Exception as e:
        print(f"[Downsample] Could not read FLAC info: {e}")
        return None

    if original_bits <= 16 and original_rate <= 44100:
        return None  # Already CD quality or below

    print(f"[Downsample] Converting {original_bits}-bit/{original_rate}Hz → 16-bit/44100Hz: {os.path.basename(final_path)}")

    ffmpeg_bin = shutil.which('ffmpeg')
    if not ffmpeg_bin:
        local = os.path.join(os.path.dirname(__file__), 'tools', 'ffmpeg')
        if os.path.isfile(local):
            ffmpeg_bin = local
        else:
            print("[Downsample] ffmpeg not found — skipping hi-res conversion")
            return None

    temp_path = final_path + '.tmp.flac'
    try:
        result = subprocess.run([
            ffmpeg_bin, '-i', final_path,
            '-sample_fmt', 's16',
            '-ar', '44100',
            '-map_metadata', '0',
            '-compression_level', '8',
            '-y', temp_path
        ], capture_output=True, text=True, timeout=300)

        if result.returncode != 0:
            print(f"[Downsample] ffmpeg failed: {result.stderr[:200]}")
            if os.path.exists(temp_path):
                os.remove(temp_path)
            return None

        # Verify the output is a valid 16-bit FLAC
        if not os.path.isfile(temp_path) or os.path.getsize(temp_path) == 0:
            print(f"[Downsample] Output file missing or empty")
            if os.path.exists(temp_path):
                os.remove(temp_path)
            return None

        verify_audio = FLAC(temp_path)
        if verify_audio.info.bits_per_sample != 16:
            print(f"[Downsample] Output not 16-bit ({verify_audio.info.bits_per_sample}-bit), aborting")
            os.remove(temp_path)
            return None

        # Atomic swap — replace original with downsampled version
        os.replace(temp_path, final_path)
        print(f"[Downsample] Converted to 16-bit/44.1kHz: {os.path.basename(final_path)}")

        # Update QUALITY tag in the new file
        new_quality = 'FLAC 16bit'
        try:
            updated_audio = FLAC(final_path)
            updated_audio['QUALITY'] = new_quality
            updated_audio.save()
        except Exception as tag_err:
            print(f"[Downsample] Could not update QUALITY tag: {tag_err}")

        # Update context so downstream (lossy copy, metadata) reflects new quality
        old_quality = context.get('_audio_quality', '')
        context['_audio_quality'] = new_quality

        # If filename contains old quality string (from $quality template), rename
        if old_quality and old_quality != new_quality and old_quality in os.path.basename(final_path):
            new_basename = os.path.basename(final_path).replace(old_quality, new_quality)
            new_path = os.path.join(os.path.dirname(final_path), new_basename)
            try:
                os.rename(final_path, new_path)
                print(f"[Downsample] Renamed: {os.path.basename(final_path)} → {new_basename}")
                # Rename matching lyrics sidecar file if it exists (.lrc or .txt)
                for lyrics_ext in ('.lrc', '.txt'):
                    old_lyrics = os.path.splitext(final_path)[0] + lyrics_ext
                    if os.path.isfile(old_lyrics):
                        new_lyrics = os.path.splitext(new_path)[0] + lyrics_ext
                        os.rename(old_lyrics, new_lyrics)
                return new_path
            except Exception as rename_err:
                print(f"[Downsample] Could not rename file: {rename_err}")

        return final_path

    except subprocess.TimeoutExpired:
        print(f"[Downsample] Conversion timed out for: {os.path.basename(final_path)}")
        if os.path.exists(temp_path):
            os.remove(temp_path)
    except Exception as e:
        print(f"[Downsample] Conversion error: {e}")
        if os.path.exists(temp_path):
            try:
                os.remove(temp_path)
            except Exception:
                pass
    return None


def _create_lossy_copy(final_path):
    """Convert a FLAC file to a lossy codec at the user's configured bitrate.

    Supported codecs: mp3 (libmp3lame), opus (libopus), aac (aac/libfdk_aac).
    Only runs when lossy_copy is enabled and the file is a FLAC.
    Places the output alongside the FLAC with the same basename.

    Returns the output path if Blasphemy Mode deleted the original, else None.
    """
    if not config_manager.get('lossy_copy.enabled', False):
        return None

    ext = os.path.splitext(final_path)[1].lower()
    if ext != '.flac':
        return None

    codec = config_manager.get('lossy_copy.codec', 'mp3').lower()
    bitrate = config_manager.get('lossy_copy.bitrate', '320')

    # Opus max per-channel bitrate is 256kbps — cap to avoid encoding failures
    if codec == 'opus' and int(bitrate) > 256:
        bitrate = '256'

    # Codec configuration: (ffmpeg_codec, extension, quality_label, extra_args)
    codec_map = {
        'mp3':  ('libmp3lame', '.mp3',  f'MP3-{bitrate}',  ['-id3v2_version', '3']),
        'opus': ('libopus',    '.opus', f'OPUS-{bitrate}',  ['-map', '0:a', '-vbr', 'on']),
        'aac':  ('aac',        '.m4a',  f'AAC-{bitrate}',   ['-movflags', '+faststart']),
    }

    if codec not in codec_map:
        print(f"[Lossy Copy] Unknown codec '{codec}' — skipping conversion")
        return None

    ffmpeg_codec, out_ext, quality_label, extra_args = codec_map[codec]
    out_path = os.path.splitext(final_path)[0] + out_ext

    # If $quality was used in filename, swap FLAC quality for lossy quality
    original_quality = _get_audio_quality_string(final_path)
    if original_quality:
        out_basename = os.path.basename(out_path)
        if original_quality in out_basename:
            out_basename = out_basename.replace(original_quality, quality_label)
            out_path = os.path.join(os.path.dirname(out_path), out_basename)

    ffmpeg_bin = shutil.which('ffmpeg')
    if not ffmpeg_bin:
        local = os.path.join(os.path.dirname(__file__), 'tools', 'ffmpeg')
        if os.path.isfile(local):
            ffmpeg_bin = local
        else:
            print(f"[Lossy Copy] ffmpeg not found — skipping {codec.upper()} conversion")
            return None

    try:
        print(f"[Lossy Copy] Converting to {quality_label}: {os.path.basename(final_path)}")
        cmd = [
            ffmpeg_bin, '-i', final_path,
            '-codec:a', ffmpeg_codec,
            '-b:a', f'{bitrate}k',
            '-map_metadata', '0',
        ] + extra_args + ['-y', out_path]

        result = subprocess.run(cmd, capture_output=True, text=True, timeout=120)

        if result.returncode == 0:
            print(f"[Lossy Copy] Created {quality_label} copy: {os.path.basename(out_path)}")

            # Fix QUALITY tag — the FLAC's tag was copied verbatim by ffmpeg
            try:
                from mutagen import File as MutagenFile
                audio = MutagenFile(out_path)
                if audio is not None:
                    if codec == 'mp3':
                        from mutagen.id3 import TXXX
                        audio.tags.add(TXXX(encoding=3, desc='QUALITY', text=[quality_label]))
                    elif codec == 'opus':
                        audio['QUALITY'] = [quality_label]
                    elif codec == 'aac':
                        from mutagen.mp4 import MP4FreeForm
                        audio['----:com.apple.iTunes:QUALITY'] = [MP4FreeForm(quality_label.encode('utf-8'))]
                    audio.save()
            except Exception as tag_err:
                print(f"[Lossy Copy] Could not update QUALITY tag: {tag_err}")

            # Embed cover art from source FLAC into the lossy copy
            # Opus/OGG can't inherit FLAC cover art via ffmpeg -map_metadata alone
            if codec in ('opus', 'aac'):
                try:
                    from mutagen import File as MutagenFile
                    from mutagen.flac import FLAC as MutagenFLAC
                    source_audio = MutagenFLAC(final_path)
                    pic = None
                    if source_audio and source_audio.pictures:
                        pic = source_audio.pictures[0]

                    # Fallback: read cover.jpg from the same directory
                    if not pic:
                        cover_path = os.path.join(os.path.dirname(final_path), 'cover.jpg')
                        if os.path.isfile(cover_path):
                            try:
                                from mutagen.flac import Picture
                                with open(cover_path, 'rb') as f:
                                    img_data = f.read()
                                pic = Picture()
                                pic.type = 3  # Cover (front)
                                pic.mime = 'image/jpeg'
                                pic.desc = 'Cover'
                                pic.width = 0
                                pic.height = 0
                                pic.depth = 0
                                pic.colors = 0
                                pic.data = img_data
                                print(f"[Lossy Copy] Using cover.jpg as art source (FLAC had no embedded art)")
                            except Exception:
                                pass

                    if pic:
                        dest_audio = MutagenFile(out_path)
                        if dest_audio is not None:
                            if codec == 'opus':
                                import base64
                                from mutagen.oggopus import OggOpus
                                if isinstance(dest_audio, OggOpus):
                                    # OGG stores pictures as base64-encoded METADATA_BLOCK_PICTURE
                                    import struct
                                    # Build METADATA_BLOCK_PICTURE block
                                    picture_data = (
                                        struct.pack('>II', pic.type, len(pic.mime.encode('utf-8')))
                                        + pic.mime.encode('utf-8')
                                        + struct.pack('>I', len(pic.desc.encode('utf-8')))
                                        + pic.desc.encode('utf-8')
                                        + struct.pack('>IIII', pic.width, pic.height, pic.depth, pic.colors)
                                        + struct.pack('>I', len(pic.data))
                                        + pic.data
                                    )
                                    dest_audio['METADATA_BLOCK_PICTURE'] = [base64.b64encode(picture_data).decode('ascii')]
                                    dest_audio.save()
                                    print(f"[Lossy Copy] Embedded cover art in Opus file")
                            elif codec == 'aac':
                                from mutagen.mp4 import MP4Cover
                                fmt = MP4Cover.FORMAT_JPEG if 'jpeg' in pic.mime else MP4Cover.FORMAT_PNG
                                dest_audio['covr'] = [MP4Cover(pic.data, imageformat=fmt)]
                                dest_audio.save()
                                print(f"[Lossy Copy] Embedded cover art in M4A file")
                except Exception as art_err:
                    print(f"[Lossy Copy] Could not embed cover art: {art_err}")

            # Blasphemy Mode: delete original FLAC if enabled and output is verified
            if config_manager.get('lossy_copy.delete_original', False):
                try:
                    if os.path.isfile(out_path) and os.path.getsize(out_path) > 0:
                        from mutagen import File as MutagenFile
                        test_audio = MutagenFile(out_path)
                        if test_audio is not None:
                            # Update provenance record to point to the new transcoded file
                            try:
                                db = get_database()
                                db.update_provenance_file_path(final_path, out_path)
                            except Exception:
                                pass
                            os.remove(final_path)
                            print(f"[Blasphemy Mode] Deleted original: {os.path.basename(final_path)}")
                            # Rename lyrics sidecar file to match the output filename
                            for lyrics_ext in ('.lrc', '.txt'):
                                src_lyrics = os.path.splitext(final_path)[0] + lyrics_ext
                                if os.path.isfile(src_lyrics):
                                    dst_lyrics = os.path.splitext(out_path)[0] + lyrics_ext
                                    try:
                                        os.rename(src_lyrics, dst_lyrics)
                                        print(f"[Blasphemy Mode] Renamed {lyrics_ext}: {os.path.basename(src_lyrics)} -> {os.path.basename(dst_lyrics)}")
                                    except Exception as lrc_err:
                                        print(f"[Blasphemy Mode] Could not rename {lyrics_ext}: {lrc_err}")
                            return out_path
                        else:
                            print(f"[Blasphemy Mode] Output failed audio validation, keeping original: {os.path.basename(final_path)}")
                    else:
                        print(f"[Blasphemy Mode] Output missing or empty, keeping original: {os.path.basename(final_path)}")
                except Exception as del_err:
                    print(f"[Blasphemy Mode] Error during original deletion, keeping original: {del_err}")
        else:
            print(f"[Lossy Copy] ffmpeg failed: {result.stderr[:200]}")
    except subprocess.TimeoutExpired:
        print(f"[Lossy Copy] Conversion timed out for: {os.path.basename(final_path)}")
    except Exception as e:
        print(f"[Lossy Copy] Conversion error: {e}")
    return None

def _apply_path_template(template: str, context: dict) -> str:
    """
    Apply template to build file path.

    Args:
        template: Template string like "$artist/$album/$track - $title"
        context: Dict with values like {'artist': 'Drake', 'album': 'Scorpion', ...}

    Returns:
        Processed path string
    """
    # Sanitize context values BEFORE template substitution
    # This prevents '/' in metadata from creating unintended path components
    clean_context = _sanitize_context_values(context)

    result = template

    # Replace variables in order from longest to shortest to avoid partial replacements
    # (e.g., $albumartist must be replaced before $album to prevent "Scorpionartist" from typo "$albumartis")

    # Longest variables first
    album_artist_value = clean_context.get('albumartist', clean_context.get('artist', 'Unknown Artist'))
    # Collaborative album artist handling: "first" uses only the primary artist for folder names
    collab_mode = config_manager.get('file_organization.collab_artist_mode', 'first')
    if collab_mode == 'first' and album_artist_value:
        # Use structured artists list to safely extract first artist
        # Only splits when we have multiple distinct artist objects (Spotify provides these)
        # Avoids string splitting which breaks names like "Tyler, the Creator" or "Simon & Garfunkel"
        artists_list = context.get('_artists_list')
        if artists_list and len(artists_list) > 1:
            # Multiple artist objects (Spotify) — use first
            first = artists_list[0]
            album_artist_value = first.get('name', first) if isinstance(first, dict) else str(first)
        elif artists_list and len(artists_list) == 1:
            # Single artist string — could be a combined name from iTunes
            # Resolve via artistId if available (safe: "Simon & Garfunkel" ID → "Simon & Garfunkel")
            itunes_artist_id = context.get('_itunes_artist_id')
            if itunes_artist_id and (',' in album_artist_value or ' & ' in album_artist_value):
                try:
                    resolved = _get_itunes_client().resolve_primary_artist(itunes_artist_id)
                    if resolved and resolved != album_artist_value:
                        album_artist_value = resolved
                except Exception:
                    pass
    result = result.replace('$albumartist', album_artist_value)
    result = result.replace('$albumtype', clean_context.get('albumtype', 'Album'))
    result = result.replace('$playlist', clean_context.get('playlist_name', ''))

    # Medium length variables
    result = result.replace('$artistletter', (clean_context.get('artist', 'U') or 'U')[0].upper())
    result = result.replace('$artist', clean_context.get('artist', 'Unknown Artist'))
    result = result.replace('$album', clean_context.get('album', 'Unknown Album'))
    result = result.replace('$title', clean_context.get('title', 'Unknown Track'))
    result = result.replace('$track', f"{clean_context.get('track_number', 1):02d}")
    result = result.replace('$year', str(clean_context.get('year', '')))  # Empty string instead of 'Unknown'

    # Clean up extra spaces that might result from empty variables
    import re
    result = re.sub(r'\s+', ' ', result)  # Multiple spaces to single space
    result = re.sub(r'\s*-\s*-\s*', ' - ', result)  # Clean up double dashes
    result = result.strip()  # Remove leading/trailing spaces

    return result

def _get_file_path_from_template(context: dict, template_type: str = 'album_path') -> tuple:
    """
    Build complete file path using configured templates.

    Args:
        context: Dict with all track/album metadata
        template_type: 'album_path', 'single_path', 'compilation_path', 'playlist_path'

    Returns:
        (folder_path, filename) tuple
    """
    # Check if template system is enabled
    if not config_manager.get('file_organization.enabled', True):
        # Fallback to hardcoded structure
        return None, None

    # Get template from config
    templates = config_manager.get('file_organization.templates', {})
    template = templates.get(template_type)

    if not template:
        # Fallback templates if config missing
        default_templates = {
            'album_path': '$albumartist/$albumartist - $album/$track - $title',
            'single_path': '$artist/$artist - $title/$title',
            'compilation_path': 'Compilations/$album/$track - $artist - $title',
            'playlist_path': '$playlist/$artist - $title'
        }
        template = default_templates.get(template_type, '$artist/$album/$track - $title')

    # Apply template
    full_path = _apply_path_template(template, context)

    # Split into folder and filename
    path_parts = full_path.split('/')

    # Handle $quality and $disc: only substituted in the filename (last component).
    # In folder components they become empty string to prevent album splits
    # when tracks arrive in mixed qualities or disc numbers in folder names.
    import re
    quality_value = context.get('quality', '')
    disc_value = f"{context.get('disc_number', 1):02d}"
    disc_value_raw = str(context.get('disc_number', 1))

    if len(path_parts) > 1:
        folder_parts = path_parts[:-1]
        filename_base = path_parts[-1]

        # Strip $quality, $discnum, $disc from folder parts and clean up artifacts
        # $discnum before $disc — longer match first to prevent partial replacement
        cleaned_folders = []
        for part in folder_parts:
            part = part.replace('$quality', '')
            part = part.replace('$discnum', '')
            part = part.replace('$disc', '')
            part = re.sub(r'\s*\[\s*\]', '', part)   # empty []
            part = re.sub(r'\s*\(\s*\)', '', part)   # empty ()
            part = re.sub(r'\s*\{\s*\}', '', part)   # empty {}
            part = re.sub(r'\s*-\s*$', '', part)     # trailing dash
            part = re.sub(r'^\s*-\s*', '', part)     # leading dash
            part = re.sub(r'\s+', ' ', part).strip()
            if part:
                cleaned_folders.append(part)

        # Substitute $quality, $discnum, $disc in filename only
        # $discnum before $disc — longer match first
        filename_base = filename_base.replace('$quality', quality_value)
        filename_base = filename_base.replace('$discnum', disc_value_raw)
        filename_base = filename_base.replace('$disc', disc_value)
        # Clean up empty brackets/parens from any variable that resolved to empty
        filename_base = re.sub(r'\s*\[\s*\]', '', filename_base)
        filename_base = re.sub(r'\s*\(\s*\)', '', filename_base)
        filename_base = re.sub(r'\s*\{\s*\}', '', filename_base)
        filename_base = re.sub(r'\s*-\s*$', '', filename_base)
        filename_base = re.sub(r'\s+', ' ', filename_base).strip()

        # Sanitize each folder component
        sanitized_folders = [_sanitize_filename(part) for part in cleaned_folders]
        folder_path = os.path.join(*sanitized_folders) if sanitized_folders else ''

        # Sanitize filename
        filename = _sanitize_filename(filename_base)

        return folder_path, filename
    else:
        # Single component, treat as filename — substitute $quality, $discnum, $disc
        full_path = full_path.replace('$quality', quality_value)
        full_path = full_path.replace('$discnum', disc_value_raw)
        full_path = full_path.replace('$disc', disc_value)
        full_path = re.sub(r'\s*\[\s*\]', '', full_path)
        full_path = re.sub(r'\s*\(\s*\)', '', full_path)
        full_path = re.sub(r'\s*\{\s*\}', '', full_path)
        full_path = re.sub(r'\s*-\s*$', '', full_path)
        full_path = re.sub(r'\s+', ' ', full_path).strip()
        return '', _sanitize_filename(full_path)

# METADATA & COVER ART HELPERS (Ported from downloads.py)
# ===================================================================
from mutagen import File as MutagenFile
from mutagen.id3 import ID3, TIT2, TPE1, TALB, TDRC, TRCK, TCON, TPE2, TPOS, TXXX, APIC, UFID, TSRC, TBPM, TCOP, TPUB, TMED, TDOR
from mutagen.flac import FLAC, Picture
from mutagen.mp4 import MP4, MP4Cover, MP4FreeForm
from mutagen.oggvorbis import OggVorbis
from mutagen.apev2 import APEv2, APENoHeaderError
import urllib.request

def _strip_all_non_audio_tags(file_path: str) -> dict:
    """
    Strip ALL non-audio tag containers from a file before metadata rewriting.
    MP3 files from Soulseek commonly carry APEv2 tags (foobar2000 users)
    with stale metadata that Mutagen's ID3 handler cannot see or clear.
    Must run BEFORE MutagenFile() opens the file.
    """
    summary = {'apev2_stripped': False, 'apev2_tag_count': 0}
    ext = os.path.splitext(file_path)[1].lower()
    if ext != '.mp3':
        return summary
    try:
        apev2_tags = APEv2(file_path)
        tag_count = len(apev2_tags)
        tag_keys = list(apev2_tags.keys())
        apev2_tags.delete(file_path)
        summary['apev2_stripped'] = True
        summary['apev2_tag_count'] = tag_count
        print(f"Stripped {tag_count} APEv2 tags: {', '.join(tag_keys[:10])}")
    except APENoHeaderError:
        pass  # No APEv2 tags — common case
    except Exception as e:
        print(f"Could not strip APEv2 tags (non-fatal): {e}")
    return summary

def _verify_metadata_written(file_path: str) -> bool:
    """Re-open file and verify core metadata fields are present."""
    try:
        check = MutagenFile(file_path)
        if check is None or check.tags is None:
            print(f"[VERIFY] Tags are None after save: {file_path}")
            return False
        title_found = False
        artist_found = False
        if isinstance(check.tags, ID3):
            title_found = bool(check.tags.getall('TIT2'))
            artist_found = bool(check.tags.getall('TPE1'))
            # Confirm APEv2 is gone
            try:
                APEv2(file_path)
                print(f"[VERIFY] APEv2 tags still present after processing!")
                return False
            except APENoHeaderError:
                pass
        elif isinstance(check, (FLAC, OggVorbis)) or _is_ogg_opus(check):
            title_found = bool(check.get('title'))
            artist_found = bool(check.get('artist'))
        elif isinstance(check, MP4):
            title_found = bool(check.get('\xa9nam'))
            artist_found = bool(check.get('\xa9ART'))
        if not title_found or not artist_found:
            print(f"[VERIFY] Missing metadata - title:{title_found} artist:{artist_found}")
            return False
        print(f"[VERIFY] Metadata verified OK")
        return True
    except Exception as e:
        print(f"[VERIFY] Verification error (non-fatal): {e}")
        return False

def _is_ogg_opus(audio_file):
    """Check if a Mutagen file object is OggOpus (uses VorbisComment tags like FLAC/OGG)."""
    return type(audio_file).__name__ == 'OggOpus'

def _enhance_file_metadata(file_path: str, context: dict, artist: dict, album_info: dict) -> bool:
    """
    Core function to enhance audio file metadata using Spotify data.
    Thread-safe with per-file locking to prevent concurrent metadata writes.

    Opens the file once in non-easy mode, clears all tags in memory, writes
    new tags using format-specific frames/keys, embeds album art and source
    IDs, then saves once.  This avoids the old clear→save→reopen pattern
    which stripped the ID3v2 header from MP3 files, leaving them tagless.
    """
    if not config_manager.get('metadata_enhancement.enabled', True):
        print("Metadata enhancement disabled in config.")
        return True

    # Acquire per-file lock to prevent concurrent metadata writes to the same file
    file_lock = _get_file_lock(file_path)
    with file_lock:
        print(f"Enhancing metadata for: {os.path.basename(file_path)}")
        try:
            # Strip APEv2 tags from MP3 (invisible to ID3 handler)
            strip_summary = _strip_all_non_audio_tags(file_path)

            audio_file = MutagenFile(file_path)
            if audio_file is None:
                print(f"Could not load audio file with Mutagen: {file_path}")
                return False

            # ── Wipe ALL existing tags and save immediately ──
            # Files from Soulseek carry random metadata (wrong comments,
            # encoder info, ReplayGain, old album art, random TXXX frames).
            # Save the cleared state FIRST so that if anything below throws,
            # the file at least has clean (empty) tags instead of junk that
            # causes album fragmentation in media servers.
            if hasattr(audio_file, 'clear_pictures'):
                audio_file.clear_pictures()

            if audio_file.tags is not None:
                if len(audio_file.tags) > 0:
                    tag_keys = list(audio_file.tags.keys())[:15]
                    print(f"Clearing {len(audio_file.tags)} existing tags: "
                          f"{', '.join(str(k) for k in tag_keys)}")
                audio_file.tags.clear()
            else:
                audio_file.add_tags()

            # Persist the wipe — guarantees junk tags are gone even if later steps fail
            if isinstance(audio_file.tags, ID3):
                audio_file.save(v1=0, v2_version=4)
            elif isinstance(audio_file, FLAC):
                audio_file.save(deleteid3=True)
            else:
                audio_file.save()

            metadata = _extract_spotify_metadata(context, artist, album_info)
            if not metadata:
                print("Could not extract Spotify metadata, saving with cleared tags.")
                if isinstance(audio_file.tags, ID3):
                    audio_file.save(v1=0, v2_version=4)
                elif isinstance(audio_file, FLAC):
                    audio_file.save(deleteid3=True)
                else:
                    audio_file.save()
                return True

            # ── Write standard tags using format-specific API ──
            track_num_str = f"{metadata.get('track_number', 1)}/{metadata.get('total_tracks', 1)}"

            if isinstance(audio_file.tags, ID3):
                # MP3: write ID3 frames directly
                if metadata.get('title'):
                    audio_file.tags.add(TIT2(encoding=3, text=[metadata['title']]))
                if metadata.get('artist'):
                    audio_file.tags.add(TPE1(encoding=3, text=[metadata['artist']]))
                if metadata.get('album_artist'):
                    audio_file.tags.add(TPE2(encoding=3, text=[metadata['album_artist']]))
                if metadata.get('album'):
                    audio_file.tags.add(TALB(encoding=3, text=[metadata['album']]))
                if metadata.get('date'):
                    audio_file.tags.add(TDRC(encoding=3, text=[metadata['date']]))
                if metadata.get('genre'):
                    audio_file.tags.add(TCON(encoding=3, text=[metadata['genre']]))
                audio_file.tags.add(TRCK(encoding=3, text=[track_num_str]))
                if metadata.get('disc_number'):
                    audio_file.tags.add(TPOS(encoding=3, text=[str(metadata['disc_number'])]))

            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                # FLAC / OGG Vorbis / OGG Opus: dict-style VorbisComment tags
                if metadata.get('title'):
                    audio_file['title'] = [metadata['title']]
                if metadata.get('artist'):
                    audio_file['artist'] = [metadata['artist']]
                if metadata.get('album_artist'):
                    audio_file['albumartist'] = [metadata['album_artist']]
                if metadata.get('album'):
                    audio_file['album'] = [metadata['album']]
                if metadata.get('date'):
                    audio_file['date'] = [metadata['date']]
                if metadata.get('genre'):
                    audio_file['genre'] = [metadata['genre']]
                audio_file['tracknumber'] = [track_num_str]
                if metadata.get('disc_number'):
                    audio_file['discnumber'] = [str(metadata['disc_number'])]

            elif isinstance(audio_file, MP4):
                # MP4 / M4A: Apple-style tag keys
                if metadata.get('title'):
                    audio_file['\xa9nam'] = [metadata['title']]
                if metadata.get('artist'):
                    audio_file['\xa9ART'] = [metadata['artist']]
                if metadata.get('album_artist'):
                    audio_file['aART'] = [metadata['album_artist']]
                if metadata.get('album'):
                    audio_file['\xa9alb'] = [metadata['album']]
                if metadata.get('date'):
                    audio_file['\xa9day'] = [metadata['date']]
                if metadata.get('genre'):
                    audio_file['\xa9gen'] = [metadata['genre']]
                track_num = metadata.get('track_number', 1)
                total_tracks = metadata.get('total_tracks', 1)
                audio_file['trkn'] = [(track_num, total_tracks)]
                if metadata.get('disc_number'):
                    audio_file['disk'] = [(metadata['disc_number'], 0)]

            # ── Embed source IDs (Spotify, MusicBrainz, etc.) on the same object ──
            # Runs before album art so MusicBrainz release ID is available for
            # Cover Art Archive high-resolution lookup.
            _embed_source_ids(audio_file, metadata)

            # Propagate MusicBrainz release ID to album_info so _download_cover_art
            # can use it for Cover Art Archive high-res cover.jpg
            if album_info is not None and metadata.get('musicbrainz_release_id'):
                album_info['musicbrainz_release_id'] = metadata['musicbrainz_release_id']

            # ── Embed album art on the same object ──
            if config_manager.get('metadata_enhancement.embed_album_art', True):
                _embed_album_art_metadata(audio_file, metadata)

            # ── Embed audio quality tag ──
            quality = context.get('_audio_quality', '')
            if quality and config_manager.get('metadata_enhancement.tags.quality_tag', True) is not False:
                if isinstance(audio_file.tags, ID3):
                    audio_file.tags.add(TXXX(encoding=3, desc='QUALITY', text=[quality]))
                elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                    audio_file['quality'] = [quality]
                elif isinstance(audio_file, MP4):
                    audio_file['----:com.apple.iTunes:QUALITY'] = [MP4FreeForm(quality.encode('utf-8'))]

            # ── Single save for everything ──
            if isinstance(audio_file.tags, ID3):
                audio_file.save(v1=0, v2_version=4)
            elif isinstance(audio_file, FLAC):
                audio_file.save(deleteid3=True)
            else:
                audio_file.save()

            # Verify metadata was written
            verified = _verify_metadata_written(file_path)
            if verified:
                print("Metadata enhanced successfully.")
            else:
                print("Metadata saved but verification found issues (see above).")
            return True
        except Exception as e:
            import traceback
            print(f"Error enhancing metadata for {file_path}: {e}")
            print(f"[Metadata Debug] Exception type: {type(e).__name__}")
            print(f"[Metadata Debug] File exists: {os.path.exists(file_path)}")
            print(f"[Metadata Debug] Artist: {artist.get('name', 'MISSING') if artist else 'None'}")
            print(f"[Metadata Debug] Album info: {album_info.get('album_name', 'MISSING') if album_info else 'None'}")
            print(f"[Metadata Debug] Traceback:\n{traceback.format_exc()}")
            return False

def _generate_lrc_file(file_path: str, context: dict, artist: dict, album_info: dict) -> bool:
    """
    Generate LRC lyrics file using LRClib API.
    Elegant addition to post-processing - extracts metadata from existing context.
    """
    if not config_manager.get('metadata_enhancement.lrclib_enabled', True):
        return False
    try:
        # Extract track information from existing context (same as metadata enhancement)
        original_search = context.get("original_search_result", {})
        spotify_album = context.get("spotify_album")

        # Get track metadata
        track_name = (original_search.get('spotify_clean_title') or
                     original_search.get('title', 'Unknown Track'))

        # Handle artist parameter (can be dict or object)
        if isinstance(artist, dict):
            artist_name = artist.get('name', 'Unknown Artist')
        elif hasattr(artist, 'name'):
            artist_name = artist.name
        else:
            artist_name = str(artist) if artist else 'Unknown Artist'
        album_name = None
        duration_seconds = None

        # Get album name if available
        if album_info.get('is_album'):
            album_name = (original_search.get('spotify_clean_album') or
                         album_info.get('album_name') or
                         (spotify_album.get('name') if spotify_album else None))

        # Get duration from original search context
        if original_search.get('duration_ms'):
            duration_seconds = int(original_search['duration_ms'] / 1000)

        # Generate LRC file using lyrics client
        success = lyrics_client.create_lrc_file(
            audio_file_path=file_path,
            track_name=track_name,
            artist_name=artist_name,
            album_name=album_name,
            duration_seconds=duration_seconds
        )

        if success:
            print(f"LRC file generated for: {track_name}")
        else:
            print(f"No lyrics found for: {track_name}")

        return success

    except Exception as e:
        print(f"Error generating LRC file for {file_path}: {e}")
        return False

def _extract_spotify_metadata(context: dict, artist: dict, album_info: dict) -> dict:
    """Extracts a comprehensive metadata dictionary from the provided context."""
    metadata = {}
    original_search = context.get("original_search_result", {})
    spotify_album = context.get("spotify_album")

    # Priority 1: Spotify clean title from context
    if original_search.get('spotify_clean_title'):
        metadata['title'] = original_search['spotify_clean_title']
        print(f"Metadata: Using Spotify clean title: '{metadata['title']}'")
    # Priority 2: Album info clean name
    elif album_info.get('clean_track_name'):
        metadata['title'] = album_info['clean_track_name']
        print(f"Metadata: Using album info clean name: '{metadata['title']}'")
    # Priority 3: Original title as fallback
    else:
        metadata['title'] = original_search.get('title', '')
        print(f"Metadata: Using original title as fallback: '{metadata['title']}'")
    # Handle multiple artists from Spotify data
    original_search = context.get("original_search_result", {})
    if 'artists' in original_search and isinstance(original_search['artists'], list) and len(original_search['artists']) > 0:
        # Join all artists with semicolon separator (standard format)
        all_artists = []
        for a in original_search['artists']:
            if isinstance(a, dict) and 'name' in a:
                all_artists.append(a['name'])
            elif isinstance(a, str):
                all_artists.append(a)
            else:
                all_artists.append(str(a))
        metadata['artist'] = ', '.join(all_artists)
        print(f"Metadata: Using all artists: '{metadata['artist']}'")
    else:
        # Fallback to single artist
        metadata['artist'] = artist.get('name', '')
        print(f"Metadata: Using primary artist: '{metadata['artist']}'")

    # Resolve album_artist for consistent tagging across all tracks in an album.
    # Priority: 1) explicit batch artist context (same artist for whole album)
    #           2) album-level artists from spotify_album
    #           3) context-level artist (spotify_artist parameter)
    #           4) collab mode first-artist resolution (per-track, last resort)
    # Using album-level artist prevents media server album splits when an artist
    # changed names (Kanye West → Ye) and Spotify returns different per-track artists.
    _raw_album_artist = artist.get('name', '')
    _track_info_ctx = context.get('track_info', {}) or {}
    _explicit_aa = _track_info_ctx.get('_explicit_artist_context') if isinstance(_track_info_ctx, dict) else None

    # Build album-level artists list for collab mode resolution.
    # Using album-level artists (instead of per-track) ensures collab mode produces
    # the SAME album_artist tag for every track, preventing media server album splits.
    _album_artists_for_collab = None
    if isinstance(_explicit_aa, dict) and _explicit_aa.get('name'):
        _raw_album_artist = _explicit_aa['name']
        _album_artists_for_collab = [_explicit_aa]
    elif isinstance(_explicit_aa, str) and _explicit_aa:
        _raw_album_artist = _explicit_aa
        _album_artists_for_collab = [{'name': _explicit_aa}]
    elif spotify_album and isinstance(spotify_album, dict):
        _sa_aa = spotify_album.get('artists', [])
        if _sa_aa:
            _first_aa = _sa_aa[0]
            if isinstance(_first_aa, dict) and _first_aa.get('name'):
                _raw_album_artist = _first_aa['name']
            elif isinstance(_first_aa, str) and _first_aa:
                _raw_album_artist = _first_aa
            _album_artists_for_collab = _sa_aa

    collab_mode = config_manager.get('file_organization.collab_artist_mode', 'first')
    if collab_mode == 'first' and _raw_album_artist:
        original_search = context.get("original_search_result", {})
        # Prefer album-level artists for collab resolution (consistent per album)
        _ctx_artists = _album_artists_for_collab or original_search.get('artists') or _track_info_ctx.get('artists') or []
        if len(_ctx_artists) > 1:
            # Multiple artist objects (Spotify) — use first
            first = _ctx_artists[0]
            _raw_album_artist = first.get('name', first) if isinstance(first, dict) else str(first)
        elif len(_ctx_artists) == 1 and (',' in _raw_album_artist or ' & ' in _raw_album_artist):
            # Single combined string (iTunes) — resolve via artist ID
            _aid = str(artist.get('id', ''))
            _src = original_search.get('_source') or _track_info_ctx.get('_source', '')
            if _aid.isdigit() and _src != 'deezer':
                try:
                    resolved = _get_itunes_client().resolve_primary_artist(_aid)
                    if resolved and resolved != _raw_album_artist:
                        _raw_album_artist = resolved
                except Exception:
                    pass
    metadata['album_artist'] = _raw_album_artist  # Crucial for library organization

    if album_info.get('is_album'):
        metadata['album'] = album_info.get('album_name', 'Unknown Album')
        track_num = album_info.get('track_number', 1)
        metadata['track_number'] = track_num
        metadata['total_tracks'] = spotify_album.get('total_tracks', 1) if spotify_album else 1
        print(f"[METADATA] Album track - track_number: {track_num}, album: {metadata['album']}")
    else:
        # SAFEGUARD: If we have spotify_album context, never use track title as album name
        # This prevents album tracks from being tagged as singles due to classification errors
        if spotify_album and spotify_album.get('name'):
            print(f"[SAFEGUARD] Using spotify_album name instead of track title for album metadata")
            metadata['album'] = spotify_album['name']
            # Use corrected track_number from album_info (which should be updated by post-processing)
            corrected_track_number = album_info.get('track_number', 1) if album_info else 1
            metadata['track_number'] = corrected_track_number
            metadata['total_tracks'] = spotify_album.get('total_tracks', 1)
            print(f"[SAFEGUARD] Using track_number: {corrected_track_number}")
        else:
            metadata['album'] = metadata['title'] # For true singles, album is the title
            metadata['track_number'] = 1
            metadata['total_tracks'] = 1

    # Always write disc_number to overwrite any stale tags from the soulseek source.
    # Without this, original disc tags persist and can cause media servers (Plex) to
    # split a single album into standard/deluxe based on differing disc numbers.
    # Priority: original_search context (from API) > album_info > default to 1
    disc_num = original_search.get('disc_number')
    if disc_num is None and album_info:
        disc_num = album_info.get('disc_number')
    if disc_num is None:
        disc_num = 1
    metadata['disc_number'] = disc_num

    if spotify_album and spotify_album.get('release_date'):
        metadata['date'] = spotify_album['release_date'][:4]

    if artist.get('genres'):
        metadata['genre'] = ', '.join(artist['genres'][:2])

    metadata['album_art_url'] = album_info.get('album_image_url')

    # Extract source IDs (Spotify or iTunes) for tag embedding
    track_info = context.get("track_info", {})
    if track_info and track_info.get('id'):
        # Spotify track IDs are alphanumeric strings; iTunes IDs are numeric
        # Beatport IDs (beatport_*) are neither — skip them for external ID tagging
        track_id = str(track_info['id'])
        if track_id.isdigit():
            metadata['itunes_track_id'] = track_id
        elif not track_id.startswith('beatport_'):
            metadata['spotify_track_id'] = track_id
    if artist.get('id'):
        artist_id = str(artist['id'])
        if artist_id.isdigit():
            metadata['itunes_artist_id'] = artist_id
        elif not artist_id.startswith('beatport_'):
            metadata['spotify_artist_id'] = artist_id
    if spotify_album and spotify_album.get('id'):
        album_id = str(spotify_album['id'])
        if album_id.isdigit():
            metadata['itunes_album_id'] = album_id
        elif not album_id.startswith('beatport_'):
            metadata['spotify_album_id'] = album_id

    # Summary log for debugging metadata issues (e.g. wrong album_artist / track_number)
    print(f"[Metadata Summary] title='{metadata.get('title')}' | artist='{metadata.get('artist')}' | album_artist='{metadata.get('album_artist')}' | album='{metadata.get('album')}' | track={metadata.get('track_number')}/{metadata.get('total_tracks')} | disc={metadata.get('disc_number')}")

    return metadata

def _get_image_dimensions(data: bytes):
    """Extract width/height from JPEG or PNG image data without PIL."""
    try:
        if data[:8] == b'\x89PNG\r\n\x1a\n':
            # PNG: width and height at bytes 16-23
            import struct
            w, h = struct.unpack('>II', data[16:24])
            return w, h
        if data[:2] == b'\xff\xd8':
            # JPEG: scan for SOF0/SOF2 marker
            import struct
            i = 2
            while i < len(data) - 9:
                if data[i] != 0xFF:
                    break
                marker = data[i + 1]
                if marker in (0xC0, 0xC2):
                    h, w = struct.unpack('>HH', data[i + 5:i + 9])
                    return w, h
                length = struct.unpack('>H', data[i + 2:i + 4])[0]
                i += 2 + length
    except Exception:
        pass
    return None, None


def _embed_album_art_metadata(audio_file, metadata: dict):
    """Downloads and embeds album art — tries Cover Art Archive (full resolution)
    first if MusicBrainz release ID is available, falls back to Spotify/iTunes URL."""
    try:
        image_data = None
        mime_type = None

        # Try Cover Art Archive first (often 1200x1200+, original quality) — opt-in
        release_mbid = metadata.get('musicbrainz_release_id')
        if release_mbid and config_manager.get('metadata_enhancement.prefer_caa_art', False):
            try:
                caa_url = f"https://coverartarchive.org/release/{release_mbid}/front"
                req = urllib.request.Request(caa_url, headers={'Accept': 'image/*'})
                with urllib.request.urlopen(req, timeout=10) as response:
                    image_data = response.read()
                    mime_type = response.info().get_content_type() or 'image/jpeg'
                if image_data and len(image_data) > 1000:
                    print(f"Cover art from Cover Art Archive ({len(image_data) // 1024}KB)")
                else:
                    image_data = None  # Too small, likely an error page
            except Exception:
                image_data = None  # Fall through to Spotify/iTunes URL

        # Fallback to Spotify/iTunes/Deezer URL (typically 640x640)
        if not image_data:
            art_url = metadata.get('album_art_url')
            if not art_url:
                print("No album art URL available for embedding.")
                return
            with urllib.request.urlopen(art_url, timeout=10) as response:
                image_data = response.read()
                mime_type = response.info().get_content_type()

        if not image_data:
            print("Failed to download album art data.")
            return

        # MP3 (ID3)
        if isinstance(audio_file.tags, ID3):
            audio_file.tags.add(APIC(encoding=3, mime=mime_type, type=3, desc='Cover', data=image_data))
        # FLAC
        elif isinstance(audio_file, FLAC):
            picture = Picture()
            picture.data = image_data
            picture.type = 3
            picture.mime = mime_type
            # Detect actual dimensions from image data
            _img_w, _img_h = _get_image_dimensions(image_data)
            picture.width = _img_w or 640
            picture.height = _img_h or 640
            picture.depth = 24
            audio_file.add_picture(picture)
        # MP4/M4A
        elif isinstance(audio_file, MP4):
            fmt = MP4Cover.FORMAT_JPEG if 'jpeg' in mime_type else MP4Cover.FORMAT_PNG
            audio_file['covr'] = [MP4Cover(image_data, imageformat=fmt)]
        
        print("Album art successfully embedded.")
    except Exception as e:
        print(f"Error embedding album art: {e}")

def _embed_source_ids(audio_file, metadata: dict):
    """
    Lookup MusicBrainz, Deezer, AudioDB, Tidal, Qobuz, Last.fm, and Genius
    metadata, then embed them along with Spotify/iTunes source IDs as custom
    tags into the audio file.
    Tags written: source IDs, BPM (Deezer), mood/style (AudioDB), ISRC
    (MB→Deezer→Tidal→Qobuz fallback), copyright (Tidal→Qobuz),
    label (Qobuz), URLs (Last.fm/Genius),
    and merged genres (Spotify+MB+AudioDB+Last.fm).
    One file write, one shot.  Concurrent calls are safe — each service has
    its own global rate limiter.
    Operates on a non-easy-mode MutagenFile object (caller must save).
    """
    try:
        # ── Per-tag config: maps internal tag name → config path ──
        # Each tag can be individually toggled via {service}.tags.{tag_name}
        _TAG_CONFIG = {
            # Spotify (from metadata, no API call)
            'SPOTIFY_TRACK_ID': 'spotify.tags.track_id',
            'SPOTIFY_ARTIST_ID': 'spotify.tags.artist_id',
            'SPOTIFY_ALBUM_ID': 'spotify.tags.album_id',
            # iTunes (from metadata, no API call)
            'ITUNES_TRACK_ID': 'itunes.tags.track_id',
            'ITUNES_ARTIST_ID': 'itunes.tags.artist_id',
            'ITUNES_ALBUM_ID': 'itunes.tags.album_id',
            # MusicBrainz IDs
            'MUSICBRAINZ_RECORDING_ID': 'musicbrainz.tags.recording_id',
            'MUSICBRAINZ_ARTIST_ID': 'musicbrainz.tags.artist_id',
            'MUSICBRAINZ_RELEASE_ID': 'musicbrainz.tags.release_id',
            'MUSICBRAINZ_RELEASEGROUPID': 'musicbrainz.tags.release_group_id',
            'MUSICBRAINZ_ALBUMARTISTID': 'musicbrainz.tags.album_artist_id',
            'MUSICBRAINZ_RELEASETRACKID': 'musicbrainz.tags.release_track_id',
            # MusicBrainz Release Info
            'RELEASETYPE': 'musicbrainz.tags.release_type',
            'ORIGINALDATE': 'musicbrainz.tags.original_date',
            'RELEASESTATUS': 'musicbrainz.tags.release_status',
            'RELEASECOUNTRY': 'musicbrainz.tags.release_country',
            'BARCODE': 'musicbrainz.tags.barcode',
            'MEDIA': 'musicbrainz.tags.media',
            'TOTALDISCS': 'musicbrainz.tags.total_discs',
            'CATALOGNUMBER': 'musicbrainz.tags.catalog_number',
            'SCRIPT': 'musicbrainz.tags.script',
            'ASIN': 'musicbrainz.tags.asin',
            # Deezer
            'DEEZER_TRACK_ID': 'deezer.tags.track_id',
            'DEEZER_ARTIST_ID': 'deezer.tags.artist_id',
            # AudioDB
            'AUDIODB_TRACK_ID': 'audiodb.tags.track_id',
            # Tidal
            'TIDAL_TRACK_ID': 'tidal.tags.track_id',
            'TIDAL_ARTIST_ID': 'tidal.tags.artist_id',
            # Qobuz
            'QOBUZ_TRACK_ID': 'qobuz.tags.track_id',
            'QOBUZ_ARTIST_ID': 'qobuz.tags.artist_id',
            # Genius
            'GENIUS_TRACK_ID': 'genius.tags.track_id',
        }

        def _tag_enabled(config_path):
            """Check if an individual tag is enabled (defaults to True)."""
            return config_manager.get(config_path, True) is not False

        # ── Helper: normalize + compare names (same logic as enrichment workers) ──
        from difflib import SequenceMatcher
        def _names_match(a: str, b: str, threshold: float = 0.75) -> bool:
            if not a or not b:
                return False
            norm = lambda s: re.sub(r'[^a-z0-9 ]', '', re.sub(r'\(.*?\)', '', s).lower()).strip()
            return SequenceMatcher(None, norm(a), norm(b)).ratio() >= threshold

        # ── 1. Collect Spotify / iTunes IDs already in metadata ──
        id_tags = {}
        if config_manager.get('spotify.embed_tags', True) is not False:
            if metadata.get('spotify_track_id'):
                id_tags['SPOTIFY_TRACK_ID'] = metadata['spotify_track_id']
            if metadata.get('spotify_artist_id'):
                id_tags['SPOTIFY_ARTIST_ID'] = metadata['spotify_artist_id']
            if metadata.get('spotify_album_id'):
                id_tags['SPOTIFY_ALBUM_ID'] = metadata['spotify_album_id']
        if config_manager.get('itunes.embed_tags', True) is not False:
            if metadata.get('itunes_track_id'):
                id_tags['ITUNES_TRACK_ID'] = metadata['itunes_track_id']
            if metadata.get('itunes_artist_id'):
                id_tags['ITUNES_ARTIST_ID'] = metadata['itunes_artist_id']
            if metadata.get('itunes_album_id'):
                id_tags['ITUNES_ALBUM_ID'] = metadata['itunes_album_id']

        # Shared post-processing context for modular lookups
        track_title = metadata.get('title', '')
        artist_name = metadata.get('album_artist', '') or metadata.get('artist', '')
        pp = {
            'id_tags': id_tags,
            'track_title': track_title,
            'artist_name': artist_name,
            'metadata': metadata,
            'recording_mbid': None,
            'artist_mbid': None,
            'release_mbid': '',
            'mb_genres': [],
            'isrc': None,
            'deezer_bpm': None, 'deezer_isrc': None,
            'audiodb_mood': None, 'audiodb_style': None, 'audiodb_genre': None,
            'tidal_isrc': None, 'tidal_copyright': None,
            'qobuz_isrc': None, 'qobuz_copyright': None, 'qobuz_label': None,
            'lastfm_tags': [], 'lastfm_url': None,
            'genius_url': None,
            'release_year': None,  # First source to find a year wins
        }

        # Run each metadata source lookup in configured order
        _pp_source_order = config_manager.get('metadata_enhancement.post_process_order', None)
        if not _pp_source_order or not isinstance(_pp_source_order, list):
            _pp_source_order = ['musicbrainz', 'deezer', 'audiodb', 'tidal', 'qobuz', 'lastfm', 'genius']

        _pp_lookup_map = {
            'musicbrainz': _pp_lookup_musicbrainz,
            'deezer': _pp_lookup_deezer,
            'audiodb': _pp_lookup_audiodb,
            'tidal': _pp_lookup_tidal,
            'qobuz': _pp_lookup_qobuz,
            'lastfm': _pp_lookup_lastfm,
            'genius': _pp_lookup_genius,
        }

        for source_name in _pp_source_order:
            fn = _pp_lookup_map.get(source_name)
            if fn:
                fn(pp, _names_match)

        # Extract results from shared context after all lookups
        recording_mbid = pp['recording_mbid']
        artist_mbid = pp['artist_mbid']
        _rc_mbid = pp['release_mbid']
        mb_genres = pp['mb_genres']
        isrc = pp['isrc']
        deezer_bpm = pp['deezer_bpm']
        deezer_isrc = pp['deezer_isrc']
        audiodb_mood = pp['audiodb_mood']
        audiodb_style = pp['audiodb_style']
        audiodb_genre = pp['audiodb_genre']
        tidal_isrc = pp['tidal_isrc']
        tidal_copyright = pp['tidal_copyright']
        qobuz_isrc = pp['qobuz_isrc']
        qobuz_copyright = pp['qobuz_copyright']
        qobuz_label = pp['qobuz_label']
        lastfm_tags = pp['lastfm_tags']
        lastfm_url = pp['lastfm_url']
        genius_url = pp['genius_url']
        id_tags = pp['id_tags']
        release_year = pp['release_year']

        # If metadata already has a date from Spotify context, use that as fallback
        if not release_year and metadata.get('date'):
            yr = str(metadata['date'])[:4]
            if yr.isdigit():
                release_year = yr

        # Store release MBID in metadata for downstream use (e.g. Cover Art Archive)
        if _rc_mbid:
            metadata['musicbrainz_release_id'] = _rc_mbid

        # Write release year to file tags if not already present
        if release_year and 'ORIGINALDATE' not in id_tags:
            id_tags['ORIGINALDATE'] = release_year
        # If the file was written without a date tag, flag it for writing below
        _needs_date_tag = release_year and not metadata.get('date')
        if _needs_date_tag:
            metadata['date'] = release_year

        # Update DB album year if currently missing
        if release_year:
            try:
                _pp_album_name = metadata.get('album', '')
                _pp_artist_name = metadata.get('album_artist', '') or metadata.get('artist', '')
                if _pp_album_name and _pp_artist_name:
                    conn = database._get_connection()
                    try:
                        cursor = conn.cursor()
                        cursor.execute("""
                            UPDATE albums SET year = ?
                            WHERE (year IS NULL OR year = 0)
                              AND id IN (
                                SELECT al.id FROM albums al
                                JOIN artists ar ON ar.id = al.artist_id
                                WHERE LOWER(al.title) = LOWER(?) AND LOWER(ar.name) = LOWER(?)
                              )
                        """, (int(release_year), _pp_album_name, _pp_artist_name))
                        if cursor.rowcount > 0:
                            conn.commit()
                            print(f"Updated album year to {release_year} in database")
                        else:
                            conn.rollback()
                    finally:
                        conn.close()
            except Exception as e:
                print(f"Could not update album year in DB: {e}")

        # (All source lookups now handled by _pp_lookup_* functions called via configurable order above)
        if False:  # Dead code — old inline blocks preserved for reference during transition
            try:
                mb_service_for_detail = mb_worker.mb_service if mb_worker else None
                if mb_service_for_detail:
                    with _mb_release_detail_cache_lock:
                        release_detail = _mb_release_detail_cache.get(_rc_mbid)
                    if release_detail is None:
                        release_detail = mb_service_for_detail.mb_client.get_release(
                            _rc_mbid, includes=['release-groups', 'labels', 'media', 'artist-credits', 'recordings']
                        ) or {}
                        with _mb_release_detail_cache_lock:
                            _mb_release_detail_cache[_rc_mbid] = release_detail
                    if release_detail:
                        rg = release_detail.get('release-group', {})
                        if rg.get('id'):
                            id_tags['MUSICBRAINZ_RELEASEGROUPID'] = rg['id']
                        ac = release_detail.get('artist-credit', [])
                        if ac and isinstance(ac[0], dict):
                            aa_artist = ac[0].get('artist', {})
                            if aa_artist.get('id'):
                                id_tags['MUSICBRAINZ_ALBUMARTISTID'] = aa_artist['id']
                        primary_type = rg.get('primary-type', '')
                        if primary_type:
                            id_tags['RELEASETYPE'] = primary_type
                        orig_date = rg.get('first-release-date', '')
                        if orig_date:
                            id_tags['ORIGINALDATE'] = orig_date
                        status = release_detail.get('status', '')
                        if status:
                            id_tags['RELEASESTATUS'] = status
                        country = release_detail.get('country', '')
                        if country:
                            id_tags['RELEASECOUNTRY'] = country
                        barcode = release_detail.get('barcode', '')
                        if barcode:
                            id_tags['BARCODE'] = barcode
                        media_list = release_detail.get('media', [])
                        if media_list:
                            media_format = media_list[0].get('format', '')
                            if media_format:
                                id_tags['MEDIA'] = media_format
                            id_tags['TOTALDISCS'] = str(len(media_list))
                        label_info = release_detail.get('label-info', [])
                        if label_info and isinstance(label_info[0], dict):
                            cat_num = label_info[0].get('catalog-number', '')
                            if cat_num:
                                id_tags['CATALOGNUMBER'] = cat_num
                        text_rep = release_detail.get('text-representation', {})
                        if isinstance(text_rep, dict) and text_rep.get('script'):
                            id_tags['SCRIPT'] = text_rep['script']
                        asin = release_detail.get('asin', '')
                        if asin:
                            id_tags['ASIN'] = asin
                        # Release Track ID — match by disc + track position
                        _trk_num = metadata.get('track_number')
                        _disc_num = metadata.get('disc_number') or 1
                        if _trk_num and media_list:
                            try:
                                _trk_num_int = int(_trk_num)
                                _disc_num_int = int(_disc_num)
                                for medium in media_list:
                                    if medium.get('position', 1) == _disc_num_int:
                                        for mtrack in (medium.get('tracks') or medium.get('track-list', [])):
                                            if mtrack.get('position') == _trk_num_int and mtrack.get('id'):
                                                id_tags['MUSICBRAINZ_RELEASETRACKID'] = mtrack['id']
                                                break
                                        break
                            except (ValueError, TypeError):
                                pass
                        print(f"MusicBrainz release details: type={primary_type or '?'}, "
                              f"country={country or '?'}, media={id_tags.get('MEDIA', '?')}")
            except Exception as e:
                print(f"MusicBrainz release detail lookup failed (non-fatal): {e}")

        # ── 2b. Deezer lookup for BPM, ISRC fallback, and source IDs ──
        deezer_bpm = None
        deezer_isrc = None
        if not config_manager.get('deezer.embed_tags', True):
            pass
        elif track_title and artist_name:
            try:
                dz_client = deezer_worker.client if deezer_worker else None
                if dz_client:
                    dz_result = dz_client.search_track(artist_name, track_title)
                    if dz_result and _names_match(dz_result.get('title', ''), track_title) and \
                       _names_match(dz_result.get('artist', {}).get('name', ''), artist_name):
                        dz_track_id = dz_result['id']
                        id_tags['DEEZER_TRACK_ID'] = str(dz_track_id)
                        dz_artist_id = dz_result.get('artist', {}).get('id')
                        if dz_artist_id:
                            id_tags['DEEZER_ARTIST_ID'] = str(dz_artist_id)
                        print(f"Deezer track matched: {dz_track_id}")

                        # Get full track details for BPM and ISRC
                        dz_details = dz_client.get_track_details(dz_track_id)
                        if dz_details:
                            bpm_val = dz_details.get('bpm')
                            if bpm_val and bpm_val > 0:
                                deezer_bpm = bpm_val
                            dz_isrc = dz_details.get('isrc')
                            if dz_isrc:
                                deezer_isrc = dz_isrc
                else:
                    print("Deezer worker not available, skipping Deezer lookup")
            except Exception as e:
                print(f"Deezer lookup failed (non-fatal): {e}")

        # ── 2c. AudioDB lookup for mood, style, genre, and source ID ──
        audiodb_mood = None
        audiodb_style = None
        audiodb_genre = None
        if not config_manager.get('audiodb.embed_tags', True):
            pass
        elif track_title and artist_name:
            try:
                adb_client = audiodb_worker.client if audiodb_worker else None
                if adb_client:
                    adb_result = adb_client.search_track(artist_name, track_title)
                    if adb_result and _names_match(adb_result.get('strTrack', ''), track_title) and \
                       _names_match(adb_result.get('strArtist', ''), artist_name):
                        adb_track_id = adb_result.get('idTrack')
                        if adb_track_id:
                            id_tags['AUDIODB_TRACK_ID'] = str(adb_track_id)
                            print(f"AudioDB track matched: {adb_track_id}")
                        # Use AudioDB's MusicBrainz IDs as fallbacks for any missing from MB lookup
                        adb_mb_track = adb_result.get('strMusicBrainzID')
                        if adb_mb_track and 'MUSICBRAINZ_RECORDING_ID' not in id_tags:
                            id_tags['MUSICBRAINZ_RECORDING_ID'] = adb_mb_track
                            recording_mbid = adb_mb_track
                            print(f"MusicBrainz recording ID from AudioDB fallback: {adb_mb_track}")
                        # NOTE: AudioDB's strMusicBrainzAlbumID is intentionally
                        # NOT used as a fallback for MUSICBRAINZ_RELEASE_ID.
                        # AudioDB links each track to its original album in MB,
                        # which differs per track on compilations and splits
                        # albums in players like Navidrome. Album MBID must come
                        # from match_release (cached) to stay consistent.
                        adb_mb_artist = adb_result.get('strMusicBrainzArtistID')
                        if adb_mb_artist and 'MUSICBRAINZ_ARTIST_ID' not in id_tags:
                            id_tags['MUSICBRAINZ_ARTIST_ID'] = adb_mb_artist
                            artist_mbid = adb_mb_artist
                            print(f"MusicBrainz artist ID from AudioDB fallback: {adb_mb_artist}")
                        audiodb_mood = adb_result.get('strMood') or None
                        audiodb_style = adb_result.get('strStyle') or None
                        audiodb_genre = adb_result.get('strGenre') or None
                else:
                    print("AudioDB worker not available, skipping AudioDB lookup")
            except Exception as e:
                print(f"AudioDB lookup failed (non-fatal): {e}")

        # ── 2d. Tidal lookup for ISRC fallback, copyright, and source IDs ──
        tidal_isrc = None
        tidal_copyright = None
        if not config_manager.get('tidal.embed_tags', True):
            pass
        elif track_title and artist_name:
            try:
                if tidal_client and tidal_client.is_authenticated():
                    td_result = tidal_client.search_track(artist_name, track_title)
                    if td_result and _names_match(td_result.get('title', ''), track_title):
                        td_track_id = td_result.get('id')
                        if td_track_id:
                            id_tags['TIDAL_TRACK_ID'] = str(td_track_id)
                            print(f"Tidal track matched: {td_track_id}")
                        td_artist = td_result.get('artist', {})
                        if isinstance(td_artist, dict) and td_artist.get('id'):
                            id_tags['TIDAL_ARTIST_ID'] = str(td_artist['id'])
                        # Get full details for ISRC and copyright
                        if td_track_id:
                            td_details = tidal_client.get_track(str(td_track_id))
                            if td_details:
                                td_isrc = td_details.get('isrc')
                                if td_isrc:
                                    tidal_isrc = td_isrc
                                td_copyright = td_details.get('copyright')
                                if isinstance(td_copyright, dict):
                                    td_copyright = td_copyright.get('text', td_copyright.get('name', ''))
                                if td_copyright:
                                    tidal_copyright = td_copyright
            except Exception as e:
                print(f"Tidal lookup failed (non-fatal): {e}")

        # ── 2e. Qobuz lookup for ISRC fallback, copyright, label, and source IDs ──
        qobuz_isrc = None
        qobuz_copyright = None
        qobuz_label = None
        if not config_manager.get('qobuz.embed_tags', True):
            pass
        elif track_title and artist_name:
            try:
                qz_client = qobuz_enrichment_worker.client if qobuz_enrichment_worker else None
                if qz_client and qz_client.is_authenticated():
                    qz_result = qz_client.search_track(artist_name, track_title)
                    if qz_result:
                        qz_performer = (qz_result.get('performer') or {})
                        if not isinstance(qz_performer, dict):
                            qz_performer = {}
                        qz_artist_name = qz_performer.get('name', '')
                        if _names_match(qz_result.get('title', ''), track_title) and \
                           _names_match(qz_artist_name, artist_name):
                            qz_track_id = qz_result.get('id')
                            if qz_track_id:
                                id_tags['QOBUZ_TRACK_ID'] = str(qz_track_id)
                                print(f"Qobuz track matched: {qz_track_id}")
                            if isinstance(qz_performer, dict) and qz_performer.get('id'):
                                id_tags['QOBUZ_ARTIST_ID'] = str(qz_performer['id'])
                            qz_isrc = qz_result.get('isrc')
                            if isinstance(qz_isrc, dict):
                                qz_isrc = qz_isrc.get('value', qz_isrc.get('id', ''))
                            if qz_isrc:
                                qobuz_isrc = qz_isrc
                            qz_copyright = qz_result.get('copyright')
                            if isinstance(qz_copyright, dict):
                                qz_copyright = qz_copyright.get('text', qz_copyright.get('name', ''))
                            if qz_copyright and isinstance(qz_copyright, str):
                                qobuz_copyright = qz_copyright
                            qz_album = qz_result.get('album', {})
                            if isinstance(qz_album, dict):
                                qz_label_info = qz_album.get('label', {})
                                if isinstance(qz_label_info, dict) and qz_label_info.get('name'):
                                    qobuz_label = qz_label_info['name']
            except Exception as e:
                print(f"Qobuz lookup failed (non-fatal): {e}")

        # ── 2f. Last.fm lookup for tags (genre merge) and URL ──
        lastfm_tags = []
        lastfm_url = None
        if not config_manager.get('lastfm.embed_tags', True):
            pass
        elif track_title and artist_name:
            try:
                lf_client = lastfm_worker.client if lastfm_worker else None
                if lf_client:
                    lf_result = lf_client.get_track_info(artist_name, track_title)
                    if lf_result:
                        lf_url = lf_result.get('url')
                        if lf_url:
                            lastfm_url = lf_url
                        lf_toptags = lf_result.get('toptags', {})
                        if isinstance(lf_toptags, dict):
                            tag_list = lf_toptags.get('tag', [])
                            if isinstance(tag_list, list):
                                lastfm_tags = [t.get('name', '') for t in tag_list if isinstance(t, dict) and t.get('name')]
                            elif isinstance(tag_list, dict) and tag_list.get('name'):
                                lastfm_tags = [tag_list['name']]
                        print(f"Last.fm track info found: {len(lastfm_tags)} tags")
            except Exception as e:
                print(f"Last.fm lookup failed (non-fatal): {e}")

        # ── 2g. Genius lookup for source ID and URL ──
        # Genius has an aggressive global rate limiter (30→60→120s backoff) that
        # blocks ALL callers including post-processing. We check the backoff
        # state directly and skip immediately if Genius is rate-limited, rather
        # than entering search_song which would sleep for up to 120s.
        genius_url = None
        if not config_manager.get('genius.embed_tags', True):
            pass
        elif track_title and artist_name:
            try:
                import core.genius_client as _genius_module
                if time.time() < _genius_module._rate_limit_until:
                    print("Genius rate-limited, skipping (non-blocking)")
                else:
                    g_client = genius_worker.client if genius_worker else None
                    if g_client:
                        g_result = g_client.search_song(artist_name, track_title)
                        if g_result:
                            g_id = g_result.get('id')
                            if g_id:
                                id_tags['GENIUS_TRACK_ID'] = str(g_id)
                                print(f"Genius song matched: {g_id}")
                            g_url = g_result.get('url')
                            if g_url:
                                genius_url = g_url
            except Exception as e:
                print(f"Genius lookup failed (non-fatal): {e}")

        if not id_tags and not deezer_bpm and not deezer_isrc and not audiodb_mood and not audiodb_style:
            return

        # ── 3. Filter tags by per-tag config, then write ──
        filtered_tags = {}
        for tag_name, value in id_tags.items():
            config_path = _TAG_CONFIG.get(tag_name)
            if config_path and not _tag_enabled(config_path):
                continue
            filtered_tags[tag_name] = value

        # ── 3a. Write ID tags (MusicBrainz, source IDs, release info) ──
        written = []

        # Format-specific tag name mappings for Picard-compatible output
        _ID3_TAG_MAP = {
            'MUSICBRAINZ_RECORDING_ID': ('UFID', 'http://musicbrainz.org'),
            'MUSICBRAINZ_ARTIST_ID': ('TXXX', 'MusicBrainz Artist Id'),
            'MUSICBRAINZ_RELEASE_ID': ('TXXX', 'MusicBrainz Album Id'),
            'MUSICBRAINZ_RELEASEGROUPID': ('TXXX', 'MusicBrainz Release Group Id'),
            'MUSICBRAINZ_ALBUMARTISTID': ('TXXX', 'MusicBrainz Album Artist Id'),
            'MUSICBRAINZ_RELEASETRACKID': ('TXXX', 'MusicBrainz Release Track Id'),
            'RELEASETYPE': ('TXXX', 'MusicBrainz Album Type'),
            'RELEASESTATUS': ('TXXX', 'MusicBrainz Album Status'),
            'RELEASECOUNTRY': ('TXXX', 'MusicBrainz Album Release Country'),
            'ORIGINALDATE': ('TDOR', None),
            'MEDIA': ('TMED', None),
        }
        _VORBIS_TAG_MAP = {
            'MUSICBRAINZ_RECORDING_ID': 'MUSICBRAINZ_TRACKID',
            'MUSICBRAINZ_ARTIST_ID': 'MUSICBRAINZ_ARTISTID',
            'MUSICBRAINZ_RELEASE_ID': 'MUSICBRAINZ_ALBUMID',
            'MUSICBRAINZ_RELEASEGROUPID': 'MUSICBRAINZ_RELEASEGROUPID',
            'MUSICBRAINZ_ALBUMARTISTID': 'MUSICBRAINZ_ALBUMARTISTID',
            'MUSICBRAINZ_RELEASETRACKID': 'MUSICBRAINZ_RELEASETRACKID',
        }
        _MP4_TAG_MAP = {
            'MUSICBRAINZ_RECORDING_ID': 'MusicBrainz Track Id',
            'MUSICBRAINZ_ARTIST_ID': 'MusicBrainz Artist Id',
            'MUSICBRAINZ_RELEASE_ID': 'MusicBrainz Album Id',
            'MUSICBRAINZ_RELEASEGROUPID': 'MusicBrainz Release Group Id',
            'MUSICBRAINZ_ALBUMARTISTID': 'MusicBrainz Album Artist Id',
            'MUSICBRAINZ_RELEASETRACKID': 'MusicBrainz Release Track Id',
            'RELEASETYPE': 'MusicBrainz Album Type',
            'RELEASESTATUS': 'MusicBrainz Album Status',
            'RELEASECOUNTRY': 'MusicBrainz Album Release Country',
        }

        # MP3 (ID3)
        if isinstance(audio_file.tags, ID3):
            for tag_name, value in filtered_tags.items():
                id3_spec = _ID3_TAG_MAP.get(tag_name)
                if id3_spec:
                    frame_type, desc = id3_spec
                    if frame_type == 'UFID':
                        audio_file.tags.add(UFID(owner=desc, data=value.encode('ascii')))
                        written.append(f'UFID:{desc}')
                    elif frame_type == 'TDOR':
                        audio_file.tags.add(TDOR(encoding=3, text=[value]))
                        written.append('TDOR')
                    elif frame_type == 'TMED':
                        audio_file.tags.add(TMED(encoding=3, text=[value]))
                        written.append('TMED')
                    else:  # TXXX
                        audio_file.tags.add(TXXX(encoding=3, desc=desc, text=[value]))
                        written.append(f'TXXX:{desc}')
                else:
                    audio_file.tags.add(TXXX(encoding=3, desc=tag_name, text=[str(value)]))
                    written.append(f'TXXX:{tag_name}')

        # FLAC / OGG Vorbis
        elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
            for tag_name, value in filtered_tags.items():
                vorbis_key = _VORBIS_TAG_MAP.get(tag_name, tag_name)
                audio_file[vorbis_key] = [str(value)]
                written.append(vorbis_key)

        # MP4 (M4A/AAC)
        elif isinstance(audio_file, MP4):
            for tag_name, value in filtered_tags.items():
                mp4_desc = _MP4_TAG_MAP.get(tag_name, tag_name)
                key = f'----:com.apple.iTunes:{mp4_desc}'
                audio_file[key] = [MP4FreeForm(str(value).encode('utf-8'))]
                written.append(key)

        if written:
            print(f"Embedded IDs: {', '.join(written)}")

        # ── 3a½. Write date tag if discovered during lookups (initial write had no date) ──
        if _needs_date_tag and release_year:
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TDRC(encoding=3, text=[release_year]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['date'] = [release_year]
            elif isinstance(audio_file, MP4):
                audio_file['\xa9day'] = [release_year]
            print(f"Date tag: {release_year}")

        # ── 3b. Write BPM tag (from Deezer) ──
        if _tag_enabled('deezer.tags.bpm') and deezer_bpm and deezer_bpm > 0:
            bpm_int = int(deezer_bpm)
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TBPM(encoding=3, text=[str(bpm_int)]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['BPM'] = [str(bpm_int)]
            elif isinstance(audio_file, MP4):
                audio_file['tmpo'] = [bpm_int]
            print(f"BPM: {bpm_int}")

        # ── 3c. Write mood tag (from AudioDB) ──
        if _tag_enabled('audiodb.tags.mood') and audiodb_mood:
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TXXX(encoding=3, desc='MOOD', text=[audiodb_mood]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['MOOD'] = [audiodb_mood]
            elif isinstance(audio_file, MP4):
                audio_file['----:com.apple.iTunes:MOOD'] = [MP4FreeForm(audiodb_mood.encode('utf-8'))]
            print(f"Mood: {audiodb_mood}")

        # ── 3d. Write style tag (from AudioDB) ──
        if _tag_enabled('audiodb.tags.style') and audiodb_style:
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TXXX(encoding=3, desc='STYLE', text=[audiodb_style]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['STYLE'] = [audiodb_style]
            elif isinstance(audio_file, MP4):
                audio_file['----:com.apple.iTunes:STYLE'] = [MP4FreeForm(audiodb_style.encode('utf-8'))]
            print(f"Style: {audiodb_style}")

        # ── 4. Merge genres (Spotify + MusicBrainz + AudioDB + Last.fm) and overwrite tag ──
        if _tag_enabled('metadata_enhancement.tags.genre_merge'):
            enrichment_genres = (mb_genres if _tag_enabled('musicbrainz.tags.genres') else []) + \
                                ([audiodb_genre] if audiodb_genre and _tag_enabled('audiodb.tags.genre') else []) + \
                                (lastfm_tags if _tag_enabled('lastfm.tags.genres') else [])
            if enrichment_genres:
                spotify_genres = [g.strip() for g in metadata.get('genre', '').split(',') if g.strip()]
                seen = set()
                merged = []
                for g in spotify_genres + enrichment_genres:
                    key = g.strip().lower()
                    if key and key not in seen:
                        seen.add(key)
                        merged.append(g.strip().title())
                    if len(merged) >= 5:
                        break

                if merged:
                    genre_string = ', '.join(merged)
                    if isinstance(audio_file.tags, ID3):
                        audio_file.tags.add(TCON(encoding=3, text=[genre_string]))
                    elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                        audio_file['GENRE'] = [genre_string]
                    elif isinstance(audio_file, MP4):
                        audio_file['\xa9gen'] = [genre_string]
                    print(f"Genres merged: {genre_string}")

        # ── 5. Write ISRC if available (per-source fallback chain) ──
        _isrc_candidates = []
        if isrc and _tag_enabled('musicbrainz.tags.isrc'):
            _isrc_candidates.append(('MusicBrainz', isrc))
        if deezer_isrc and _tag_enabled('deezer.tags.isrc'):
            _isrc_candidates.append(('Deezer', deezer_isrc))
        if tidal_isrc and _tag_enabled('tidal.tags.isrc'):
            _isrc_candidates.append(('Tidal', tidal_isrc))
        if qobuz_isrc and _tag_enabled('qobuz.tags.isrc'):
            _isrc_candidates.append(('Qobuz', qobuz_isrc))
        if _isrc_candidates:
            source, final_isrc = _isrc_candidates[0]
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TSRC(encoding=3, text=[final_isrc]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['ISRC'] = [final_isrc]
            elif isinstance(audio_file, MP4):
                audio_file['----:com.apple.iTunes:ISRC'] = [MP4FreeForm(final_isrc.encode('utf-8'))]
            print(f"ISRC ({source}): {final_isrc}")

        # ── 6. Write copyright tag (Tidal → Qobuz fallback) ──
        _copyright_candidates = []
        if tidal_copyright and _tag_enabled('tidal.tags.copyright'):
            _copyright_candidates.append(('Tidal', tidal_copyright))
        if qobuz_copyright and _tag_enabled('qobuz.tags.copyright'):
            _copyright_candidates.append(('Qobuz', qobuz_copyright))
        if _copyright_candidates:
            source, final_copyright = _copyright_candidates[0]
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TCOP(encoding=3, text=[final_copyright]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['COPYRIGHT'] = [final_copyright]
            elif isinstance(audio_file, MP4):
                audio_file['cprt'] = [final_copyright]
            print(f"©️ Copyright ({source}): {final_copyright[:60]}")

        # ── 7. Write label/publisher tag (from Qobuz) ──
        if _tag_enabled('qobuz.tags.label') and qobuz_label:
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TPUB(encoding=3, text=[qobuz_label]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['LABEL'] = [qobuz_label]
            elif isinstance(audio_file, MP4):
                audio_file['----:com.apple.iTunes:LABEL'] = [MP4FreeForm(qobuz_label.encode('utf-8'))]
            print(f"Label (Qobuz): {qobuz_label}")

        # ── 8. Write Last.fm and Genius URLs as custom tags ──
        if _tag_enabled('lastfm.tags.url') and lastfm_url:
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TXXX(encoding=3, desc='LASTFM_URL', text=[lastfm_url]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['LASTFM_URL'] = [lastfm_url]
            elif isinstance(audio_file, MP4):
                audio_file['----:com.apple.iTunes:LASTFM_URL'] = [MP4FreeForm(lastfm_url.encode('utf-8'))]

        if _tag_enabled('genius.tags.url') and genius_url:
            if isinstance(audio_file.tags, ID3):
                audio_file.tags.add(TXXX(encoding=3, desc='GENIUS_URL', text=[genius_url]))
            elif isinstance(audio_file, (FLAC, OggVorbis)) or _is_ogg_opus(audio_file):
                audio_file['GENIUS_URL'] = [genius_url]
            elif isinstance(audio_file, MP4):
                audio_file['----:com.apple.iTunes:GENIUS_URL'] = [MP4FreeForm(genius_url.encode('utf-8'))]

    except Exception as e:
        print(f"Error embedding source IDs (non-fatal): {e}")

def _download_cover_art(album_info: dict, target_dir: str, context: dict = None):
    """Downloads cover.jpg into the specified directory.
    Tries Cover Art Archive first (high-res) if MusicBrainz release ID is available
    (set by _enhance_file_metadata during post-processing), falls back to source URL.
    Accepts optional context to extract image URL from spotify_album when album_info lacks it."""
    if not config_manager.get('metadata_enhancement.cover_art_download', True):
        return
    try:
        cover_path = os.path.join(target_dir, "cover.jpg")
        release_mbid = album_info.get('musicbrainz_release_id') if album_info else None
        prefer_caa = config_manager.get('metadata_enhancement.prefer_caa_art', False)

        # If cover.jpg exists but we now have a CAA MBID, check if we should upgrade
        if os.path.exists(cover_path):
            if release_mbid and prefer_caa:
                try:
                    existing_size = os.path.getsize(cover_path)
                    # Typical Spotify/iTunes cover is ~50-150KB at 640x640
                    # CAA covers are usually 300KB+ at 1200x1200
                    if existing_size > 200_000:
                        return  # Already high-res, skip
                    # Low-res cover exists — try to upgrade from CAA
                    is_upgrade = True
                    print(f"Existing cover.jpg is {existing_size // 1024}KB — attempting CAA upgrade...")
                except Exception:
                    return
            else:
                return
        else:
            is_upgrade = False

        image_data = None

        # Try Cover Art Archive first (often 1200x1200+, original quality) — opt-in
        # The MBID is stored in album_info by _enhance_file_metadata before this is called
        if release_mbid and prefer_caa:
            try:
                caa_url = f"https://coverartarchive.org/release/{release_mbid}/front"
                req = urllib.request.Request(caa_url, headers={'Accept': 'image/*'})
                with urllib.request.urlopen(req, timeout=10) as response:
                    image_data = response.read()
                if image_data and len(image_data) > 1000:
                    print(f"Cover art from Cover Art Archive ({len(image_data) // 1024}KB)")
                else:
                    image_data = None
            except Exception:
                image_data = None

        # If upgrading and CAA failed, keep existing cover — don't overwrite with same low-res
        if is_upgrade and not image_data:
            print(f"CAA upgrade failed — keeping existing cover.jpg")
            return

        # Fallback to Spotify/iTunes/Deezer URL (typically 640x640)
        if not image_data:
            art_url = album_info.get('album_image_url')
            # If album_info lacks the URL, try the context's spotify_album
            if not art_url and context:
                spotify_album = context.get('spotify_album') or {}
                art_url = spotify_album.get('image_url')
                # Also try images array (raw Spotify API format)
                if not art_url:
                    images = spotify_album.get('images', [])
                    if images and isinstance(images, list) and len(images) > 0:
                        art_url = images[0].get('url') if isinstance(images[0], dict) else None
                if art_url:
                    print(f"Using cover art URL from spotify_album context")
            if not art_url:
                print("No cover art URL available for download.")
                return
            with urllib.request.urlopen(art_url, timeout=10) as response:
                image_data = response.read()

        if not image_data:
            return

        with open(cover_path, 'wb') as f:
            f.write(image_data)

        print(f"Cover art downloaded to: {cover_path}")
    except Exception as e:
        print(f"Error downloading cover.jpg: {e}")




def _get_spotify_album_tracks(spotify_album: dict) -> list:
    """Fetches all tracks for a given Spotify album ID."""
    if not spotify_album or not spotify_album.get('id'):
        return []
    try:
        tracks_data = spotify_client.get_album_tracks(spotify_album['id'])
        if tracks_data and 'items' in tracks_data:
            return [{
                'name': item.get('name'),
                'track_number': item.get('track_number'),
                'disc_number': item.get('disc_number', 1),
                'id': item.get('id'),
                'explicit': item.get('explicit', False)
            } for item in tracks_data['items']]
        return []
    except Exception as e:
        print(f"Error fetching Spotify album tracks: {e}")
        return []

def _match_track_to_spotify_title(slsk_track_meta: dict, spotify_tracks: list) -> dict:
    """
    Intelligently matches a Soulseek track to a track from the official Spotify
    tracklist using track numbers and title similarity. Returns the matched Spotify track data.
    """
    if not spotify_tracks:
        return slsk_track_meta # Return original if no list to match against

    # Priority 1: Match by track number
    if slsk_track_meta.get('track_number'):
        track_num = slsk_track_meta['track_number']
        for sp_track in spotify_tracks:
            if sp_track.get('track_number') == track_num:
                print(f"Matched track by number ({track_num}): '{slsk_track_meta['title']}' -> '{sp_track['name']}'")
                # Return a new dict with the corrected title and number
                return {
                    'title': sp_track['name'],
                    'artist': slsk_track_meta.get('artist'),
                    'album': slsk_track_meta.get('album'),
                    'track_number': sp_track['track_number'],
                    'disc_number': sp_track.get('disc_number', 1),
                    'explicit': sp_track.get('explicit', False)
                }

    # Priority 2: Match by title similarity (if track number fails)
    best_match = None
    best_score = 0.6 # Require a decent similarity
    for sp_track in spotify_tracks:
        score = matching_engine.similarity_score(
            matching_engine.normalize_string(slsk_track_meta.get('title', '')),
            matching_engine.normalize_string(sp_track.get('name', ''))
        )
        if score > best_score:
            best_score = score
            best_match = sp_track

    if best_match:
        print(f"Matched track by title similarity ({best_score:.2f}): '{slsk_track_meta['title']}' -> '{best_match['name']}'")
        return {
            'title': best_match['name'],
            'artist': slsk_track_meta.get('artist'),
            'album': slsk_track_meta.get('album'),
            'track_number': best_match['track_number'],
            'disc_number': best_match.get('disc_number', 1),
            'explicit': best_match.get('explicit', False)
        }

    print(f"Could not confidently match track '{slsk_track_meta['title']}'. Using original metadata.")
    return slsk_track_meta # Fallback to original



# --- Post-Processing Logic ---
# ── Modular post-processing metadata lookup functions ──
# Each function receives a shared `pp` context dict and writes its results to it.
# The orchestrator in _post_process_matched_download calls them in configurable order.

def _pp_lookup_musicbrainz(pp, _names_match):
    """MusicBrainz: recording MBID, artist MBID, release MBID, ISRC, genres, release details."""
    if not config_manager.get('musicbrainz.embed_tags', True):
        return
    track_title = pp['track_title']
    artist_name = pp['artist_name']
    metadata = pp['metadata']
    id_tags = pp['id_tags']
    if not track_title or not artist_name:
        return
    try:
        mb_service = mb_worker.mb_service if mb_worker else None
        if not mb_service:
            print("MusicBrainz worker not available, skipping MBID lookup")
            return
        result = mb_service.match_recording(track_title, artist_name)
        if result and result.get('mbid'):
            pp['recording_mbid'] = result['mbid']
            id_tags['MUSICBRAINZ_RECORDING_ID'] = pp['recording_mbid']
            print(f"MusicBrainz recording matched: {pp['recording_mbid']}")
            details = mb_service.mb_client.get_recording(pp['recording_mbid'], includes=['isrcs', 'genres'])
            if details:
                isrcs = details.get('isrcs', [])
                if isrcs:
                    pp['isrc'] = isrcs[0]
                pp['mb_genres'] = [g['name'] for g in sorted(details.get('genres', []), key=lambda x: x.get('count', 0), reverse=True)]

        track_artist_name = metadata.get('artist', '') or artist_name
        if ', ' in track_artist_name:
            track_artist_name = track_artist_name.split(', ')[0]
        artist_result = mb_service.match_artist(track_artist_name)
        if artist_result and artist_result.get('mbid'):
            pp['artist_mbid'] = artist_result['mbid']
            id_tags['MUSICBRAINZ_ARTIST_ID'] = pp['artist_mbid']

        album_name_for_mb = metadata.get('album', '')
        if album_name_for_mb:
            # Use normalized key (strips edition suffixes) so "Album (Deluxe Edition)"
            # and "Album (Deluxe)" and "Album" all share the same cached MBID.
            # This prevents Navidrome from splitting one album into multiple entries.
            _artist_key = artist_name.lower().strip()
            _rc_key_norm = (_normalize_album_cache_key(album_name_for_mb), _artist_key)
            _rc_key_exact = (album_name_for_mb.lower().strip(), _artist_key)
            with _mb_release_cache_lock:
                # Check normalized key first (catches edition variants)
                cached = _mb_release_cache.get(_rc_key_norm)
                if cached is None:
                    cached = _mb_release_cache.get(_rc_key_exact)
                if cached is not None:
                    pp['release_mbid'] = cached
                else:
                    try:
                        _rc_result = mb_service.match_release(album_name_for_mb, artist_name)
                        pp['release_mbid'] = _rc_result.get('mbid', '') if _rc_result else ''
                    except Exception:
                        pp['release_mbid'] = ''
                    # Cache under both normalized and exact keys
                    _mb_release_cache[_rc_key_norm] = pp['release_mbid']
                    _mb_release_cache[_rc_key_exact] = pp['release_mbid']
            if pp['release_mbid']:
                id_tags['MUSICBRAINZ_RELEASE_ID'] = pp['release_mbid']

        # Release details (group, barcode, media, etc.)
        if pp['release_mbid']:
            with _mb_release_detail_cache_lock:
                release_detail = _mb_release_detail_cache.get(pp['release_mbid'])
            if release_detail is None:
                release_detail = mb_service.mb_client.get_release(
                    pp['release_mbid'], includes=['release-groups', 'labels', 'media', 'artist-credits', 'recordings']
                ) or {}
                with _mb_release_detail_cache_lock:
                    _mb_release_detail_cache[pp['release_mbid']] = release_detail
            if release_detail:
                rg = release_detail.get('release-group', {})
                if rg.get('id'): id_tags['MUSICBRAINZ_RELEASEGROUPID'] = rg['id']
                ac = release_detail.get('artist-credit', [])
                if ac and isinstance(ac[0], dict):
                    aa = ac[0].get('artist', {})
                    if aa.get('id'): id_tags['MUSICBRAINZ_ALBUMARTISTID'] = aa['id']
                if rg.get('primary-type'): id_tags['RELEASETYPE'] = rg['primary-type']
                if rg.get('first-release-date'):
                    id_tags['ORIGINALDATE'] = rg['first-release-date']
                    if not pp['release_year'] and len(rg['first-release-date']) >= 4:
                        yr = rg['first-release-date'][:4]
                        if yr.isdigit():
                            pp['release_year'] = yr
                if release_detail.get('status'): id_tags['RELEASESTATUS'] = release_detail['status']
                if release_detail.get('country'): id_tags['RELEASECOUNTRY'] = release_detail['country']
                if release_detail.get('barcode'): id_tags['BARCODE'] = release_detail['barcode']
                media_list = release_detail.get('media', [])
                if media_list:
                    fmt = media_list[0].get('format', '')
                    if fmt: id_tags['MEDIA'] = fmt
                    id_tags['TOTALDISCS'] = str(len(media_list))
                label_info = release_detail.get('label-info', [])
                if label_info and isinstance(label_info[0], dict):
                    cat = label_info[0].get('catalog-number', '')
                    if cat: id_tags['CATALOGNUMBER'] = cat
                text_rep = release_detail.get('text-representation', {})
                if isinstance(text_rep, dict) and text_rep.get('script'):
                    id_tags['SCRIPT'] = text_rep['script']
                if release_detail.get('asin'): id_tags['ASIN'] = release_detail['asin']
                _trk_num = metadata.get('track_number')
                _disc_num = metadata.get('disc_number') or 1
                if _trk_num and media_list:
                    try:
                        _trk_num_int, _disc_num_int = int(_trk_num), int(_disc_num)
                        for medium in media_list:
                            if medium.get('position', 1) == _disc_num_int:
                                for mtrack in (medium.get('tracks') or medium.get('track-list', [])):
                                    if mtrack.get('position') == _trk_num_int and mtrack.get('id'):
                                        id_tags['MUSICBRAINZ_RELEASETRACKID'] = mtrack['id']
                                        break
                                break
                    except (ValueError, TypeError):
                        pass
    except Exception as e:
        print(f"MusicBrainz lookup failed (non-fatal): {e}")


def _pp_lookup_deezer(pp, _names_match):
    """Deezer: BPM, ISRC fallback, track/artist IDs."""
    if not config_manager.get('deezer.embed_tags', True):
        return
    track_title, artist_name = pp['track_title'], pp['artist_name']
    id_tags = pp['id_tags']
    if not track_title or not artist_name:
        return
    try:
        dz_client = deezer_worker.client if deezer_worker else None
        if not dz_client:
            print("Deezer worker not available, skipping Deezer lookup")
            return
        dz_result = dz_client.search_track(artist_name, track_title)
        if dz_result and _names_match(dz_result.get('title', ''), track_title) and \
           _names_match(dz_result.get('artist', {}).get('name', ''), artist_name):
            dz_track_id = dz_result['id']
            id_tags['DEEZER_TRACK_ID'] = str(dz_track_id)
            dz_artist_id = dz_result.get('artist', {}).get('id')
            if dz_artist_id:
                id_tags['DEEZER_ARTIST_ID'] = str(dz_artist_id)
            print(f"Deezer track matched: {dz_track_id}")
            dz_details = dz_client.get_track_details(dz_track_id)
            if dz_details:
                bpm_val = dz_details.get('bpm')
                if bpm_val and bpm_val > 0:
                    pp['deezer_bpm'] = bpm_val
                dz_isrc = dz_details.get('isrc')
                if dz_isrc:
                    pp['deezer_isrc'] = dz_isrc
            # Release year from Deezer album
            if not pp['release_year']:
                dz_album = dz_result.get('album', {})
                dz_release = (dz_album.get('release_date', '') if isinstance(dz_album, dict) else '') or ''
                if len(dz_release) >= 4 and dz_release[:4].isdigit():
                    pp['release_year'] = dz_release[:4]
    except Exception as e:
        print(f"Deezer lookup failed (non-fatal): {e}")


def _pp_lookup_audiodb(pp, _names_match):
    """AudioDB: mood, style, genre, track ID, MusicBrainz ID fallbacks."""
    if not config_manager.get('audiodb.embed_tags', True):
        return
    track_title, artist_name = pp['track_title'], pp['artist_name']
    id_tags = pp['id_tags']
    if not track_title or not artist_name:
        return
    try:
        adb_client = audiodb_worker.client if audiodb_worker else None
        if not adb_client:
            print("AudioDB worker not available, skipping AudioDB lookup")
            return
        adb_result = adb_client.search_track(artist_name, track_title)
        if adb_result and _names_match(adb_result.get('strTrack', ''), track_title) and \
           _names_match(adb_result.get('strArtist', ''), artist_name):
            adb_track_id = adb_result.get('idTrack')
            if adb_track_id:
                id_tags['AUDIODB_TRACK_ID'] = str(adb_track_id)
                print(f"AudioDB track matched: {adb_track_id}")
            adb_mb_track = adb_result.get('strMusicBrainzID')
            if adb_mb_track and 'MUSICBRAINZ_RECORDING_ID' not in id_tags:
                id_tags['MUSICBRAINZ_RECORDING_ID'] = adb_mb_track
                pp['recording_mbid'] = adb_mb_track
                print(f"MusicBrainz recording ID from AudioDB fallback: {adb_mb_track}")
            adb_mb_artist = adb_result.get('strMusicBrainzArtistID')
            if adb_mb_artist and 'MUSICBRAINZ_ARTIST_ID' not in id_tags:
                id_tags['MUSICBRAINZ_ARTIST_ID'] = adb_mb_artist
                pp['artist_mbid'] = adb_mb_artist
                print(f"MusicBrainz artist ID from AudioDB fallback: {adb_mb_artist}")
            pp['audiodb_mood'] = adb_result.get('strMood') or None
            pp['audiodb_style'] = adb_result.get('strStyle') or None
            pp['audiodb_genre'] = adb_result.get('strGenre') or None
    except Exception as e:
        print(f"AudioDB lookup failed (non-fatal): {e}")


def _pp_lookup_tidal(pp, _names_match):
    """Tidal: ISRC fallback, copyright, track/artist IDs."""
    if not config_manager.get('tidal.embed_tags', True):
        return
    track_title, artist_name = pp['track_title'], pp['artist_name']
    id_tags = pp['id_tags']
    if not track_title or not artist_name:
        return
    try:
        if not (tidal_client and tidal_client.is_authenticated()):
            return
        td_result = tidal_client.search_track(artist_name, track_title)
        if td_result and _names_match(td_result.get('title', ''), track_title):
            td_track_id = td_result.get('id')
            if td_track_id:
                id_tags['TIDAL_TRACK_ID'] = str(td_track_id)
                print(f"Tidal track matched: {td_track_id}")
            td_artist = td_result.get('artist', {})
            if isinstance(td_artist, dict) and td_artist.get('id'):
                id_tags['TIDAL_ARTIST_ID'] = str(td_artist['id'])
            if td_track_id:
                td_details = tidal_client.get_track(str(td_track_id))
                if td_details:
                    td_isrc = td_details.get('isrc')
                    if td_isrc:
                        pp['tidal_isrc'] = td_isrc
                    td_copyright = td_details.get('copyright')
                    if isinstance(td_copyright, dict):
                        td_copyright = td_copyright.get('text', td_copyright.get('name', ''))
                    if td_copyright:
                        pp['tidal_copyright'] = td_copyright
            # Release year from Tidal album
            if not pp['release_year']:
                td_album = td_result.get('album', {})
                td_release = ''
                if isinstance(td_album, dict):
                    td_release = str(td_album.get('release_date', '') or td_album.get('releaseDate', '') or '')
                if len(td_release) >= 4 and td_release[:4].isdigit():
                    pp['release_year'] = td_release[:4]
    except Exception as e:
        print(f"Tidal lookup failed (non-fatal): {e}")


def _pp_lookup_qobuz(pp, _names_match):
    """Qobuz: ISRC fallback, copyright, label, track/artist IDs."""
    if not config_manager.get('qobuz.embed_tags', True):
        return
    track_title, artist_name = pp['track_title'], pp['artist_name']
    id_tags = pp['id_tags']
    if not track_title or not artist_name:
        return
    try:
        qz_client = qobuz_enrichment_worker.client if qobuz_enrichment_worker else None
        if not (qz_client and qz_client.is_authenticated()):
            return
        qz_result = qz_client.search_track(artist_name, track_title)
        if qz_result:
            qz_performer = (qz_result.get('performer') or {})
            if not isinstance(qz_performer, dict):
                qz_performer = {}
            qz_artist_name = qz_performer.get('name', '')
            if _names_match(qz_result.get('title', ''), track_title) and \
               _names_match(qz_artist_name, artist_name):
                qz_track_id = qz_result.get('id')
                if qz_track_id:
                    id_tags['QOBUZ_TRACK_ID'] = str(qz_track_id)
                    print(f"Qobuz track matched: {qz_track_id}")
                if isinstance(qz_performer, dict) and qz_performer.get('id'):
                    id_tags['QOBUZ_ARTIST_ID'] = str(qz_performer['id'])
                qz_isrc = qz_result.get('isrc')
                if isinstance(qz_isrc, dict):
                    qz_isrc = qz_isrc.get('value', qz_isrc.get('id', ''))
                if qz_isrc:
                    pp['qobuz_isrc'] = qz_isrc
                qz_copyright = qz_result.get('copyright')
                if isinstance(qz_copyright, dict):
                    qz_copyright = qz_copyright.get('text', qz_copyright.get('name', ''))
                if qz_copyright and isinstance(qz_copyright, str):
                    pp['qobuz_copyright'] = qz_copyright
                qz_album = qz_result.get('album', {})
                if isinstance(qz_album, dict):
                    qz_label_info = qz_album.get('label', {})
                    if isinstance(qz_label_info, dict) and qz_label_info.get('name'):
                        pp['qobuz_label'] = qz_label_info['name']
                    # Release year from Qobuz album (prefer date string over Unix timestamp)
                    if not pp['release_year']:
                        qz_release = str(qz_album.get('release_date_original', '') or '')
                        if not qz_release:
                            # released_at is a Unix timestamp — convert to year
                            qz_ts = qz_album.get('released_at')
                            if qz_ts and isinstance(qz_ts, (int, float)) and qz_ts > 0:
                                import datetime as _dt
                                qz_release = str(_dt.datetime.utcfromtimestamp(qz_ts).year)
                        if len(qz_release) >= 4 and qz_release[:4].isdigit():
                            pp['release_year'] = qz_release[:4]
    except Exception as e:
        print(f"Qobuz lookup failed (non-fatal): {e}")


def _pp_lookup_lastfm(pp, _names_match):
    """Last.fm: genre tags, track URL."""
    if not config_manager.get('lastfm.embed_tags', True):
        return
    track_title, artist_name = pp['track_title'], pp['artist_name']
    if not track_title or not artist_name:
        return
    try:
        lf_client = lastfm_worker.client if lastfm_worker else None
        if not lf_client:
            return
        lf_result = lf_client.get_track_info(artist_name, track_title)
        if lf_result:
            lf_url = lf_result.get('url')
            if lf_url:
                pp['lastfm_url'] = lf_url
            lf_toptags = lf_result.get('toptags', {})
            if isinstance(lf_toptags, dict):
                tag_list = lf_toptags.get('tag', [])
                if isinstance(tag_list, list):
                    pp['lastfm_tags'] = [t.get('name', '') for t in tag_list if isinstance(t, dict) and t.get('name')]
                elif isinstance(tag_list, dict) and tag_list.get('name'):
                    pp['lastfm_tags'] = [tag_list['name']]
            print(f"Last.fm track info found: {len(pp['lastfm_tags'])} tags")
    except Exception as e:
        print(f"Last.fm lookup failed (non-fatal): {e}")


def _pp_lookup_genius(pp, _names_match):
    """Genius: track ID, URL."""
    if not config_manager.get('genius.embed_tags', True):
        return
    track_title, artist_name = pp['track_title'], pp['artist_name']
    id_tags = pp['id_tags']
    if not track_title or not artist_name:
        return
    try:
        import core.genius_client as _genius_module
        if time.time() < _genius_module._rate_limit_until:
            print("Genius rate-limited, skipping (non-blocking)")
            return
        g_client = genius_worker.client if genius_worker else None
        if not g_client:
            return
        g_result = g_client.search_song(artist_name, track_title)
        if g_result:
            g_id = g_result.get('id')
            if g_id:
                id_tags['GENIUS_TRACK_ID'] = str(g_id)
                print(f"Genius song matched: {g_id}")
            g_url = g_result.get('url')
            if g_url:
                pp['genius_url'] = g_url
    except Exception as e:
        print(f"Genius lookup failed (non-fatal): {e}")


def _post_process_matched_download_with_verification(context_key, context, file_path, task_id, batch_id):
    """
    NEW VERIFICATION WORKFLOW: Enhanced post-processing with file verification.
    Only sets task status to 'completed' after successful file verification and move operation.
    """
    _pp = pp_logger
    try:
        # Call the existing post-processing logic (but skip its completion callback)
        # We'll handle the completion callback ourselves after verification
        original_task_id = context.pop('task_id', None)  # Temporarily remove to prevent double callback
        original_batch_id = context.pop('batch_id', None)
        _post_process_matched_download(context_key, context, file_path)
        # Restore the IDs for our own callback
        if original_task_id:
            context['task_id'] = original_task_id
        if original_batch_id:
            context['batch_id'] = original_batch_id

        # Check if race guard detected the source file was already gone
        if context.get('_race_guard_failed'):
            _pp.info(f"Race guard: source file gone for task {task_id} — marking as failed")
            with tasks_lock:
                if task_id in download_tasks:
                    download_tasks[task_id]['status'] = 'failed'
                    download_tasks[task_id]['error_message'] = 'Source file was already processed or removed by another task'
            with matched_context_lock:
                if context_key in matched_downloads_context:
                    del matched_downloads_context[context_key]
            _on_download_completed(batch_id, task_id, success=False)
            return

        # Check if AcoustID quarantined the file — no further processing needed
        if context.get('_acoustid_quarantined'):
            failure_msg = context.get('_acoustid_failure_msg', 'AcoustID verification failed')
            _pp.info(f"File was quarantined by AcoustID verification (task={task_id}): {failure_msg}")
            with tasks_lock:
                if task_id in download_tasks:
                    download_tasks[task_id]['status'] = 'failed'
                    download_tasks[task_id]['error_message'] = f"AcoustID verification failed: {failure_msg}"
            with matched_context_lock:
                if context_key in matched_downloads_context:
                    del matched_downloads_context[context_key]
            _on_download_completed(batch_id, task_id, success=False)
            return

        # Check if simple download handler already completed everything
        if context.get('_simple_download_completed'):
            expected_final_path = context.get('_final_path')

            if expected_final_path and os.path.exists(expected_final_path):
                with tasks_lock:
                    if task_id in download_tasks:
                        _mark_task_completed(task_id, context.get('track_info'))

                with matched_context_lock:
                    if context_key in matched_downloads_context:
                        del matched_downloads_context[context_key]

                _on_download_completed(batch_id, task_id, success=True)
                return
            else:
                _pp.info(f"FAILED simple download file not found at: {expected_final_path} (task={task_id}, context={context_key})")
                with tasks_lock:
                    if task_id in download_tasks:
                        download_tasks[task_id]['status'] = 'failed'
                        download_tasks[task_id]['error_message'] = f'Downloaded file not found at expected location: {os.path.basename(expected_final_path)}'

                with matched_context_lock:
                    if context_key in matched_downloads_context:
                        del matched_downloads_context[context_key]

                _on_download_completed(batch_id, task_id, success=False)
                return

        # VERIFICATION: Use the actual path that _post_process_matched_download computed and
        # moved the file to, instead of recomputing independently. Independent recomputation
        # can produce path mismatches (e.g., track_number extraction/validation differences)
        # causing false "file verification failed" errors on successfully processed files.
        expected_final_path = context.get('_final_processed_path')
        if not expected_final_path:
            _pp.info(f"No _final_processed_path in context for task {task_id} — cannot verify, assuming success")
            with tasks_lock:
                if task_id in download_tasks:
                    _mark_task_completed(task_id, context.get('track_info'))
            with matched_context_lock:
                if context_key in matched_downloads_context:
                    del matched_downloads_context[context_key]
            _on_download_completed(batch_id, task_id, success=True)
            return

        # VERIFICATION: Check if file exists at the path processing actually used
        if os.path.exists(expected_final_path):
            # Mark task as completed only after successful verification
            redownload_ctx = None
            with tasks_lock:
                if task_id in download_tasks:
                    _mark_task_completed(task_id, context.get('track_info'))
                    download_tasks[task_id]['metadata_enhanced'] = True
                    redownload_ctx = download_tasks[task_id].get('_redownload_context')

            with matched_context_lock:
                if context_key in matched_downloads_context:
                    del matched_downloads_context[context_key]

            # Redownload hook: delete old file and update DB path (outside locks)
            if redownload_ctx:
                try:
                    old_path = redownload_ctx.get('old_file_path')
                    lib_track_id = redownload_ctx.get('library_track_id')
                    if redownload_ctx.get('delete_old_file') and old_path and os.path.exists(old_path):
                        if os.path.normpath(old_path) != os.path.normpath(expected_final_path):
                            os.remove(old_path)
                            logger.info(f"[Redownload] Deleted old file: {old_path}")
                    if lib_track_id and expected_final_path:
                        _rd_db = get_database()
                        _rd_conn = _rd_db._get_connection()
                        _rd_cursor = _rd_conn.cursor()
                        _rd_cursor.execute("""
                            UPDATE tracks SET file_path = ?, updated_at = CURRENT_TIMESTAMP
                            WHERE id = ?
                        """, (expected_final_path, lib_track_id))
                        _rd_conn.commit()
                        _rd_conn.close()
                        logger.info(f"[Redownload] Updated DB path for track {lib_track_id}")
                except Exception as e:
                    logger.error(f"[Redownload] Post-processing hook error: {e}")

            _on_download_completed(batch_id, task_id, success=True)
        else:
            # Log failure details for diagnosis
            track_name = context.get('original_search_result', {}).get('spotify_clean_title', context_key)
            _pp.info(f"FAILED verification for '{track_name}' (task={task_id})")
            _pp.info(f"  expected_final_path: {expected_final_path}")
            _pp.info(f"  file_path (source): {file_path}, exists={os.path.exists(file_path)}")
            _pp.info(f"  is_album={context.get('is_album_download', False)}, has_clean_data={context.get('has_clean_spotify_data', False)}")
            expected_dir = os.path.dirname(expected_final_path)
            if os.path.exists(expected_dir):
                dir_contents = os.listdir(expected_dir)
                _pp.info(f"  directory contains {len(dir_contents)} files: {dir_contents[:20]}")
            else:
                _pp.info(f"  directory does not exist: {expected_dir}")

            with tasks_lock:
                if task_id in download_tasks:
                    download_tasks[task_id]['status'] = 'failed'
                    download_tasks[task_id]['error_message'] = f'File verification failed: expected file at {os.path.basename(expected_final_path)} but it was not found after processing'

            with matched_context_lock:
                if context_key in matched_downloads_context:
                    del matched_downloads_context[context_key]

            _on_download_completed(batch_id, task_id, success=False)

    except Exception as e:
        import traceback
        _pp.info(f"EXCEPTION in post-processing for '{context_key}' (task={task_id}): {e}")
        _pp.info(traceback.format_exc())
        with tasks_lock:
            if task_id in download_tasks:
                download_tasks[task_id]['status'] = 'failed'
                download_tasks[task_id]['error_message'] = f"Post-processing verification failed: {str(e)}"

        with matched_context_lock:
            if context_key in matched_downloads_context:
                del matched_downloads_context[context_key]

        _on_download_completed(batch_id, task_id, success=False)


def _check_flac_bit_depth(file_path, context, context_key):
    """
    Check if a FLAC file matches the user's preferred bit depth.
    Returns True if the file was rejected (caller should return), False if OK.
    With fallback enabled (default), accepts any FLAC bit depth rather than quarantining.
    """
    if not context.get('_audio_quality', '').startswith('FLAC'):
        return False

    from database.music_database import MusicDatabase
    _qp_db = MusicDatabase()
    _quality_profile = _qp_db.get_quality_profile()
    _flac_config = _quality_profile.get('qualities', {}).get('flac', {})
    _flac_pref = _flac_config.get('bit_depth', 'any')

    if _flac_pref == 'any':
        return False

    # Parse actual bit depth from quality string like "FLAC 16bit"
    _actual_bits = context['_audio_quality'].replace('FLAC ', '').replace('bit', '')
    if _actual_bits == _flac_pref:
        return False

    # Bit depth doesn't match preference — check if fallback or downsample is enabled
    _flac_fallback = _flac_config.get('bit_depth_fallback', True)
    _downsample_enabled = config_manager.get('lossy_copy.downsample_hires', False)

    if _flac_fallback or _downsample_enabled:
        # Accept the file — it will be downsampled or a FLAC at any bit depth is better than a failed download
        track_info = context.get('track_info', {})
        track_name = track_info.get('name', os.path.basename(file_path))
        if _downsample_enabled:
            print(f"[FLAC Downsample] Accepted {_actual_bits}-bit FLAC (will be downsampled to {_flac_pref}-bit): {track_name}")
        else:
            print(f"[FLAC Fallback] Accepted {_actual_bits}-bit FLAC (preferred {_flac_pref}-bit): {track_name}")
        return False

    # Strict mode — reject and quarantine
    rejection_msg = f"FLAC bit depth mismatch: file is {_actual_bits}-bit, preference is {_flac_pref}-bit"
    try:
        quarantine_path = _move_to_quarantine(file_path, context, rejection_msg)
        print(f"File quarantined due to bit depth filter: {quarantine_path}")
    except Exception as quarantine_error:
        logger.error(f"Quarantine failed ({quarantine_error}), deleting file: {file_path}")
        try:
            os.remove(file_path)
        except Exception:
            pass

    context['_bitdepth_rejected'] = True
    with matched_context_lock:
        if context_key in matched_downloads_context:
            del matched_downloads_context[context_key]

    task_id = context.get('task_id')
    batch_id = context.get('batch_id')
    if task_id:
        with tasks_lock:
            if task_id in download_tasks:
                download_tasks[task_id]['status'] = 'failed'
                download_tasks[task_id]['error_message'] = f"Bit depth filter: {rejection_msg}"
    if task_id and batch_id:
        _on_download_completed(batch_id, task_id, success=False)
    return True


def _move_to_quarantine(file_path: str, context: dict, reason: str) -> str:
    """
    Move a file to quarantine folder when AcoustID verification fails.
    Creates a JSON sidecar file with metadata about why the file was quarantined.

    Args:
        file_path: Original file path
        context: Download context with track info
        reason: Reason for quarantine

    Returns:
        Path to quarantined file
    """
    import json
    from pathlib import Path
    from datetime import datetime

    # Get quarantine directory (inside download folder — always writable, even in Docker)
    download_dir = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
    quarantine_dir = Path(download_dir) / "ss_quarantine"
    quarantine_dir.mkdir(parents=True, exist_ok=True)

    # Create quarantine entry with timestamp
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    original_name = Path(file_path).stem
    file_ext = Path(file_path).suffix

    # Build quarantine filename: TIMESTAMP_originalname.ext.quarantined
    # The .quarantined extension prevents audio file searches and media servers
    # from picking up known-wrong files sitting in the downloads folder.
    quarantine_filename = f"{timestamp}_{original_name}{file_ext}.quarantined"
    quarantine_path = quarantine_dir / quarantine_filename

    # Move file to quarantine
    _safe_move_file(file_path, str(quarantine_path))

    # Write metadata sidecar file
    metadata_path = quarantine_dir / f"{timestamp}_{original_name}.json"

    # Extract track info from context
    track_info = context.get('track_info', {})
    original_search = context.get('original_search_result', {})
    spotify_artist = context.get('spotify_artist', {})

    metadata = {
        'original_filename': Path(file_path).name,
        'quarantine_reason': reason,
        'timestamp': datetime.now().isoformat(),
        'expected_track': (
            original_search.get('spotify_clean_title') or
            track_info.get('name') or
            original_search.get('title', 'Unknown')
        ),
        'expected_artist': spotify_artist.get('name', 'Unknown'),
        'context_key': context.get('context_key', 'unknown')
    }

    try:
        with open(metadata_path, 'w', encoding='utf-8') as f:
            json.dump(metadata, f, indent=2, ensure_ascii=False)
    except Exception as e:
        logger.warning(f"Failed to write quarantine metadata: {e}")

    logger.warning(f"File quarantined: {quarantine_path} - Reason: {reason}")

    try:
        if automation_engine:
            ti = context.get('track_info', {})
            artists = ti.get('artists', [])
            artist_name = ''
            if artists:
                a = artists[0]
                artist_name = a.get('name', str(a)) if isinstance(a, dict) else str(a)
            automation_engine.emit('download_quarantined', {
                'artist': artist_name,
                'title': ti.get('name', ''),
                'reason': reason or 'Unknown',
            })
    except Exception:
        pass

    return str(quarantine_path)


def _safe_move_file(src, dst):
    """
    Safely move a file across different filesystems/volumes.
    Handles Docker volume mount issues where shutil.move() fails on metadata preservation.

    Args:
        src: Source file path (str or Path)
        dst: Destination file path (str or Path)
    """
    import shutil
    from pathlib import Path

    src = Path(src)
    dst = Path(dst)

    # Ensure parent directory exists
    dst.parent.mkdir(parents=True, exist_ok=True)

    # If source doesn't exist, check if it was already moved to destination
    # This happens when a retry or parallel thread already transferred the file
    if not src.exists():
        if dst.exists():
            logger.info(f"Source gone but destination exists, file already transferred: {dst.name}")
            return
        else:
            raise FileNotFoundError(f"Source file not found and destination does not exist: {src}")

    # On Windows, shutil.move fails with FileExistsError if destination exists.
    # Remove it first, retrying briefly for Windows file locks (e.g. Plex scanning).
    if dst.exists():
        for _attempt in range(3):
            try:
                dst.unlink()
                break
            except PermissionError:
                if _attempt < 2:
                    time.sleep(1)
                else:
                    logger.warning(f"Could not remove locked destination after 3 attempts: {dst.name}")
            except Exception:
                break

    try:
        # Try standard move first (works if same filesystem)
        shutil.move(str(src), str(dst))
        return
    except FileNotFoundError:
        # Source vanished between our exists() check and the move - another thread got it first
        # If destination now exists, the other thread completed the transfer successfully
        if dst.exists():
            logger.info(f"Source moved by another thread, destination exists: {dst.name}")
            return
        raise
    except (OSError, PermissionError) as e:
        error_msg = str(e).lower()

        # shutil.move may have already copied the file successfully but failed
        # to delete the source (e.g. permission denied on slskd-owned downloads).
        # If destination exists with content, treat as success.
        if dst.exists() and dst.stat().st_size > 0:
            logger.warning(f"Move raised {type(e).__name__} but destination exists, treating as success: {e}")
            # Try to clean up source, but don't fail if we can't
            try:
                src.unlink()
            except Exception:
                logger.info(f"Could not delete source file (may be owned by another process): {src}")
            return

        # Cross-device link error — do manual binary copy
        if "cross-device" in error_msg or "operation not permitted" in error_msg or "permission denied" in error_msg:
            logger.warning(f"Cross-device move detected, using fallback copy method: {e}")
            try:
                # Simple copy without metadata preservation (avoids permission errors)
                with open(src, 'rb') as f_src:
                    with open(dst, 'wb') as f_dst:
                        shutil.copyfileobj(f_src, f_dst)
                        f_dst.flush()
                        os.fsync(f_dst.fileno())

                # Delete source after successful copy
                try:
                    src.unlink()
                except PermissionError:
                    logger.info(f"Could not delete source file (may be owned by another process): {src}")
                logger.info(f"Successfully moved file using fallback method: {src} -> {dst}")
                return
            except Exception as fallback_error:
                logger.error(f"Fallback copy also failed: {fallback_error}")
                raise
        else:
            # Re-raise if it's a different error
            raise


def _post_process_matched_download(context_key, context, file_path):
    """
    This is the final, corrected post-processing function. It now mirrors the
    GUI's logic by trusting the pre-matched context for album downloads, which
    solves the track numbering issue.

    Also handles simple downloads (from search page "Download" button) which
    just move files to /Transfer without metadata enhancement.
    """
    # --- PER-FILE LOCK ---
    # Acquire a per-context-key lock so only one thread processes a given file at a time.
    # The Stream Processor and Verification Worker both call this function for the same file.
    # Without serialization, they race to move the source file and the loser gets FileNotFoundError.
    # With the lock, the second thread waits, then the existing protection checks detect
    # "source gone + destination exists" and return early.
    with _post_process_locks_lock:
        if context_key not in _post_process_locks:
            _post_process_locks[context_key] = threading.Lock()
        file_lock = _post_process_locks[context_key]

    file_lock.acquire()
    try:
        import os
        import shutil
        import time
        from pathlib import Path

        # --- RACE CONDITION GUARD ---
        # If source file is already gone, another thread (stream processor or
        # verification worker) already processed it. Check immediately after
        # acquiring the lock to avoid wasting time on stability checks / acoustid.
        if not os.path.exists(file_path):
            existing_final = context.get('_final_processed_path')
            if existing_final and os.path.exists(existing_final):
                print(f"[Race Guard] Source gone but destination exists — already processed by another thread: {os.path.basename(existing_final)}")
                return
            print(f"[Race Guard] Source file gone and no known destination — marking as failed: {os.path.basename(file_path)}")
            context['_race_guard_failed'] = True
            return
        # --- END RACE CONDITION GUARD ---

        # --- FILE STABILITY CHECK ---
        # Wait for the file to stop growing before processing. slskd may still be
        # flushing write buffers when it reports "Completed". We poll the file size
        # a few times; once it stabilises we know the write is finished.
        _basename = os.path.basename(file_path)
        _prev_size = -1
        for _stability_check in range(5):
            try:
                _cur_size = os.path.getsize(file_path)
            except OSError:
                _cur_size = -1
            if _cur_size == _prev_size and _cur_size > 0:
                # Size unchanged — file is stable
                break
            _prev_size = _cur_size
            if _stability_check == 0:
                print(f"Waiting for file to stabilise: {_basename} ({_cur_size} bytes)")
            time.sleep(1.5)
        else:
            print(f"File may still be writing after stability checks: {_basename} ({_prev_size} bytes)")
        # --- END FILE STABILITY CHECK ---

        # --- ACOUSTID VERIFICATION ---
        # Optional verification that downloaded audio matches expected track.
        # Only runs if enabled and configured. Fails gracefully (skips on any error).
        # Runs for ALL download sources — streaming APIs can return wrong versions
        # (live, remix, cover) despite downloading by track ID.
        _skip_acoustid = False

        try:
            from core.acoustid_verification import AcoustIDVerification, VerificationResult

            verifier = AcoustIDVerification()
            available, available_reason = verifier.quick_check_available()

            if available and not _skip_acoustid:
                # Extract expected track info from context
                track_info = context.get('track_info', {})
                original_search = context.get('original_search_result', {})
                spotify_artist = context.get('spotify_artist', {})

                expected_track = (
                    original_search.get('spotify_clean_title') or
                    track_info.get('name') or
                    original_search.get('title', '')
                )

                # Use track-level artist for verification, NOT album artist.
                # For compilations, spotify_artist is "Various Artists" which
                # will never match AcoustID's actual track artist.
                expected_artist = ''
                track_artists = track_info.get('artists', [])
                if track_artists:
                    first = track_artists[0]
                    if isinstance(first, dict):
                        expected_artist = first.get('name', '')
                    elif isinstance(first, str):
                        expected_artist = first
                # Fallback to album artist if no track artists available
                if not expected_artist:
                    expected_artist = spotify_artist.get('name', '')

                if expected_track and expected_artist:
                    print(f"Running AcoustID verification for: '{expected_track}' by '{expected_artist}'")
                    verification_result, verification_msg = verifier.verify_audio_file(
                        file_path,
                        expected_track,
                        expected_artist,
                        context
                    )
                    print(f"AcoustID verification result: {verification_result.value} - {verification_msg}")
                    context['_acoustid_result'] = verification_result.value

                    if verification_result == VerificationResult.FAIL:
                        # Move to quarantine instead of Transfer
                        try:
                            quarantine_path = _move_to_quarantine(file_path, context, verification_msg)
                            print(f"File quarantined due to verification failure: {quarantine_path}")
                        except Exception as quarantine_error:
                            # Quarantine failed — delete the known-wrong file instead
                            # NEVER save a file we've confirmed is wrong
                            logger.error(f"Quarantine failed ({quarantine_error}), deleting wrong file: {file_path}")
                            print(f"Quarantine failed, deleting wrong file: {file_path}")
                            try:
                                os.remove(file_path)
                            except Exception as del_error:
                                logger.error(f"Could not delete wrong file either: {del_error}")

                        # These always execute for FAIL — whether quarantine succeeded or not
                        context['_acoustid_quarantined'] = True
                        context['_acoustid_failure_msg'] = verification_msg

                        # Clean up context
                        with matched_context_lock:
                            if context_key in matched_downloads_context:
                                del matched_downloads_context[context_key]

                        # Mark as failed in download tasks if we have task info
                        task_id = context.get('task_id')
                        batch_id = context.get('batch_id')
                        if task_id:
                            with tasks_lock:
                                if task_id in download_tasks:
                                    download_tasks[task_id]['status'] = 'failed'
                                    download_tasks[task_id]['error_message'] = f"AcoustID verification failed: {verification_msg}"

                        # Call completion callback with failure
                        if task_id and batch_id:
                            _on_download_completed(batch_id, task_id, success=False)

                        return  # NEVER continue processing a known-wrong file
                else:
                    print(f"AcoustID verification skipped: missing track/artist info")
                    context['_acoustid_result'] = 'skip'
            else:
                print(f"ℹ️ AcoustID verification not available: {available_reason}")
                context['_acoustid_result'] = 'disabled'
        except Exception as verify_error:
            # Any verification error should NOT block the download - fail open
            print(f"AcoustID verification error (continuing normally): {verify_error}")
            context['_acoustid_result'] = 'error'
        # --- END ACOUSTID VERIFICATION ---

        # --- SIMPLE DOWNLOAD HANDLING ---
        # Check if this is a simple download (search page "Download ⬇" button only)
        search_result = context.get('search_result', {})
        is_simple_download = search_result.get('is_simple_download', False)

        if is_simple_download:
            # Simple transfer: move to Transfer folder, no metadata enhancement
            logger.info(f"Processing simple download (no metadata enhancement): {file_path}")

            transfer_path = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))

            # Check if this download has album info (from path or search result)
            album_name = None
            original_filename = search_result.get('filename', '')

            if '/' in original_filename or '\\' in original_filename:
                # Get parent directory as album name
                path_parts = original_filename.replace('\\', '/').split('/')
                if len(path_parts) >= 2:
                    album_name = path_parts[-2]  # Parent directory

            # If no album from path, check search result
            if not album_name:
                album_name = search_result.get('album')

            # Determine destination
            filename = Path(file_path).name

            if album_name and album_name.lower() not in ['unknown', 'unknown album', '']:
                # Has album info - create album folder
                import re
                album_name = re.sub(r'[<>:"/\\|?*]', '_', album_name).strip()
                album_folder = Path(transfer_path) / album_name
                album_folder.mkdir(parents=True, exist_ok=True)
                destination = album_folder / filename
                logger.info(f"Moving to album folder: {album_name}")
            else:
                # No album info - move directly to Transfer root (singles)
                Path(transfer_path).mkdir(parents=True, exist_ok=True)
                destination = Path(transfer_path) / filename
                logger.info(f"Moving to Transfer root (single track)")

            _safe_move_file(file_path, destination)
            logger.info(f"Moved simple download to: {destination}")

            # Clean up context
            with matched_context_lock:
                if context_key in matched_downloads_context:
                    del matched_downloads_context[context_key]

            # Trigger library scan (using correct method name)
            if web_scan_manager:
                threading.Thread(
                    target=lambda: web_scan_manager.request_scan("Simple download completed"),
                    daemon=True
                ).start()

            add_activity_item("", "Download Complete", f"{album_name}/{filename}", "Now")
            logger.info(f"Simple download post-processing complete: {album_name}/{filename}")

            # Set flag in context so verification function knows this was fully handled
            context['_simple_download_completed'] = True
            context['_final_path'] = str(destination)
            _emit_track_downloaded(context)
            _record_library_history_download(context)
            _record_download_provenance(context)
            return
        # --- END SIMPLE DOWNLOAD HANDLING ---

        print(f"Starting robust post-processing for: {context_key}")

        spotify_artist = context.get("spotify_artist")
        if not spotify_artist:
            print(f"Post-processing failed: Missing spotify_artist context.")
            return

        # Check if playlist folder mode is enabled (sync page playlists only)
        track_info = context.get("track_info", {})
        playlist_folder_mode = track_info.get("_playlist_folder_mode", False)

        print(f"[Debug] Post-processing - track_info type: {type(track_info)}, is None: {track_info is None}, is empty: {not track_info}")
        print(f"[Debug] Post-processing - playlist_folder_mode: {playlist_folder_mode}")
        if track_info:
            print(f"[Debug] Post-processing - track_info keys: {list(track_info.keys())}")

        if playlist_folder_mode:
            # Use shared path builder for playlist mode
            playlist_name = track_info.get("_playlist_name", "Unknown Playlist")
            print(f"[Playlist Folder Mode] Organizing in playlist folder: {playlist_name}")

            file_ext = os.path.splitext(file_path)[1]

            # Build final path FIRST so we can check for already-processed files
            final_path, _ = _build_final_path_for_track(context, spotify_artist, None, file_ext)
            print(f"Playlist mode final path: '{final_path}'")

            # RACE CONDITION GUARD: If source file is gone but destination exists,
            # another thread (stream processor or verification worker) already moved it.
            # Return early to avoid deleting the successfully processed file.
            if not os.path.exists(file_path):
                if os.path.exists(final_path):
                    print(f"[Playlist Folder Mode] Source gone but destination exists — already processed by another thread: {os.path.basename(final_path)}")
                    context['_final_processed_path'] = final_path
                    return
                else:
                    pp_logger.info(f"[inner] EXCEPTION in post-processing for {context_key}: Source file not found and destination does not exist: {file_path}")
                    raise FileNotFoundError(f"Source file not found and destination does not exist: {file_path}")

            context['_audio_quality'] = _get_audio_quality_string(file_path)
            if context['_audio_quality']:
                print(f"Audio quality detected: {context['_audio_quality']}")

            # FLAC bit depth filter
            if _check_flac_bit_depth(file_path, context, context_key):
                return

            # Enhance metadata before moving
            try:
                print(f"[Metadata Input] Playlist mode - artist: '{spotify_artist.get('name', 'MISSING')}' (id: {spotify_artist.get('id', 'MISSING')})")
                _enhance_file_metadata(file_path, context, spotify_artist, None)
            except Exception as meta_err:
                import traceback
                pp_logger.info(f"[inner] Metadata enhancement FAILED for {context_key}: {meta_err}\n{traceback.format_exc()}")

            # Move file to playlist folder
            print(f"Moving '{os.path.basename(file_path)}' to '{final_path}'")
            _safe_move_file(file_path, final_path)

            # Store final path for verification wrapper (before conversions may override)
            context['_final_processed_path'] = final_path

            # Downsample hi-res FLAC to CD quality if enabled (must run before lossy copy)
            downsampled_path = _downsample_hires_flac(final_path, context)
            if downsampled_path:
                final_path = downsampled_path
                context['_final_processed_path'] = final_path

            # Lossy copy: create MP3 version if enabled
            blasphemy_path = _create_lossy_copy(final_path)
            if blasphemy_path:
                context['_final_processed_path'] = blasphemy_path

            # Clean up empty directories in downloads folder
            downloads_path = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
            _cleanup_empty_directories(downloads_path, file_path)

            print(f"[Playlist Folder Mode] Post-processing complete: {final_path}")

            # WISHLIST REMOVAL: Check if this track should be removed from wishlist
            try:
                _check_and_remove_from_wishlist(context)
            except Exception as wishlist_error:
                print(f"[Playlist Folder] Error checking wishlist removal: {wishlist_error}")

            _emit_track_downloaded(context)
            _record_library_history_download(context)
            _record_download_provenance(context)

            # Mark as stream processed so the verification worker doesn't search
            # for the file by its original Soulseek name (which no longer exists after rename)
            task_id = context.get('task_id')
            batch_id = context.get('batch_id')
            if task_id and batch_id:
                with tasks_lock:
                    if task_id in download_tasks:
                        download_tasks[task_id]['stream_processed'] = True
                        download_tasks[task_id]['status'] = 'completed'
                        print(f"[Playlist Folder Mode] Marked task {task_id} as completed")
                _on_download_completed(batch_id, task_id, success=True)

            return  # Skip normal album/artist folder structure processing

        is_album_download = context.get("is_album_download", False)
        has_clean_spotify_data = context.get("has_clean_spotify_data", False)

        if is_album_download and has_clean_spotify_data:
            # Build album_info directly from clean Spotify metadata (GUI PARITY)
            print("Album context with clean Spotify data found - using direct album info")
            original_search = context.get("original_search_result", {})
            spotify_album = context.get("spotify_album", {})
            
            # Use clean Spotify metadata (matches GUI's SpotifyBasedSearchResult approach)
            clean_track_name = original_search.get('spotify_clean_title', 'Unknown Track')
            clean_album_name = original_search.get('spotify_clean_album', 'Unknown Album')
            
            # DEBUG: Check what's in original_search
            print(f"[DEBUG] Path 1 - Clean Spotify data path:")
            print(f"   original_search keys: {list(original_search.keys())}")
            print(f"   track_number in original_search: {'track_number' in original_search}")
            print(f"   track_number value: {original_search.get('track_number', 'NOT_FOUND')}")
            
            album_info = {
                'is_album': True,
                'album_name': clean_album_name,  # Use clean Spotify album name
                'track_number': original_search.get('track_number', 1),
                'disc_number': original_search.get('disc_number', 1),
                'clean_track_name': clean_track_name,
                'album_image_url': spotify_album.get('image_url'),
                'confidence': 1.0,  # High confidence since we have clean Spotify data
                'source': 'clean_spotify_metadata'
            }

            print(f"Using clean Spotify album: '{clean_album_name}' for track: '{clean_track_name}'")
        elif is_album_download:
            # CRITICAL FIX: Album context without clean Spotify data - still force album treatment
            print("Album context found but no clean Spotify data - using enhanced fallback")
            original_search = context.get("original_search_result", {})
            spotify_album = context.get("spotify_album", {})
            clean_track_name = original_search.get('spotify_clean_title') or original_search.get('title', 'Unknown Track')
            
            # DEBUG: Check what's in original_search for path 2
            print(f"[DEBUG] Path 2 - Enhanced fallback album context path:")
            print(f"   original_search keys: {list(original_search.keys())}")
            print(f"   track_number in original_search: {'track_number' in original_search}")
            print(f"   track_number value: {original_search.get('track_number', 'NOT_FOUND')}")
            print(f"   spotify_album name: {spotify_album.get('name', 'NOT_FOUND')}")
            
            # ENHANCEMENT: Use spotify_clean_album if available for consistency 
            album_name = (original_search.get('spotify_clean_album') or 
                         spotify_album.get('name') or 
                         'Unknown Album')
            
            album_info = {
                'is_album': True,  # FORCE TRUE - user explicitly selected album for download
                'album_name': album_name,
                'track_number': original_search.get('track_number', 1),
                'disc_number': original_search.get('disc_number', 1),
                'clean_track_name': clean_track_name,
                'album_image_url': spotify_album.get('image_url'),
                'confidence': 0.9,  # Higher confidence - user explicitly chose album
                'source': 'enhanced_fallback_album_context'
            }
            print(f"[FORCED ALBUM] Using album: '{album_name}' for track: '{clean_track_name}'")
        else:
            # For singles, we still need to detect if they belong to an album.
            print("Single track download - attempting album detection")
            album_info = _detect_album_info_web(context, spotify_artist)

        # --- Album grouping resolution ---
        # Only run smart grouping for singles/auto-detected albums.
        # Explicit album downloads already have the correct Spotify album name —
        # re-grouping would mangle names like "(Reworked and Remastered)" into "(Deluxe Edition)".
        if album_info and album_info['is_album'] and not is_album_download:
            print(f"\nSMART ALBUM GROUPING for track: '{album_info.get('clean_track_name', 'Unknown')}'")
            print(f"   Original album: '{album_info.get('album_name', 'None')}'")

            # Get original album name from context if available
            original_album = None
            if context.get("original_search_result", {}).get("album"):
                original_album = context["original_search_result"]["album"]

            # Use the GUI's smart album grouping algorithm
            consistent_album_name = _resolve_album_group(spotify_artist, album_info, original_album)
            album_info['album_name'] = consistent_album_name

            print(f"   Final album name: '{consistent_album_name}'")
            print(f"Album grouping complete!\n")
        elif album_info and album_info['is_album'] and is_album_download:
            print(f"\nEXPLICIT ALBUM DOWNLOAD - preserving Spotify album name: '{album_info.get('album_name', 'None')}'")
            print(f"   Skipping smart grouping (not needed for explicit album downloads)\n")

        # 1. Get transfer path (directory creation handled by _build_final_path_for_track)
        file_ext = os.path.splitext(file_path)[1]
        context['_audio_quality'] = _get_audio_quality_string(file_path)
        if context['_audio_quality']:
            print(f"Audio quality detected: {context['_audio_quality']}")

        # FLAC bit depth filter
        if _check_flac_bit_depth(file_path, context, context_key):
            return

        # 2. Build the final path using GUI-style track naming with multiple fallback sources
        if album_info and album_info['is_album']:
            album_name_sanitized = _sanitize_filename(album_info['album_name'])
            
            # --- GUI PARITY: Use multiple sources for clean track name ---
            original_search = context.get("original_search_result", {})
            clean_track_name = album_info['clean_track_name']
            
            # Priority 1: Spotify clean title from context
            if original_search.get('spotify_clean_title'):
                clean_track_name = original_search['spotify_clean_title']
                print(f"Using Spotify clean title: '{clean_track_name}'")
            # Priority 2: Album info clean name
            elif album_info.get('clean_track_name'):
                clean_track_name = album_info['clean_track_name']
                print(f"Using album info clean name: '{clean_track_name}'")
            # Priority 3: Original title as fallback
            else:
                clean_track_name = original_search.get('title', 'Unknown Track')
                print(f"Using original title as fallback: '{clean_track_name}'")
            
            final_track_name_sanitized = _sanitize_filename(clean_track_name)
            track_number = album_info['track_number']
            
            # DEBUG: Check final track_number values
            print(f"[DEBUG] Final track_number processing:")
            print(f"   album_info source: {album_info.get('source', 'unknown')}")
            print(f"   album_info track_number: {album_info.get('track_number', 'NOT_FOUND')}")
            print(f"   track_number variable: {track_number}")
            
            # Fix: Handle None track_number
            if track_number is None:
                print(f"Track number is None, extracting from filename: {os.path.basename(file_path)}")
                track_number = _extract_track_number_from_filename(file_path)
                print(f"   -> Extracted track number: {track_number}")
            
            # Ensure track_number is valid
            if not isinstance(track_number, int) or track_number < 1:
                print(f"Invalid track number ({track_number}), defaulting to 1")
                track_number = 1
                
            print(f"[DEBUG] FINAL track_number used for filename: {track_number}")
            
            # CRITICAL FIX: Update album_info with corrected track_number for metadata enhancement
            album_info['track_number'] = track_number
            album_info['clean_track_name'] = clean_track_name  # Ensure clean name is in album_info
            print(f"[FIX] Updated album_info track_number to {track_number} for consistent metadata")

            # Use shared path builder for album mode
            final_path, _ = _build_final_path_for_track(context, spotify_artist, album_info, file_ext)
            print(f"Album path: '{final_path}'")
        else:
            # Single track structure: Transfer/ARTIST/ARTIST - SINGLE/SINGLE.ext
            # --- GUI PARITY: Use multiple sources for clean track name ---
            original_search = context.get("original_search_result", {})
            clean_track_name = album_info['clean_track_name']
            
            # Priority 1: Spotify clean title from context  
            if original_search.get('spotify_clean_title'):
                clean_track_name = original_search['spotify_clean_title']
                print(f"Using Spotify clean title: '{clean_track_name}'")
            # Priority 2: Album info clean name
            elif album_info and album_info.get('clean_track_name'):
                clean_track_name = album_info['clean_track_name']
                print(f"Using album info clean name: '{clean_track_name}'")
            # Priority 3: Original title as fallback
            else:
                clean_track_name = original_search.get('title', 'Unknown Track')
                print(f"Using original title as fallback: '{clean_track_name}'")
            
            # Ensure clean name is in album_info for path builder
            if album_info:
                album_info['clean_track_name'] = clean_track_name

            # Use shared path builder for single mode
            final_path, _ = _build_final_path_for_track(context, spotify_artist, album_info, file_ext)
            print(f"Single path: '{final_path}'")

        # Store the actual computed path so verification uses this exact path
        # instead of recomputing independently (which can produce mismatches)
        context['_final_processed_path'] = final_path

        # 3. Enhance metadata, move file, download art, and cleanup
        try:
            print(f"[Metadata Input] artist: '{spotify_artist.get('name', 'MISSING')}' (id: {spotify_artist.get('id', 'MISSING')})")
            if album_info:
                print(f"[Metadata Input] album: '{album_info.get('album_name', 'MISSING')}', track#: {album_info.get('track_number', 'MISSING')}, disc#: {album_info.get('disc_number', 'MISSING')}, source: {album_info.get('source', 'unknown')}")
            else:
                print(f"[Metadata Input] album_info: None (single track)")
            _enhance_file_metadata(file_path, context, spotify_artist, album_info)
        except Exception as meta_err:
            import traceback
            pp_logger.info(f"[inner] Metadata enhancement FAILED for {context_key}: {meta_err}\n{traceback.format_exc()}")
            # Continue anyway - file can still be moved

        # Detect enhance mode from track context
        _enhance_source_info = context.get('track_info', {}).get('source_info') or {}
        if isinstance(_enhance_source_info, str):
            try:
                _enhance_source_info = json.loads(_enhance_source_info)
            except (json.JSONDecodeError, TypeError):
                _enhance_source_info = {}
        is_enhance_download = _enhance_source_info.get('enhance', False)

        print(f"Moving '{os.path.basename(file_path)}' to '{final_path}'")
        if os.path.exists(final_path):
            # PROTECTION: If destination already exists, check before overwriting
            # If the source file is gone, another thread already handled this - don't delete the destination
            if not os.path.exists(file_path):
                print(f"[Protection] Destination exists and source already gone - file already transferred: {os.path.basename(final_path)}")
                return
            try:
                from mutagen import File as MutagenFile
                existing_file = MutagenFile(final_path)
                has_metadata = existing_file is not None and len(existing_file.tags or {}) > 2  # More than basic tags

                if has_metadata and not is_enhance_download:
                    # Check if incoming file is higher quality and setting is enabled
                    _replace_lower = config_manager.get('import.replace_lower_quality', False)
                    if _replace_lower:
                        _existing_tier = _get_quality_tier_from_extension(final_path)
                        _incoming_tier = _get_quality_tier_from_extension(file_path)
                        if _incoming_tier[1] < _existing_tier[1]:
                            # Incoming is higher quality (lower tier number) — replace
                            print(f"[Quality Replace] Replacing {_existing_tier[0]} with {_incoming_tier[0]}: {os.path.basename(final_path)}")
                            try:
                                os.remove(final_path)
                            except Exception as e:
                                print(f"[Quality Replace] Could not remove existing file: {e}")
                        else:
                            print(f"[Protection] Existing file is same or better quality ({_existing_tier[0]} vs {_incoming_tier[0]}) - skipping: {os.path.basename(final_path)}")
                            try:
                                os.remove(file_path)
                            except FileNotFoundError:
                                pass
                            except Exception as e:
                                print(f"[Protection] Error removing redundant file: {e}")
                            return
                    else:
                        print(f"[Protection] Existing file already has metadata enhancement - skipping overwrite: {os.path.basename(final_path)}")
                        print(f"[Protection] Removing redundant download file: {os.path.basename(file_path)}")
                        try:
                            os.remove(file_path)
                        except FileNotFoundError:
                            print(f"[Protection] Could not remove redundant file (already gone): {file_path}")
                        except Exception as e:
                            print(f"[Protection] Error removing redundant file: {e}")
                        return  # Don't overwrite the good file
                elif is_enhance_download:
                    # ENHANCE BYPASS: Allow overwrite — backup original, then remove to allow move
                    print(f"[Enhance] Quality enhance mode — replacing existing file: {os.path.basename(final_path)}")
                    try:
                        os.remove(final_path)
                    except Exception as e:
                        print(f"[Enhance] Could not remove existing file for replacement: {e}")
                else:
                    print(f"[Protection] Existing file lacks metadata - safe to overwrite: {os.path.basename(final_path)}")
                    try:
                        os.remove(final_path)
                    except FileNotFoundError:
                        pass # It was just there, but now gone?
            except Exception as check_error:
                print(f"[Protection] Error checking existing file metadata, proceeding with overwrite: {check_error}")
                try:
                    if os.path.exists(final_path):
                        os.remove(final_path)
                except Exception as e:
                    print(f"[Protection] Failed to remove existing file for overwrite: {e}")

        # --- PRE-MOVE SOURCE CHECK ---
        # Right before moving, verify the source file still exists.
        # Another thread (Stream Processor or Verification Worker) may have
        # already moved this file during the sleep + metadata enhancement window.
        if not os.path.exists(file_path):
            if os.path.exists(final_path):
                print(f"[Pre-Move] Source already gone and destination exists - another thread completed transfer: {os.path.basename(final_path)}")
                # Still do cover art + lyrics since the other thread might not have finished those
                _download_cover_art(album_info, os.path.dirname(final_path), context)
                _generate_lrc_file(final_path, context, spotify_artist, album_info)
                return
            else:
                # Source gone, exact destination not found — check if stream processor already
                # moved it with a quality tag (e.g. "track [FLAC 24bit].flac" vs "track.flac")
                expected_dir = os.path.dirname(final_path)
                expected_stem = os.path.splitext(os.path.basename(final_path))[0]
                expected_ext = os.path.splitext(final_path)[1]
                found_variant = None
                # Also check for lossy output if Blasphemy Mode may have deleted the .flac
                check_exts = {expected_ext}
                if expected_ext == '.flac' and config_manager.get('lossy_copy.enabled', False) and config_manager.get('lossy_copy.delete_original', False):
                    _lossy_ext_map = {'mp3': '.mp3', 'opus': '.opus', 'aac': '.m4a'}
                    _lossy_codec = config_manager.get('lossy_copy.codec', 'mp3')
                    check_exts.add(_lossy_ext_map.get(_lossy_codec, '.mp3'))
                if os.path.exists(expected_dir):
                    for f in os.listdir(expected_dir):
                        # Match files that start with the expected stem and have a matching extension
                        # This catches "01 - track [FLAC 24bit].flac" when expecting "01 - track.flac"
                        # and "01 - track [MP3-320].mp3" when Blasphemy Mode deleted the FLAC
                        f_ext = os.path.splitext(f)[1].lower()
                        if f_ext in check_exts and os.path.splitext(f)[0].startswith(expected_stem):
                            found_variant = os.path.join(expected_dir, f)
                            break
                if found_variant:
                    print(f"[Pre-Move] Source gone but found variant in destination (stream processor handled it): {os.path.basename(found_variant)}")
                    context['_final_processed_path'] = found_variant
                    _download_cover_art(album_info, expected_dir, context)
                    _generate_lrc_file(found_variant, context, spotify_artist, album_info)
                    return
                else:
                    print(f"[Pre-Move] Source file gone and no matching file in destination: {os.path.basename(file_path)}")
                    raise FileNotFoundError(f"Source file vanished before move and destination does not exist: {file_path}")

        _safe_move_file(file_path, final_path)

        # ENHANCE CLEANUP: If format changed (e.g. MP3→FLAC), remove old-format file
        if is_enhance_download and _enhance_source_info.get('original_file_path'):
            original_enhance_path = _enhance_source_info['original_file_path']
            if os.path.normpath(original_enhance_path) != os.path.normpath(final_path) and os.path.exists(original_enhance_path):
                try:
                    os.remove(original_enhance_path)
                    old_fmt = os.path.splitext(original_enhance_path)[1]
                    new_fmt = os.path.splitext(final_path)[1]
                    print(f"[Enhance] Upgraded {old_fmt} → {new_fmt}: {os.path.basename(final_path)}")
                except Exception as e:
                    print(f"[Enhance] Could not remove old-format file: {e}")
            elif is_enhance_download:
                old_fmt = _enhance_source_info.get('original_format', 'unknown')
                new_fmt = os.path.splitext(final_path)[1]
                print(f"[Enhance] Replaced in-place ({old_fmt} → {new_fmt}): {os.path.basename(final_path)}")

        _download_cover_art(album_info, os.path.dirname(final_path), context)

        # 4. Generate LRC lyrics file at final location (elegant addition)
        _generate_lrc_file(final_path, context, spotify_artist, album_info)

        # Downsample hi-res FLAC to CD quality if enabled (must run before lossy copy)
        downsampled_path = _downsample_hires_flac(final_path, context)
        if downsampled_path:
            final_path = downsampled_path
            context['_final_processed_path'] = final_path

        # Lossy copy: create MP3 version if enabled
        blasphemy_path = _create_lossy_copy(final_path)
        if blasphemy_path:
            context['_final_processed_path'] = blasphemy_path

        downloads_path = docker_resolve_path(config_manager.get('soulseek.download_path', './downloads'))
        _cleanup_empty_directories(downloads_path, file_path)

        print(f"Post-processing complete for: {context.get('_final_processed_path', final_path)}")

        _emit_track_downloaded(context)
        _record_library_history_download(context)
        _record_download_provenance(context)

        # RETAG DATA CAPTURE: Record completed album/single downloads for retag tool
        try:
            if not playlist_folder_mode:
                completed_path = context.get('_final_processed_path', final_path)
                _record_retag_download(context, spotify_artist, album_info, completed_path)
        except Exception as retag_err:
            print(f"[Post-Process] Retag data capture failed (non-fatal): {retag_err}")

        # REPAIR: Register album folder for repair scanning when batch completes
        try:
            completed_path = context.get('_final_processed_path', final_path)
            batch_id_for_repair = context.get('batch_id')
            if completed_path and batch_id_for_repair and repair_worker:
                album_folder = os.path.dirname(str(completed_path))
                if album_folder:
                    repair_worker.register_folder(batch_id_for_repair, album_folder)
        except Exception as repair_err:
            print(f"[Post-Process] Repair folder registration failed: {repair_err}")

        # WISHLIST REMOVAL: Check if this track should be removed from wishlist after successful download
        try:
            _check_and_remove_from_wishlist(context)
        except Exception as wishlist_error:
            print(f"[Post-Process] Error checking wishlist removal: {wishlist_error}")
        
        # Call completion callback for missing downloads tasks to start next batch
        task_id = context.get('task_id')
        batch_id = context.get('batch_id')
        if task_id and batch_id:
            print(f"[Post-Process] Calling completion callback for task {task_id} in batch {batch_id}")
            
            # Mark task as stream processed and set terminal status so
            # _validate_worker_counts won't count this task as active
            # (prevents active_count inflation race).
            # NOTE: Only set status here — don't call _mark_task_completed() because
            # _run_post_processing_worker will call it later with the session counter
            # increment. Calling it here too would double-count the download.
            with tasks_lock:
                if task_id in download_tasks:
                    download_tasks[task_id]['stream_processed'] = True
                    download_tasks[task_id]['status'] = 'completed'
                    print(f"[Post-Process] Marked task {task_id} as completed")
            
            _on_download_completed(batch_id, task_id, success=True)

    except Exception as e:
        import traceback
        pp_logger.info(f"[inner] EXCEPTION in post-processing for {context_key}: {e}")
        pp_logger.info(traceback.format_exc())
        print(f"\nCRITICAL ERROR in post-processing for {context_key}: {e}")
        traceback.print_exc()

        # Only retry if the source file still exists - otherwise retrying is pointless
        # and creates an infinite loop of failures
        import os as _os
        source_exists = _os.path.exists(file_path) if file_path else False
        if source_exists:
            # Remove from processed set so it can be retried
            if context_key in _processed_download_ids:
                _processed_download_ids.remove(context_key)
                print(f"Removed {context_key} from processed set - will retry on next check")

            # Re-add to matched context for retry
            with matched_context_lock:
                if context_key not in matched_downloads_context:
                    matched_downloads_context[context_key] = context
                    print(f"Re-added {context_key} to context for retry")
        else:
            print(f"Source file gone, not retrying: {context_key}")
    finally:
        file_lock.release()
        # Clean up the lock entry to prevent unbounded memory growth
        with _post_process_locks_lock:
            _post_process_locks.pop(context_key, None)

# Keep track of processed downloads to avoid re-processing
_processed_download_ids = set()

# Track stale transfer keys (completed in slskd but no context — e.g., from before app restart)
# so we only log the warning once per key instead of spamming every poll cycle
_stale_transfer_keys = set()

# Per-context-key locks to prevent two threads from processing the same file simultaneously.
# Without this, the Stream Processor and Verification Worker race to move the same source file,
# and the loser gets a FileNotFoundError because the winner already moved it.
_post_process_locks = {}  # {context_key: threading.Lock()}
_post_process_locks_lock = threading.Lock()  # protects the dict itself

# --- File Discovery Retry System ---
# Prevents race condition where slskd reports completion before file is written to disk
# Tracks retry attempts per download to give files time to finish writing
_download_retry_attempts = {}  # {context_key: {'count': N, 'first_attempt': timestamp}}
_download_retry_max = 10  # Max retries before giving up (10 seconds with 1s poll interval)
_download_retry_lock = threading.Lock()

def _record_retag_download(context, spotify_artist, album_info, final_path):
    """Record a completed download in the retag tables for later re-tagging."""
    from database.music_database import get_database
    db = get_database()

    # Extract artist name
    if isinstance(spotify_artist, dict):
        artist_name = spotify_artist.get('name', 'Unknown Artist')
    else:
        artist_name = getattr(spotify_artist, 'name', 'Unknown Artist')

    spotify_album = context.get('spotify_album', {})
    original_search = context.get('original_search_result', {})
    track_info = context.get('track_info', {})

    is_album = album_info and album_info.get('is_album', False)
    group_type = 'album' if is_album else 'single'
    album_name = album_info.get('album_name', '') if album_info else (
        original_search.get('spotify_clean_title', 'Unknown'))

    # Determine album IDs (Spotify vs iTunes) — skip beatport_ prefixed IDs
    spotify_album_id = None
    itunes_album_id = None
    if spotify_album:
        album_id_raw = str(spotify_album.get('id', ''))
        if album_id_raw and album_id_raw.isdigit():
            itunes_album_id = album_id_raw
        elif album_id_raw and not album_id_raw.startswith('beatport_'):
            spotify_album_id = album_id_raw

    image_url = album_info.get('album_image_url') if album_info else None
    total_tracks = spotify_album.get('total_tracks', 1) if spotify_album else 1
    release_date = spotify_album.get('release_date', '') if spotify_album else ''

    # Find or create group (avoid duplicating for multi-track albums)
    group_id = db.find_retag_group(artist_name, album_name)
    if group_id is None:
        group_id = db.add_retag_group(
            group_type=group_type, artist_name=artist_name, album_name=album_name,
            image_url=image_url, spotify_album_id=spotify_album_id,
            itunes_album_id=itunes_album_id, total_tracks=total_tracks,
            release_date=release_date
        )
    if group_id is None:
        return

    # Track details
    track_number = album_info.get('track_number', 1) if album_info else 1
    disc_number = original_search.get('disc_number') or (
        album_info.get('disc_number', 1) if album_info else 1)
    title = original_search.get('spotify_clean_title') or (
        album_info.get('clean_track_name', 'Unknown Track') if album_info else 'Unknown Track')
    file_format = os.path.splitext(str(final_path))[1].lstrip('.').lower()

    # Track IDs (Spotify vs iTunes) — skip beatport_ prefixed IDs
    spotify_track_id = None
    itunes_track_id = None
    if track_info and track_info.get('id'):
        tid = str(track_info['id'])
        if tid.isdigit():
            itunes_track_id = tid
        elif not tid.startswith('beatport_'):
            spotify_track_id = tid

    # Avoid duplicate track entries
    if not db.retag_track_exists(group_id, str(final_path)):
        db.add_retag_track(
            group_id=group_id, track_number=track_number, disc_number=disc_number,
            title=title, file_path=str(final_path), file_format=file_format,
            spotify_track_id=spotify_track_id, itunes_track_id=itunes_track_id
        )
        print(f"[Retag] Recorded track for retag: '{title}' in '{album_name}'")

    # Cap retag groups at 100, remove oldest
    db.trim_retag_groups(100)


def _execute_retag(group_id, album_id):
    """Execute a retag operation: re-tag files in a group with metadata from a new album match."""
    global retag_state
    from database.music_database import get_database

    try:
        with retag_lock:
            retag_state.update({
                "status": "running",
                "phase": "Fetching album metadata...",
                "progress": 0,
                "current_track": "",
                "total_tracks": 0,
                "processed": 0,
                "error_message": ""
            })

        # 1. Fetch new album metadata from Spotify/iTunes
        album_data = spotify_client.get_album(album_id)
        if not album_data:
            raise ValueError(f"Could not fetch album data for ID: {album_id}")

        album_tracks_response = spotify_client.get_album_tracks(album_id)
        if not album_tracks_response:
            raise ValueError(f"Could not fetch album tracks for ID: {album_id}")

        album_tracks_items = album_tracks_response.get('items', [])

        # Extract artist info
        album_artists = album_data.get('artists', [])
        new_artist = album_artists[0] if album_artists else {'name': 'Unknown Artist', 'id': ''}
        # Ensure artist is a dict with expected fields
        if not isinstance(new_artist, dict):
            new_artist = {'name': str(new_artist), 'id': ''}
        new_album_name = album_data.get('name', 'Unknown Album')
        new_images = album_data.get('images', [])
        new_image_url = new_images[0]['url'] if new_images else None
        new_release_date = album_data.get('release_date', '')
        total_tracks = album_data.get('total_tracks', len(album_tracks_items))

        # Build spotify track list
        spotify_tracks = []
        for item in album_tracks_items:
            track_artists = item.get('artists', [])
            spotify_tracks.append({
                'name': item.get('name', ''),
                'track_number': item.get('track_number', 1),
                'disc_number': item.get('disc_number', 1),
                'id': item.get('id', ''),
                'artists': track_artists,
                'duration_ms': item.get('duration_ms', 0)
            })

        total_discs = max((t['disc_number'] for t in spotify_tracks), default=1)

        # 2. Load existing tracks for this group
        db = get_database()
        existing_tracks = db.get_retag_tracks(group_id)
        if not existing_tracks:
            raise ValueError(f"No tracks found for retag group {group_id}")

        with retag_lock:
            retag_state['total_tracks'] = len(existing_tracks)
            retag_state['phase'] = "Matching tracks..."

        # 3. Match existing files to new tracklist
        matched_pairs = []
        for existing_track in existing_tracks:
            best_match = None
            best_score = 0

            # Priority 1: Match by track number
            for st in spotify_tracks:
                if (st['track_number'] == existing_track.get('track_number') and
                        st['disc_number'] == existing_track.get('disc_number', 1)):
                    best_match = st
                    best_score = 1.0
                    break

            # Priority 2: Match by title similarity
            if not best_match:
                from difflib import SequenceMatcher
                existing_title = (existing_track.get('title') or '').lower().strip()
                for st in spotify_tracks:
                    st_title = (st.get('name') or '').lower().strip()
                    score = SequenceMatcher(None, existing_title, st_title).ratio()
                    if score > best_score and score > 0.6:
                        best_score = score
                        best_match = st

            if best_match:
                matched_pairs.append((existing_track, best_match))
            else:
                print(f"[Retag] No match found for track: '{existing_track.get('title')}'")
                matched_pairs.append((existing_track, None))

        with retag_lock:
            retag_state['phase'] = "Retagging files..."

        # 4. Retag each matched track
        for existing_track, matched_spotify in matched_pairs:
            current_file_path = existing_track.get('file_path', '')
            track_title = matched_spotify['name'] if matched_spotify else existing_track.get('title', 'Unknown')

            with retag_lock:
                retag_state['current_track'] = track_title

            if not matched_spotify:
                with retag_lock:
                    retag_state['processed'] += 1
                    retag_state['progress'] = int(retag_state['processed'] / retag_state['total_tracks'] * 100)
                continue

            # Verify file exists
            if not os.path.exists(current_file_path):
                print(f"[Retag] File not found, skipping: {current_file_path}")
                with retag_lock:
                    retag_state['processed'] += 1
                    retag_state['progress'] = int(retag_state['processed'] / retag_state['total_tracks'] * 100)
                continue

            # Build synthetic context for _enhance_file_metadata
            track_artists = matched_spotify.get('artists', [])
            context = {
                'original_search_result': {
                    'spotify_clean_title': matched_spotify['name'],
                    'spotify_clean_album': new_album_name,
                    'track_number': matched_spotify['track_number'],
                    'disc_number': matched_spotify.get('disc_number', 1),
                    'artists': track_artists,
                    'title': matched_spotify['name']
                },
                'spotify_album': {
                    'id': album_id,
                    'name': new_album_name,
                    'release_date': new_release_date,
                    'total_tracks': total_tracks,
                    'image_url': new_image_url,
                    'total_discs': total_discs
                },
                'track_info': {'id': matched_spotify['id']},
                'spotify_artist': new_artist,
                '_audio_quality': _get_audio_quality_string(current_file_path) or ''
            }

            album_info = {
                'is_album': total_tracks > 1,
                'album_name': new_album_name,
                'track_number': matched_spotify['track_number'],
                'disc_number': matched_spotify.get('disc_number', 1),
                'clean_track_name': matched_spotify['name'],
                'album_image_url': new_image_url
            }

            # Re-write metadata tags
            try:
                _enhance_file_metadata(current_file_path, context, new_artist, album_info)
                print(f"[Retag] Re-tagged: '{track_title}'")
            except Exception as meta_err:
                print(f"[Retag] Metadata write failed for '{track_title}': {meta_err}")

            # Compute new path and move if different
            file_ext = os.path.splitext(current_file_path)[1]
            try:
                new_path, _ = _build_final_path_for_track(context, new_artist, album_info, file_ext)

                if os.path.normpath(current_file_path) != os.path.normpath(new_path):
                    print(f"[Retag] Moving '{os.path.basename(current_file_path)}' -> '{new_path}'")
                    old_dir = os.path.dirname(current_file_path)
                    os.makedirs(os.path.dirname(new_path), exist_ok=True)
                    _safe_move_file(current_file_path, new_path)

                    # Move lyrics sidecar file alongside audio file if it exists
                    for lyrics_ext in ('.lrc', '.txt'):
                        old_lyrics = os.path.splitext(current_file_path)[0] + lyrics_ext
                        if os.path.exists(old_lyrics):
                            new_lyrics = os.path.splitext(new_path)[0] + lyrics_ext
                            try:
                                _safe_move_file(old_lyrics, new_lyrics)
                                print(f"[Retag] Moved {lyrics_ext} file alongside audio")
                            except Exception as lrc_err:
                                print(f"[Retag] Failed to move {lyrics_ext} file: {lrc_err}")

                    # Remove old cover.jpg if directory changed and old dir is now empty of audio
                    new_dir = os.path.dirname(new_path)
                    if os.path.normpath(old_dir) != os.path.normpath(new_dir):
                        old_cover = os.path.join(old_dir, 'cover.jpg')
                        if os.path.exists(old_cover):
                            # Check if any audio files remain in old directory
                            audio_exts = {'.flac', '.mp3', '.m4a', '.ogg', '.opus', '.wav', '.aac'}
                            remaining_audio = [f for f in os.listdir(old_dir)
                                               if os.path.splitext(f)[1].lower() in audio_exts]
                            if not remaining_audio:
                                try:
                                    os.remove(old_cover)
                                    print(f"[Retag] Removed orphaned cover.jpg from old directory")
                                except Exception:
                                    pass

                    # Cleanup old empty directories
                    transfer_dir = docker_resolve_path(config_manager.get('soulseek.transfer_path', './Transfer'))
                    _cleanup_empty_directories(transfer_dir, current_file_path)

                    # Update DB record
                    db.update_retag_track_path(existing_track['id'], str(new_path))
                    current_file_path = new_path
                else:
                    print(f"[Retag] Path unchanged for '{track_title}', no move needed")
            except Exception as move_err:
                print(f"[Retag] Path/move failed for '{track_title}': {move_err}")

            # Download cover art to album directory
            try:
                _download_cover_art(album_info, os.path.dirname(current_file_path), context)
            except Exception as cover_err:
                print(f"[Retag] Cover art download failed: {cover_err}")

            with retag_lock:
                retag_state['processed'] += 1
                retag_state['progress'] = int(retag_state['processed'] / retag_state['total_tracks'] * 100)

        # 5. Update the retag group record with new metadata
        update_kwargs = {
            'artist_name': new_artist.get('name', 'Unknown Artist'),
            'album_name': new_album_name,
            'image_url': new_image_url,
            'total_tracks': total_tracks,
            'release_date': new_release_date
        }
        # Set the correct ID field based on Spotify vs iTunes
        if str(album_id).isdigit():
            update_kwargs['itunes_album_id'] = album_id
            update_kwargs['spotify_album_id'] = None
        else:
            update_kwargs['spotify_album_id'] = album_id
            update_kwargs['itunes_album_id'] = None

        db.update_retag_group(group_id, **update_kwargs)

        with retag_lock:
            retag_state.update({
                "status": "finished",
                "phase": "Retag complete!",
                "progress": 100,
                "current_track": ""
            })
        print(f"[Retag] Retag operation complete for group {group_id}")

    except Exception as e:
        import traceback
        print(f"[Retag] Error during retag: {e}")
        print(traceback.format_exc())
        with retag_lock:
            retag_state.update({
                "status": "error",
                "phase": "Error",
                "error_message": str(e)
            })


def _check_and_remove_from_wishlist(context):
    """
    Check if a successfully downloaded track should be removed from wishlist.
    Extracts Spotify track data from download context and removes from wishlist if found.
    """
    try:
        from core.wishlist_service import get_wishlist_service
        wishlist_service = get_wishlist_service()
        
        # Try to extract Spotify track ID from various sources in the context
        spotify_track_id = None
        
        # Method 1: Direct track_info with id
        track_info = context.get('track_info', {})
        if track_info.get('id'):
            spotify_track_id = track_info['id']
            print(f"[Wishlist] Found Spotify ID from track_info: {spotify_track_id}")
        
        # Method 2: From original search result
        elif context.get('original_search_result', {}).get('id'):
            spotify_track_id = context['original_search_result']['id']
            print(f"[Wishlist] Found Spotify ID from original_search_result: {spotify_track_id}")
        
        # Method 3: Check if this is a wishlist download (context has wishlist_id)
        elif 'wishlist_id' in track_info:
            wishlist_id = track_info['wishlist_id']
            print(f"[Wishlist] Found wishlist_id in context: {wishlist_id}")
            
            # Get the Spotify track ID from the wishlist entry (search all profiles)
            database = get_database()
            all_profiles = database.get_all_profiles()
            wishlist_tracks = []
            for p in all_profiles:
                wishlist_tracks.extend(wishlist_service.get_wishlist_tracks_for_download(profile_id=p['id']))
            for wl_track in wishlist_tracks:
                if wl_track.get('wishlist_id') == wishlist_id:
                    spotify_track_id = wl_track.get('spotify_track_id') or wl_track.get('id')
                    print(f"[Wishlist] Found Spotify ID from wishlist entry: {spotify_track_id}")
                    break

        # Method 4: Try to construct ID from track metadata for fuzzy matching
        if not spotify_track_id:
            track_name = track_info.get('name') or context.get('original_search_result', {}).get('title', '')
            artist_name = _get_track_artist_name(track_info) or _get_track_artist_name(context.get('original_search_result', {}))

            if track_name and artist_name:
                print(f"[Wishlist] No Spotify ID found, checking for fuzzy match: '{track_name}' by '{artist_name}'")

                # Get all wishlist tracks and find potential matches (search all profiles)
                if not wishlist_tracks:
                    database = get_database()
                    all_profiles = database.get_all_profiles()
                    wishlist_tracks = []
                    for p in all_profiles:
                        wishlist_tracks.extend(wishlist_service.get_wishlist_tracks_for_download(profile_id=p['id']))
                for wl_track in wishlist_tracks:
                    wl_name = wl_track.get('name', '').lower()
                    wl_artists = wl_track.get('artists', [])
                    wl_artist_name = ''
                    
                    # Extract artist name from wishlist track
                    if wl_artists:
                        if isinstance(wl_artists[0], dict):
                            wl_artist_name = wl_artists[0].get('name', '').lower()
                        else:
                            wl_artist_name = str(wl_artists[0]).lower()
                    
                    # Simple fuzzy matching
                    if (wl_name == track_name.lower() and wl_artist_name == artist_name.lower()):
                        spotify_track_id = wl_track.get('spotify_track_id') or wl_track.get('id')
                        print(f"[Wishlist] Found fuzzy match - Spotify ID: {spotify_track_id}")
                        break
        
        # If we found a Spotify track ID, remove it from wishlist
        if spotify_track_id:
            print(f"[Wishlist] Attempting to remove track from wishlist: {spotify_track_id}")
            removed = wishlist_service.mark_track_download_result(spotify_track_id, success=True)
            if removed:
                print(f"[Wishlist] Successfully removed track from wishlist: {spotify_track_id}")
            else:
                print(f"ℹ️ [Wishlist] Track not found in wishlist or already removed: {spotify_track_id}")
        else:
            print(f"ℹ️ [Wishlist] No Spotify track ID found for wishlist removal check")
            
    except Exception as e:
        print(f"[Wishlist] Error in wishlist removal check: {e}")
        import traceback
        traceback.print_exc()

def _check_and_remove_track_from_wishlist_by_metadata(track_data):
    """
    Check if a track found during database analysis should be removed from wishlist.
    Uses track metadata (name, artists, id) to find and remove from wishlist.
    """
    try:
        from core.wishlist_service import get_wishlist_service
        wishlist_service = get_wishlist_service()
        
        # Extract track info
        track_name = track_data.get('name', '')
        track_id = track_data.get('id', '')
        artists = track_data.get('artists', [])
        
        print(f"[Analysis] Checking if track should be removed from wishlist: '{track_name}' (ID: {track_id})")
        
        # Method 1: Direct Spotify ID match
        if track_id:
            removed = wishlist_service.mark_track_download_result(track_id, success=True)
            if removed:
                print(f"[Analysis] Removed track from wishlist via direct ID match: {track_id}")
                return True
        
        # Method 2: Fuzzy matching by name and artist if no direct ID match
        if track_name and artists:
            # Extract primary artist name
            primary_artist = ''
            if isinstance(artists[0], dict) and 'name' in artists[0]:
                primary_artist = artists[0]['name']
            elif isinstance(artists[0], str):
                primary_artist = artists[0]
            else:
                primary_artist = str(artists[0])
            
            print(f"[Analysis] No direct ID match, trying fuzzy match: '{track_name}' by '{primary_artist}'")

            # Get all wishlist tracks and find matches (search all profiles)
            database = get_database()
            all_profiles = database.get_all_profiles()
            wishlist_tracks = []
            for p in all_profiles:
                wishlist_tracks.extend(wishlist_service.get_wishlist_tracks_for_download(profile_id=p['id']))
            for wl_track in wishlist_tracks:
                wl_name = wl_track.get('name', '').lower()
                wl_artists = wl_track.get('artists', [])
                wl_artist_name = ''
                
                # Extract artist name from wishlist track
                if wl_artists:
                    if isinstance(wl_artists[0], dict):
                        wl_artist_name = wl_artists[0].get('name', '').lower()
                    else:
                        wl_artist_name = str(wl_artists[0]).lower()
                
                # Fuzzy matching - normalize strings for comparison
                if (wl_name == track_name.lower() and wl_artist_name == primary_artist.lower()):
                    spotify_track_id = wl_track.get('spotify_track_id') or wl_track.get('id')
                    if spotify_track_id:
                        removed = wishlist_service.mark_track_download_result(spotify_track_id, success=True)
                        if removed:
                            print(f"[Analysis] Removed track from wishlist via fuzzy match: {spotify_track_id}")
                            return True
        
        print(f"ℹ️ [Analysis] Track not found in wishlist or already removed: '{track_name}'")
        return False
        
    except Exception as e:
        print(f"[Analysis] Error checking wishlist removal by metadata: {e}")
        import traceback
        traceback.print_exc()
        return False

def _automatic_wishlist_cleanup_after_db_update():
    """
    Automatic wishlist cleanup that runs after database updates.
    This is a simplified version of the cleanup API endpoint designed for background execution.
    """
    try:
        from core.wishlist_service import get_wishlist_service
        from database.music_database import MusicDatabase
        
        wishlist_service = get_wishlist_service()
        db = MusicDatabase()
        active_server = config_manager.get_active_media_server()
        
        print("[Auto Cleanup] Starting automatic wishlist cleanup after database update...")

        # Get all wishlist tracks (across all profiles - cleanup is global)
        database = get_database()
        all_profiles = database.get_all_profiles()
        wishlist_tracks = []
        for p in all_profiles:
            wishlist_tracks.extend(wishlist_service.get_wishlist_tracks_for_download(profile_id=p['id']))
        if not wishlist_tracks:
            print("[Auto Cleanup] No tracks in wishlist to clean up")
            return
        
        print(f"[Auto Cleanup] Found {len(wishlist_tracks)} tracks in wishlist")
        
        removed_count = 0
        
        for track in wishlist_tracks:
            track_name = track.get('name', '')
            artists = track.get('artists', [])
            spotify_track_id = track.get('spotify_track_id') or track.get('id')
            track_album = track.get('album', {}).get('name') if isinstance(track.get('album'), dict) else track.get('album')

            # Skip if no essential data
            if not track_name or not artists or not spotify_track_id:
                continue

            # Check each artist
            found_in_db = False
            for artist in artists:
                # Handle both string format and dict format
                if isinstance(artist, str):
                    artist_name = artist
                elif isinstance(artist, dict) and 'name' in artist:
                    artist_name = artist['name']
                else:
                    artist_name = str(artist)

                try:
                    db_track, confidence = db.check_track_exists(
                        track_name, artist_name,
                        confidence_threshold=0.7,
                        server_source=active_server,
                        album=track_album
                    )
                    
                    if db_track and confidence >= 0.7:
                        found_in_db = True
                        print(f"[Auto Cleanup] Track found in database: '{track_name}' by {artist_name} (confidence: {confidence:.2f})")
                        break
                        
                except Exception as db_error:
                    print(f"[Auto Cleanup] Error checking database for track '{track_name}': {db_error}")
                    continue
            
            # If found in database, remove from wishlist
            if found_in_db:
                try:
                    removed = wishlist_service.mark_track_download_result(spotify_track_id, success=True)
                    if removed:
                        removed_count += 1
                        print(f"[Auto Cleanup] Removed track from wishlist: '{track_name}' ({spotify_track_id})")
                except Exception as remove_error:
                    print(f"[Auto Cleanup] Error removing track from wishlist: {remove_error}")
        
        print(f"[Auto Cleanup] Completed automatic cleanup: {removed_count} tracks removed from wishlist")
        
    except Exception as e:
        print(f"[Auto Cleanup] Error in automatic wishlist cleanup: {e}")
        import traceback
        traceback.print_exc()

# ── Update detection ─────────────────────────────────────────────
_GITHUB_REPO = "Nezreka/SoulSync"
_update_cache = {'latest_sha': None, 'last_check': 0, 'error': None}
_UPDATE_CHECK_INTERVAL = 3600  # 1 hour

def _get_current_commit_sha():
    """Get the commit SHA of the running instance (env var for Docker, git for local)."""
    # Docker: baked in at build time via COMMIT_SHA build arg
    sha = os.environ.get('SOULSYNC_COMMIT_SHA', '').strip()
    if sha:
        return sha
    # Local dev: read from git
    try:
        import subprocess
        result = subprocess.run(['git', 'rev-parse', 'HEAD'], capture_output=True, text=True, cwd=os.path.dirname(__file__) or '.')
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return None

_current_commit_sha = _get_current_commit_sha()

def _check_for_updates():
    """Check GitHub for the latest commit SHA on main branch."""
    import time as _time
    now = _time.time()
    if now - _update_cache['last_check'] < _UPDATE_CHECK_INTERVAL:
        return  # Still fresh
    _update_cache['last_check'] = now
    try:
        import urllib.request
        import json as _json
        req = urllib.request.Request(
            f"https://api.github.com/repos/{_GITHUB_REPO}/commits/main",
            headers={'Accept': 'application/vnd.github.v3+json', 'User-Agent': 'SoulSync-UpdateCheck'}
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            data = _json.loads(resp.read().decode())
            _update_cache['latest_sha'] = data.get('sha')
            _update_cache['error'] = None
    except Exception as e:
        _update_cache['error'] = str(e)
        logger.debug(f"Update check failed: {e}")

@app.route('/api/update-check', methods=['GET'])
def check_for_update():
    """Check if a newer version is available on GitHub."""
    _check_for_updates()
    current = _current_commit_sha
    latest = _update_cache.get('latest_sha')
    update_available = bool(current and latest and current != latest)
    return jsonify({
        'update_available': update_available,
        'current_sha': current[:8] if current else None,
        'latest_sha': latest[:8] if latest else None,
        'is_docker': os.path.exists('/.dockerenv'),
    })

