@app.route('/api/server/playlists', methods=['GET'])
def get_server_playlists():
    """Get all playlists from the active media server."""
    try:
        active_server = config_manager.get_active_media_server()
        logger.info(f"[ServerPlaylists] Active server: {active_server}")
        if not active_server:
            return jsonify({"success": False, "error": "No media server configured"}), 400

        playlists_data = []
        if active_server == 'plex' and plex_client and plex_client.is_connected():
            # Use raw Plex API to get playlist metadata without fetching all tracks
            try:
                raw_playlists = plex_client.server.playlists()
                logger.info(f"[ServerPlaylists] Plex returned {len(raw_playlists)} total playlists")
                for playlist in raw_playlists:
                    if playlist.playlistType == 'audio':
                        playlists_data.append({
                            'id': str(playlist.ratingKey),
                            'name': playlist.title,
                            'track_count': playlist.leafCount,
                        })
                logger.info(f"[ServerPlaylists] Found {len(playlists_data)} audio playlists")
            except Exception as e:
                logger.error(f"[ServerPlaylists] Error fetching Plex playlists: {e}", exc_info=True)
                return jsonify({"success": False, "error": f"Plex error: {str(e)}"}), 500
        elif active_server == 'jellyfin' and jellyfin_client and jellyfin_client.is_connected():
            for pl in jellyfin_client.get_all_playlists():
                playlists_data.append({
                    'id': pl.id,
                    'name': pl.title,
                    'track_count': pl.leaf_count,
                })
        elif active_server == 'navidrome' and navidrome_client and navidrome_client.is_connected():
            for pl in navidrome_client.get_all_playlists():
                playlists_data.append({
                    'id': pl.id,
                    'name': pl.title,
                    'track_count': pl.leaf_count,
                })
        else:
            logger.warning(f"[ServerPlaylists] Server '{active_server}' not connected. plex_client={plex_client is not None}, jellyfin_client={jellyfin_client is not None}, navidrome_client={navidrome_client is not None}")
            return jsonify({"success": False, "error": f"{active_server} not connected"}), 400

        return jsonify({"success": True, "server_type": active_server, "playlists": playlists_data})
    except Exception as e:
        logger.error(f"Error getting server playlists: {e}", exc_info=True)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/server/playlist/<playlist_id>/tracks', methods=['GET'])
def get_server_playlist_tracks(playlist_id):
    """Get tracks from a server playlist with source match info from sync history."""
    try:
        active_server = config_manager.get_active_media_server()
        playlist_name = request.args.get('name', '')

        # Get tracks from server
        server_tracks = []
        if active_server == 'plex' and plex_client:
            try:
                # Try by ID first, fall back to name lookup (ID changes when playlist is recreated)
                raw_playlist = None
                try:
                    raw_playlist = plex_client.server.fetchItem(int(playlist_id))
                except Exception:
                    pass
                if not raw_playlist and playlist_name:
                    try:
                        raw_playlist = plex_client.server.playlist(playlist_name)
                    except Exception:
                        pass
                if raw_playlist:
                    if not playlist_name:
                        playlist_name = raw_playlist.title
                    plex_base = getattr(plex_client.server, '_baseurl', '') or ''
                    plex_token = getattr(plex_client.server, '_token', '') or ''
                    if not plex_base:
                        # Fallback: get from config
                        _pc = config_manager.get_plex_config()
                        plex_base = (_pc.get('base_url', '') or '').rstrip('/')
                        plex_token = plex_token or _pc.get('token', '')
                    logger.debug(f"[ServerPlaylistTracks] Plex base URL: {plex_base}")
                    for item in raw_playlist.items():
                        grandparent = getattr(item, 'grandparentTitle', '') or ''
                        parent = getattr(item, 'parentTitle', '') or ''
                        # Build full thumb URL from Plex relative path
                        thumb = ''
                        raw_thumb = getattr(item, 'thumb', '') or getattr(item, 'parentThumb', '') or ''
                        if raw_thumb and plex_base and plex_token:
                            thumb = f"{plex_base}{raw_thumb}?X-Plex-Token={plex_token}"
                        server_tracks.append({
                            'id': str(item.ratingKey),
                            'title': item.title,
                            'artist': grandparent,
                            'album': parent,
                            'duration': item.duration or 0,
                            'thumb': thumb,
                        })
            except Exception as e:
                logger.error(f"[ServerPlaylistTracks] Plex error: {e}", exc_info=True)
        elif active_server == 'jellyfin' and jellyfin_client:
            tracks = jellyfin_client.get_playlist_tracks(playlist_id)
            jf_base = jellyfin_client.base_url or ''
            for t in (tracks or []):
                raw = t._data if hasattr(t, '_data') else {}
                artists = raw.get('Artists', [])
                # Jellyfin image: /Items/{Id}/Images/Primary
                album_id = raw.get('AlbumId', '')
                thumb = f"{jf_base}/Items/{album_id}/Images/Primary?maxHeight=100" if album_id and jf_base else ''
                server_tracks.append({
                    'id': str(t.ratingKey),
                    'title': t.title,
                    'artist': artists[0] if artists else raw.get('AlbumArtist', ''),
                    'album': raw.get('Album', ''),
                    'duration': t.duration,
                    'thumb': thumb,
                })
        elif active_server == 'navidrome' and navidrome_client:
            tracks = navidrome_client.get_playlist_tracks(playlist_id)
            for t in (tracks or []):
                raw = t._data if hasattr(t, '_data') else {}
                # Navidrome cover art via Subsonic API
                cover_id = raw.get('coverArt', '') or raw.get('albumId', '')
                thumb = f"/api/navidrome/cover/{cover_id}" if cover_id else ''
                server_tracks.append({
                    'id': str(t.ratingKey),
                    'title': t.title,
                    'artist': raw.get('artist', ''),
                    'album': raw.get('album', ''),
                    'duration': t.duration,
                    'thumb': thumb,
                })

        # Get source tracks — prefer mirrored playlist, fall back to sync history
        source_tracks = []
        mirrored_id = request.args.get('mirrored_playlist_id')
        if mirrored_id:
            db = get_database()
            raw_tracks = db.get_mirrored_playlist_tracks(int(mirrored_id))

            # Build server art URL prefix for resolving relative thumb paths
            _art_prefix = ''
            _art_suffix = ''
            if active_server == 'plex' and plex_client and plex_client.server:
                _ab = getattr(plex_client.server, '_baseurl', '') or ''
                _at = getattr(plex_client.server, '_token', '') or ''
                if not _ab:
                    _pc = config_manager.get_plex_config()
                    _ab = (_pc.get('base_url', '') or '').rstrip('/')
                    _at = _at or _pc.get('token', '')
                _art_prefix = _ab
                _art_suffix = f"?X-Plex-Token={_at}" if _at else ''

            def _resolve_thumb(url):
                """Make relative server thumb URLs absolute."""
                if not url:
                    return ''
                if url.startswith('http'):
                    return url
                if url.startswith('/') and _art_prefix:
                    return f"{_art_prefix}{url}{_art_suffix}"
                return url

            # Build art lookup from server tracks we already fetched (no extra DB queries)
            _server_art_map = {}
            for svr in server_tracks:
                if svr.get('thumb'):
                    key = f"{(svr.get('artist') or '').lower().strip()}|{svr['title'].lower().strip()}"
                    _server_art_map[key] = svr['thumb']
                    # Also store by title-only as fallback
                    _server_art_map[svr['title'].lower().strip()] = svr['thumb']

            for t in raw_tracks:
                img = t.get('image_url') or ''
                if not img:
                    # Try artist+title first, fall back to title-only
                    key = f"{(t.get('artist_name') or '').lower().strip()}|{(t.get('track_name') or '').lower().strip()}"
                    img = _server_art_map.get(key, '') or _server_art_map.get((t.get('track_name') or '').lower().strip(), '')

                source_tracks.append({
                    'name': t.get('track_name', ''),
                    'artist': t.get('artist_name', ''),
                    'album': t.get('album_name', ''),
                    'image_url': img,
                    'duration_ms': t.get('duration_ms', 0),
                    'position': t.get('position', 0),
                })
        elif playlist_name:
            # Legacy fallback: cross-reference with sync history
            db = get_database()
            entries, _ = db.get_sync_history(page=1, limit=50)
            for entry in entries:
                if entry.get('playlist_name', '').lower() == playlist_name.lower():
                    full_entry = db.get_sync_history_entry(entry['id'])
                    if full_entry:
                        try:
                            tr = json.loads(full_entry.get('track_results') or '[]')
                            source_tracks = tr if isinstance(tr, list) else []
                        except (json.JSONDecodeError, TypeError):
                            pass
                        if not source_tracks:
                            try:
                                source_tracks = json.loads(full_entry.get('tracks_json') or '[]')
                            except (json.JSONDecodeError, TypeError):
                                pass
                    break

        # Build combined view with two-pass matching (exact then fuzzy)
        from difflib import SequenceMatcher
        combined = []
        used_server_indices = set()
        unmatched_source = []  # (index_in_combined, src_dict) for fuzzy second pass

        # Pass 1: Exact title match
        for i, src in enumerate(source_tracks):
            src_name = src.get('name', '')
            src_artist = src.get('artist', '')
            if not src_artist and src.get('artists'):
                a = src['artists'][0] if src['artists'] else ''
                src_artist = a.get('name', a) if isinstance(a, dict) else str(a)

            src_entry = {
                'name': src_name, 'artist': src_artist,
                'album': src.get('album', ''), 'image_url': src.get('image_url', ''),
                'duration_ms': src.get('duration_ms', 0), 'position': src.get('position', i),
            }

            best_idx = -1
            for j, svr in enumerate(server_tracks):
                if j in used_server_indices:
                    continue
                if svr['title'].lower().strip() == src_name.lower().strip():
                    best_idx = j
                    break

            if best_idx >= 0:
                used_server_indices.add(best_idx)
                combined.append({
                    'source_track': src_entry,
                    'server_track': server_tracks[best_idx],
                    'match_status': 'matched',
                    'confidence': 1.0,
                })
            else:
                idx = len(combined)
                combined.append({
                    'source_track': src_entry,
                    'server_track': None,
                    'match_status': 'missing',
                    'confidence': 0.0,
                })
                unmatched_source.append((idx, src_entry))

        # Pass 2: Fuzzy match on remaining unmatched source tracks
        for combo_idx, src_entry in unmatched_source:
            src_key = f"{src_entry['artist']} {src_entry['name']}".lower().strip()
            best_score = 0.0
            best_j = -1
            for j, svr in enumerate(server_tracks):
                if j in used_server_indices:
                    continue
                svr_key = f"{svr['artist']} {svr['title']}".lower().strip()
                score = SequenceMatcher(None, src_key, svr_key).ratio()
                if score > best_score and score >= 0.75:
                    best_score = score
                    best_j = j

            if best_j >= 0:
                used_server_indices.add(best_j)
                combined[combo_idx] = {
                    'source_track': src_entry,
                    'server_track': server_tracks[best_j],
                    'match_status': 'matched',
                    'confidence': round(best_score, 3),
                }

        # Add server tracks that aren't in the source (extra tracks on server)
        for j, svr in enumerate(server_tracks):
            if j not in used_server_indices:
                combined.append({
                    'source_track': None,
                    'server_track': svr,
                    'match_status': 'extra',
                    'confidence': 0.0,
                })

        return jsonify({
            "success": True,
            "server_type": active_server,
            "playlist_name": playlist_name,
            "tracks": combined,
            "server_track_count": len(server_tracks),
            "source_track_count": len(source_tracks),
        })
    except Exception as e:
        logger.error(f"Error getting server playlist tracks: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/server/playlist/<playlist_id>/replace-track', methods=['POST'])
def server_playlist_replace_track(playlist_id):
    """Replace a track in a server playlist. Rebuilds the playlist with the swap."""
    try:
        data = request.get_json()
        old_track_id = data.get('old_track_id')
        new_track_id = data.get('new_track_id')
        playlist_name = data.get('playlist_name', '')

        if not old_track_id or not new_track_id:
            return jsonify({"success": False, "error": "old_track_id and new_track_id required"}), 400
        if not playlist_name:
            return jsonify({"success": False, "error": "playlist_name required"}), 400

        active_server = config_manager.get_active_media_server()

        if active_server == 'plex' and plex_client:
            # Use raw Plex API - fetch playlist directly
            try:
                raw_playlist = plex_client.server.playlist(playlist_name)
            except Exception:
                return jsonify({"success": False, "error": "Playlist not found on server"}), 404

            # Build new track list with replacement
            new_tracks = []
            replaced = False
            for item in raw_playlist.items():
                if str(item.ratingKey) == str(old_track_id) and not replaced:
                    new_item = plex_client.server.fetchItem(int(new_track_id))
                    if new_item:
                        new_tracks.append(new_item)
                        replaced = True
                    else:
                        new_tracks.append(item)
                else:
                    new_tracks.append(item)

            if replaced:
                # Delete old and recreate directly (avoid update_playlist's backup logic)
                raw_playlist.delete()
                from plexapi.playlist import Playlist
                new_pl = Playlist.create(plex_client.server, playlist_name, items=new_tracks)
                return jsonify({"success": True, "message": "Track replaced", "new_playlist_id": str(new_pl.ratingKey)})
            else:
                return jsonify({"success": False, "error": "Old track not found in playlist"}), 404

        elif active_server == 'jellyfin' and jellyfin_client:
            current_tracks = jellyfin_client.get_playlist_tracks(playlist_id)
            new_track_ids = []
            replaced = False
            for t in (current_tracks or []):
                tid = str(t.ratingKey)
                if tid == str(old_track_id) and not replaced:
                    new_track_ids.append(new_track_id)
                    replaced = True
                else:
                    new_track_ids.append(tid)

            if replaced:
                new_track_objs = [type('T', (), {'ratingKey': tid, 'title': ''})() for tid in new_track_ids]
                jellyfin_client.update_playlist(playlist_name, new_track_objs)
                return jsonify({"success": True, "message": "Track replaced"})
            return jsonify({"success": False, "error": "Old track not found"}), 404

        elif active_server == 'navidrome' and navidrome_client:
            current_tracks = navidrome_client.get_playlist_tracks(playlist_id)
            new_track_ids = []
            replaced = False
            for t in (current_tracks or []):
                tid = str(t.ratingKey)
                if tid == str(old_track_id) and not replaced:
                    new_track_ids.append(new_track_id)
                    replaced = True
                else:
                    new_track_ids.append(tid)

            if replaced:
                new_track_objs = [type('T', (), {'ratingKey': tid, 'title': ''})() for tid in new_track_ids]
                navidrome_client.create_playlist(playlist_name, new_track_objs, playlist_id=playlist_id)
                return jsonify({"success": True, "message": "Track replaced"})
            return jsonify({"success": False, "error": "Old track not found"}), 404

        return jsonify({"success": False, "error": f"Unsupported server: {active_server}"}), 400
    except Exception as e:
        logger.error(f"Error replacing track in server playlist: {e}", exc_info=True)
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/server/playlist/<playlist_id>/add-track', methods=['POST'])
def server_playlist_add_track(playlist_id):
    """Add a track to a server playlist at a specific position."""
    try:
        data = request.get_json()
        track_id = data.get('track_id')
        playlist_name = data.get('playlist_name', '')
        position = data.get('position')  # 0-based index; None = append

        if not track_id:
            return jsonify({"success": False, "error": "track_id required"}), 400
        if not playlist_name:
            return jsonify({"success": False, "error": "playlist_name required"}), 400

        active_server = config_manager.get_active_media_server()

        if active_server == 'plex' and plex_client:
            try:
                raw_playlist = plex_client.server.playlist(playlist_name)
            except Exception:
                return jsonify({"success": False, "error": "Playlist not found"}), 404
            new_item = plex_client.server.fetchItem(int(track_id))
            if not new_item:
                return jsonify({"success": False, "error": "Track not found on server"}), 404

            logger.info(f"[ServerPlaylist] Adding track: '{new_item.title}' (ratingKey={new_item.ratingKey}) at position={position} to playlist '{playlist_name}'")

            if position is not None:
                # Rebuild playlist with track inserted at correct position
                current_items = list(raw_playlist.items())
                logger.info(f"[ServerPlaylist] Current playlist has {len(current_items)} tracks, inserting at pos {position}")
                pos = max(0, min(int(position), len(current_items)))
                current_items.insert(pos, new_item)
                # Delete old and recreate directly (avoid update_playlist's backup logic)
                raw_playlist.delete()
                from plexapi.playlist import Playlist
                new_pl = Playlist.create(plex_client.server, playlist_name, items=current_items)
                new_id = str(new_pl.ratingKey)
                logger.info(f"[ServerPlaylist] Recreated playlist with {len(current_items)} tracks, new ID: {new_id}")
            else:
                raw_playlist.addItems([new_item])
                new_id = str(raw_playlist.ratingKey)
            return jsonify({"success": True, "message": "Track added", "new_playlist_id": new_id})

        elif active_server == 'jellyfin' and jellyfin_client:
            current_tracks = jellyfin_client.get_playlist_tracks(playlist_id) or []
            track_ids = [str(t.ratingKey) for t in current_tracks]
            pos = max(0, min(int(position), len(track_ids))) if position is not None else len(track_ids)
            track_ids.insert(pos, track_id)
            new_track_objs = [type('T', (), {'ratingKey': tid, 'title': ''})() for tid in track_ids]
            jellyfin_client.update_playlist(playlist_name, new_track_objs)
            return jsonify({"success": True, "message": "Track added"})

        elif active_server == 'navidrome' and navidrome_client:
            current_tracks = navidrome_client.get_playlist_tracks(playlist_id) or []
            track_ids = [str(t.ratingKey) for t in current_tracks]
            pos = max(0, min(int(position), len(track_ids))) if position is not None else len(track_ids)
            track_ids.insert(pos, track_id)
            new_track_objs = [type('T', (), {'ratingKey': tid, 'title': ''})() for tid in track_ids]
            navidrome_client.create_playlist(playlist_name, new_track_objs, playlist_id=playlist_id)
            return jsonify({"success": True, "message": "Track added"})

        return jsonify({"success": False, "error": f"Unsupported server: {active_server}"}), 400
    except Exception as e:
        logger.error(f"Error adding track to server playlist: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/server/playlist/<playlist_id>/remove-track', methods=['POST'])
def server_playlist_remove_track(playlist_id):
    """Remove a track from a server playlist by its server track ID."""
    try:
        data = request.get_json()
        remove_track_id = data.get('track_id')
        playlist_name = data.get('playlist_name', '')

        if not remove_track_id:
            return jsonify({"success": False, "error": "track_id required"}), 400
        if not playlist_name:
            return jsonify({"success": False, "error": "playlist_name required"}), 400

        active_server = config_manager.get_active_media_server()

        if active_server == 'plex' and plex_client:
            try:
                raw_playlist = plex_client.server.playlist(playlist_name)
            except Exception:
                return jsonify({"success": False, "error": "Playlist not found"}), 404

            # Rebuild without the target track
            current_items = list(raw_playlist.items())
            new_items = [item for item in current_items if str(item.ratingKey) != str(remove_track_id)]
            if len(new_items) == len(current_items):
                return jsonify({"success": False, "error": "Track not found in playlist"}), 404
            raw_playlist.delete()
            if new_items:
                from plexapi.playlist import Playlist
                new_pl = Playlist.create(plex_client.server, playlist_name, items=new_items)
                return jsonify({"success": True, "message": "Track removed", "new_playlist_id": str(new_pl.ratingKey)})
            return jsonify({"success": True, "message": "Track removed (playlist now empty)"})

        elif active_server == 'jellyfin' and jellyfin_client:
            current_tracks = jellyfin_client.get_playlist_tracks(playlist_id) or []
            new_ids = [str(t.ratingKey) for t in current_tracks if str(t.ratingKey) != str(remove_track_id)]
            if len(new_ids) == len(current_tracks):
                return jsonify({"success": False, "error": "Track not found in playlist"}), 404
            new_track_objs = [type('T', (), {'ratingKey': tid, 'title': ''})() for tid in new_ids]
            jellyfin_client.update_playlist(playlist_name, new_track_objs)
            return jsonify({"success": True, "message": "Track removed"})

        elif active_server == 'navidrome' and navidrome_client:
            current_tracks = navidrome_client.get_playlist_tracks(playlist_id) or []
            new_ids = [str(t.ratingKey) for t in current_tracks if str(t.ratingKey) != str(remove_track_id)]
            if len(new_ids) == len(current_tracks):
                return jsonify({"success": False, "error": "Track not found in playlist"}), 404
            new_track_objs = [type('T', (), {'ratingKey': tid, 'title': ''})() for tid in new_ids]
            navidrome_client.create_playlist(playlist_name, new_track_objs, playlist_id=playlist_id)
            return jsonify({"success": True, "message": "Track removed"})

        return jsonify({"success": False, "error": f"Unsupported server: {active_server}"}), 400
    except Exception as e:
        logger.error(f"Error removing track from server playlist: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/library/search-tracks', methods=['GET'])
def library_search_tracks():
    """Search SoulSync's local database for tracks (for manual match correction)."""
    try:
        query = request.args.get('q', '').strip()
        limit = int(request.args.get('limit', 10))
        if not query:
            return jsonify({"success": True, "tracks": []})

        active_server = config_manager.get_active_media_server()
        database = get_database()

        # Build thumb URL resolver for this server
        _art_prefix = ''
        _art_suffix = ''
        if active_server == 'plex' and plex_client and plex_client.server:
            _ab = getattr(plex_client.server, '_baseurl', '') or ''
            _at = getattr(plex_client.server, '_token', '') or ''
            if not _ab:
                _pc = config_manager.get_plex_config()
                _ab = (_pc.get('base_url', '') or '').rstrip('/')
                _at = _at or _pc.get('token', '')
            _art_prefix = _ab
            _art_suffix = f"?X-Plex-Token={_at}" if _at else ''

        def _resolve_search_thumb(url):
            if not url:
                return ''
            if url.startswith('http'):
                return url
            if url.startswith('/') and _art_prefix:
                return f"{_art_prefix}{url}{_art_suffix}"
            return url

        results = database.search_tracks(title=query, artist='', limit=limit, server_source=active_server)

        tracks = []
        for t in results:
            tracks.append({
                'id': t.id,
                'title': t.title,
                'artist_name': t.artist_name,
                'album_title': getattr(t, 'album_title', ''),
                'album_thumb_url': _resolve_search_thumb(getattr(t, 'album_thumb_url', '')),
                'file_path': getattr(t, 'file_path', ''),
                'bitrate': getattr(t, 'bitrate', 0),
                'duration': getattr(t, 'duration', 0),
                'server_source': getattr(t, 'server_source', ''),
            })

        return jsonify({"success": True, "tracks": tracks})
    except Exception as e:
        logger.error(f"Error searching library tracks: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


@app.route('/api/playlists/<playlist_id>/start-missing-process', methods=['POST'])
def start_missing_tracks_process(playlist_id):
    """
    A single, robust endpoint to kick off the entire missing tracks workflow.
    It creates a batch and starts the master worker in the background.
    """
    data = request.get_json()
    tracks = data.get('tracks', [])
    playlist_name = data.get('playlist_name', 'Unknown Playlist')
    force_download_all = data.get('force_download_all', False)
    playlist_folder_mode = data.get('playlist_folder_mode', False)
    wing_it = data.get('wing_it', False)

    # Get album/artist context for artist album downloads
    is_album_download = data.get('is_album_download', False)
    album_context = data.get('album_context', None)
    artist_context = data.get('artist_context', None)

    if not tracks:
        return jsonify({"success": False, "error": "No tracks provided"}), 400

    # Log album context if provided
    if is_album_download and album_context and artist_context:
        print(f"[Artist Album] Received album context: '{album_context.get('name')}' by '{artist_context.get('name')}' ({album_context.get('album_type', 'album')})")
        print(f"   Release: {album_context.get('release_date', 'Unknown')}, Tracks: {album_context.get('total_tracks', len(tracks))}")

    # Log playlist folder mode if enabled
    if playlist_folder_mode:
        print(f"[Playlist Folder] Enabled for playlist: '{playlist_name}'")

    # Limit concurrent analysis processes to prevent resource exhaustion
    with tasks_lock:
        active_analysis_count = sum(1 for batch in download_batches.values() 
                                  if batch.get('phase') == 'analysis')
        if active_analysis_count >= 3:  # Allow max 3 concurrent analysis processes
            return jsonify({
                "success": False, 
                "error": "Too many analysis processes running. Please wait for one to complete."
            }), 429

    batch_id = str(uuid.uuid4())

    with tasks_lock:
        download_batches[batch_id] = {
            'phase': 'analysis',
            'playlist_id': playlist_id,
            'playlist_name': playlist_name,
            'queue': [],
            'active_count': 0,
            'max_concurrent': _get_batch_max_concurrent(is_album=is_album_download),
            # Track state management (replicating sync.py)
            'permanently_failed_tracks': [],
            'cancelled_tracks': set(),
            'queue_index': 0,
            'analysis_total': len(tracks),
            # Profile context for failed track wishlist re-adds
            'profile_id': get_current_profile_id(),
            'analysis_processed': 0,
            'analysis_results': [],
            'force_download_all': force_download_all,  # Pass the force flag to the batch
            'playlist_folder_mode': playlist_folder_mode,  # Organize downloads by playlist folder
            # Album context for artist album downloads (explicit folder structure)
            'is_album_download': is_album_download,
            'album_context': album_context,
            'artist_context': artist_context,
            'wing_it': wing_it,
        }

    # Record sync history
    _record_sync_history_start(batch_id, playlist_id, playlist_name, tracks,
                               is_album_download, album_context, artist_context,
                               playlist_folder_mode)

    # Link YouTube playlist to download process if this is a YouTube playlist
    if playlist_id.startswith('youtube_'):
        url_hash = playlist_id.replace('youtube_', '')
        if url_hash in youtube_playlist_states:
            youtube_playlist_states[url_hash]['download_process_id'] = batch_id
            youtube_playlist_states[url_hash]['phase'] = 'downloading'
            youtube_playlist_states[url_hash]['converted_spotify_playlist_id'] = playlist_id
            print(f"Linked YouTube playlist {url_hash} to download process {batch_id} (converted ID: {playlist_id})")
    
    # Link Tidal playlist to download process if this is a Tidal playlist
    if playlist_id.startswith('tidal_'):
        tidal_playlist_id = playlist_id.replace('tidal_', '')
        if tidal_playlist_id in tidal_discovery_states:
            tidal_discovery_states[tidal_playlist_id]['download_process_id'] = batch_id
            tidal_discovery_states[tidal_playlist_id]['phase'] = 'downloading'
            tidal_discovery_states[tidal_playlist_id]['converted_spotify_playlist_id'] = playlist_id
            print(f"Linked Tidal playlist {tidal_playlist_id} to download process {batch_id} (converted ID: {playlist_id})")

    # Link Spotify Public playlist to download process if this is a Spotify Public playlist
    if playlist_id.startswith('spotify_public_'):
        sp_url_hash = playlist_id.replace('spotify_public_', '')
        if sp_url_hash in spotify_public_discovery_states:
            spotify_public_discovery_states[sp_url_hash]['download_process_id'] = batch_id
            spotify_public_discovery_states[sp_url_hash]['phase'] = 'downloading'
            spotify_public_discovery_states[sp_url_hash]['converted_spotify_playlist_id'] = playlist_id
            print(f"Linked Spotify Public playlist {sp_url_hash} to download process {batch_id} (converted ID: {playlist_id})")

    # Link Deezer playlist to download process if this is a Deezer playlist
    if playlist_id.startswith('deezer_'):
        deezer_playlist_id = playlist_id.replace('deezer_', '')
        if deezer_playlist_id in deezer_discovery_states:
            deezer_discovery_states[deezer_playlist_id]['download_process_id'] = batch_id
            deezer_discovery_states[deezer_playlist_id]['phase'] = 'downloading'
            deezer_discovery_states[deezer_playlist_id]['converted_spotify_playlist_id'] = playlist_id
            print(f"Linked Deezer playlist {deezer_playlist_id} to download process {batch_id} (converted ID: {playlist_id})")

    # Stamp original index to keep task indices aligned with frontend row order
    for i, track in enumerate(tracks):
        if '_original_index' not in track:
            track['_original_index'] = i

    missing_download_executor.submit(_run_full_missing_tracks_process, batch_id, playlist_id, tracks)

    return jsonify({
        "success": True,
        "batch_id": batch_id
    })

@app.route('/api/tracks/download_missing', methods=['POST'])
def start_missing_downloads():
    """Legacy endpoint - redirect to new playlist-based endpoint"""
    dl_err = check_download_permission()
    if dl_err:
        return dl_err
    data = request.get_json()
    missing_tracks = data.get('missing_tracks', [])

    if not missing_tracks:
        return jsonify({"success": False, "error": "No missing tracks provided"}), 400
    
    # Use a default playlist_id for legacy compatibility
    playlist_id = "legacy_modal"
    
    # Call the new endpoint logic directly
    try:
        batch_id = str(uuid.uuid4())
        
        # Create task queue for this batch
        task_queue = []
        with tasks_lock:
            # Initialize batch management
            download_batches[batch_id] = {
                'queue': [],
                'active_count': 0,
                'max_concurrent': _get_max_concurrent(),
                'queue_index': 0,
                # Track state management (replicating sync.py)
                'permanently_failed_tracks': [],
                'cancelled_tracks': set(),
                # Profile context for failed track wishlist re-adds
                'profile_id': get_current_profile_id()
            }

            for track_index, track_data in enumerate(missing_tracks):
                task_id = str(uuid.uuid4())
                download_tasks[task_id] = {
                    'status': 'pending',
                    'track_info': track_data,
                    'playlist_id': playlist_id,
                    'batch_id': batch_id,
                    'track_index': track_index,
                    'download_id': None,
                    'username': None
                }
                
                # Add to batch queue instead of submitting immediately
                download_batches[batch_id]['queue'].append(task_id)
        
        # Start the first batch of downloads (up to 3)
        _start_next_batch_of_downloads(batch_id)

        return jsonify({"success": True, "batch_id": batch_id, "message": f"Queued {len(missing_tracks)} downloads for processing."})
        
    except Exception as e:
        print(f"Error starting missing downloads: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

# ===============================
# == SYNC PAGE API             ==
# ===============================

def _load_sync_status_file():
    """Load sync statuses from database."""
    try:
        database = get_database()
        raw = database.get_preference('sync_statuses')
        if raw:
            data = json.loads(raw)
            return data
        return {}
    except Exception as e:
        print(f"Error loading sync status: {e}")
        return {}

def _save_sync_status_file(sync_statuses):
    """Save sync statuses to database."""
    try:
        database = get_database()
        database.set_preference('sync_statuses', json.dumps(sync_statuses))
    except Exception as e:
        print(f"Error saving sync status: {e}")

def _update_and_save_sync_status(playlist_id, playlist_name, playlist_owner, snapshot_id, **kwargs):
    """Updates the sync status for a given playlist and saves to file (same logic as GUI)."""
    try:
        # Load existing sync statuses
        sync_statuses = _load_sync_status_file()

        # Update this playlist's sync status
        from datetime import datetime
        now = datetime.now()
        status = {
            'name': playlist_name,
            'owner': playlist_owner,
            'snapshot_id': snapshot_id,
            'last_synced': now.isoformat()
        }
        # Store match counts and track hash for smart-skip on scheduled syncs
        for key in ('matched_tracks', 'total_tracks', 'discovered_tracks', 'tracks_hash'):
            if key in kwargs:
                status[key] = kwargs[key]
        sync_statuses[playlist_id] = status
        
        # Save to file
        _save_sync_status_file(sync_statuses)
        print(f"Updated sync status for playlist '{playlist_name}' (ID: {playlist_id})")
        
    except Exception as e:
        print(f"Error updating sync status for {playlist_id}: {e}")

@app.route('/api/spotify/playlists', methods=['GET'])
def get_spotify_playlists():
    """Fetches all user playlists from Spotify and enriches them with local sync status."""
    client = get_spotify_client_for_profile()
    if not client or not client.is_authenticated():
        return jsonify({"error": "Spotify not authenticated."}), 401
    try:
        playlists = client.get_user_playlists_metadata_only()
        sync_statuses = _load_sync_status_file()

        playlist_data = []

        # Add regular playlists first
        for p in playlists:
            status_info = sync_statuses.get(p.id, {})
            sync_status = "Never Synced"
            # Handle snapshot_id safely - may not exist in core Playlist class
            playlist_snapshot = getattr(p, 'snapshot_id', '')

            print(f"Processing playlist: {p.name} (ID: {p.id})")
            print(f"   - Playlist snapshot: '{playlist_snapshot}'")
            print(f"   - Status info: {status_info}")

            if 'last_synced' in status_info:
                stored_snapshot = status_info.get('snapshot_id')
                last_sync_time = datetime.fromisoformat(status_info['last_synced']).strftime('%b %d, %H:%M')
                print(f"   - Stored snapshot: '{stored_snapshot}'")
                print(f"   - Snapshots match: {playlist_snapshot == stored_snapshot}")

                if playlist_snapshot != stored_snapshot:
                    sync_status = f"Last Sync: {last_sync_time}"
                    print(f"   - Result: Needs Sync (showing: {sync_status})")
                else:
                    sync_status = f"Synced: {last_sync_time}"
                    print(f"   - Result: {sync_status}")
            else:
                print(f"   - No last_synced found - Never Synced")

            playlist_data.append({
                "id": p.id, "name": p.name, "owner": p.owner,
                "track_count": p.total_tracks,
                "image_url": getattr(p, 'image_url', None),
                "sync_status": sync_status,
                "snapshot_id": playlist_snapshot
            })

        # Add virtual "Liked Songs" playlist at the END (just count, no full fetch)
        try:
            liked_songs_count = spotify_client.get_saved_tracks_count()
            if liked_songs_count > 0:
                liked_songs_id = "spotify:liked-songs"
                status_info = sync_statuses.get(liked_songs_id, {})
                sync_status = "Never Synced"

                if 'last_synced' in status_info:
                    last_sync_time = datetime.fromisoformat(status_info['last_synced']).strftime('%b %d, %H:%M')
                    sync_status = f"Synced: {last_sync_time}"

                # Get user info for owner name
                user_info = spotify_client.get_user_info()
                owner_name = user_info.get('display_name', 'You') if user_info else 'You'

                # Add Liked Songs as LAST playlist
                playlist_data.append({
                    "id": liked_songs_id,
                    "name": "Liked Songs",
                    "owner": owner_name,
                    "track_count": liked_songs_count,
                    "image_url": None,  # Spotify doesn't provide image for Liked Songs
                    "sync_status": sync_status,
                    "snapshot_id": ""  # Liked Songs doesn't have a snapshot_id
                })
                print(f"Added virtual 'Liked Songs' playlist with {liked_songs_count} tracks (count only)")
        except Exception as liked_error:
            print(f"Failed to add Liked Songs playlist: {liked_error}")
            # Don't fail the entire request if Liked Songs fails

        return jsonify(playlist_data)
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/spotify/playlist/<playlist_id>', methods=['GET'])
def get_playlist_tracks(playlist_id):
    """Fetches full track details for a specific playlist."""
    if not spotify_client or not spotify_client.is_authenticated():
        return jsonify({"error": "Spotify not authenticated."}), 401
    try:
        # Handle special "Liked Songs" virtual playlist
        if playlist_id == "spotify:liked-songs":
            user_info = spotify_client.get_user_info()
            owner_name = user_info.get('display_name', 'You') if user_info else 'You'

            # Fetch raw saved tracks with full album data
            tracks = []
            limit = 50
            offset = 0

            while True:
                if _spotify_rate_limited():
                    return jsonify({"error": "Spotify is currently rate limited. Please try again later."}), 429
                results = spotify_client.sp.current_user_saved_tracks(limit=limit, offset=offset)

                if not results or 'items' not in results:
                    break

                for item in results['items']:
                    if item['track'] and item['track']['id']:
                        track_data = item['track']
                        tracks.append({
                            'id': track_data['id'],
                            'name': track_data['name'],
                            'artists': track_data['artists'],  # Full artist objects (matches Download Missing Tracks behavior)
                            'album': track_data['album'],  # Full album object
                            'duration_ms': track_data['duration_ms'],
                            'popularity': track_data.get('popularity', 0),
                            'spotify_track_id': track_data['id']
                        })

                if len(results['items']) < limit or not results.get('next'):
                    break

                offset += limit

            # Create virtual playlist dict for Liked Songs
            playlist_dict = {
                'id': 'spotify:liked-songs',
                'name': 'Liked Songs',
                'description': 'Your saved tracks on Spotify',
                'owner': owner_name,
                'public': False,
                'collaborative': False,
                'track_count': len(tracks),
                'image_url': None,
                'snapshot_id': '',
                'tracks': tracks
            }
            return jsonify(playlist_dict)

        # Handle regular playlists
        if _spotify_rate_limited():
            return jsonify({"error": "Spotify is currently rate limited. Please try again later."}), 429
        # Fetch raw playlist data to preserve full album objects
        playlist_data = spotify_client.sp.playlist(playlist_id)

        # Fetch all tracks with full album data
        tracks = []
        try:
            results = spotify_client._get_playlist_items_page(playlist_id, limit=100)
        except Exception as items_err:
            # 403 on followed playlists — try the public embed scraper as fallback
            logger.warning(f"Playlist items fetch failed ({items_err}), trying public embed scraper")
            try:
                from core.spotify_public_scraper import scrape_spotify_embed
                embed_data = scrape_spotify_embed('playlist', playlist_id)
                if embed_data and not embed_data.get('error') and embed_data.get('tracks'):
                    for t in embed_data['tracks']:
                        artists = t.get('artists', [])
                        tracks.append({
                            'id': t.get('id', ''),
                            'name': t.get('name', ''),
                            'artists': artists if artists else [{'name': 'Unknown'}],
                            'album': {'name': '', 'images': []},
                            'duration_ms': t.get('duration_ms', 0),
                            'popularity': 0,
                            'spotify_track_id': t.get('id', '')
                        })
                    playlist_dict = {
                        'id': playlist_data['id'],
                        'name': playlist_data['name'],
                        'description': playlist_data.get('description', ''),
                        'owner': playlist_data['owner']['display_name'],
                        'public': playlist_data.get('public', False),
                        'collaborative': playlist_data.get('collaborative', False),
                        'track_count': len(tracks),
                        'image_url': playlist_data['images'][0]['url'] if playlist_data.get('images') else None,
                        'snapshot_id': playlist_data.get('snapshot_id', ''),
                        'tracks': tracks
                    }
                    return jsonify(playlist_dict)
            except Exception as scrape_err:
                logger.warning(f"Public embed scraper also failed: {scrape_err}")
            raise items_err  # Re-raise original error if both failed

        while results:
            for item in results['items']:
                # Handle both old API ('track') and new Feb 2026 API ('item') field names
                track_data = item.get('track') or item.get('item')
                if track_data and track_data.get('id'):
                    tracks.append({
                        'id': track_data['id'],
                        'name': track_data['name'],
                        'artists': track_data['artists'],  # Full artist objects (matches Download Missing Tracks behavior)
                        'album': track_data['album'],  # Full album object with album_type, total_tracks, etc.
                        'duration_ms': track_data['duration_ms'],
                        'popularity': track_data.get('popularity', 0),
                        'spotify_track_id': track_data['id']  # Also include as spotify_track_id for consistency
                    })

            results = spotify_client.sp.next(results) if results['next'] else None

        # Convert playlist to dict
        playlist_dict = {
            'id': playlist_data['id'],
            'name': playlist_data['name'],
            'description': playlist_data.get('description', ''),
            'owner': playlist_data['owner']['display_name'],
            'public': playlist_data.get('public', False),
            'collaborative': playlist_data.get('collaborative', False),
            'track_count': len(tracks),
            'image_url': playlist_data['images'][0]['url'] if playlist_data.get('images') else None,
            'snapshot_id': playlist_data.get('snapshot_id', ''),
            'tracks': tracks
        }
        return jsonify(playlist_dict)
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/spotify/album/<album_id>', methods=['GET'])
def get_album_tracks(album_id):
    """Fetches full track details for a specific album."""
    use_hydrabase = _is_hydrabase_active()

    # Try Hydrabase first when active — look up by album soul_id
    if use_hydrabase:
        album_name = request.args.get('name', '')
        album_artist = request.args.get('artist', '')
        try:
            hydra_tracks = hydrabase_client.get_album_tracks(album_id, limit=50)
            if hydra_tracks:
                track_items = []
                for t in hydra_tracks:
                    artist_list = t.artists if isinstance(t.artists, list) else [t.artists] if t.artists else []
                    track_items.append({
                        'name': t.name,
                        'track_number': t.track_number or 0,
                        'disc_number': t.disc_number or 1,
                        'duration_ms': t.duration_ms,
                        'id': t.id,
                        'artists': [{'name': a} if isinstance(a, str) else a for a in artist_list],
                        'uri': ''
                    })
                return jsonify({
                    'id': album_id,
                    'name': album_name or hydra_tracks[0].album or '',
                    'artists': [{'name': album_artist}] if album_artist else [],
                    'release_date': '',
                    'total_tracks': len(track_items),
                    'album_type': 'album',
                    'images': [],
                    'tracks': track_items
                })
        except Exception as e:
            logger.warning(f"Hydrabase album_tracks failed for '{album_id}', falling back to Spotify: {e}")

    # Source override: when user clicked from a specific search tab
    source_override = request.args.get('source', '')

    if not spotify_client or not spotify_client.is_authenticated():
        return jsonify({"error": "Spotify not authenticated."}), 401
    try:
        # Use explicit source client when overridden (prevents numeric ID misrouting)
        client = spotify_client
        if source_override == 'itunes':
            client = _get_itunes_client()
        elif source_override == 'hydrabase':
            # Hydrabase IDs originate from whichever plugin the peer runs.
            # 'plugin' param is authoritative; fall back to ID format detection.
            plugin = request.args.get('plugin', '').lower()
            if plugin == 'itunes' or (not plugin and album_id.isdigit()):
                client = _get_itunes_client()
            elif plugin == 'deezer':
                client = _get_deezer_client()
            # else: spotify (default)
        elif source_override == 'deezer':
            client = _get_deezer_client()
        elif source_override == 'discogs':
            client = _get_discogs_client()

        album_data = client.get_album(album_id)
        if not album_data:
            return jsonify({"error": "Album not found"}), 404

        # Extract tracks from album data (Spotify format)
        tracks = album_data.get('tracks', {}).get('items', [])

        # If no tracks in album data (iTunes format), fetch them separately
        if not tracks:
            tracks_data = client.get_album_tracks(album_id)
            if tracks_data and 'items' in tracks_data:
                tracks = tracks_data['items']

        # Format response
        album_dict = {
            'id': album_data['id'],
            'name': album_data['name'],
            'artists': album_data.get('artists', []),
            'release_date': album_data.get('release_date', ''),
            'total_tracks': album_data.get('total_tracks', 0),
            'album_type': album_data.get('album_type', 'album'),
            'images': album_data.get('images', []),
            'tracks': tracks
        }
        return jsonify(album_dict)
    except Exception as e:
        logger.error(f"Error fetching album tracks: {e}")
        return jsonify({"error": str(e)}), 500


@app.route('/api/spotify/track/<track_id>', methods=['GET'])
def get_spotify_track(track_id):
    """Fetches full track details including album data for a specific track."""
    # Try Hydrabase first when active and track name provided
    if _is_hydrabase_active():
        track_name = request.args.get('name', '')
        track_artist = request.args.get('artist', '')
        if track_name:
            try:
                query = f"{track_artist} {track_name}".strip() if track_artist else track_name
                hydra_tracks = hydrabase_client.search_tracks(query, limit=1)
                if hydra_tracks:
                    t = hydra_tracks[0]
                    artist_list = t.artists if isinstance(t.artists, list) else [t.artists] if t.artists else []
                    return jsonify({
                        'id': t.id,
                        'name': t.name,
                        'artists': [{'name': a} if isinstance(a, str) else a for a in artist_list],
                        'album': {'name': t.album, 'images': [{'url': t.image_url}] if t.image_url else []},
                        'duration_ms': t.duration_ms,
                        'preview_url': t.preview_url,
                        'external_urls': t.external_urls or {},
                        'popularity': t.popularity,
                    })
            except Exception as e:
                logger.warning(f"Hydrabase track lookup failed for '{track_name}', falling back to Spotify: {e}")

    if not spotify_client or not spotify_client.is_authenticated():
        return jsonify({"error": "Spotify not authenticated."}), 401
    try:
        track_data = spotify_client.get_track_details(track_id)
        if not track_data:
            return jsonify({"error": "Track not found"}), 404

        return jsonify(track_data)
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route('/api/spotify/search', methods=['GET'])
def search_spotify():
    """Generic Spotify search endpoint - supports tracks, albums, artists"""
    use_hydrabase = _is_hydrabase_active()
    if not use_hydrabase:
        if not spotify_client or not spotify_client.is_authenticated():
            return jsonify({"error": "Spotify not authenticated."}), 401

    try:
        query = request.args.get('q', '').strip()
        search_type = request.args.get('type', 'track').strip()
        limit = int(request.args.get('limit', 20))

        if not query:
            return jsonify({"error": "Query parameter 'q' is required"}), 400

        if use_hydrabase:
            tracks = hydrabase_client.search_tracks(query, limit=limit)
        else:
            # Mirror to Hydrabase P2P network
            if hydrabase_worker and dev_mode_enabled:
                hydrabase_worker.enqueue(query, search_type)
            tracks = spotify_client.search_tracks(query, limit=limit)

        tracks_items = [{
            'id': t.id,
            'name': t.name,
            'artists': t.artists if isinstance(t.artists, list) else [t.artists],
            'album': t.album,
            'duration_ms': t.duration_ms,
            'uri': f"spotify:track:{t.id}"
        } for t in tracks]

        return jsonify({'tracks': {'items': tracks_items}})

    except Exception as e:
        print(f"Error searching Spotify: {e}")
        return jsonify({"error": str(e)}), 500

@app.route('/api/spotify/search_tracks', methods=['GET'])
def search_spotify_tracks():
    """Search for tracks on Spotify - used by discovery fix modal"""
    use_hydrabase = _is_hydrabase_active()
    if not use_hydrabase:
        if not spotify_client or not spotify_client.is_authenticated():
            return jsonify({"error": "Spotify not authenticated."}), 401

    try:
        # Support field-specific search params (track, artist) or legacy combined query
        track_q = request.args.get('track', '').strip()
        artist_q = request.args.get('artist', '').strip()
        legacy_query = request.args.get('query', '').strip()
        limit = int(request.args.get('limit', 20))

        # Build Spotify field-filtered query
        if track_q or artist_q:
            parts = []
            if track_q:
                parts.append(f'track:{track_q}')
            if artist_q:
                parts.append(f'artist:{artist_q}')
            query = ' '.join(parts)
        elif legacy_query:
            query = legacy_query
        else:
            return jsonify({"error": "Query parameter is required"}), 400

        if use_hydrabase:
            tracks = hydrabase_client.search_tracks(query, limit=limit)
        else:
            if hydrabase_worker and dev_mode_enabled:
                hydrabase_worker.enqueue(query, 'tracks')
            tracks = spotify_client.search_tracks(query, limit=limit)

        tracks_dict = [{
            'id': t.id,
            'name': t.name,
            'artists': t.artists,
            'album': t.album,
            'duration_ms': t.duration_ms
        } for t in tracks]

        return jsonify({'tracks': tracks_dict})

    except Exception as e:
        print(f"Error searching Spotify tracks: {e}")
        return jsonify({"error": str(e)}), 500


