@app.route('/api/watchlist/scan', methods=['POST'])
def start_watchlist_scan():
    """Start a watchlist scan for new releases"""
    try:
        # Check if MetadataService can provide a working client (Spotify OR fallback)
        from core.metadata_service import MetadataService
        metadata_service = MetadataService()

        # Get active provider - will be spotify or the configured fallback
        active_provider = metadata_service.get_active_provider()
        provider_info = metadata_service.get_provider_info()

        # Verify we have at least one working provider
        if not provider_info['spotify_authenticated'] and not provider_info['itunes_available']:
            fallback_name = provider_info.get('fallback_source', 'iTunes').capitalize()
            return jsonify({
                "success": False,
                "error": f"No music provider available. Please authenticate Spotify or ensure {fallback_name} is accessible."
            }), 400
        
        logger.info(f"Starting watchlist scan with {active_provider} provider")

        # Check if watchlist is already scanning
        if is_watchlist_actually_scanning():
            return jsonify({"success": False, "error": "Watchlist scan is already in progress."}), 409
        
        # Start the scan in a background thread
        scan_profile_id = get_current_profile_id()
        def run_scan():
            _ew_state = {}
            try:
                global watchlist_scan_state, watchlist_auto_scanning, watchlist_auto_scanning_timestamp
                from core.watchlist_scanner import WatchlistScanner
                from database.music_database import get_database

                # Set flag and timestamp for manual scan
                import time
                with watchlist_timer_lock:
                    watchlist_auto_scanning = True
                    watchlist_auto_scanning_timestamp = time.time()
                    print(f"[Manual Watchlist Scan] Flag set at timestamp {watchlist_auto_scanning_timestamp}")

                # Get list of artists to scan (for the current profile)
                database = get_database()
                watchlist_artists = database.get_watchlist_artists(profile_id=scan_profile_id)

                # Apply global overrides if enabled
                _apply_watchlist_global_overrides(watchlist_artists)

                if not watchlist_artists:
                    watchlist_scan_state['status'] = 'completed'
                    watchlist_scan_state['summary'] = {
                        'total_artists': 0,
                        'successful_scans': 0,
                        'new_tracks_found': 0,
                        'tracks_added_to_wishlist': 0
                    }
                    # Reset flag
                    with watchlist_timer_lock:
                        watchlist_auto_scanning = False
                        watchlist_auto_scanning_timestamp = 0
                    return

                # Initialize scanner with MetadataService for cross-provider support
                scanner = WatchlistScanner(metadata_service=metadata_service)
                
                # PROACTIVE ID BACKFILLING (cross-provider support)
                # Before scanning, ensure all artists have IDs for ALL available sources
                providers_to_backfill = ['itunes', 'deezer']
                if spotify_client and spotify_client.is_spotify_authenticated():
                    providers_to_backfill.append('spotify')
                try:
                    if config_manager.get('discogs.token', ''):
                        providers_to_backfill.append('discogs')
                except Exception:
                    pass
                for _bf_provider in providers_to_backfill:
                    try:
                        print(f"Checking for missing {_bf_provider} IDs in watchlist...")
                        scanner._backfill_missing_ids(watchlist_artists, _bf_provider)
                    except Exception as backfill_error:
                        print(f"Error during {_bf_provider} ID backfilling: {backfill_error}")
                        # Continue with next provider

                # IMAGE BACKFILL — fix watchlist artists with missing images
                # Uses DB-only lookups (metadata cache + album art) — no API calls
                try:
                    conn = database._get_connection()
                    cursor = conn.cursor()
                    cursor.execute("""
                        SELECT id, artist_name, spotify_artist_id, itunes_artist_id,
                               deezer_artist_id, discogs_artist_id
                        FROM watchlist_artists
                        WHERE profile_id = ? AND (image_url IS NULL OR image_url = '' OR image_url = 'None'
                              OR image_url NOT LIKE 'http%')
                    """, (scan_profile_id,))
                    imageless = cursor.fetchall()

                    if imageless:
                        print(f"Backfilling images for {len(imageless)} watchlist artists...")
                        filled = 0
                        for row in imageless:
                            name = row['artist_name']
                            nn = name.lower().strip()
                            img = None

                            # 1. Check metadata cache for artist image
                            cursor.execute("""
                                SELECT image_url FROM metadata_cache_entities
                                WHERE entity_type = 'artist' AND name = ? COLLATE NOCASE
                                  AND image_url IS NOT NULL AND image_url LIKE 'http%'
                                LIMIT 1
                            """, (name,))
                            cr = cursor.fetchone()
                            if cr:
                                img = cr['image_url']

                            # 2. Deezer direct URL (no API call needed)
                            if not img and row['deezer_artist_id']:
                                img = f"https://api.deezer.com/artist/{row['deezer_artist_id']}/image?size=big"

                            # 3. Deezer ID from cache (artist may have a Deezer match we haven't stored on watchlist)
                            if not img:
                                cursor.execute("""
                                    SELECT entity_id FROM metadata_cache_entities
                                    WHERE entity_type = 'artist' AND source = 'deezer'
                                      AND name = ? COLLATE NOCASE LIMIT 1
                                """, (name,))
                                dz = cursor.fetchone()
                                if dz and dz['entity_id']:
                                    img = f"https://api.deezer.com/artist/{dz['entity_id']}/image?size=big"

                            # 4. Album art fallback (iTunes artists have no artist images)
                            if not img:
                                cursor.execute("""
                                    SELECT image_url FROM metadata_cache_entities
                                    WHERE entity_type = 'album' AND image_url LIKE 'http%'
                                      AND artist_name = ? COLLATE NOCASE LIMIT 1
                                """, (name,))
                                alb = cursor.fetchone()
                                if alb:
                                    img = alb['image_url']

                            if img:
                                aid = (row['spotify_artist_id'] or row['itunes_artist_id']
                                       or row['deezer_artist_id'] or row['discogs_artist_id'])
                                if aid:
                                    database.update_watchlist_artist_image(aid, img)
                                else:
                                    # No external IDs — update by internal row ID directly
                                    cursor.execute("""
                                        UPDATE watchlist_artists SET image_url = ?, updated_at = CURRENT_TIMESTAMP
                                        WHERE id = ?
                                    """, (img, row['id']))
                                    conn.commit()
                                filled += 1

                        if filled:
                            print(f"Backfilled {filled}/{len(imageless)} watchlist artist images")
                except Exception as img_err:
                    print(f"Image backfill error: {img_err}")

                # Initialize detailed progress tracking
                watchlist_scan_state.update({
                    'total_artists': len(watchlist_artists),
                    'current_artist_index': 0,
                    'current_artist_name': '',
                    'current_artist_image_url': '',
                    'current_phase': 'starting',
                    'albums_to_check': 0,
                    'albums_checked': 0,
                    'current_album': '',
                    'current_album_image_url': '',
                    'current_track_name': '',
                    'tracks_found_this_scan': 0,
                    'tracks_added_this_scan': 0,
                    'recent_wishlist_additions': []
                })
                
                scan_results = []

                # Pause enrichment workers during scan to reduce API contention
                _ew_state = _pause_enrichment_workers('watchlist scan')

                # Dynamic delay calculation based on scan scope
                lookback_period = scanner._get_lookback_period_setting()
                is_full_discography = (lookback_period == 'all')
                artist_count = len(watchlist_artists)

                base_artist_delay = 2.0
                base_album_delay = 0.5

                # Scale up for full discography (way more albums per artist)
                if is_full_discography:
                    base_artist_delay *= 2.0
                    base_album_delay *= 2.0

                # Scale up further for large artist counts (sustained API pressure)
                if artist_count > 200:
                    base_artist_delay *= 1.5
                    base_album_delay *= 1.25
                elif artist_count > 100:
                    base_artist_delay *= 1.25

                artist_delay = base_artist_delay
                album_delay = base_album_delay
                print(f"Scan parameters: {artist_count} artists, lookback={lookback_period}, "
                      f"delays: {artist_delay:.1f}s/artist, {album_delay:.1f}s/album")

                # Circuit breaker: pause scan on consecutive rate-limit failures
                consecutive_failures = 0
                CIRCUIT_BREAKER_THRESHOLD = 3
                circuit_breaker_pause = 60  # seconds, doubles each trigger, max 600s

                for i, artist in enumerate(watchlist_artists):
                    # Check for cancel request
                    if watchlist_scan_state.get('cancel_requested'):
                        print(f"[Manual Watchlist Scan] Cancel requested after {i}/{len(watchlist_artists)} artists")
                        watchlist_scan_state['status'] = 'cancelled'
                        watchlist_scan_state['current_phase'] = 'cancelled'
                        watchlist_scan_state['summary'] = {
                            'total_artists': i,
                            'successful_scans': len([r for r in scan_results if r.success]),
                            'new_tracks_found': sum(r.new_tracks_found for r in scan_results if r.success),
                            'tracks_added_to_wishlist': sum(r.tracks_added_to_wishlist for r in scan_results if r.success),
                            'cancelled': True
                        }
                        break

                    try:
                        # Fetch artist image using provider-aware method
                        artist_image_url = scanner.get_artist_image_url(artist) or ''

                        # Update progress
                        watchlist_scan_state.update({
                            'current_artist_index': i + 1,
                            'current_artist_name': artist.artist_name,
                            'current_artist_image_url': artist_image_url,
                            'current_phase': 'fetching_discography',
                            'albums_to_check': 0,
                            'albums_checked': 0,
                            'current_album': '',
                            'current_album_image_url': '',
                            'current_track_name': ''
                        })

                        # Get artist discography using provider-aware method
                        albums = scanner.get_artist_discography_for_watchlist(artist, artist.last_scan_timestamp)

                        if albums is None:
                            scan_results.append(type('ScanResult', (), {
                                'artist_name': artist.artist_name,
                                'spotify_artist_id': artist.spotify_artist_id,
                                'albums_checked': 0,
                                'new_tracks_found': 0,
                                'tracks_added_to_wishlist': 0,
                                'success': False,
                                'error_message': "Failed to get artist discography"
                            })())
                            continue
                        
                        # Update with album count
                        watchlist_scan_state.update({
                            'current_phase': 'checking_albums',
                            'albums_to_check': len(albums),
                            'albums_checked': 0
                        })
                        
                        # Track progress for this artist
                        artist_new_tracks = 0
                        artist_added_tracks = 0
                        
                        # Scan each album
                        for album_index, album in enumerate(albums):
                            try:
                                # Get album tracks using provider-aware method
                                album_data = scanner.metadata_service.get_album(album.id)
                                if not album_data or 'tracks' not in album_data:
                                    logger.debug(f"Skipping album {album.name} (id={album.id}): no track data returned")
                                    continue

                                tracks = album_data['tracks']['items']

                                # Check release type filter (album/EP/single)
                                if not scanner._should_include_release(len(tracks), artist):
                                    continue

                                # Get album image
                                album_image_url = ''
                                if 'images' in album_data and album_data['images']:
                                    album_image_url = album_data['images'][0]['url']

                                watchlist_scan_state.update({
                                    'albums_checked': album_index + 1,
                                    'current_album': album.name,
                                    'current_album_image_url': album_image_url,
                                    'current_phase': f'checking_album_{album_index + 1}_of_{len(albums)}'
                                })

                                # Check each track
                                for track in tracks:
                                    # Check content type filter (live/remix/acoustic/compilation)
                                    if not scanner._should_include_track(track, album_data, artist):
                                        continue

                                    # Update current track being processed
                                    track_name = track.get('name', 'Unknown Track')
                                    watchlist_scan_state['current_track_name'] = track_name

                                    if scanner.is_track_missing_from_library(track):
                                        artist_new_tracks += 1
                                        watchlist_scan_state['tracks_found_this_scan'] += 1

                                        # Add to wishlist
                                        if scanner.add_track_to_wishlist(track, album_data, artist):
                                            artist_added_tracks += 1
                                            watchlist_scan_state['tracks_added_this_scan'] += 1

                                            # Add to recent wishlist additions feed
                                            track_artists = track.get('artists', [])
                                            track_artist_name = track_artists[0].get('name', 'Unknown Artist') if track_artists else 'Unknown Artist'

                                            watchlist_scan_state['recent_wishlist_additions'].insert(0, {
                                                'track_name': track_name,
                                                'artist_name': track_artist_name,
                                                'album_image_url': album_image_url
                                            })

                                            # Keep only last 10
                                            if len(watchlist_scan_state['recent_wishlist_additions']) > 10:
                                                watchlist_scan_state['recent_wishlist_additions'].pop()

                                # Rate-limited delay between albums
                                import time
                                time.sleep(album_delay)

                            except Exception as e:
                                print(f"Error checking album {album.name}: {e}")
                                continue

                        # Update scan timestamp
                        scanner.update_artist_scan_timestamp(artist)

                        # Store result
                        scan_results.append(type('ScanResult', (), {
                            'artist_name': artist.artist_name,
                            'spotify_artist_id': artist.spotify_artist_id,
                            'albums_checked': len(albums),
                            'new_tracks_found': artist_new_tracks,
                            'tracks_added_to_wishlist': artist_added_tracks,
                            'success': True,
                            'error_message': None
                        })())

                        print(f"Scanned {artist.artist_name}: {artist_new_tracks} new tracks found, {artist_added_tracks} added to wishlist")

                        # Fetch similar artists for discovery feature
                        # This is critical for the discover page to work
                        try:
                            watchlist_scan_state['current_phase'] = 'fetching_similar_artists'
                            source_artist_id = artist.spotify_artist_id or artist.itunes_artist_id or str(artist.id)

                            # If Spotify is authenticated, also require Spotify IDs to be present
                            spotify_authenticated = spotify_client and spotify_client.is_spotify_authenticated()
                            if database.has_fresh_similar_artists(source_artist_id, days_threshold=30, require_spotify=spotify_authenticated, profile_id=scan_profile_id):
                                print(f"  Similar artists for {artist.artist_name} are cached and fresh")
                                # Still backfill missing iTunes IDs
                                scanner._backfill_similar_artists_itunes_ids(source_artist_id, profile_id=scan_profile_id)
                            else:
                                print(f"  Fetching similar artists for {artist.artist_name}...")
                                scanner.update_similar_artists(artist, profile_id=scan_profile_id)
                                print(f"  Similar artists updated for {artist.artist_name}")
                        except Exception as similar_error:
                            print(f"  Failed to update similar artists for {artist.artist_name}: {similar_error}")

                        # Delay between artists
                        if i < len(watchlist_artists) - 1:
                            watchlist_scan_state['current_phase'] = 'rate_limiting'
                            time.sleep(artist_delay)

                        # Reset circuit breaker on successful artist scan
                        consecutive_failures = 0
                        circuit_breaker_pause = 60

                    except Exception as e:
                        print(f"Error scanning artist {artist.artist_name}: {e}")

                        # Circuit breaker: detect consecutive rate-limit failures
                        error_str = str(e).lower()
                        if "429" in error_str or "rate limit" in error_str:
                            consecutive_failures += 1
                            if consecutive_failures >= CIRCUIT_BREAKER_THRESHOLD:
                                print(f"Circuit breaker: {consecutive_failures} consecutive rate-limit failures, pausing {circuit_breaker_pause}s")
                                watchlist_scan_state['current_phase'] = 'circuit_breaker_pause'
                                time.sleep(circuit_breaker_pause)
                                circuit_breaker_pause = min(circuit_breaker_pause * 2, 600)
                                consecutive_failures = 0
                        else:
                            consecutive_failures = 0

                        scan_results.append(type('ScanResult', (), {
                            'artist_name': artist.artist_name,
                            'spotify_artist_id': artist.spotify_artist_id,
                            'albums_checked': 0,
                            'new_tracks_found': 0,
                            'tracks_added_to_wishlist': 0,
                            'success': False,
                            'error_message': str(e)
                        })())

                # Store final results (skip if cancelled — already set by cancel handler)
                was_cancelled = watchlist_scan_state.get('cancel_requested', False)
                if not was_cancelled:
                    watchlist_scan_state['status'] = 'completed'
                    watchlist_scan_state['results'] = scan_results
                    watchlist_scan_state['completed_at'] = datetime.now()
                    _artmap_cache_invalidate(scan_profile_id)
                    watchlist_scan_state['current_phase'] = 'completed'

                    # Calculate summary
                    successful_scans = [r for r in scan_results if r.success]
                    total_new_tracks = sum(r.new_tracks_found for r in successful_scans)
                    total_added_to_wishlist = sum(r.tracks_added_to_wishlist for r in successful_scans)

                    watchlist_scan_state['summary'] = {
                        'total_artists': len(scan_results),
                        'successful_scans': len(successful_scans),
                        'new_tracks_found': total_new_tracks,
                        'tracks_added_to_wishlist': total_added_to_wishlist
                    }

                    print(f"Watchlist scan completed: {len(successful_scans)}/{len(scan_results)} artists scanned successfully")
                    print(f"Found {total_new_tracks} new tracks, added {total_added_to_wishlist} to wishlist")
                else:
                    print(f"Watchlist scan cancelled — skipping post-scan steps")

                # Post-scan steps — skip if cancelled
                if not was_cancelled:
                    # Populate discovery pool from similar artists
                    print("Starting discovery pool population...")
                    watchlist_scan_state['current_phase'] = 'populating_discovery_pool'
                    try:
                        scanner.populate_discovery_pool(profile_id=scan_profile_id)
                        print("Discovery pool population complete")
                    except Exception as discovery_error:
                        print(f"Error populating discovery pool: {discovery_error}")
                        import traceback
                        traceback.print_exc()

                    # Update ListenBrainz playlists cache
                    print("Starting ListenBrainz playlists update...")
                    watchlist_scan_state['current_phase'] = 'updating_listenbrainz'
                    try:
                        from core.listenbrainz_manager import ListenBrainzManager
                        db = get_database()
                        db_path = str(db.database_path)
                        # Update for all profiles with LB tokens
                        lb_profiles = db.get_profiles_with_listenbrainz()
                        if lb_profiles:
                            for lb_prof in lb_profiles:
                                lb_manager = ListenBrainzManager(db_path, profile_id=lb_prof['id'], token=lb_prof['token'], base_url=lb_prof['base_url'])
                                lb_result = lb_manager.update_all_playlists()
                                if lb_result.get('success'):
                                    print(f"ListenBrainz update complete for profile {lb_prof['id']}: {lb_result.get('summary', {})}")
                        else:
                            # Fallback: use global config token
                            lb_manager = ListenBrainzManager(db_path)
                            lb_result = lb_manager.update_all_playlists()
                            if lb_result.get('success'):
                                print(f"ListenBrainz update complete (global): {lb_result.get('summary', {})}")
                            elif lb_result.get('error'):
                                print(f"ListenBrainz update skipped: {lb_result.get('error')}")
                    except Exception as lb_error:
                        print(f"Error updating ListenBrainz: {lb_error}")
                        import traceback
                        traceback.print_exc()

                    # Update current seasonal playlist (weekly refresh)
                    print("Starting seasonal content update...")
                    watchlist_scan_state['current_phase'] = 'updating_seasonal'
                    try:
                        from core.seasonal_discovery import get_seasonal_discovery_service
                        seasonal_service = get_seasonal_discovery_service(spotify_client, database)

                        # Only update the current active season
                        current_season = seasonal_service.get_current_season()
                        if current_season:
                            if seasonal_service.should_populate_seasonal_content(current_season, days_threshold=7):
                                print(f"Updating {current_season} seasonal content...")
                                seasonal_service.populate_seasonal_content(current_season)
                                seasonal_service.curate_seasonal_playlist(current_season)
                                print(f"{current_season.capitalize()} seasonal content updated")
                            else:
                                print(f"{current_season.capitalize()} seasonal content recently updated, skipping")
                        else:
                            print("ℹ️ No active season at this time")
                    except Exception as seasonal_error:
                        print(f"Error updating seasonal content: {seasonal_error}")
                        import traceback
                        traceback.print_exc()

                    # Sync Spotify library cache
                    print("Syncing Spotify library cache...")
                    watchlist_scan_state['current_phase'] = 'syncing_spotify_library'
                    try:
                        scanner.sync_spotify_library_cache(profile_id=scan_profile_id)
                        print("Spotify library cache sync complete")
                    except Exception as lib_error:
                        print(f"Error syncing Spotify library: {lib_error}")

            except Exception as e:
                print(f"Error during watchlist scan: {e}")
                watchlist_scan_state['status'] = 'error'
                watchlist_scan_state['error'] = str(e)

            finally:
                # Resume enrichment workers if we paused them
                _resume_enrichment_workers(_ew_state, 'watchlist scan')

                # Clear one-time rescan cutoff after full scan cycle
                try:
                    scanner._clear_rescan_cutoff()
                except Exception:
                    pass

                # Always reset flag when scan completes (success or error)
                with watchlist_timer_lock:
                    watchlist_auto_scanning = False
                    watchlist_auto_scanning_timestamp = 0
                    print("[Manual Watchlist Scan] Flag reset - scan complete")
        
        # Initialize scan state
        global watchlist_scan_state
        watchlist_scan_state = {
            'status': 'scanning',
            'started_at': datetime.now(),
            'results': [],
            'summary': {},
            'error': None,
            'cancel_requested': False
        }
        
        # Start scan in background
        thread = threading.Thread(target=run_scan)
        thread.daemon = True
        thread.start()
        
        return jsonify({"success": True, "message": "Watchlist scan started"})
        
    except Exception as e:
        print(f"Error starting watchlist scan: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/watchlist/scan/status', methods=['GET'])
def get_watchlist_scan_status():
    """Get the current status of watchlist scanning"""
    try:
        global watchlist_scan_state
        if 'watchlist_scan_state' not in globals():
            return jsonify({
                "success": True,
                "status": "idle",
                "summary": {}
            })

        # Convert datetime objects to ISO format for JSON serialization
        state = watchlist_scan_state.copy()
        if 'started_at' in state and state['started_at']:
            state['started_at'] = state['started_at'].isoformat()
        if 'completed_at' in state and state['completed_at']:
            state['completed_at'] = state['completed_at'].isoformat()

        # Remove results array - it contains ScanResult objects that aren't JSON serializable
        # The summary already contains the aggregate data we need
        if 'results' in state:
            del state['results']

        return jsonify({"success": True, **state})

    except Exception as e:
        print(f"Error getting watchlist scan status: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/watchlist/scan/cancel', methods=['POST'])
def cancel_watchlist_scan():
    """Cancel a running watchlist scan"""
    try:
        global watchlist_scan_state
        if watchlist_scan_state.get('status') != 'scanning':
            return jsonify({"success": False, "error": "No scan is currently running"}), 400

        watchlist_scan_state['cancel_requested'] = True
        print("[Watchlist Scan] Cancel requested by user")
        return jsonify({"success": True, "message": "Cancel request sent"})

    except Exception as e:
        print(f"Error cancelling watchlist scan: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

# Similar Artists Update State
similar_artists_update_state = {
    'status': 'idle',  # idle, running, completed, error
    'artists_processed': 0,
    'total_artists': 0,
    'current_artist': None,
    'error': None
}
similar_artists_executor = ThreadPoolExecutor(max_workers=1, thread_name_prefix="SimilarArtistsUpdate")

@app.route('/api/watchlist/update-similar-artists', methods=['POST'])
def update_similar_artists_endpoint():
    """Update similar artists for all watchlist artists (for discovery feature)"""
    try:
        global similar_artists_update_state

        if similar_artists_update_state['status'] == 'running':
            return jsonify({"success": False, "error": "Similar artists update already in progress"}), 409

        if not spotify_client or not spotify_client.is_authenticated():
            return jsonify({"success": False, "error": "Spotify client not available"}), 400

        # Reset state
        similar_artists_update_state = {
            'status': 'running',
            'artists_processed': 0,
            'total_artists': 0,
            'current_artist': None,
            'error': None
        }

        # Start update in background
        similar_artists_executor.submit(_update_similar_artists_worker)

        return jsonify({"success": True, "message": "Similar artists update started"})

    except Exception as e:
        print(f"Error starting similar artists update: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

