@app.route('/api/watchlist/artist/<artist_id>/config', methods=['GET', 'POST'])
def watchlist_artist_config(artist_id):
    """Get or update watchlist artist configuration"""
    try:
        from database.music_database import get_database

        database = get_database()

        if request.method == 'GET':
            # Get current config from database
            conn = sqlite3.connect(str(database.database_path))
            cursor = conn.cursor()
            cursor.execute("""
                SELECT include_albums, include_eps, include_singles,
                       include_live, include_remixes, include_acoustic, include_compilations,
                       artist_name, image_url, spotify_artist_id, itunes_artist_id,
                       last_scan_timestamp, date_added, include_instrumentals, deezer_artist_id,
                       lookback_days, discogs_artist_id
                FROM watchlist_artists
                WHERE spotify_artist_id = ? OR itunes_artist_id = ? OR deezer_artist_id = ? OR discogs_artist_id = ?
            """, (artist_id, artist_id, artist_id, artist_id))
            result = cursor.fetchone()
            conn.close()

            if not result:
                return jsonify({"success": False, "error": "Artist not found in watchlist"}), 404

            # Determine if this is an iTunes or Spotify artist
            is_itunes_artist = artist_id.isdigit()
            spotify_id = result[9]  # spotify_artist_id from query
            itunes_id = result[10]  # itunes_artist_id from query
            deezer_id = result[14]  # deezer_artist_id from query
            discogs_id = result[16]  # discogs_artist_id from query

            # Get artist info from Spotify (only for Spotify artists)
            artist_info = None
            if not is_itunes_artist and spotify_client and spotify_client.is_authenticated() and spotify_id and not _spotify_rate_limited():
                try:
                    artist_data = spotify_client.sp.artist(spotify_id)
                    if artist_data:
                        artist_info = {
                            'id': artist_data['id'],
                            'name': artist_data['name'],
                            'image_url': artist_data['images'][0]['url'] if artist_data.get('images') else None,
                            'followers': artist_data.get('followers', {}).get('total', 0),
                            'popularity': artist_data.get('popularity', 0),
                            'genres': artist_data.get('genres', [])
                        }
                except Exception as e:
                    print(f"Warning: Could not fetch artist info from Spotify: {e}")

            # Fallback to database info if Spotify fetch failed
            if not artist_info:
                artist_info = {
                    'id': artist_id,
                    'name': result[7],  # artist_name
                    'image_url': result[8],  # image_url
                    'followers': 0,
                    'popularity': 0,
                    'genres': []
                }

            # Enrich with library artist data (banner, bio, style, mood, label)
            try:
                conn2 = sqlite3.connect(str(database.database_path))
                cur2 = conn2.cursor()
                cur2.execute("""
                    SELECT banner_url, summary, style, mood, label, genres
                    FROM artists
                    WHERE spotify_artist_id = ? OR itunes_artist_id = ? OR deezer_artist_id = ? OR discogs_artist_id = ?
                    LIMIT 1
                """, (artist_id, artist_id, artist_id, artist_id))
                lib_row = cur2.fetchone()
                if lib_row:
                    artist_info['banner_url'] = lib_row[0]
                    artist_info['summary'] = lib_row[1]
                    artist_info['style'] = lib_row[2]
                    artist_info['mood'] = lib_row[3]
                    artist_info['label'] = lib_row[4]
                    # Backfill genres from library if Spotify didn't provide any
                    if not artist_info.get('genres') and lib_row[5]:
                        try:
                            artist_info['genres'] = json.loads(lib_row[5])
                        except (json.JSONDecodeError, TypeError):
                            pass

                # Get recent releases for this watchlist artist
                cur2.execute("""
                    SELECT rr.album_name, rr.release_date, rr.album_cover_url, rr.track_count
                    FROM recent_releases rr
                    JOIN watchlist_artists wa ON rr.watchlist_artist_id = wa.id
                    WHERE wa.spotify_artist_id = ? OR wa.itunes_artist_id = ? OR wa.deezer_artist_id = ?
                    ORDER BY rr.release_date DESC
                    LIMIT 6
                """, (artist_id, artist_id, artist_id))
                releases = [
                    {
                        'album_name': r[0],
                        'release_date': r[1],
                        'album_cover_url': r[2],
                        'track_count': r[3],
                    }
                    for r in cur2.fetchall()
                ]
                conn2.close()
            except Exception as e:
                print(f"Warning: Could not enrich artist from library: {e}")
                releases = []

            config = {
                'include_albums': bool(result[0]),  # Convert INTEGER to boolean
                'include_eps': bool(result[1]),
                'include_singles': bool(result[2]),
                'include_live': bool(result[3]),
                'include_remixes': bool(result[4]),
                'include_acoustic': bool(result[5]),
                'include_compilations': bool(result[6]),
                'include_instrumentals': bool(result[13]) if result[13] is not None else False,
                'last_scan_timestamp': result[11],
                'date_added': result[12],
                'lookback_days': result[15] if len(result) > 15 else None,
            }

            return jsonify({
                "success": True,
                "config": config,
                "artist": artist_info,
                "recent_releases": releases,
                "spotify_artist_id": spotify_id,
                "itunes_artist_id": itunes_id,
                "deezer_artist_id": deezer_id,
                "discogs_artist_id": discogs_id,
                "watchlist_name": result[7],  # Original stored watchlist artist name
            })

        else:  # POST
            data = request.get_json()
            if not data:
                return jsonify({"success": False, "error": "No data provided"}), 400

            include_albums = data.get('include_albums', True)
            include_eps = data.get('include_eps', True)
            include_singles = data.get('include_singles', True)
            include_live = data.get('include_live', False)
            include_remixes = data.get('include_remixes', False)
            include_acoustic = data.get('include_acoustic', False)
            include_compilations = data.get('include_compilations', False)
            include_instrumentals = data.get('include_instrumentals', False)
            lookback_days = data.get('lookback_days', None)  # None = use global setting
            # Validate lookback_days if provided
            if lookback_days is not None:
                lookback_days = int(lookback_days) if lookback_days != '' else None

            # Validate at least one release type is selected
            if not (include_albums or include_eps or include_singles):
                return jsonify({"success": False, "error": "At least one release type must be selected"}), 400

            # Update database
            conn = sqlite3.connect(str(database.database_path))
            cursor = conn.cursor()

            # Check if lookback_days changed — if so, clear last_scan_timestamp to force rescan
            cursor.execute("""
                SELECT lookback_days FROM watchlist_artists
                WHERE spotify_artist_id = ? OR itunes_artist_id = ? OR deezer_artist_id = ? OR discogs_artist_id = ?
            """, (artist_id, artist_id, artist_id, artist_id))
            old_row = cursor.fetchone()
            old_lookback = old_row[0] if old_row else None
            lookback_changed = old_lookback != lookback_days

            cursor.execute("""
                UPDATE watchlist_artists
                SET include_albums = ?, include_eps = ?, include_singles = ?,
                    include_live = ?, include_remixes = ?, include_acoustic = ?, include_compilations = ?,
                    include_instrumentals = ?, lookback_days = ?,
                    last_scan_timestamp = CASE WHEN ? THEN NULL ELSE last_scan_timestamp END,
                    updated_at = CURRENT_TIMESTAMP
                WHERE spotify_artist_id = ? OR itunes_artist_id = ? OR deezer_artist_id = ? OR discogs_artist_id = ?
            """, (int(include_albums), int(include_eps), int(include_singles),
                  int(include_live), int(include_remixes), int(include_acoustic), int(include_compilations),
                  int(include_instrumentals), lookback_days, lookback_changed,
                  artist_id, artist_id, artist_id, artist_id))
            conn.commit()

            if cursor.rowcount == 0:
                conn.close()
                return jsonify({"success": False, "error": "Artist not found in watchlist"}), 404

            conn.close()

            print(f"Updated watchlist config for artist {artist_id}: albums={include_albums}, eps={include_eps}, singles={include_singles}, live={include_live}, remixes={include_remixes}, acoustic={include_acoustic}, compilations={include_compilations}, instrumentals={include_instrumentals}")

            return jsonify({
                "success": True,
                "message": "Artist configuration updated successfully",
                "config": {
                    'include_albums': include_albums,
                    'include_eps': include_eps,
                    'include_singles': include_singles,
                    'include_live': include_live,
                    'include_remixes': include_remixes,
                    'include_acoustic': include_acoustic,
                    'include_compilations': include_compilations,
                    'include_instrumentals': include_instrumentals,
                }
            })

    except Exception as e:
        print(f"Error in watchlist artist config: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/watchlist/artist/<artist_id>/link-provider', methods=['POST'])
def watchlist_artist_link_provider(artist_id):
    """Manually link a watchlist artist to a different Spotify/iTunes artist."""
    try:
        from database.music_database import get_database
        database = get_database()

        data = request.get_json()
        if not data:
            return jsonify({"success": False, "error": "No data provided"}), 400

        new_provider_id = data.get('provider_id', '').strip()
        provider = data.get('provider', '').strip()

        valid_providers = ('spotify', 'itunes', 'deezer', 'discogs')
        if provider not in valid_providers:
            return jsonify({"success": False, "error": f"Invalid provider. Must be one of: {', '.join(valid_providers)}"}), 400

        # Empty provider_id = clear the match for this source
        is_clear = not new_provider_id

        conn = sqlite3.connect(str(database.database_path))
        cursor = conn.cursor()

        # Find the watchlist artist row
        cursor.execute("""
            SELECT id, artist_name, spotify_artist_id, itunes_artist_id
            FROM watchlist_artists
            WHERE spotify_artist_id = ? OR itunes_artist_id = ? OR deezer_artist_id = ? OR discogs_artist_id = ?
        """, (artist_id, artist_id, artist_id, artist_id))
        row = cursor.fetchone()

        if not row:
            conn.close()
            return jsonify({"success": False, "error": "Artist not found in watchlist"}), 404

        watchlist_row_id = row[0]
        artist_name = row[1]

        # Check for duplicate — another watchlist artist already has this provider ID
        col_map = {'spotify': 'spotify_artist_id', 'itunes': 'itunes_artist_id', 'deezer': 'deezer_artist_id', 'discogs': 'discogs_artist_id'}
        col = col_map[provider]

        if not is_clear:
            cursor.execute(f"SELECT id, artist_name FROM watchlist_artists WHERE {col} = ? AND id != ?",
                           (new_provider_id, watchlist_row_id))
            duplicate = cursor.fetchone()
            if duplicate:
                conn.close()
                return jsonify({"success": False, "error": f"Another watchlist artist ('{duplicate[1]}') already has this {provider} ID"}), 409

        # Set to new ID or NULL (clear)
        update_val = new_provider_id if not is_clear else None
        cursor.execute(f"UPDATE watchlist_artists SET {col} = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?",
                       (update_val, watchlist_row_id))

        conn.commit()
        conn.close()

        action = 'Cleared' if is_clear else 'Linked'
        print(f"{action} watchlist artist '{artist_name}' {provider} ID: {new_provider_id or 'NULL'}")

        return jsonify({
            "success": True,
            "message": f"Linked to {provider} artist successfully",
            "new_provider_id": new_provider_id
        })

    except Exception as e:
        print(f"Error linking watchlist artist provider: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500

@app.route('/api/watchlist/global-config', methods=['GET', 'POST'])
def watchlist_global_config():
    """Get or update global watchlist configuration (overrides per-artist settings)"""
    try:
        if request.method == 'GET':
            config = {
                'global_override_enabled': config_manager.get('watchlist.global_override_enabled', False),
                'include_albums': config_manager.get('watchlist.global_include_albums', True),
                'include_eps': config_manager.get('watchlist.global_include_eps', True),
                'include_singles': config_manager.get('watchlist.global_include_singles', True),
                'include_live': config_manager.get('watchlist.global_include_live', False),
                'include_remixes': config_manager.get('watchlist.global_include_remixes', False),
                'include_acoustic': config_manager.get('watchlist.global_include_acoustic', False),
                'include_compilations': config_manager.get('watchlist.global_include_compilations', False),
                'include_instrumentals': config_manager.get('watchlist.global_include_instrumentals', False),
                'exclude_terms': config_manager.get('watchlist.exclude_terms', ''),
            }
            return jsonify({"success": True, "config": config})

        else:  # POST
            data = request.get_json()
            if not data:
                return jsonify({"success": False, "error": "No data provided"}), 400

            global_override_enabled = data.get('global_override_enabled', False)
            include_albums = data.get('include_albums', True)
            include_eps = data.get('include_eps', True)
            include_singles = data.get('include_singles', True)
            include_live = data.get('include_live', False)
            include_remixes = data.get('include_remixes', False)
            include_acoustic = data.get('include_acoustic', False)
            include_compilations = data.get('include_compilations', False)
            include_instrumentals = data.get('include_instrumentals', False)
            exclude_terms = data.get('exclude_terms', '')

            # When override is enabled, validate at least one release type
            if global_override_enabled and not (include_albums or include_eps or include_singles):
                return jsonify({"success": False, "error": "At least one release type must be selected"}), 400

            config_manager.set('watchlist.global_override_enabled', global_override_enabled)
            config_manager.set('watchlist.global_include_albums', include_albums)
            config_manager.set('watchlist.global_include_eps', include_eps)
            config_manager.set('watchlist.global_include_singles', include_singles)
            config_manager.set('watchlist.global_include_live', include_live)
            config_manager.set('watchlist.global_include_remixes', include_remixes)
            config_manager.set('watchlist.global_include_acoustic', include_acoustic)
            config_manager.set('watchlist.global_include_compilations', include_compilations)
            config_manager.set('watchlist.global_include_instrumentals', include_instrumentals)
            config_manager.set('watchlist.exclude_terms', exclude_terms)

            print(f"Updated global watchlist config: override={global_override_enabled}, "
                  f"albums={include_albums}, eps={include_eps}, singles={include_singles}, "
                  f"live={include_live}, remixes={include_remixes}, acoustic={include_acoustic}, "
                  f"compilations={include_compilations}, instrumentals={include_instrumentals}, "
                  f"exclude_terms='{exclude_terms}'")

            return jsonify({
                "success": True,
                "message": "Global watchlist configuration updated",
                "config": {
                    'global_override_enabled': global_override_enabled,
                    'include_albums': include_albums,
                    'include_eps': include_eps,
                    'include_singles': include_singles,
                    'include_live': include_live,
                    'include_remixes': include_remixes,
                    'include_acoustic': include_acoustic,
                    'include_compilations': include_compilations,
                    'include_instrumentals': include_instrumentals,
                    'exclude_terms': exclude_terms,
                }
            })

    except Exception as e:
        print(f"Error in watchlist global config: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({"success": False, "error": str(e)}), 500

def _apply_watchlist_global_overrides(watchlist_artists):
    """If global override is enabled, overwrite per-artist settings on WatchlistArtist objects."""
    if not config_manager.get('watchlist.global_override_enabled', False):
        return
    # Read global settings once
    g_albums = config_manager.get('watchlist.global_include_albums', True)
    g_eps = config_manager.get('watchlist.global_include_eps', True)
    g_singles = config_manager.get('watchlist.global_include_singles', True)
    g_live = config_manager.get('watchlist.global_include_live', False)
    g_remixes = config_manager.get('watchlist.global_include_remixes', False)
    g_acoustic = config_manager.get('watchlist.global_include_acoustic', False)
    g_compilations = config_manager.get('watchlist.global_include_compilations', False)
    g_instrumentals = config_manager.get('watchlist.global_include_instrumentals', False)
    print(f"[Watchlist] Global override is ACTIVE — applying to {len(watchlist_artists)} artists "
          f"(albums={g_albums}, eps={g_eps}, singles={g_singles}, live={g_live}, "
          f"remixes={g_remixes}, acoustic={g_acoustic}, compilations={g_compilations}, "
          f"instrumentals={g_instrumentals})")
    for artist in watchlist_artists:
        artist.include_albums = g_albums
        artist.include_eps = g_eps
        artist.include_singles = g_singles
        artist.include_live = g_live
        artist.include_remixes = g_remixes
        artist.include_acoustic = g_acoustic
        artist.include_compilations = g_compilations
        artist.include_instrumentals = g_instrumentals

def _update_similar_artists_worker():
    """Background worker to update similar artists for all watchlist artists"""
    global similar_artists_update_state

    try:
        from core.watchlist_scanner import get_watchlist_scanner
        from database.music_database import get_database
        import time

        print("[Similar Artists] Starting similar artists update...")

        database = get_database()
        all_profiles = database.get_all_profiles()

        # Build per-profile artist lists and deduplicate for API calls
        # artist_key -> (artist_obj, [profile_ids])
        artist_profiles = {}
        for p in all_profiles:
            for artist in database.get_watchlist_artists(profile_id=p['id']):
                key = (artist.spotify_artist_id or '', artist.itunes_artist_id or '', artist.artist_name.lower())
                if key not in artist_profiles:
                    artist_profiles[key] = (artist, [])
                artist_profiles[key][1].append(p['id'])

        if not artist_profiles:
            similar_artists_update_state['status'] = 'completed'
            print("[Similar Artists] No watchlist artists to process")
            return

        similar_artists_update_state['total_artists'] = len(artist_profiles)
        print(f"[Similar Artists] Processing {len(artist_profiles)} unique watchlist artists across {len(all_profiles)} profiles")

        scanner = get_watchlist_scanner(spotify_client)

        for idx, (key, (artist, profile_ids)) in enumerate(artist_profiles.items(), 1):
            try:
                similar_artists_update_state['artists_processed'] = idx
                similar_artists_update_state['current_artist'] = artist.artist_name

                print(f"[{idx}/{len(artist_profiles)}] Updating similar artists for {artist.artist_name} (profiles: {profile_ids})")

                # Update similar artists for each profile that watches this artist
                for pid in profile_ids:
                    scanner.update_similar_artists(artist, limit=10, profile_id=pid)

                # Rate limiting
                if idx < len(artist_profiles):
                    time.sleep(2.0)  # 2 seconds between artists

            except Exception as artist_error:
                print(f"[Similar Artists] Error processing {artist.artist_name}: {artist_error}")
                continue

        # Update complete
        similar_artists_update_state['status'] = 'completed'
        similar_artists_update_state['current_artist'] = None

        print(f"[Similar Artists] Update complete! Processed {len(artist_profiles)} artists")

    except Exception as e:
        print(f"[Similar Artists] Critical error: {e}")
        import traceback
        traceback.print_exc()

        similar_artists_update_state['status'] = 'error'
        similar_artists_update_state['error'] = str(e)

# --- Watchlist Auto-Scanning System ---

watchlist_scan_state = {
    'status': 'idle',
    'results': [],
    'summary': {},
    'error': None
}

def _process_watchlist_scan_automatically(automation_id=None, profile_id=None):
    """Main automatic scanning logic that runs in background thread.

    Args:
        automation_id: ID of the automation triggering this scan
        profile_id: If provided, only scan this profile's watchlist (manual trigger).
                    If None, scan all profiles (scheduled automation).
    """
    global watchlist_auto_scanning, watchlist_auto_scanning_timestamp, watchlist_scan_state

    scope_label = f"profile {profile_id}" if profile_id else "all profiles"
    print(f"[Auto-Watchlist] Timer triggered - starting automatic watchlist scan ({scope_label})...")

    _ew_state = {}

    try:
        # CRITICAL FIX: Use smart stuck detection BEFORE acquiring lock
        # This prevents deadlock and handles stuck flags (2-hour timeout)
        if is_watchlist_actually_scanning():
            print("[Auto-Watchlist] Already scanning (verified with stuck detection), skipping.")
            return

        with watchlist_timer_lock:
            # Re-check inside lock to handle race conditions
            if watchlist_auto_scanning:
                print("[Auto-Watchlist] Already scanning (race condition check), skipping.")
                return

            # Set flag and timestamp
            import time
            watchlist_auto_scanning = True
            watchlist_auto_scanning_timestamp = time.time()
            print(f"[Auto-Watchlist] Flag set at timestamp {watchlist_auto_scanning_timestamp}")

        # Use app context for database operations
        with app.app_context():
            from core.watchlist_scanner import get_watchlist_scanner
            from database.music_database import get_database

            database = get_database()

            # Determine which profiles to scan
            if profile_id:
                # Manual trigger — scan only the triggering profile
                scan_profiles = [{'id': profile_id}]
            else:
                # Scheduled automation — scan all profiles
                scan_profiles = database.get_all_profiles()

            watchlist_count = sum(database.get_watchlist_count(profile_id=p['id']) for p in scan_profiles)
            profile_label = f"profile {profile_id}" if profile_id else f"{len(scan_profiles)} profiles"
            print(f"[Auto-Watchlist] Watchlist count check: {watchlist_count} artists found ({profile_label})")

            if watchlist_count == 0:
                print("ℹ️ [Auto-Watchlist] No artists in watchlist for auto-scanning.")
                with watchlist_timer_lock:
                    watchlist_auto_scanning = False
                    watchlist_auto_scanning_timestamp = 0
                return

            if not spotify_client or not spotify_client.is_authenticated():
                print("ℹ️ [Auto-Watchlist] Spotify client not available or not authenticated.")
                with watchlist_timer_lock:
                    watchlist_auto_scanning = False
                    watchlist_auto_scanning_timestamp = 0
                return

            print(f"[Auto-Watchlist] Found {watchlist_count} artists in watchlist, starting automatic scan...")
            _update_automation_progress(automation_id, progress=5, phase='Loading watchlist',
                                         log_line=f'{watchlist_count} artists ({profile_label})', log_type='info')

            # Get list of artists to scan
            watchlist_artists = []
            for p in scan_profiles:
                watchlist_artists.extend(database.get_watchlist_artists(profile_id=p['id']))
            scanner = get_watchlist_scanner(spotify_client)
            all_profiles = scan_profiles  # Used later for discovery pool population

            # Apply global overrides if enabled
            _apply_watchlist_global_overrides(watchlist_artists)

            # Initialize detailed progress tracking (same as manual scan)
            watchlist_scan_state = {
                'status': 'scanning',
                'started_at': datetime.now(),
                'total_artists': len(watchlist_artists),
                'current_artist_index': 0,
                'current_artist_name': '',
                'current_artist_image_url': '',
                'current_phase': 'starting',
                'albums_to_check': 0,
                'albums_checked': 0,
                'current_album': '',
                'current_album_image_url': '',
                'current_track_name': '',
                'tracks_found_this_scan': 0,
                'tracks_added_this_scan': 0,
                'recent_wishlist_additions': [],
                'results': [],
                'summary': {},
                'error': None,
                'cancel_requested': False
            }

            scan_results = []

            # Pause enrichment workers during scan to reduce API contention
            _ew_state = _pause_enrichment_workers('auto-watchlist scan')

            # Dynamic delay calculation based on scan scope
            lookback_period = scanner._get_lookback_period_setting()
            is_full_discography = (lookback_period == 'all')
            artist_count = len(watchlist_artists)

            base_artist_delay = 2.0
            base_album_delay = 0.5

            # Scale up for full discography (way more albums per artist)
            if is_full_discography:
                base_artist_delay *= 2.0
                base_album_delay *= 2.0

            # Scale up further for large artist counts (sustained API pressure)
            if artist_count > 200:
                base_artist_delay *= 1.5
                base_album_delay *= 1.25
            elif artist_count > 100:
                base_artist_delay *= 1.25

            artist_delay = base_artist_delay
            album_delay = base_album_delay
            print(f"[Auto-Watchlist] Scan parameters: {artist_count} artists, lookback={lookback_period}, "
                  f"delays: {artist_delay:.1f}s/artist, {album_delay:.1f}s/album")

            # Circuit breaker: pause scan on consecutive rate-limit failures
            consecutive_failures = 0
            CIRCUIT_BREAKER_THRESHOLD = 3
            circuit_breaker_pause = 60  # seconds, doubles each trigger, max 600s

            # Scan each artist with detailed tracking
            for i, artist in enumerate(watchlist_artists):
                # Check for cancel request
                if watchlist_scan_state.get('cancel_requested'):
                    print(f"[Auto-Watchlist] Cancel requested after {i}/{len(watchlist_artists)} artists")
                    watchlist_scan_state['status'] = 'cancelled'
                    watchlist_scan_state['current_phase'] = 'cancelled'
                    watchlist_scan_state['summary'] = {
                        'total_artists': i,
                        'successful_scans': len([r for r in scan_results if r.success]),
                        'new_tracks_found': sum(r.new_tracks_found for r in scan_results if r.success),
                        'tracks_added_to_wishlist': sum(r.tracks_added_to_wishlist for r in scan_results if r.success),
                        'cancelled': True
                    }
                    _update_automation_progress(automation_id, progress=100, phase='Cancelled by user',
                                                 log_line='Scan cancelled by user', log_type='warning')
                    break

                try:
                    # Fetch artist image using provider-aware method
                    artist_image_url = scanner.get_artist_image_url(artist) or ''

                    pct = 5 + (i / max(1, len(watchlist_artists))) * 90
                    _update_automation_progress(automation_id, progress=pct,
                        phase=f'Scanning: {artist.artist_name} ({i+1}/{len(watchlist_artists)})',
                        current_item=artist.artist_name,
                        processed=i, total=len(watchlist_artists))

                    # Update progress
                    watchlist_scan_state.update({
                        'current_artist_index': i + 1,
                        'current_artist_name': artist.artist_name,
                        'current_artist_image_url': artist_image_url,
                        'current_phase': 'fetching_discography',
                        'albums_to_check': 0,
                        'albums_checked': 0,
                        'current_album': '',
                        'current_album_image_url': '',
                        'current_track_name': ''
                    })

                    # Get artist discography using provider-aware method
                    albums = scanner.get_artist_discography_for_watchlist(artist, artist.last_scan_timestamp)

                    if albums is None:
                        scan_results.append(type('ScanResult', (), {
                            'artist_name': artist.artist_name,
                            'spotify_artist_id': artist.spotify_artist_id,
                            'albums_checked': 0,
                            'new_tracks_found': 0,
                            'tracks_added_to_wishlist': 0,
                            'success': False,
                            'error_message': "Failed to get artist discography"
                        })())
                        continue

                    # Update with album count
                    watchlist_scan_state.update({
                        'current_phase': 'checking_albums',
                        'albums_to_check': len(albums),
                        'albums_checked': 0
                    })

                    # Track progress for this artist
                    artist_new_tracks = 0
                    artist_added_tracks = 0

                    # Scan each album
                    for album_index, album in enumerate(albums):
                        try:
                            # Get album tracks using provider-aware method
                            album_data = scanner.metadata_service.get_album(album.id)
                            if not album_data or 'tracks' not in album_data:
                                logger.debug(f"Skipping album {album.name} (id={album.id}): no track data returned")
                                continue

                            tracks = album_data['tracks']['items']

                            # Check release type filter (album/EP/single)
                            if not scanner._should_include_release(len(tracks), artist):
                                continue

                            # Get album image
                            album_image_url = ''
                            if 'images' in album_data and album_data['images']:
                                album_image_url = album_data['images'][0]['url']

                            watchlist_scan_state.update({
                                'albums_checked': album_index + 1,
                                'current_album': album.name,
                                'current_album_image_url': album_image_url,
                                'current_phase': f'checking_album_{album_index + 1}_of_{len(albums)}'
                            })

                            # Check each track
                            for track in tracks:
                                # Check content type filter (live/remix/acoustic/compilation)
                                if not scanner._should_include_track(track, album_data, artist):
                                    continue

                                # Update current track being processed
                                track_name = track.get('name', 'Unknown Track')
                                watchlist_scan_state['current_track_name'] = track_name

                                if scanner.is_track_missing_from_library(track):
                                    artist_new_tracks += 1
                                    watchlist_scan_state['tracks_found_this_scan'] += 1

                                    # Add to wishlist
                                    if scanner.add_track_to_wishlist(track, album_data, artist):
                                        artist_added_tracks += 1
                                        watchlist_scan_state['tracks_added_this_scan'] += 1

                                        # Add to recent wishlist additions feed
                                        track_artists = track.get('artists', [])
                                        track_artist_name = track_artists[0].get('name', 'Unknown Artist') if track_artists else 'Unknown Artist'

                                        watchlist_scan_state['recent_wishlist_additions'].insert(0, {
                                            'track_name': track_name,
                                            'artist_name': track_artist_name,
                                            'album_image_url': album_image_url
                                        })

                                        # Keep only last 10
                                        if len(watchlist_scan_state['recent_wishlist_additions']) > 10:
                                            watchlist_scan_state['recent_wishlist_additions'].pop()

                            # Rate-limited delay between albums
                            import time
                            time.sleep(album_delay)

                        except Exception as e:
                            print(f"Error checking album {album.name}: {e}")
                            continue

                    # Update scan timestamp
                    scanner.update_artist_scan_timestamp(artist)

                    # Store result
                    scan_results.append(type('ScanResult', (), {
                        'artist_name': artist.artist_name,
                        'spotify_artist_id': artist.spotify_artist_id,
                        'albums_checked': len(albums),
                        'new_tracks_found': artist_new_tracks,
                        'tracks_added_to_wishlist': artist_added_tracks,
                        'success': True,
                        'error_message': None
                    })())

                    print(f"Scanned {artist.artist_name}: {artist_new_tracks} new tracks found, {artist_added_tracks} added to wishlist")
                    if artist_new_tracks > 0:
                        _update_automation_progress(automation_id,
                            log_line=f'{artist.artist_name} — {artist_new_tracks} new, {artist_added_tracks} added', log_type='success')
                    else:
                        _update_automation_progress(automation_id,
                            log_line=f'{artist.artist_name} — no new tracks', log_type='skip')

                    # Emit watchlist_new_release event if new tracks were found
                    if artist_new_tracks > 0:
                        try:
                            if automation_engine:
                                automation_engine.emit('watchlist_new_release', {
                                    'artist': artist.artist_name,
                                    'new_tracks': str(artist_new_tracks),
                                    'added_to_wishlist': str(artist_added_tracks),
                                })
                        except Exception:
                            pass

                    # Fetch similar artists for discovery feature (per-profile)
                    try:
                        watchlist_scan_state['current_phase'] = 'fetching_similar_artists'
                        source_artist_id = artist.spotify_artist_id or artist.itunes_artist_id or str(artist.id)
                        artist_profile_id = getattr(artist, 'profile_id', 1)

                        spotify_authenticated = spotify_client and spotify_client.is_spotify_authenticated()
                        if database.has_fresh_similar_artists(source_artist_id, days_threshold=30, require_spotify=spotify_authenticated, profile_id=artist_profile_id):
                            print(f"  Similar artists for {artist.artist_name} are cached and fresh (profile {artist_profile_id})")
                            scanner._backfill_similar_artists_itunes_ids(source_artist_id, profile_id=artist_profile_id)
                        else:
                            print(f"  Fetching similar artists for {artist.artist_name} (profile {artist_profile_id})...")
                            scanner.update_similar_artists(artist, profile_id=artist_profile_id)
                            print(f"  Similar artists updated for {artist.artist_name}")
                    except Exception as similar_error:
                        print(f"  Failed to update similar artists for {artist.artist_name}: {similar_error}")

                    # Delay between artists
                    if i < len(watchlist_artists) - 1:
                        watchlist_scan_state['current_phase'] = 'rate_limiting'
                        time.sleep(artist_delay)

                    # Reset circuit breaker on successful artist scan
                    consecutive_failures = 0
                    circuit_breaker_pause = 60

                except Exception as e:
                    print(f"Error scanning artist {artist.artist_name}: {e}")
                    _update_automation_progress(automation_id,
                        log_line=f'{artist.artist_name} — error: {str(e)[:60]}', log_type='error')

                    # Circuit breaker: detect consecutive rate-limit failures
                    error_str = str(e).lower()
                    if "429" in error_str or "rate limit" in error_str:
                        consecutive_failures += 1
                        if consecutive_failures >= CIRCUIT_BREAKER_THRESHOLD:
                            print(f"[Auto-Watchlist] Circuit breaker: {consecutive_failures} consecutive rate-limit failures, pausing {circuit_breaker_pause}s")
                            watchlist_scan_state['current_phase'] = 'circuit_breaker_pause'
                            time.sleep(circuit_breaker_pause)
                            circuit_breaker_pause = min(circuit_breaker_pause * 2, 600)
                            consecutive_failures = 0
                    else:
                        consecutive_failures = 0

                    scan_results.append(type('ScanResult', (), {
                        'artist_name': artist.artist_name,
                        'spotify_artist_id': artist.spotify_artist_id,
                        'albums_checked': 0,
                        'new_tracks_found': 0,
                        'tracks_added_to_wishlist': 0,
                        'success': False,
                        'error_message': str(e)
                    })())
                    continue

            # Update state with results (skip if cancelled — already set by cancel handler)
            was_cancelled = watchlist_scan_state.get('cancel_requested', False)
            if not was_cancelled:
                successful_scans = [r for r in scan_results if r.success]
                total_new_tracks = sum(r.new_tracks_found for r in successful_scans)
                total_added_to_wishlist = sum(r.tracks_added_to_wishlist for r in successful_scans)

                watchlist_scan_state['status'] = 'completed'
                watchlist_scan_state['results'] = scan_results
                watchlist_scan_state['completed_at'] = datetime.now()
                watchlist_scan_state['summary'] = {
                    'total_artists': len(scan_results),
                    'successful_scans': len(successful_scans),
                    'new_tracks_found': total_new_tracks,
                    'tracks_added_to_wishlist': total_added_to_wishlist
                }

                print(f"Automatic watchlist scan completed: {len(successful_scans)}/{len(scan_results)} artists scanned successfully")
                print(f"Found {total_new_tracks} new tracks, added {total_added_to_wishlist} to wishlist")
                _update_automation_progress(automation_id, progress=95, phase='Scan complete',
                                             log_line=f'Scanned {len(successful_scans)} artists — {total_new_tracks} new tracks, {total_added_to_wishlist} added to wishlist',
                                             log_type='success' if total_new_tracks > 0 else 'info')
            else:
                total_new_tracks = watchlist_scan_state.get('summary', {}).get('new_tracks_found', 0)
                total_added_to_wishlist = watchlist_scan_state.get('summary', {}).get('tracks_added_to_wishlist', 0)
                print(f"Automatic watchlist scan cancelled — skipping post-scan steps")

            # Post-scan steps — skip if cancelled
            if not was_cancelled:
                # Populate discovery pool from similar artists (per-profile)
                print("Starting discovery pool population...")
                watchlist_scan_state['current_phase'] = 'populating_discovery_pool'
                _update_automation_progress(automation_id, progress=96, phase='Populating discovery pool',
                                             log_line='Building discovery pool from similar artists...', log_type='info')
                try:
                    def _discovery_progress(event_type, message):
                        if event_type == 'artist':
                            _update_automation_progress(automation_id, phase=f'Discovery pool: {message}',
                                                         log_line=message, log_type='info',
                                                         current_item=message)
                        elif event_type == 'phase':
                            _update_automation_progress(automation_id, phase=message,
                                                         log_line=message, log_type='info')
                        elif event_type == 'success':
                            _update_automation_progress(automation_id,
                                                         log_line=message, log_type='success')
                        elif event_type == 'skip':
                            _update_automation_progress(automation_id,
                                                         log_line=message, log_type='info')

                    for p in all_profiles:
                        scanner.populate_discovery_pool(profile_id=p['id'], progress_callback=_discovery_progress)
                    print("Discovery pool population complete")
                except Exception as discovery_error:
                    print(f"Error populating discovery pool: {discovery_error}")
                    import traceback
                    traceback.print_exc()
                    _update_automation_progress(automation_id,
                                                 log_line=f'Discovery pool error: {discovery_error}', log_type='error')

                # Update ListenBrainz playlists cache
                print("Starting ListenBrainz playlists update...")
                watchlist_scan_state['current_phase'] = 'updating_listenbrainz'
                _update_automation_progress(automation_id, progress=97, phase='Updating ListenBrainz',
                                             log_line='Fetching ListenBrainz playlists...', log_type='info')
                try:
                    from core.listenbrainz_manager import ListenBrainzManager
                    db = get_database()
                    db_path = str(db.database_path)
                    lb_profiles = db.get_profiles_with_listenbrainz()
                    if lb_profiles:
                        for lb_prof in lb_profiles:
                            lb_manager = ListenBrainzManager(db_path, profile_id=lb_prof['id'], token=lb_prof['token'], base_url=lb_prof['base_url'])
                            lb_result = lb_manager.update_all_playlists()
                            if lb_result.get('success'):
                                summary = lb_result.get('summary', {})
                                print(f"ListenBrainz update complete for profile {lb_prof['id']}: {summary}")
                                _update_automation_progress(automation_id,
                                                             log_line=f'ListenBrainz (profile {lb_prof["id"]}): playlists updated', log_type='success')
                    else:
                        lb_manager = ListenBrainzManager(db_path)
                        lb_result = lb_manager.update_all_playlists()
                        if lb_result.get('success'):
                            summary = lb_result.get('summary', {})
                            print(f"ListenBrainz update complete (global): {summary}")
                            _update_automation_progress(automation_id,
                                                         log_line=f'ListenBrainz: playlists updated', log_type='success')
                        else:
                            print(f"ListenBrainz update had issues: {lb_result.get('error', 'Unknown error')}")
                            _update_automation_progress(automation_id,
                                                         log_line=f'ListenBrainz: {lb_result.get("error", "Unknown error")}', log_type='error')
                except Exception as lb_error:
                    print(f"Error updating ListenBrainz: {lb_error}")
                    import traceback
                    traceback.print_exc()
                    _update_automation_progress(automation_id,
                                                 log_line=f'ListenBrainz error: {lb_error}', log_type='error')

                # Update current seasonal playlist (weekly refresh)
                print("Starting seasonal content update...")
                watchlist_scan_state['current_phase'] = 'updating_seasonal'
                _update_automation_progress(automation_id, progress=98, phase='Updating seasonal content',
                                             log_line='Checking seasonal playlists...', log_type='info')
                try:
                    from core.seasonal_discovery import get_seasonal_discovery_service
                    seasonal_service = get_seasonal_discovery_service(spotify_client, database)

                    # Only update the current active season
                    current_season = seasonal_service.get_current_season()
                    if current_season:
                        if seasonal_service.should_populate_seasonal_content(current_season, days_threshold=7):
                            print(f"Updating {current_season} seasonal content...")
                            _update_automation_progress(automation_id,
                                                         log_line=f'Updating {current_season} seasonal content...', log_type='info')
                            seasonal_service.populate_seasonal_content(current_season)
                            seasonal_service.curate_seasonal_playlist(current_season)
                            print(f"{current_season.capitalize()} seasonal content updated")
                            _update_automation_progress(automation_id,
                                                         log_line=f'{current_season.capitalize()} seasonal content updated', log_type='success')
                        else:
                            print(f"{current_season.capitalize()} seasonal content recently updated, skipping")
                            _update_automation_progress(automation_id,
                                                         log_line=f'{current_season.capitalize()} seasonal content up to date', log_type='info')
                    else:
                        print("ℹ️ No active season at this time")
                        _update_automation_progress(automation_id,
                                                     log_line='No active season', log_type='info')
                except Exception as seasonal_error:
                    print(f"Error updating seasonal content: {seasonal_error}")
                    import traceback
                    traceback.print_exc()
                    _update_automation_progress(automation_id,
                                                 log_line=f'Seasonal error: {seasonal_error}', log_type='error')

                # Sync Spotify library cache
                print("Syncing Spotify library cache...")
                try:
                    for p in all_profiles:
                        scanner.sync_spotify_library_cache(profile_id=p['id'])
                    print("Spotify library cache sync complete")
                    _update_automation_progress(automation_id,
                                                 log_line='Spotify library cache synced', log_type='info')
                except Exception as lib_error:
                    print(f"Error syncing Spotify library: {lib_error}")
                    _update_automation_progress(automation_id,
                                                 log_line=f'Library cache error: {lib_error}', log_type='error')

                # Add activity for watchlist scan completion
                if total_added_to_wishlist > 0:
                    add_activity_item("", "Watchlist Scan Complete", f"{total_added_to_wishlist} new tracks added to wishlist", "Now")

                try:
                    if automation_engine:
                        automation_engine.emit('watchlist_scan_completed', {
                            'artists_scanned': str(len(scan_results)),
                            'new_tracks_found': str(total_new_tracks),
                            'tracks_added': str(total_added_to_wishlist),
                        })
                except Exception:
                    pass

    except Exception as e:
        print(f"Error in automatic watchlist scan: {e}")
        import traceback
        traceback.print_exc()
        _update_automation_progress(automation_id, log_line=f'Error: {str(e)}', log_type='error')

        watchlist_scan_state['status'] = 'error'
        watchlist_scan_state['error'] = str(e)
        raise  # re-raise so automation wrapper returns error status

    finally:
        # Resume enrichment workers if we paused them
        _resume_enrichment_workers(_ew_state, 'auto-watchlist scan')

        # Clear one-time rescan cutoff after full scan cycle
        try:
            scanner._clear_rescan_cutoff()
        except Exception:
            pass

        # Always reset flag
        with watchlist_timer_lock:
            watchlist_auto_scanning = False
            watchlist_auto_scanning_timestamp = 0

    print("Automatic watchlist scanning complete")

